def get_runtime_dir() -> Path:
    """Retourne le dossier de travail de l'application.

    - En mode développement : le dossier contenant app.py.
    - En mode EXE PyInstaller : le dossier contenant CLYO_Stock.exe.

    Cela permet de garder referentiel_stock.xlsx, stock_assets.db et qr_codes
    à côté de l'exécutable, donc faciles à sauvegarder et modifier.
    """
    if getattr(sys, "frozen", False):
        return Path(sys.executable).resolve().parent
    return Path(__file__).resolve().parent


APP_DIR = get_runtime_dir()
APP_RESOURCE_DIR = Path(getattr(sys, "_MEIPASS", APP_DIR))
# Dossier applicatif fixe utilisé par l'installateur intégré sous Windows.
# Le ZIP de mise à jour est copié ici avant lancement du build EXE.
FIXED_APP_INSTALL_DIR = APP_DIR  # V8.0.6 : l’Updater installe dans le dossier réel de l’application, plus dans un chemin utilisateur fixe.


def get_writable_root_dir() -> Path:
    """Dossier racine inscriptible pour les fichiers de travail.

    En mode portable, les données restent à côté de l'application comme avant.
    En mode programme installé dans Program Files, les données sont déplacées
    dans ProgramData pour éviter les blocages de droits Windows.
    """
    forced = os.environ.get("CLYO_STOCK_APPDATA_DIR") or os.environ.get("CLYO_STOCK_DATA_ROOT")
    if forced:
        return Path(forced).expanduser().resolve()
    if os.name == "nt" and getattr(sys, "frozen", False):
        try:
            app_dir_resolved = APP_DIR.resolve()
            program_files_dirs = [os.environ.get("ProgramFiles"), os.environ.get("ProgramFiles(x86)")]
            for raw in program_files_dirs:
                if not raw:
                    continue
                try:
                    if str(app_dir_resolved).lower().startswith(str(Path(raw).resolve()).lower()):
                        return (Path(os.environ.get("ProgramData", r"C:\ProgramData")) / "CLYO Stock Atelier").resolve()
                except Exception:
                    continue
        except Exception:
            return Path(os.environ.get("ProgramData", r"C:\ProgramData")) / "CLYO Stock Atelier"
    return APP_DIR


APP_WRITABLE_ROOT_DIR = get_writable_root_dir()


def get_update_workspace_dir_v7776() -> Path:
    """Retourne un dossier inscriptible pour les téléchargements de mise à jour.

    Quand l'application est installée dans Program Files, un utilisateur standard
    ne peut pas écrire dans APP_DIR/update_backups. Les fichiers temporaires de
    mise à jour doivent donc être stockés dans ProgramData/LocalAppData/TEMP.
    """
    forced = os.environ.get("CLYO_STOCK_UPDATE_DIR")
    candidates: list[Path] = []
    if forced:
        candidates.append(Path(forced).expanduser())
    candidates.append(APP_WRITABLE_ROOT_DIR / "update_backups")
    if os.name == "nt":
        for env_name in ("LOCALAPPDATA", "TEMP", "TMP"):
            raw = os.environ.get(env_name)
            if raw:
                candidates.append(Path(raw) / "CLYO Stock Atelier" / "update_backups")
    else:
        candidates.append(Path(os.environ.get("TMPDIR", "/tmp")) / "clyo_stock_atelier" / "update_backups")
    candidates.append(APP_DIR / "update_backups")

    seen: set[str] = set()
    last_error = ""
    for candidate in candidates:
        try:
            candidate = candidate.resolve()
            key = str(candidate).lower()
            if key in seen:
                continue
            seen.add(key)
            candidate.mkdir(parents=True, exist_ok=True)
            probe = candidate / ".write_test"
            probe.write_text("ok", encoding="utf-8")
            probe.unlink(missing_ok=True)
            return candidate
        except Exception as exc:
            last_error = f"{candidate}: {type(exc).__name__}: {exc}"
            continue

    raise HTTPException(
        status_code=500,
        detail=f"Aucun dossier de travail inscriptible pour la mise à jour GitHub. Dernière erreur : {last_error}",
    )


