def _safe_data_path_v808(raw: Any) -> Path:
    """Convertit un chemin sans forcer Path.resolve().

    Sur Windows, resolve() peut déclencher un accès immédiat au réseau sur un
    chemin UNC (ex. \\NAS\Partage) et lever WinError 67 si le NAS est
    momentanément indisponible. Pour les bases NAS, il faut conserver le chemin
    tel quel et tester l'accès séparément.
    """
    try:
        p = Path(str(raw or "").strip().strip('"')).expanduser()
    except Exception:
        p = Path(str(raw or ""))
    try:
        if not p.is_absolute():
            p = APP_DIR / p
    except Exception:
        pass
    return p


def _path_exists_quiet_v808(path: Path) -> bool:
    try:
        return path.exists()
    except OSError:
        return False
    except Exception:
        return False


def _active_data_config_candidates_v814() -> list[Path]:
    """Emplacements possibles du fichier qui mémorise la base active.

    Les anciennes versions ont pu écrire cette configuration à côté de l'EXE,
    dans ProgramData ou dans un dossier utilisateur. Lors d'une mise à jour,
    on doit récupérer ce chemin au lieu de redemander une base.
    """
    candidates: list[Path] = [ACTIVE_DATA_CONFIG_PATH, ACTIVE_DATA_PRESERVE_PATH_V814]
    try:
        candidates.append(APP_DIR / "nexvandal_active_data.json")
    except Exception:
        pass
    try:
        candidates.append(APP_DIR / "data" / "nexvandal_active_data.json")
    except Exception:
        pass
    if os.name == "nt":
        for env_name in ("ProgramData", "LOCALAPPDATA", "APPDATA"):
            raw = os.environ.get(env_name)
            if raw:
                candidates.append(Path(raw) / "CLYO Stock Atelier" / "nexvandal_active_data.json")
                candidates.append(Path(raw) / "CLYO Stock Atelier" / "nexvandal_active_data_preserved_before_update.json")
    seen: set[str] = set()
    ordered: list[Path] = []
    for p in candidates:
        try:
            key = str(p).lower()
        except Exception:
            continue
        if key in seen:
            continue
        seen.add(key)
        ordered.append(p)
    return ordered


def _read_active_config_file_v814(path: Path) -> dict[str, Any] | None:
    try:
        if not path.exists() or not path.is_file():
            return None
        data = json.loads(path.read_text(encoding="utf-8", errors="ignore") or "{}")
        return data if isinstance(data, dict) else None
    except Exception:
        return None


def _mirror_active_config_to_primary_v814(data: dict[str, Any]) -> None:
    """Copie le choix récupéré vers le nouvel emplacement principal.

    Cette opération n'efface jamais le chemin de base. Si l'écriture échoue,
    l'application continue quand même avec la base détectée.
    """
    try:
        if not isinstance(data, dict):
            return
        payload = dict(data)
        payload["recovered_by_version"] = APP_VERSION
        payload["updated_at"] = datetime.now().isoformat(timespec="seconds")
        ACTIVE_DATA_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
        ACTIVE_DATA_CONFIG_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass


def read_active_data_dir_from_config() -> Path:
    """Retourne le dossier de données actif sans planter si un NAS est absent.

    V8.1.4 : recherche aussi les anciens fichiers de configuration afin qu'une
    mise à jour conserve toujours l'ancienne base de travail locale, NAS ou SQL.
    """
    global DATA_DIR_STARTUP_ERROR, DATA_DIR_CONFIGURED_SOURCE, DATA_DIR_FALLBACK_ACTIVE
    DATA_DIR_STARTUP_ERROR = ""
    DATA_DIR_CONFIGURED_SOURCE = ""
    DATA_DIR_FALLBACK_ACTIVE = False

    first_unavailable = ""
    for cfg_path in _active_data_config_candidates_v814():
        data = _read_active_config_file_v814(cfg_path)
        if not data:
            continue
        raw = data.get("data_dir")
        if raw:
            candidate = _safe_data_path_v808(raw)
            DATA_DIR_CONFIGURED_SOURCE = str(candidate)
            if _path_exists_quiet_v808(candidate):
                _mirror_active_config_to_primary_v814(data)
                return candidate
            if not first_unavailable:
                first_unavailable = f"Base configurée inaccessible : {candidate}"
        # Si le poste est configuré SQL, le dossier local reste seulement le
        # support de configuration/historique. On garde ce mode sans forcer la
        # sélection d'une nouvelle base.
        try:
            if str(data.get("database_mode") or "").lower() in {"sql", "mariadb", "mysql"}:
                _mirror_active_config_to_primary_v814(data)
                return DEFAULT_DATA_DIR
        except Exception:
            pass

    if first_unavailable:
        DATA_DIR_STARTUP_ERROR = first_unavailable
        DATA_DIR_FALLBACK_ACTIVE = True
    return DEFAULT_DATA_DIR


