def _mkdir_quiet_v808(path: Path, label: str = "") -> bool:
    global DATA_DIR_STARTUP_ERROR
    try:
        path.mkdir(parents=True, exist_ok=True)
        return True
    except Exception as exc:
        msg = f"Dossier inaccessible {label or path} : {exc}"
        if not DATA_DIR_STARTUP_ERROR:
            DATA_DIR_STARTUP_ERROR = msg
        return False


def ensure_data_directories() -> None:
    """Crée les dossiers utiles sans bloquer le démarrage si le NAS est indisponible."""
    _mkdir_quiet_v808(ACTIVE_DATA_CONFIG_PATH.parent, "configuration application")
    for path, label in [
        (DATA_DIR, "dossier de données"),
        (QR_DIR, "QR codes"),
        (BACKUP_DIR, "sauvegardes"),
        (PRODUCT_IMAGES_DIR, "images matériel"),
        (ARCHIVE_DIR, "archives"),
        (DOCUMENT_TEMPLATES_DIR, "modèles documents"),
        (GENERATED_DOCUMENTS_DIR, "documents clients"),
        (CONNECTION_SCHEMA_IMAGES_DIR, "images schémas"),
        (CONNECTION_EQUIPMENT_IMAGES_DIR, "images équipements"),
        (MATERIAL_CONNECTION_IMAGES_DIR, "images connexions matériel"),
        (DRAWING_LAYOUT_IMAGES_DIR, "images dessins"),
    ]:
        _mkdir_quiet_v808(path, label)
    try:
        target_template = DOCUMENT_TEMPLATES_DIR / DEFAULT_INSTALL_TEMPLATE_FILENAME
        if DEFAULT_INSTALL_TEMPLATE_SOURCE.exists() and not target_template.exists():
            shutil.copy2(DEFAULT_INSTALL_TEMPLATE_SOURCE, target_template)
    except Exception:
        pass


def save_active_data_dir(path: Path) -> None:
    """Enregistre la base active sans supprimer les informations déjà connues.

    V8.1.4 : le fichier est aussi recopié dans un fichier de préservation afin
    qu'une mise à jour EXE puisse relancer l'application sur la même base.
    """
    payload: dict[str, Any] = {}
    try:
        if ACTIVE_DATA_CONFIG_PATH.exists():
            raw = json.loads(ACTIVE_DATA_CONFIG_PATH.read_text(encoding="utf-8", errors="ignore") or "{}")
            if isinstance(raw, dict):
                payload.update(raw)
    except Exception:
        pass
    payload.update({
        "data_dir": str(_safe_data_path_v808(path)),
        "updated_at": datetime.now().isoformat(timespec="seconds"),
        "app_version": APP_VERSION,
    })
    ACTIVE_DATA_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    ACTIVE_DATA_CONFIG_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    try:
        ACTIVE_DATA_PRESERVE_PATH_V814.write_text(json.dumps({**payload, "preserved_at": datetime.now().isoformat(timespec="seconds")}, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass


def switch_active_data_dir(path: Path) -> None:
    refresh_data_paths(path)
    ensure_data_directories()
    save_active_data_dir(DATA_DIR)
    clear_excel_read_cache() if "clear_excel_read_cache" in globals() else None


refresh_data_paths(read_active_data_dir_from_config())
ensure_data_directories()

# Anciens emplacements à migrer automatiquement sans écraser les données du dossier actif.
LEGACY_DATA_DIR = APP_DIR / "data"
LEGACY_DB_PATH = APP_DIR / "stock_assets.db"
LEGACY_EXCEL_PATH = APP_DIR / "referentiel_stock.xlsx"
LEGACY_QR_DIR = APP_DIR / "qr_codes"


def migrate_legacy_files() -> None:
    """Copie les anciens fichiers vers NexVandal sans écraser l'existant.

    Ordre de migration :
    1. ancien dossier data/ ;
    2. anciens fichiers placés à côté de app.py / EXE.
    """
    old_data_db = LEGACY_DATA_DIR / "stock_assets.db"
    old_data_excel = LEGACY_DATA_DIR / "referentiel_stock.xlsx"
    old_data_qr = LEGACY_DATA_DIR / "qr_codes"
    old_data_ui = LEGACY_DATA_DIR / "ui_settings.json"

    if not DB_PATH.exists():
        if old_data_db.exists():
            shutil.copy2(old_data_db, DB_PATH)
        elif LEGACY_DB_PATH.exists():
            shutil.copy2(LEGACY_DB_PATH, DB_PATH)

    if not EXCEL_PATH.exists():
        if old_data_excel.exists():
            shutil.copy2(old_data_excel, EXCEL_PATH)
        elif LEGACY_EXCEL_PATH.exists():
            shutil.copy2(LEGACY_EXCEL_PATH, EXCEL_PATH)

    if not UI_SETTINGS_PATH.exists() and old_data_ui.exists():
        shutil.copy2(old_data_ui, UI_SETTINGS_PATH)

    if old_data_qr.exists():
        shutil.copytree(old_data_qr, QR_DIR, dirs_exist_ok=True)
    if LEGACY_QR_DIR.exists():
        shutil.copytree(LEGACY_QR_DIR, QR_DIR, dirs_exist_ok=True)


try:
    migrate_legacy_files()
except Exception as _migrate_startup_exc:
    if not DATA_DIR_STARTUP_ERROR:
        DATA_DIR_STARTUP_ERROR = f"Migration des anciennes données ignorée au démarrage : {_migrate_startup_exc}"

