app = FastAPI(title=APP_NAME, version=APP_VERSION)


@app.exception_handler(Exception)
async def clyo_unhandled_exception_handler(request: Request, exc: Exception):
    """Retourne un JSON exploitable au lieu d'un simple Internal Server Error HTML/texte."""
    try:
        append_update_history_event({
            "event": "api_unhandled_exception",
            "version": APP_VERSION,
            "path": str(getattr(request, "url", "")),
            "method": str(getattr(request, "method", "")),
            "error_type": type(exc).__name__,
            "error": str(exc),
        })
    except Exception:
        pass
    return JSONResponse(
        status_code=500,
        content={
            "detail": f"Erreur interne API : {type(exc).__name__}: {exc}",
            "error_type": type(exc).__name__,
            "path": str(getattr(request, "url", "")),
            "version": APP_VERSION,
        },
    )
