# Arrêt automatique : tant qu'une page du navigateur envoie un heartbeat,
# le serveur reste ouvert. Si toutes les pages sont fermées, les heartbeats
# s'arrêtent et l'application locale s'éteint automatiquement.
AUTO_STOP_ENABLED = os.environ.get("CLYO_STOCK_AUTO_STOP", "0") == "1"
AUTO_STOP_AFTER_SECONDS = int(os.environ.get("CLYO_STOCK_AUTO_STOP_SECONDS", "3600"))
heartbeat_lock = RLock()
last_browser_heartbeat_at = 0.0
heartbeat_monitor_started = False


def heartbeat_monitor_loop() -> None:
    global last_browser_heartbeat_at
    while True:
        time.sleep(5)
        if not AUTO_STOP_ENABLED:
            continue
        with heartbeat_lock:
            last_seen = last_browser_heartbeat_at
        if last_seen and (time.monotonic() - last_seen) > AUTO_STOP_AFTER_SECONDS:
            safe_log("Aucune page active détectée : arrêt automatique de CLYO Stock.")
            os._exit(0)


def mark_browser_heartbeat() -> None:
    global last_browser_heartbeat_at, heartbeat_monitor_started
    if not AUTO_STOP_ENABLED:
        return
    with heartbeat_lock:
        last_browser_heartbeat_at = time.monotonic()
        if not heartbeat_monitor_started:
            threading.Thread(target=heartbeat_monitor_loop, daemon=True).start()
            heartbeat_monitor_started = True


