def normalize_excel_header(value: Any) -> str:
    """Normalise un nom de colonne Excel pour comparer les schémas."""
    if value is None:
        return ""
    return str(value).strip().replace("\ufeff", "")


def excel_headers_match_expected(headers: list[Any], expected: list[str]) -> bool:
    clean_headers = [normalize_excel_header(header) for header in headers]
    return clean_headers[: len(expected)] == expected


def load_deleted_status_values() -> set[str]:
    """Statuts système supprimés volontairement par l'utilisateur.

    Sans cette mémoire, un statut par défaut supprimé était recréé automatiquement
    au démarrage ou lors d'un rafraîchissement Excel, parfois avec un nouvel ID.
    """
    try:
        if not DELETED_STATUS_VALUES_PATH.exists():
            return set()
        data = json.loads(DELETED_STATUS_VALUES_PATH.read_text(encoding="utf-8"))
        values = data.get("values", data if isinstance(data, list) else [])
        if not isinstance(values, list):
            return set()
        return {str(value).strip() for value in values if str(value or "").strip()}
    except Exception:
        return set()

def save_deleted_status_values(values: set[str]) -> None:
    try:
        DELETED_STATUS_VALUES_PATH.parent.mkdir(parents=True, exist_ok=True)
        DELETED_STATUS_VALUES_PATH.write_text(
            json.dumps({"values": sorted(values), "updated_at": now_iso()}, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
    except Exception:
        pass

def mark_status_value_deleted(value: str) -> None:
    value = str(value or "").strip()
    if not value or value not in DEFAULT_STATUS_OPTIONS:
        return
    values = load_deleted_status_values()
    values.add(value)
    save_deleted_status_values(values)

def unmark_status_value_deleted(value: str) -> None:
    value = str(value or "").strip()
    if not value:
        return
    values = load_deleted_status_values()
    if value in values:
        values.remove(value)
        save_deleted_status_values(values)

def slugify_status_value(label: str) -> str:
    value = normalize_text(label or "").lower()
    value = re.sub(r"[^a-z0-9]+", "_", value).strip("_")
    return value or "statut"

def ensure_status_defaults() -> None:
    """Crée l'onglet Statuts et y ajoute les statuts par défaut si absent."""
    try:
        rows = read_excel_sheet("Statuts")
        existing = {str(row.get("value") or "").strip() for row in rows}
        deleted_defaults = load_deleted_status_values()
        now = now_iso()
        for value, label in DEFAULT_STATUS_OPTIONS.items():
            if value in deleted_defaults or value in existing:
                continue
            append_excel_row("Statuts", {
                "value": value,
                "label": label,
                "is_default": 1,
                "updated_at": now,
            })
    except Exception as exc:
        safe_log(f"Initialisation statuts impossible : {exc}")

