def safe_filename_part(value: Any, fallback: str = "document") -> str:
    text = str(value or "").strip()
    text = re.sub(r"[^A-Za-z0-9_.-]+", "_", text)
    text = re.sub(r"_+", "_", text).strip("._-")
    return (text or fallback)[:80]


def clamp_percent(value: Any, default: float) -> float:
    try:
        n = float(value)
    except (TypeError, ValueError):
        n = float(default)
    return max(0.0, min(100.0, n))


def normalize_connection_schema_item(item: dict[str, Any] | None, defaults: dict[str, Any]) -> dict[str, Any]:
    raw = item if isinstance(item, dict) else {}
    merged = {**defaults, **raw}
    merged["x"] = clamp_percent(merged.get("x"), defaults.get("x", 50))
    merged["y"] = clamp_percent(merged.get("y"), defaults.get("y", 50))
    merged["image_point_x"] = clamp_percent(merged.get("image_point_x"), defaults.get("image_point_x", 50))
    merged["image_point_y"] = clamp_percent(merged.get("image_point_y"), defaults.get("image_point_y", 50))
    merged["name"] = str(merged.get("name") or defaults.get("name") or "").strip()
    merged["label"] = str(merged.get("label") or defaults.get("label") or merged.get("name") or "").strip()
    merged["port"] = str(merged.get("port") or defaults.get("port") or "").strip()
    merged["color"] = str(merged.get("color") or defaults.get("color") or "#2563eb").strip()
    aliases = merged.get("aliases") or defaults.get("aliases") or []
    if isinstance(aliases, str):
        aliases = [aliases]
    merged["aliases"] = [str(alias).strip().upper() for alias in aliases if str(alias or "").strip()]
    merged["default_show"] = bool(merged.get("default_show", defaults.get("default_show", False)))
    return merged


def default_connection_schema(model_id: int | None = None) -> dict[str, Any]:
    return {
        "model_id": int(model_id or 0),
        "title": "Schéma générique",
        "base_image_path": "",
        "ports": [dict(port) for port in DEFAULT_CONNECTION_PORTS],
        "equipment": [dict(item) for item in DEFAULT_CONNECTION_EQUIPMENT],
        "updated_at": None,
    }


def normalize_connection_schema(schema: dict[str, Any] | None, model_id: int | None = None) -> dict[str, Any]:
    defaults = default_connection_schema(model_id)
    raw = schema if isinstance(schema, dict) else {}
    model_value = raw.get("model_id", model_id or defaults["model_id"])
    try:
        model_value = int(model_value or 0)
    except (TypeError, ValueError):
        model_value = int(model_id or 0)
    ports_by_name = {str(port.get("name") or "").upper(): port for port in raw.get("ports") or [] if isinstance(port, dict)}
    normalized_ports = []
    for default_port in DEFAULT_CONNECTION_PORTS:
        key = str(default_port.get("name") or "").upper()
        normalized_ports.append(normalize_connection_schema_item(ports_by_name.get(key), default_port))
    # Conserver aussi les ports personnalisés que l'utilisateur aurait ajoutés manuellement dans le JSON.
    for port in raw.get("ports") or []:
        if not isinstance(port, dict):
            continue
        key = str(port.get("name") or "").upper()
        if key and key not in {str(p.get("name") or "").upper() for p in normalized_ports}:
            normalized_ports.append(normalize_connection_schema_item(port, {"name": key, "x": 50, "y": 50, "color": "#2563eb"}))

    raw_equipment = {str(item.get("key") or "").strip(): item for item in raw.get("equipment") or [] if isinstance(item, dict)}
    normalized_equipment = []
    for default_item in DEFAULT_CONNECTION_EQUIPMENT:
        key = str(default_item.get("key") or "")
        normalized_equipment.append(normalize_connection_schema_item(raw_equipment.get(key), default_item))
    for item in raw.get("equipment") or []:
        if not isinstance(item, dict):
            continue
        key = str(item.get("key") or "").strip()
        if key and key not in {str(x.get("key") or "") for x in normalized_equipment}:
            base = {"key": key, "label": item.get("label") or key, "port": item.get("port") or "USB", "x": 50, "y": 72, "color": item.get("color") or "#2563eb", "aliases": [], "default_show": False}
            normalized_equipment.append(normalize_connection_schema_item(item, base))

    return {
        "model_id": model_value,
        "title": str(raw.get("title") or defaults["title"]).strip() or defaults["title"],
        "base_image_path": str(raw.get("base_image_path") or "").strip(),
        "ports": normalized_ports,
        "equipment": normalized_equipment,
        "updated_at": raw.get("updated_at"),
    }


def enrich_connection_schema_for_api(schema: dict[str, Any], model_id: int | None = None) -> dict[str, Any]:
    normalized = normalize_connection_schema(schema, model_id)
    equipment = []
    for item in normalized.get("equipment") or []:
        equipment.append({**item, "image_url": schema_equipment_image_url(item.get("image_path"))})
    return {**normalized, "base_image_url": schema_image_url(normalized.get("base_image_path")), "equipment": equipment}


def load_connection_schemas() -> dict[str, Any]:
    try:
        if not CONNECTION_SCHEMAS_PATH.exists():
            return {"schemas": {}, "updated_at": None}
        data = json.loads(CONNECTION_SCHEMAS_PATH.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return {"schemas": {}, "updated_at": None}
        schemas = data.get("schemas") if isinstance(data.get("schemas"), dict) else {}
        normalized = {}
        for key, schema in schemas.items():
            try:
                model_id = int(key)
            except (TypeError, ValueError):
                model_id = int((schema or {}).get("model_id") or 0)
            if model_id:
                normalized[str(model_id)] = normalize_connection_schema(schema, model_id)
        return {"schemas": normalized, "updated_at": data.get("updated_at")}
    except Exception as exc:
        safe_log(f"Lecture schémas de branchement impossible : {exc}")
        return {"schemas": {}, "updated_at": None}


def save_connection_schemas(payload: dict[str, Any]) -> dict[str, Any]:
    data = {"schemas": payload.get("schemas", {}), "updated_at": now_iso()}
    CONNECTION_SCHEMAS_PATH.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    return data


def get_connection_schema_for_model(model_id: int | None) -> dict[str, Any]:
    if not model_id:
        return default_connection_schema(None)
    data = load_connection_schemas()
    schema = data.get("schemas", {}).get(str(int(model_id)))
    return normalize_connection_schema(schema, int(model_id)) if schema else default_connection_schema(int(model_id))


def resolve_schema_image_path(base_image_path: str | None) -> Path | None:
    if not base_image_path:
        return None
    try:
        raw = str(base_image_path).strip()
        candidate = Path(raw)
        if not candidate.is_absolute():
            candidate = CONNECTION_SCHEMA_IMAGES_DIR / candidate.name
        candidate = candidate.resolve()
        root = CONNECTION_SCHEMA_IMAGES_DIR.resolve()
        if root not in candidate.parents and candidate != root:
            return None
        if candidate.exists() and candidate.is_file():
            return candidate
    except Exception:
        return None
    return None


def schema_image_url(base_image_path: str | None) -> str:
    path = resolve_schema_image_path(base_image_path)
    if not path:
        return ""
    return f"/api/connection-schema-images/{urllib.parse.quote(path.name)}"


