POINT_COLOR_MAP = {entry["value"].lower(): entry["value"] for entry in POINT_COLOR_PALETTE}
POINT_COLOR_NAME_MAP = {entry["name"].lower(): entry["value"] for entry in POINT_COLOR_PALETTE}

def default_material_connection_profile(model_id: int | None) -> dict[str, Any]:
    return {"model_id": int(model_id or 0) or None, "image_path": "", "points": [], "updated_at": None}


def normalize_point_palette_color(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if not raw:
        return POINT_COLOR_PALETTE[0]["value"]
    if raw in POINT_COLOR_MAP:
        return POINT_COLOR_MAP[raw]
    if raw in POINT_COLOR_NAME_MAP:
        return POINT_COLOR_NAME_MAP[raw]
    # tolérance pour anciennes valeurs proches en hex
    if raw.startswith("#") and len(raw) in {4, 7}:
        return raw.upper() if len(raw) == 7 else raw
    return POINT_COLOR_PALETTE[0]["value"]


def normalize_material_connection_point(raw: dict[str, Any] | None, index: int = 0) -> dict[str, Any]:
    raw = raw if isinstance(raw, dict) else {}
    point_id = str(raw.get("id") or f"pt_{index+1}").strip() or f"pt_{index+1}"
    name = str(raw.get("name") or f"Point {index+1}").strip() or f"Point {index+1}"
    color = normalize_point_palette_color(raw.get("color") or POINT_COLOR_PALETTE[0]["value"])
    return {
        "id": point_id,
        "name": name,
        "color": color,
        "x": clamp_percent(raw.get("x"), 50),
        "y": clamp_percent(raw.get("y"), 50),
    }


def normalize_material_connection_profile(raw: dict[str, Any] | None, model_id: int | None = None) -> dict[str, Any]:
    base = default_material_connection_profile(model_id)
    raw = raw if isinstance(raw, dict) else {}
    points = []
    for idx, point in enumerate(raw.get("points") or []):
        points.append(normalize_material_connection_point(point, idx))
    return {
        "model_id": int(raw.get("model_id") or base["model_id"] or 0) or None,
        "image_path": str(raw.get("image_path") or "").strip(),
        "points": points,
        "updated_at": raw.get("updated_at"),
    }


def enrich_material_connection_profile_for_api(profile: dict[str, Any], model_id: int | None = None) -> dict[str, Any]:
    normalized = normalize_material_connection_profile(profile, model_id)
    return {**normalized, "image_url": material_connection_image_url(normalized.get("image_path"))}


def load_material_connection_profiles() -> dict[str, Any]:
    try:
        if not MATERIAL_CONNECTION_PROFILES_PATH.exists():
            return {"profiles": {}, "updated_at": None}
        data = json.loads(MATERIAL_CONNECTION_PROFILES_PATH.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return {"profiles": {}, "updated_at": None}
        profiles = data.get("profiles") if isinstance(data.get("profiles"), dict) else {}
        normalized = {}
        for key, profile in profiles.items():
            try:
                mid = int(key)
            except Exception:
                mid = int((profile or {}).get("model_id") or 0)
            if mid:
                normalized[str(mid)] = normalize_material_connection_profile(profile, mid)
        return {"profiles": normalized, "updated_at": data.get("updated_at")}
    except Exception as exc:
        safe_log(f"Lecture profils connexion matériel impossible : {exc}")
        return {"profiles": {}, "updated_at": None}


def save_material_connection_profiles(payload: dict[str, Any]) -> dict[str, Any]:
    data = {"profiles": payload.get("profiles", {}), "updated_at": now_iso()}
    MATERIAL_CONNECTION_PROFILES_PATH.parent.mkdir(parents=True, exist_ok=True)
    MATERIAL_CONNECTION_PROFILES_PATH.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    return data


def load_material_connection_profiles_from_excel() -> dict[int, dict[str, Any]]:
    try:
        rows = read_excel_sheet("ProfilsConnexionMateriel")
    except Exception:
        return {}
    result: dict[int, dict[str, Any]] = {}
    for row in rows:
        try:
            model_id = int(row.get("model_id") or 0)
        except (TypeError, ValueError):
            continue
        if model_id <= 0:
            continue
        points_raw = row.get("points_json")
        points = []
        if points_raw not in (None, ""):
            try:
                parsed = json.loads(str(points_raw))
                if isinstance(parsed, list):
                    points = parsed
            except Exception:
                points = []
        result[model_id] = normalize_material_connection_profile(
            {
                "model_id": model_id,
                "image_path": str(row.get("image_path") or "").strip(),
                "points": points,
                "updated_at": row.get("updated_at") or row.get("created_at"),
            },
            model_id,
        )
    return result


def ensure_material_connection_excel_sheet() -> None:
    """Garantit que l'onglet ProfilsConnexionMateriel existe dans la base Excel active."""
    ensure_reference_workbook()
    try:
        with excel_lock:
            wb = load_workbook(EXCEL_PATH)
            changed = ensure_sheet_schema(wb, "ProfilsConnexionMateriel", "TableProfilsConnexionMateriel")
            if changed:
                save_reference_workbook(wb)
    except HTTPException:
        raise
    except Exception as exc:
        safe_log(f"Création onglet ProfilsConnexionMateriel impossible : {exc}")


def upsert_material_connection_profile_excel(profile: dict[str, Any]) -> dict[str, Any]:
    model_id = int(profile.get("model_id") or 0)
    if model_id <= 0:
        raise HTTPException(status_code=400, detail="model_id invalide pour le profil matériel")
    ensure_material_connection_excel_sheet()
    normalized = normalize_material_connection_profile(profile, model_id)
    try:
        rows = read_excel_sheet("ProfilsConnexionMateriel")
    except HTTPException as exc:
        if exc.status_code == 500 and "ProfilsConnexionMateriel" in str(exc.detail):
            ensure_material_connection_excel_sheet()
            rows = read_excel_sheet("ProfilsConnexionMateriel")
        else:
            raise
    existing = next((row for row in rows if int(row.get("model_id") or 0) == model_id), None)
    payload = {
        "model_id": model_id,
        "image_path": str(normalized.get("image_path") or "").strip(),
        "points_json": json.dumps(normalized.get("points") or [], ensure_ascii=False),
        "updated_at": now_iso(),
    }
    if existing and existing.get("id") is not None:
        updated = update_excel_row_by_id("ProfilsConnexionMateriel", int(existing.get("id")), payload)
        return updated
    created = append_excel_row("ProfilsConnexionMateriel", payload)
    return created


def get_material_connection_profile(model_id: int | None) -> dict[str, Any]:
    if not model_id:
        return default_material_connection_profile(None)
    data = load_material_connection_profiles()
    profile = data.get("profiles", {}).get(str(int(model_id)))
    return normalize_material_connection_profile(profile, int(model_id)) if profile else default_material_connection_profile(int(model_id))


def model_has_material_connection_profile(model_id: int | None) -> bool:
    profile = get_material_connection_profile(model_id)
    return bool(profile.get("image_path") and profile.get("points"))


def get_asset_connection_profile(asset: dict[str, Any]) -> dict[str, Any]:
    return get_material_connection_profile(asset.get("model_id"))


def build_connection_signature(assets: list[dict[str, Any]]) -> str:
    parts = []
    for asset in sorted(assets, key=lambda a: (0 if is_caisse_category(a.get("category")) else 1, str(a.get("category") or ""), str(a.get("brand") or ""), str(a.get("model_name") or ""))):
        parts.append(f"{asset.get('model_id') or 0}:{asset.get('category') or ''}")
    return "|".join(parts)


def build_installation_assets_signature(assets: list[dict[str, Any]]) -> str:
    """Signature stable basée sur les SN attribués au client.

    Si les numéros de série restent les mêmes, on considère qu'il s'agit de la même fiche
    et l'ancienne génération est écrasée. Si la liste des SN change, une nouvelle fiche est conservée.
    """
    parts: list[str] = []
    for asset in sorted(assets, key=lambda a: (str(a.get("serial_number_norm") or normalize_sn(a.get("serial_number_raw") or "")), str(a.get("serial_number_raw") or ""), str(a.get("category") or ""))):
        serial = str(asset.get("serial_number_norm") or normalize_sn(asset.get("serial_number_raw") or "")).strip()
        if not serial:
            serial = f"NO-SN::{asset.get('model_id') or ''}::{asset.get('category') or ''}"
        parts.append(serial)
    digest = hashlib.sha1("\n".join(parts).encode("utf-8")).hexdigest()[:12]
    return digest or "empty"


def cleanup_previous_installation_documents_for_signature(code: str, name: str, signature: str) -> None:
    """Supprime d'anciens fichiers de même fiche avant de réécrire la fiche PDF."""
    GENERATED_DOCUMENTS_DIR.mkdir(parents=True, exist_ok=True)
    prefix = f"Fiche_installation_{code}_{name}_{signature}"
    for path in GENERATED_DOCUMENTS_DIR.glob(prefix + "*"):
        if path.suffix.lower() in {".docx", ".pdf"}:
            try:
                path.unlink()
            except Exception as exc:
                safe_log(f"Suppression ancienne fiche installation impossible : {path.name} / {exc}")


def default_drawing_layout_settings() -> dict[str, Any]:
    return {"header_image_path": "", "footer_image_path": "", "updated_at": None}


def load_drawing_layout_settings() -> dict[str, Any]:
    try:
        if DRAWING_LAYOUT_SETTINGS_PATH.exists():
            data = json.loads(DRAWING_LAYOUT_SETTINGS_PATH.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                return {**default_drawing_layout_settings(), **data}
    except Exception as exc:
        safe_log(f"Lecture mise en page dessin impossible : {exc}")
    return default_drawing_layout_settings()


def save_drawing_layout_settings(settings: dict[str, Any]) -> dict[str, Any]:
    merged = {**default_drawing_layout_settings(), **settings, "updated_at": now_iso()}
    DRAWING_LAYOUT_SETTINGS_PATH.parent.mkdir(parents=True, exist_ok=True)
    DRAWING_LAYOUT_SETTINGS_PATH.write_text(json.dumps(merged, ensure_ascii=False, indent=2), encoding="utf-8")
    return merged


def resolve_drawing_layout_image_path(image_path: str | None) -> Path | None:
    if not image_path:
        return None
    try:
        raw = str(image_path).strip()
        candidate = Path(raw)
        if not candidate.is_absolute():
            candidate = DRAWING_LAYOUT_IMAGES_DIR / candidate.name
        candidate = candidate.resolve()
        root = DRAWING_LAYOUT_IMAGES_DIR.resolve()
        if root not in candidate.parents and candidate != root:
            return None
        if candidate.exists() and candidate.is_file():
            return candidate
    except Exception:
        return None
    return None


def drawing_layout_image_url(image_path: str | None) -> str:
    path = resolve_drawing_layout_image_path(image_path)
    if not path:
        return ""
    return f"/api/drawing-layout-images/{urllib.parse.quote(path.name)}"


def enrich_drawing_layout_settings(settings: dict[str, Any] | None = None) -> dict[str, Any]:
    data = {**default_drawing_layout_settings(), **(settings or load_drawing_layout_settings())}
    return {
        **data,
        "header_image_url": drawing_layout_image_url(data.get("header_image_path")),
        "footer_image_url": drawing_layout_image_url(data.get("footer_image_path")),
        "folder": str(DRAWING_LAYOUT_IMAGES_DIR),
    }


def paste_layout_image_on_page(base_image: Any, image_path: Path | None, box: tuple[int, int, int, int]) -> bool:
    if not image_path:
        return False
    try:
        from PIL import Image, ImageOps
        img = Image.open(image_path).convert("RGBA")
        max_size = (max(1, box[2] - box[0]), max(1, box[3] - box[1]))
        img = ImageOps.contain(img, max_size)
        x = box[0] + (max_size[0] - img.width) // 2
        y = box[1] + (max_size[1] - img.height) // 2
        base_image.paste(img, (x, y), img)
        return True
    except Exception as exc:
        safe_log(f"Image entête/pied dessin non appliquée : {exc}")
        return False


def paste_header_logo_inside_guide(base_image: Any, image_path: Path | None, page_width: int) -> bool:
    """Place l'image d'entête utilisateur uniquement dans la case logo, sans agrandir la mise en page."""
    if not image_path:
        return False
    try:
        from PIL import Image, ImageChops, ImageOps
        img = Image.open(image_path).convert("RGBA")

        # Recadrage automatique des marges blanches / transparentes autour du logo.
        white_bg = Image.new("RGBA", img.size, "white")
        white_bg.alpha_composite(img)
        rgb = white_bg.convert("RGB")
        diff = ImageChops.difference(rgb, Image.new("RGB", rgb.size, "white")).convert("L")
        mask = diff.point(lambda p: 255 if p > 14 else 0)
        bbox = mask.getbbox()
        if bbox:
            pad_x = max(2, int((bbox[2] - bbox[0]) * 0.03))
            pad_y = max(2, int((bbox[3] - bbox[1]) * 0.05))
            bbox = (
                max(0, bbox[0] - pad_x),
                max(0, bbox[1] - pad_y),
                min(img.width, bbox[2] + pad_x),
                min(img.height, bbox[3] + pad_y),
            )
            img = img.crop(bbox)

        x1, y1, x2, y2 = 95, 35, page_width - 95, 205
        total_w = x2 - x1
        left_w = int(total_w * 0.335)
        left = (x1, y1, x1 + left_w, y2)
        cell_w = left[2] - left[0]
        cell_h = left[3] - left[1]

        # L'image personnalisée doit maintenant occuper presque toute la case de gauche.
        # On conserve les proportions, mais on utilise toute la zone utile du carreau.
        inner_pad_x = 6
        inner_pad_y = 6
        max_size = (max(1, cell_w - inner_pad_x * 2), max(1, cell_h - inner_pad_y * 2))
        img = ImageOps.contain(img, max_size)

        # Centrage dans toute la cellule gauche pour que l'image remplisse bien le carreau.
        px = int(left[0] + (cell_w - img.width) / 2)
        py = int(left[1] + (cell_h - img.height) / 2)

        # Sécurité : l'image reste strictement dans la zone gauche.
        px = max(left[0] + inner_pad_x, min(px, left[2] - img.width - inner_pad_x))
        py = max(left[1] + inner_pad_y, min(py, left[3] - img.height - inner_pad_y))
        base_image.paste(img, (px, py), img)
        return True
    except Exception as exc:
        safe_log(f"Image entête guide non appliquée dans la case logo : {exc}")
        return False


def model_display_label(model: dict[str, Any] | None) -> str:
    if not model:
        return "Caisse non renseignée"
    parts = [str(model.get("brand") or "").strip(), str(model.get("model_name") or "").strip()]
    return " ".join([p for p in parts if p]) or f"Modèle #{model.get('id')}"


def asset_text_for_matching(asset: dict[str, Any]) -> str:
    parts = [asset.get("category"), asset.get("brand"), asset.get("model_name"), asset.get("supplier_name"), asset.get("serial_number_raw")]
    return normalize_text(" ".join(str(p or "") for p in parts))


def equipment_asset_match(asset: dict[str, Any], equipment: dict[str, Any]) -> bool:
    text = asset_text_for_matching(asset)
    aliases = equipment.get("aliases") or []
    if any(alias and alias in text for alias in aliases):
        return True
    key = normalize_text(equipment.get("key") or "")
    label = normalize_text(equipment.get("label") or "")
    return bool((key and key in text) or (label and label in text))


def default_connection_for_asset(asset: dict[str, Any]) -> str:
    text = asset_text_for_matching(asset)
    if any(token in text for token in ["BALANCE", "METTLER", "SCALE"]):
        return "COM1"
    if any(token in text for token in ["AFFICHEUR", "DISPLAY", "GLANCETRON"]):
        return "COM2"
    if any(token in text for token in ["BOX", "INTERNET", "ROUTEUR", "LIVEBOX", "FREEBOX"]):
        return "LAN"
    if any(token in text for token in ["TIROIR", "DRAWER"]):
        return "USB"
    if any(token in text for token in ["TICKET", "IMPRIMANTE", "PRINTER"]):
        return "USB"
    if "CAISSE" in text:
        return "DHCP"
    return ""


def get_installation_assets_for_customer(conn: sqlite3.Connection, customer: dict[str, Any]) -> list[dict[str, Any]]:
    customer_id = int(customer.get("id"))
    display = customer_display_name(customer) or ""
    company = str(customer.get("company") or "").strip()
    name = str(customer.get("name") or "").strip()
    candidates = [display, company, name, str(customer.get("customer_code") or "")]
    like_params = [f"%{c}%" for c in candidates if c]
    where = "customer_id = ?"
    params: list[Any] = [customer_id]
    for value in like_params:
        where += " OR COALESCE(client_name,'') LIKE ?"
        params.append(value)
    rows = conn.execute(
        f"SELECT id FROM assets WHERE {where} ORDER BY CASE WHEN status='vendu' THEN 0 ELSE 1 END, updated_at DESC, id DESC",
        params,
    ).fetchall()
    seen: set[int] = set()
    assets: list[dict[str, Any]] = []
    for row in rows:
        asset_id = int(row["id"])
        if asset_id in seen:
            continue
        seen.add(asset_id)
        assets.append(get_asset_full(conn, asset_id))
    return assets


def find_caisse_asset(assets: list[dict[str, Any]]) -> dict[str, Any] | None:
    for asset in assets:
        if is_caisse_category(asset.get("category")):
            return asset
    return assets[0] if assets else None


def detect_diagram_equipment(assets: list[dict[str, Any]], schema: dict[str, Any]) -> list[dict[str, Any]]:
    caisse_asset = find_caisse_asset(assets)
    used_asset_ids: set[int] = set()
    if caisse_asset and caisse_asset.get("id") is not None:
        try:
            used_asset_ids.add(int(caisse_asset["id"]))
        except Exception:
            pass
    items: list[dict[str, Any]] = []
    for equipment in schema.get("equipment") or []:
        matched_asset = None
        for asset in assets:
            try:
                asset_id = int(asset.get("id") or 0)
            except Exception:
                asset_id = 0
            if asset_id in used_asset_ids:
                continue
            if equipment_asset_match(asset, equipment):
                matched_asset = asset
                if asset_id:
                    used_asset_ids.add(asset_id)
                break
        if matched_asset or equipment.get("default_show"):
            items.append({**equipment, "asset": matched_asset})
    remaining = []
    for asset in assets:
        try:
            asset_id = int(asset.get("id") or 0)
        except Exception:
            asset_id = 0
        if asset_id and asset_id not in used_asset_ids:
            remaining.append(asset)
    fallback_positions = [(18, 86), (40, 86), (62, 86), (82, 86), (30, 94), (55, 94), (78, 94)]
    for idx, asset in enumerate(remaining[:7]):
        x, y = fallback_positions[idx % len(fallback_positions)]
        items.append({
            "key": f"asset_{asset.get('id')}",
            "label": asset.get("category") or asset.get("model_name") or "Matériel",
            "port": default_connection_for_asset(asset) or "USB",
            "x": x,
            "y": y,
            "color": "#2563eb",
            "aliases": [],
            "default_show": False,
            "asset": asset,
        })
    return items


def pil_font(size: int, bold: bool = False):
    from PIL import ImageFont
    candidates = []
    if os.name == "nt":
        candidates.extend([
            Path(r"C:\Windows\Fonts\arialbd.ttf") if bold else Path(r"C:\Windows\Fonts\arial.ttf"),
            Path(r"C:\Windows\Fonts\segoeuib.ttf") if bold else Path(r"C:\Windows\Fonts\segoeui.ttf"),
        ])
    candidates.extend([
        Path("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf") if bold else Path("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf"),
        Path("/usr/share/fonts/truetype/liberation2/LiberationSans-Bold.ttf") if bold else Path("/usr/share/fonts/truetype/liberation2/LiberationSans-Regular.ttf"),
    ])
    for path in candidates:
        try:
            if path.exists():
                return ImageFont.truetype(str(path), size=size)
        except Exception:
            continue
    return ImageFont.load_default()


def draw_centered_text(draw: Any, box: tuple[int, int, int, int], text: str, font: Any, fill: str = "#111827") -> None:
    x1, y1, x2, y2 = box
    text = str(text or "")
    bbox = draw.textbbox((0, 0), text, font=font)
    w = bbox[2] - bbox[0]
    h = bbox[3] - bbox[1]
    draw.text((x1 + (x2 - x1 - w) / 2, y1 + (y2 - y1 - h) / 2), text, font=font, fill=fill)


def wrap_text_by_width(draw: Any, text: str, font: Any, max_width: int) -> list[str]:
    words = str(text or "").replace("\n", " ").split()
    lines: list[str] = []
    current = ""
    for word in words:
        candidate = f"{current} {word}".strip()
        bbox = draw.textbbox((0, 0), candidate, font=font)
        if bbox[2] - bbox[0] <= max_width or not current:
            current = candidate
        else:
            lines.append(current)
            current = word
    if current:
        lines.append(current)
    return lines or [""]


def draw_arrow(draw: Any, start: tuple[int, int], end: tuple[int, int], color: str, width: int = 4) -> None:
    draw.line((start[0], start[1], end[0], end[1]), fill=color, width=width)
    angle = math.atan2(end[1] - start[1], end[0] - start[0])
    head_len = 16
    left = (end[0] - head_len * math.cos(angle - math.pi / 6), end[1] - head_len * math.sin(angle - math.pi / 6))
    right = (end[0] - head_len * math.cos(angle + math.pi / 6), end[1] - head_len * math.sin(angle + math.pi / 6))
    draw.polygon([end, left, right], fill=color)


def draw_installation_guide_header(draw: Any, page_width: int, customer_name: str, when: datetime | None = None, draw_default_logo: bool = True) -> None:
    """Dessine l'entête du guide d'installation avec le modèle fourni par l'utilisateur."""
    when = when or datetime.now()
    x1, y1, x2, y2 = 95, 35, page_width - 95, 205
    total_w = x2 - x1
    left_w = int(total_w * 0.335)
    center_w = int(total_w * 0.335)
    right_w = total_w - left_w - center_w
    left = (x1, y1, x1 + left_w, y2)
    center = (left[2], y1, left[2] + center_w, y2)
    right = (center[2], y1, x2, y2)
    line = "#6b7280"
    header_fill = "#ffffff"
    date_fill = "#eeeeee"

    # Contours et séparations, comme le modèle envoyé.
    draw.rectangle((x1, y1, x2, y2), outline=line, width=2, fill=header_fill)
    draw.line((left[2], y1, left[2], y2), fill=line, width=2)
    draw.line((center[2], y1, center[2], y2), fill=line, width=2)
    mid_y = y1 + (y2 - y1) // 2
    draw.line((right[0], mid_y, right[2], mid_y), fill=line, width=2)
    draw.rectangle((right[0]+1, mid_y+1, right[2]-1, y2-1), fill=date_fill)
    draw.line((right[0], mid_y, right[2], mid_y), fill=line, width=2)

    # Logo CLYO Systems par défaut uniquement si aucune image d'entête personnalisée n'est fournie.
    if draw_default_logo:
        logo_font = pil_font(74, bold=False)
        logo_small = pil_font(18, bold=True)
        lx = left[0] + 36
        ly = left[1] + 43
        draw.text((lx, ly), "CL", font=logo_font, fill="#8a8d90")
        draw.text((lx + 128, ly), "Y", font=logo_font, fill="#88cff0")
        draw.text((lx + 205, ly), "O", font=logo_font, fill="#8a8d90")
        draw.text((lx + 16, left[3] - 48), "S    Y    S    T    E    M    S", font=logo_small, fill="#8a8d90")

    # Nom client/site au centre : aucune sortie de cellule, même avec un nom long.
    # V8.0.6 : réduction adaptative + retour à la ligne sur 3 lignes maximum.
    title = str(customer_name or "Client").strip() or "Client"
    max_w = center[2] - center[0] - 34
    max_h = center[3] - center[1] - 18
    chosen_font = pil_font(30, bold=True)
    chosen_lines = [title]
    chosen_line_h = 34
    for size in range(58, 25, -2):
        candidate_font = pil_font(size, bold=True)
        lines = wrap_text_by_width(draw, title, candidate_font, max_w)
        if len(lines) > 3:
            continue
        line_h_candidate = max(size + 4, int(size * 1.12))
        widths = [draw.textbbox((0, 0), line, font=candidate_font)[2] for line in lines]
        total_h = line_h_candidate * len(lines)
        if widths and max(widths) <= max_w and total_h <= max_h:
            chosen_font = candidate_font
            chosen_lines = lines
            chosen_line_h = line_h_candidate
            break
    safe_lines = []
    for line_text in chosen_lines[:3]:
        txt = str(line_text)
        while txt and (draw.textbbox((0, 0), txt, font=chosen_font)[2] > max_w):
            txt = txt[:-2].rstrip() + "…"
            if len(txt) <= 3:
                break
        safe_lines.append(txt)
    start_y = center[1] + ((center[3] - center[1]) - chosen_line_h * len(safe_lines)) // 2 - 2
    for idx, line_text in enumerate(safe_lines):
        bbox = draw.textbbox((0, 0), line_text, font=chosen_font)
        tw = bbox[2] - bbox[0]
        draw.text((center[0] + (center[2] - center[0] - tw) / 2, start_y + idx * chosen_line_h), line_text, font=chosen_font, fill="#737373")

    # Bloc droit : le titre doit rester entièrement dans la zone haute.
    guide_lines = ["GUIDE", "D’INSTALLATION"]
    upper_h = mid_y - right[1]
    right_inner_w = max(20, right[2] - right[0] - 24)
    guide_font = pil_font(28, bold=True)
    guide_line_h = 32
    for size in range(28, 17, -1):
        candidate = pil_font(size, bold=True)
        line_h = max(size + 4, int(size * 1.18))
        widths = [draw.textbbox((0, 0), txt, font=candidate)[2] for txt in guide_lines]
        if max(widths) <= right_inner_w and (line_h * len(guide_lines)) <= upper_h - 8:
            guide_font = candidate
            guide_line_h = line_h
            break
    guide_total_h = guide_line_h * len(guide_lines)
    guide_start = right[1] + max(2, (upper_h - guide_total_h) // 2)
    for idx, txt in enumerate(guide_lines):
        bbox = draw.textbbox((0, 0), txt, font=guide_font)
        tw = bbox[2] - bbox[0]
        draw.text((right[0] + (right[2] - right[0] - tw) / 2, guide_start + idx * guide_line_h), txt, font=guide_font, fill="#777777")

    date_font = pil_font(26, bold=True)
    date_text = f"Date : {when.strftime('%d/%m/%Y')}"
    bbox = draw.textbbox((0, 0), date_text, font=date_font)
    tw = bbox[2] - bbox[0]
    th = bbox[3] - bbox[1]
    draw.text((right[0] + (right[2] - right[0] - tw) / 2, mid_y + (y2 - mid_y - th) / 2 - 2), date_text, font=date_font, fill="#777777")


def generate_connection_diagram_image(customer: dict[str, Any], assets: list[dict[str, Any]], schema: dict[str, Any]) -> Path:
    from PIL import Image, ImageDraw, ImageOps

    GENERATED_DOCUMENTS_DIR.mkdir(parents=True, exist_ok=True)
    # Page A4 portrait : le dessin généré reprend le style de la première page du modèle Word
    # fourni : entête encadrée avec nom client en rouge et pied de page dédié au schéma.
    width, height = 1654, 2339
    image = Image.new("RGB", (width, height), "white")
    draw = ImageDraw.Draw(image)
    title_font = pil_font(54, bold=True)
    label_font = pil_font(22, bold=True)
    small_font = pil_font(18, bold=False)
    tiny_font = pil_font(15, bold=False)

    customer_title = str(customer.get("company") or customer.get("name") or "Client").strip()
    layout_settings = load_drawing_layout_settings()
    header_image = resolve_drawing_layout_image_path(layout_settings.get("header_image_path"))
    header_logo_applied = bool(header_image and Path(header_image).exists())
    draw_installation_guide_header(draw, width, customer_title, datetime.now(), draw_default_logo=not header_logo_applied)
    if header_logo_applied:
        paste_header_logo_inside_guide(image, header_image, width)

    caisse_asset = find_caisse_asset(assets)
    ordered: list[dict[str, Any]] = []
    if caisse_asset:
        ordered.append(caisse_asset)
    ordered.extend([a for a in assets if not caisse_asset or int(a.get("id") or 0) != int(caisse_asset.get("id") or 0)])

    placements: dict[int, dict[str, Any]] = {}
    top_card = (width // 2 - 330, 235, width // 2 + 330, 655)
    if caisse_asset:
        placements[int(caisse_asset.get("id") or -1)] = {"rect": top_card, "image_max": (600, 260)}
    others = [a for a in ordered if not caisse_asset or int(a.get("id") or 0) != int(caisse_asset.get("id") or 0)]
    cols = 3
    card_w, card_h = 450, 330
    start_x = 95
    gap_x = 55
    start_y = 760
    gap_y = 85
    for idx, asset in enumerate(others):
        row = idx // cols
        col = idx % cols
        x1 = start_x + col * (card_w + gap_x)
        y1 = start_y + row * (card_h + gap_y)
        placements[int(asset.get("id") or 0)] = {"rect": (x1, y1, x1 + card_w, y1 + card_h), "image_max": (card_w - 40, 150)}

    absolute_points: list[dict[str, Any]] = []
    signature = build_connection_signature(assets)
    draw.rounded_rectangle((70, 230, width - 70, height - 185), radius=24, outline="#e2e8f0", width=2)

    for asset in ordered:
        asset_id = int(asset.get("id") or 0)
        placement = placements.get(asset_id)
        if not placement:
            continue
        rect = placement["rect"]
        draw.rounded_rectangle(rect, radius=20, fill="#ffffff", outline="#cbd5e1", width=3)
        accent = "#1d4ed8" if is_caisse_category(asset.get("category")) else "#64748b"
        draw.rounded_rectangle((rect[0]+2, rect[1]+2, rect[2]-2, rect[1]+42), radius=18, fill="#eff6ff" if is_caisse_category(asset.get("category")) else "#f8fafc", outline=accent, width=1)
        title = str(asset.get("category") or "Matériel").strip() or "Matériel"
        draw.text((rect[0] + 16, rect[1] + 10), title[:38], font=label_font, fill="#0f172a")
        sub = f"SN : {str(asset.get('serial_number_raw') or '')[:40]}"
        draw.text((rect[0] + 16, rect[1] + 50), sub, font=tiny_font, fill="#64748b")
        if asset.get("client_name"):
            draw.text((rect[0] + 16, rect[1] + 70), str(asset.get("client_name"))[:46], font=tiny_font, fill="#475569")

        profile = get_asset_connection_profile(asset)
        img_rect = (rect[0] + 16, rect[1] + 100, rect[2] - 16, rect[1] + 100 + placement["image_max"][1])
        image_left, image_top, image_w, image_h = img_rect[0], img_rect[1], placement["image_max"][0], placement["image_max"][1]
        material_path = resolve_material_connection_image_path(profile.get("image_path"))
        if material_path:
            try:
                mat_img = Image.open(material_path).convert("RGBA")
                mat_img = ImageOps.contain(mat_img, placement["image_max"])
                px = rect[0] + ((rect[2] - rect[0]) - mat_img.width) // 2
                py = rect[1] + 100
                image.paste(mat_img, (px, py), mat_img)
                image_left, image_top, image_w, image_h = px, py, mat_img.width, mat_img.height
            except Exception:
                draw.rounded_rectangle(img_rect, radius=12, fill="#f8fafc", outline="#cbd5e1")
                draw_centered_text(draw, img_rect, "Image du bas non lisible", small_font, fill="#94a3b8")
        else:
            draw.rounded_rectangle(img_rect, radius=12, fill="#f8fafc", outline="#cbd5e1")
            draw_centered_text(draw, img_rect, "Ajoute l'image du bas du matériel", small_font, fill="#94a3b8")

        points = profile.get("points") or []
        for point in points:
            abs_x = int(image_left + image_w * clamp_percent(point.get("x"), 50) / 100)
            abs_y = int(image_top + image_h * clamp_percent(point.get("y"), 50) / 100)
            color = str(point.get("color") or "#2563eb")
            draw.ellipse((abs_x - 9, abs_y - 9, abs_x + 9, abs_y + 9), fill=color)
            absolute_points.append({
                "asset_id": asset_id,
                "asset": asset,
                "color": color.lower(),
                "name": str(point.get("name") or ""),
                "xy": (abs_x, abs_y),
                "is_caisse": is_caisse_category(asset.get("category")),
            })

    points_by_color: dict[str, list[dict[str, Any]]] = {}
    for point in absolute_points:
        points_by_color.setdefault(point["color"], []).append(point)

    for color, plist in points_by_color.items():
        if len(plist) < 2:
            continue
        caisse_points = [p for p in plist if p.get("is_caisse")]
        other_points = [p for p in plist if not p.get("is_caisse")]
        if caisse_points and other_points:
            for idx, target in enumerate(other_points):
                source = caisse_points[min(idx, len(caisse_points)-1)]
                draw_arrow(draw, source["xy"], target["xy"], color, width=5)
        else:
            source = plist[0]
            for target in plist[1:]:
                draw_arrow(draw, source["xy"], target["xy"], color, width=5)

    legend_entries: list[tuple[str, str]] = []
    seen_legend: set[tuple[str, str]] = set()
    for point in absolute_points:
        key = (str(point.get("color") or "#2563eb").lower(), str(point.get("name") or "").strip())
        if not key[1] or key in seen_legend:
            continue
        seen_legend.add(key)
        legend_entries.append(key)
    if legend_entries:
        legend_box = (100, height - 360, width - 100, height - 205)
        draw.rounded_rectangle(legend_box, radius=18, fill="#ffffff", outline="#cbd5e1", width=2)
        draw.text((legend_box[0] + 16, legend_box[1] + 12), "Légende des points", font=label_font, fill="#0f172a")
        columns = 2 if len(legend_entries) > 6 else 1
        rows_per_col = max(1, math.ceil(len(legend_entries) / columns))
        col_width = (legend_box[2] - legend_box[0] - 34) // columns
        for idx, (color, label) in enumerate(legend_entries[:14]):
            col = idx // rows_per_col
            row = idx % rows_per_col
            base_x = legend_box[0] + 18 + col * col_width
            base_y = legend_box[1] + 46 + row * 24
            draw.ellipse((base_x, base_y, base_x + 14, base_y + 14), fill=color, outline="#334155")
            draw.text((base_x + 22, base_y - 3), label[:34], font=small_font, fill="#111827")

    footer_box = (100, height - 180, width - 100, height - 40)
    footer_image = resolve_drawing_layout_image_path(layout_settings.get("footer_image_path"))
    if not paste_layout_image_on_page(image, footer_image, footer_box):
        fallback_footer_box = (180, height - 145, width - 180, height - 65)
        draw.rectangle(fallback_footer_box, outline="#111827", width=1, fill="#ffffff")
        draw.text((fallback_footer_box[0] + 18, fallback_footer_box[1] + 16), f"Numéro CLYO : {customer.get('customer_code') or ''}", font=small_font, fill="#0f172a")
        draw.text((fallback_footer_box[0] + 18, fallback_footer_box[1] + 42), f"Signature schéma : {signature[:90]}", font=tiny_font, fill="#475569")
        footer_text = f"Document généré le {datetime.now().strftime('%d/%m/%Y %H:%M')} - {APP_NAME} {APP_VERSION}"
        fbox = draw.textbbox((0, 0), footer_text, font=tiny_font)
        draw.text((fallback_footer_box[2] - (fbox[2]-fbox[0]) - 18, fallback_footer_box[1] + 42), footer_text, font=tiny_font, fill="#64748b")

    file_name = f"schema_{safe_filename_part(customer.get('customer_code'), 'client')}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.png"
    out_path = GENERATED_DOCUMENTS_DIR / file_name
    image.save(out_path, format="PNG")
    return out_path
def docx_set_cell_text(cell: Any, text: Any, bold: bool = False, size: float = 8.5) -> None:
    from docx.shared import Pt
    cell.text = ""
    p = cell.paragraphs[0]
    p.paragraph_format.space_after = Pt(0)
    p.paragraph_format.space_before = Pt(0)
    run = p.add_run(str(text or ""))
    run.bold = bold
    run.font.size = Pt(size)


def docx_style_table_header(row: Any) -> None:
    from docx.oxml import OxmlElement
    from docx.oxml.ns import qn
    from docx.shared import RGBColor
    for cell in row.cells:
        tc_pr = cell._tc.get_or_add_tcPr()
        shd = OxmlElement("w:shd")
        shd.set(qn("w:fill"), "1F4E78")
        tc_pr.append(shd)
        for p in cell.paragraphs:
            for run in p.runs:
                run.font.bold = True
                run.font.color.rgb = RGBColor(255, 255, 255)


def format_doc_date(value: Any) -> str:
    if not value:
        return ""
    text = str(value)
    try:
        d = date.fromisoformat(text[:10])
        return d.strftime("%m/%y")
    except Exception:
        return text


def format_doc_full_date(value: Any) -> str:
    if not value:
        return ""
    text = str(value)
    try:
        d = date.fromisoformat(text[:10])
        return d.strftime("%d/%m/%Y")
    except Exception:
        return text


def asset_installation_extra(asset: dict[str, Any]) -> dict[str, Any]:
    raw = asset.get("notes")
    if not raw:
        return {}
    try:
        data = json.loads(str(raw))
        if isinstance(data, dict) and isinstance(data.get("installation_extra"), dict):
            return data.get("installation_extra") or {}
    except Exception:
        return {}
    return {}


def asset_connection_doc_text(asset: dict[str, Any]) -> str:
    extra = asset_installation_extra(asset)
    if extra.get("printer_connection"):
        text = str(extra.get("printer_connection") or "")
        if extra.get("printer_ip"):
            text += f" / IP {extra.get('printer_ip')}"
        return text
    return default_connection_for_asset(asset)


def asset_omada_doc_text(asset: dict[str, Any]) -> str:
    extra = asset_installation_extra(asset)
    user = str(extra.get("omada_user") or "").strip()
    password = str(extra.get("omada_password") or "").strip()
    if user or password:
        return f"OMADA {user} / {password}"
    return ""


def docx_xml_escape(value: Any) -> str:
    text = str(value if value is not None else "")
    return (
        text.replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
        .replace("'", "&apos;")
    )


def docx_xml_text(value: Any) -> str:
    text = docx_xml_escape(value)
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    parts = text.split("\n")
    if len(parts) == 1:
        return f'<w:t xml:space="preserve">{parts[0]}</w:t>'
    runs = []
    for idx, part in enumerate(parts):
        if idx:
            runs.append("<w:br/>")
        runs.append(f'<w:t xml:space="preserve">{part}</w:t>')
    return "".join(runs)


def fallback_docx_run(text: Any, bold: bool = False, size_half_points: int | None = None, color: str | None = None) -> str:
    props: list[str] = []
    if bold:
        props.append("<w:b/>")
    if color:
        props.append(f'<w:color w:val="{docx_xml_escape(color)}"/>')
    if size_half_points:
        props.append(f'<w:sz w:val="{int(size_half_points)}"/>')
        props.append(f'<w:szCs w:val="{int(size_half_points)}"/>')
    rpr = f"<w:rPr>{''.join(props)}</w:rPr>" if props else ""
    return f"<w:r>{rpr}{docx_xml_text(text)}</w:r>"


def fallback_docx_paragraph(text: Any = "", *, bold: bool = False, size_half_points: int | None = None, color: str | None = None, align: str | None = None) -> str:
    ppr = ""
    if align:
        ppr = f'<w:pPr><w:jc w:val="{docx_xml_escape(align)}"/></w:pPr>'
    return f"<w:p>{ppr}{fallback_docx_run(text, bold=bold, size_half_points=size_half_points, color=color)}</w:p>"


def fallback_docx_image_paragraph(rid: str, width_in: float, height_in: float) -> str:
    cx = int(width_in * 914400)
    cy = int(height_in * 914400)
    return f'''<w:p><w:pPr><w:jc w:val="center"/></w:pPr><w:r><w:drawing>
<wp:inline distT="0" distB="0" distL="0" distR="0" xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing">
<wp:extent cx="{cx}" cy="{cy}"/><wp:effectExtent l="0" t="0" r="0" b="0"/><wp:docPr id="1" name="Schéma de branchement"/><wp:cNvGraphicFramePr/>
<a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture">
<pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="0" name="schema.png"/><pic:cNvPicPr/></pic:nvPicPr>
<pic:blipFill><a:blip r:embed="{rid}" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill>
<pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="{cx}" cy="{cy}"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr>
</pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p>'''


def fallback_docx_table(headers: list[str], rows: list[list[Any]]) -> str:
    grid_cols = "".join('<w:gridCol w:w="2200"/>' for _ in headers)

    def cell(value: Any, header: bool = False) -> str:
        shading = '<w:shd w:fill="1F4E78"/>' if header else ""
        color = "FFFFFF" if header else None
        return f'''<w:tc><w:tcPr><w:tcW w:w="2200" w:type="dxa"/>{shading}</w:tcPr>{fallback_docx_paragraph(value, bold=header, size_half_points=17, color=color)}</w:tc>'''

    header_xml = "<w:tr>" + "".join(cell(h, True) for h in headers) + "</w:tr>"
    rows_xml = "".join("<w:tr>" + "".join(cell(v, False) for v in row) + "</w:tr>" for row in rows)
    return f'''<w:tbl><w:tblPr><w:tblStyle w:val="TableGrid"/><w:tblW w:w="0" w:type="auto"/><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:left w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:bottom w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:right w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideH w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideV w:val="single" w:sz="4" w:space="0" w:color="auto"/></w:tblBorders></w:tblPr><w:tblGrid>{grid_cols}</w:tblGrid>{header_xml}{rows_xml}</w:tbl>'''


def write_fallback_installation_docx(out_path: Path, customer: dict[str, Any], sorted_assets: list[dict[str, Any]], caisse_asset: dict[str, Any] | None, model: dict[str, Any] | None, schema: dict[str, Any], diagram_path: Path) -> None:
    code = customer.get("customer_code") or ""
    client_name = customer_display_name(customer) or "Client"
    title = str(customer.get("company") or customer.get("name") or "Client").strip().upper()
    headers = ["nom du matériel", "catégorie", "Ip/connexion", "nom/MAC/SSID", "numéro de série /IMEI", "date réception", "fournisseur", "TeamViewer caisse"]
    rows: list[list[Any]] = []
    caisse_teamviewer_id = str((caisse_asset or {}).get("teamviewer_id") or "") if caisse_asset else ""
    for asset in sorted_assets:
        material_name = str(asset.get("category") or "").strip()
        rows.append([
            material_name,
            asset.get("category") or "",
            asset_connection_doc_text(asset),
            "CAISSE1" if is_caisse_category(asset.get("category")) else asset_omada_doc_text(asset),
            asset.get("serial_number_raw") or "",
            format_doc_full_date(asset.get("purchase_date")),
            asset.get("supplier_name") or "",
            caisse_teamviewer_id if caisse_asset and int(asset.get("id") or 0) == int(caisse_asset.get("id") or 0) else "",
        ])
    if customer.get("notes"):
        rows.append(["NOTES", str(customer.get("notes") or "")[:120], "", "", "", "", "", ""])

    width_in = 9.2
    height_in = 6.4
    try:
        from PIL import Image
        with Image.open(diagram_path) as img:
            w_px, h_px = img.size
        if w_px > 0 and h_px > 0:
            height_in = min(6.4, width_in * h_px / w_px)
    except Exception:
        pass

    body_parts = [
        fallback_docx_image_paragraph("rId1", width_in, height_in),
        '<w:p><w:r><w:br w:type="page"/></w:r></w:p>',
        fallback_docx_paragraph(f"Numéro CLYO : {code}", bold=True, size_half_points=32),
        fallback_docx_paragraph(f"Client : {client_name}"),
    ]
    contact_parts = [str(x) for x in [customer.get("phone"), customer.get("email")] if x]
    if contact_parts:
        body_parts.append(fallback_docx_paragraph("Contact : " + " / ".join(contact_parts)))
    if customer.get("address"):
        body_parts.append(fallback_docx_paragraph("Adresse : " + str(customer.get("address") or "")))
    body_parts.append(fallback_docx_table(headers, rows))
    body_parts.append(fallback_docx_paragraph(f"Document généré le {datetime.now().strftime('%d/%m/%Y à %H:%M')} - {APP_NAME} v{APP_VERSION}", size_half_points=16, align="right"))

    document_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">
<w:body>{''.join(body_parts)}<w:sectPr><w:pgSz w:w="16838" w:h="11906" w:orient="landscape"/><w:pgMar w:top="648" w:right="648" w:bottom="648" w:left="648" w:header="708" w:footer="708" w:gutter="0"/></w:sectPr></w:body></w:document>'''
    rels_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="media/schema.png"/></Relationships>'''
    package_rels = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'''
    content_types = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Default Extension="png" ContentType="image/png"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'''
    styles_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:qFormat/></w:style><w:style w:type="table" w:styleId="TableGrid"><w:name w:val="Table Grid"/><w:tblPr><w:tblBorders><w:top w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:left w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:bottom w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:right w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideH w:val="single" w:sz="4" w:space="0" w:color="auto"/><w:insideV w:val="single" w:sz="4" w:space="0" w:color="auto"/></w:tblBorders></w:tblPr></w:style></w:styles>'''
    created = datetime.utcnow().replace(microsecond=0).isoformat() + "Z"
    core_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>{docx_xml_escape('Fiche installation ' + str(code))}</dc:title><dc:creator>{docx_xml_escape(APP_NAME)}</dc:creator><cp:lastModifiedBy>{docx_xml_escape(APP_NAME)}</cp:lastModifiedBy><dcterms:created xsi:type="dcterms:W3CDTF">{created}</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">{created}</dcterms:modified></cp:coreProperties>'''
    app_xml = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties" xmlns:vt="http://schemas.openxmlformats.org/officeDocument/2006/docPropsVTypes"><Application>Clyo Stock Atelier</Application></Properties>'''

    out_path.parent.mkdir(parents=True, exist_ok=True)
    with zipfile.ZipFile(out_path, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("[Content_Types].xml", content_types)
        zf.writestr("_rels/.rels", package_rels)
        zf.writestr("word/document.xml", document_xml)
        zf.writestr("word/_rels/document.xml.rels", rels_xml)
        zf.writestr("word/styles.xml", styles_xml)
        zf.writestr("docProps/core.xml", core_xml)
        zf.writestr("docProps/app.xml", app_xml)
        zf.write(diagram_path, "word/media/schema.png")


def generate_installation_pdf(customer: dict[str, Any], sorted_assets: list[dict[str, Any]], schema: dict[str, Any], diagram_path: Path, out_path: Path) -> Path:
    from PIL import Image, ImageDraw, ImageOps

    def make_page(size=(1654, 2339), bg="white"):
        return Image.new("RGB", size, bg)

    def draw_wrapped(draw, text, xy, font, fill, max_width, line_height):
        lines = wrap_text_by_width(draw, text, font, max_width)
        x, y = xy
        for line in lines:
            draw.text((x, y), line, font=font, fill=fill)
            y += line_height
        return y

    layout_settings = load_drawing_layout_settings()
    header_image = resolve_drawing_layout_image_path(layout_settings.get("header_image_path"))
    footer_image = resolve_drawing_layout_image_path(layout_settings.get("footer_image_path"))

    page1 = make_page((1654, 2339), "white")
    d1 = ImageDraw.Draw(page1)
    title_font = pil_font(48, bold=True)
    try:
        diagram = Image.open(diagram_path).convert("RGB")
        diagram = ImageOps.contain(diagram, (1654, 2339))
        x = (1654 - diagram.width) // 2
        y = (2339 - diagram.height) // 2
        page1.paste(diagram, (x, y))
    except Exception:
        d1.text((120, 280), "Schéma indisponible", font=title_font, fill="#b91c1c")
        if header_image:
            paste_layout_image_on_page(page1, header_image, (100, 28, 1554, 188))
        if footer_image:
            paste_layout_image_on_page(page1, footer_image, (100, 2150, 1554, 2298))

    page2 = make_page((2339, 1654), "white")
    d2 = ImageDraw.Draw(page2)
    h1 = pil_font(34, bold=True)
    h2 = pil_font(20, bold=False)
    small = pil_font(16, bold=False)
    tiny = pil_font(14, bold=False)

    customer_title_page2 = str(customer.get("company") or customer.get("name") or "Client").strip()
    header_logo_applied_page2 = bool(header_image and Path(header_image).exists())
    draw_installation_guide_header(d2, 2339, customer_title_page2, datetime.now(), draw_default_logo=not header_logo_applied_page2)
    if header_logo_applied_page2:
        paste_header_logo_inside_guide(page2, header_image, 2339)
    footer_applied = paste_layout_image_on_page(page2, footer_image, (60, 1460, 2279, 1628)) if footer_image else False

    start_y = 235
    d2.text((60, start_y), f"Numéro CLYO : {customer.get('customer_code') or ''}", font=h1, fill="#111827")
    info_y = start_y + 55
    info_y = draw_wrapped(d2, f"Client : {customer_display_name(customer) or ''}", (60, info_y), h2, "#111827", 2200, 28) + 6
    contact = " / ".join([str(x) for x in [customer.get('phone'), customer.get('email')] if x])
    if contact:
        info_y = draw_wrapped(d2, f"Contact : {contact}", (60, info_y), h2, "#111827", 2200, 28) + 6
    if customer.get('address'):
        info_y = draw_wrapped(d2, f"Adresse : {customer.get('address')}", (60, info_y), h2, "#111827", 2200, 28) + 12
    top = max(360, info_y)
    headers = ["Matériel", "Catégorie", "Connexion", "N° série / IMEI", "Date réception", "Fournisseur", "TeamViewer caisse"]
    col_x = [60, 520, 800, 1080, 1515, 1775, 2065, 2279]
    row_h = 38
    d2.rectangle((60, top, 2279, top + row_h), fill="#1f4e78")
    for idx, h in enumerate(headers):
        d2.text((col_x[idx] + 8, top + 8), h, font=h2, fill="white")
    y = top + row_h
    caisse_asset = find_caisse_asset(sorted_assets)
    caisse_teamviewer_id = str((caisse_asset or {}).get('teamviewer_id') or '') if caisse_asset else ''
    for asset in sorted_assets[:26]:
        material_name = str(asset.get("category") or "").strip()
        vals = [
            material_name,
            str(asset.get("category") or ""),
            asset_connection_doc_text(asset) or "",
            str(asset.get("serial_number_raw") or ""),
            format_doc_full_date(asset.get("purchase_date")),
            str(asset.get("supplier_name") or ""),
            caisse_teamviewer_id if caisse_asset and int(asset.get("id") or 0) == int(caisse_asset.get("id") or 0) else "",
        ]
        d2.rectangle((60, y, 2279, y + row_h), outline="#cbd5e1", width=1)
        for idx, val in enumerate(vals):
            txt = str(val or "")[:26 if idx not in (0,5) else 32]
            d2.text((col_x[idx] + 8, y + 10), txt, font=small, fill="#111827")
        y += row_h
        if y > 1415:
            break

    footer = f"Document généré le {datetime.now().strftime('%d/%m/%Y à %H:%M')} - {APP_NAME} v{APP_VERSION}"
    if not footer_applied:
        d2.text((1500, 1585), footer, font=small, fill="#64748b")
    else:
        d2.text((60, 1432), footer, font=tiny, fill="#64748b")

    page1.save(out_path, save_all=True, append_images=[page2])
    return out_path


def build_installation_docx_response(customer: dict[str, Any], sorted_assets: list[dict[str, Any]], caisse_asset: dict[str, Any] | None, model: dict[str, Any] | None, schema: dict[str, Any], diagram_path: Path, out_path: Path, pdf_path: Path | None = None, request: Request | None = None, fallback: bool = False) -> dict[str, Any]:
    file_name = out_path.name
    if fallback:
        write_app_log("installation_sheet_generated_fallback", "customer", customer.get("id"), f"Fiche installation générée sans module python-docx : {file_name}", request=request)
    else:
        write_app_log("installation_sheet_generated", "customer", customer.get("id"), f"Fiche installation générée : {file_name}", request=request)
    pdf_file_name = pdf_path.name if pdf_path else ""
    return {
        "status": "ok",
        "customer": customer,
        "assets_count": len(sorted_assets),
        "caisse_model": model_display_label(model or caisse_asset),
        "schema_title": schema.get("title"),
        "file_name": file_name,
        "download_url": f"/api/generated-documents/{urllib.parse.quote(file_name)}",
        "pdf_file_name": pdf_file_name,
        "pdf_download_url": f"/api/generated-documents/{urllib.parse.quote(pdf_file_name)}" if pdf_file_name else "",
        "diagram_file": diagram_path.name,
        "diagram_url": f"/api/generated-documents/{urllib.parse.quote(diagram_path.name)}",
        "path": str(out_path),
        "docx_engine": "fallback_zip" if fallback else "python-docx",
    }


def generate_installation_docx(customer_id: int, request: Request | None = None) -> dict[str, Any]:
    """Génère uniquement une fiche installation PDF.

    La fonction conserve son nom historique pour ne pas casser l'API existante
    /api/customers/{id}/installation-sheet, mais aucune génération DOCX/Word
    n'est effectuée à partir de cette version. Cela fiabilise l'application
    packagée : seuls les chemins du dossier de données actif et le moteur PDF
    interne sont utilisés.
    """
    GENERATED_DOCUMENTS_DIR.mkdir(parents=True, exist_ok=True)
    with db() as conn:
        customer = get_customer_by_id(customer_id, conn)
        if not customer:
            raise HTTPException(status_code=404, detail="Client introuvable")
        assets = get_installation_assets_for_customer(conn, customer)
    if not assets:
        raise HTTPException(status_code=400, detail="Fiche installation impossible : aucun matériel vendu n’est lié à ce client.")

    caisse_asset = find_caisse_asset(assets)
    model = get_reference_by_id("Modeles", caisse_asset.get("model_id")) if caisse_asset else None
    schema = {
        "title": f"Schéma auto - {len(assets)} matériel(s)",
        "signature": build_connection_signature(assets),
        "caisse_model": model_display_label(model) if model else "",
    }

    diagram_path = generate_connection_diagram_image(customer, assets, schema)
    sorted_assets = sorted(
        assets,
        key=lambda a: (
            0 if is_caisse_category(a.get("category")) else 1,
            str(a.get("category") or ""),
            str(a.get("model_name") or ""),
        ),
    )

    code = safe_filename_part(customer.get("customer_code"), "client")
    name = safe_filename_part(customer.get("company") or customer.get("name"), "client")
    material_signature = build_installation_assets_signature(sorted_assets)
    cleanup_previous_installation_documents_for_signature(code, name, material_signature)

    # Nettoyage supplémentaire : suppression des anciens DOCX liés à la même fiche.
    for old_docx in GENERATED_DOCUMENTS_DIR.glob(f"Fiche_installation_{code}_{name}_{material_signature}*.docx"):
        try:
            old_docx.unlink()
        except Exception as exc:
            safe_log(f"Suppression ancien DOCX impossible : {old_docx.name} / {exc}")

    pdf_file_name = f"Fiche_installation_{code}_{name}_{material_signature}.pdf"
    pdf_path = GENERATED_DOCUMENTS_DIR / pdf_file_name
    generate_installation_pdf(customer, sorted_assets, schema, diagram_path, pdf_path)

    write_app_log(
        "installation_sheet_pdf_generated",
        "customer",
        customer.get("id"),
        f"Fiche installation PDF générée : {pdf_file_name}",
        request=request,
    )
    return {
        "status": "ok",
        "customer": customer,
        "assets_count": len(sorted_assets),
        "caisse_model": model_display_label(model or caisse_asset),
        "schema_title": schema.get("title"),
        "file_name": pdf_file_name,
        "download_url": f"/api/generated-documents/{urllib.parse.quote(pdf_file_name)}",
        "pdf_file_name": pdf_file_name,
        "pdf_download_url": f"/api/generated-documents/{urllib.parse.quote(pdf_file_name)}",
        "diagram_file": diagram_path.name,
        "diagram_url": f"/api/generated-documents/{urllib.parse.quote(diagram_path.name)}",
        "path": str(pdf_path),
        "format": "PDF",
        "docx_engine": "disabled_pdf_only",
    }


def list_generated_installation_documents(customer_id: int | None = None) -> list[dict[str, Any]]:
    GENERATED_DOCUMENTS_DIR.mkdir(parents=True, exist_ok=True)
    code = None
    if customer_id:
        customer = get_customer_by_id(customer_id)
        code = str((customer or {}).get("customer_code") or "").strip()
    docs: list[dict[str, Any]] = []
    for path in GENERATED_DOCUMENTS_DIR.iterdir():
        if not path.is_file() or not path.name.startswith("Fiche_installation_") or path.suffix.lower() != ".pdf":
            continue
        if code and f"_{code}_" not in path.name:
            continue
        try:
            stat = path.stat()
            docs.append({
                "file_name": path.name,
                "format": path.suffix.lower().lstrip('.').upper(),
                "download_url": f"/api/generated-documents/{urllib.parse.quote(path.name)}",
                "created_at": datetime.fromtimestamp(stat.st_mtime).isoformat(timespec="seconds"),
                "size_kb": round(stat.st_size / 1024, 1),
            })
        except Exception:
            continue
    docs.sort(key=lambda item: item.get("created_at") or "", reverse=True)
    return docs[:50]


DEFAULT_UI_SETTINGS: dict[str, Any] = {
    "primary_color": "#2563eb",
    "text_color": "#1f2937",
    "section_text_color": "#1f2937",
    "result_text_color": "#1f2937",
    "background_color": "#f3f5f9",
    "card_radius": 16,
    "bubble_radius": 999,
    "font_family": "Inter, Segoe UI, Arial, sans-serif",
    "sidebar_background_color": "#eaf6fe",
    "sidebar_button_color": "#0f4b7d",
    "sidebar_button_text_color": "#ffffff",
    "sidebar_active_color": "#0c4778",
    "sidebar_active_text_color": "#ffffff",
    "sidebar_hover_color": "#155e95",
    "sidebar_radius": 22,
    "logo_data_url": "",
    "layout_positions": {},
    "force_config_visibility": True,
}


def _sanitize_ui_settings_dict(data: dict[str, Any]) -> dict[str, Any]:
    cleaned = {**DEFAULT_UI_SETTINGS, **(data or {})}
    # Ne jamais réimporter les anciens logos / images d'interface depuis une base existante.
    cleaned["logo_data_url"] = ""
    for legacy_key in [
        "logo_path", "logo_file", "app_icon", "app_icon_path", "app-icon",
        "login_logo", "login_logo_data_url", "login_image", "background_image",
        "appearance_logo", "brand_logo", "splash_logo"
    ]:
        if legacy_key in cleaned:
            cleaned[legacy_key] = ""
    return cleaned


def load_ui_settings() -> dict[str, Any]:
    if not UI_SETTINGS_PATH.exists():
        return DEFAULT_UI_SETTINGS.copy()
    try:
        data = json.loads(UI_SETTINGS_PATH.read_text(encoding="utf-8"))
        if not isinstance(data, dict):
            return DEFAULT_UI_SETTINGS.copy()
        return _sanitize_ui_settings_dict(data)
    except Exception:
        return DEFAULT_UI_SETTINGS.copy()


def save_ui_settings(settings: dict[str, Any]) -> dict[str, Any]:
    merged = _sanitize_ui_settings_dict({**DEFAULT_UI_SETTINGS, **settings})
    try:
        merged["card_radius"] = max(0, min(40, int(merged.get("card_radius") or 16)))
    except (TypeError, ValueError):
        merged["card_radius"] = DEFAULT_UI_SETTINGS["card_radius"]
    try:
        merged["bubble_radius"] = max(0, min(999, int(merged.get("bubble_radius") or 999)))
    except (TypeError, ValueError):
        merged["bubble_radius"] = DEFAULT_UI_SETTINGS["bubble_radius"]
    try:
        merged["sidebar_radius"] = max(0, min(40, int(merged.get("sidebar_radius") or 22)))
    except (TypeError, ValueError):
        merged["sidebar_radius"] = DEFAULT_UI_SETTINGS["sidebar_radius"]
    if not isinstance(merged.get("layout_positions"), dict):
        merged["layout_positions"] = {}
    merged["force_config_visibility"] = bool(merged.get("force_config_visibility", True))
    UI_SETTINGS_PATH.write_text(json.dumps(merged, ensure_ascii=False, indent=2), encoding="utf-8")
    return merged


def load_setup_choice() -> dict[str, Any]:
    if not SETUP_CHOICE_PATH.exists():
        return {}
    try:
        data = json.loads(SETUP_CHOICE_PATH.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def setup_choice_required() -> bool:
    """Indique si l'écran de sélection de base doit être affiché.

    Avant la V8.0.6, l'application redemandait une sélection de base à
    chaque changement de version parce que setup_choice.json stockait
    l'ancien numéro d'application. Pour une mise à jour, ce n'est pas le bon
    comportement : si une base a déjà été choisie ou si un dossier de données
    actif existe, on doit rouvrir l'application normalement.
    """
    data = load_setup_choice()

    # Une base déjà choisie reste valide après une mise à jour, même si le
    # numéro de version stocké est plus ancien.
    if data.get("choice") in {"use_existing", "create_new", "use_sql"}:
        return False

    # Compatibilité : si une ancienne version a bien enregistré un dossier de
    # données actif, ne pas forcer l'utilisateur à le sélectionner à nouveau.
    try:
        if ACTIVE_DATA_CONFIG_PATH.exists():
            cfg = json.loads(ACTIVE_DATA_CONFIG_PATH.read_text(encoding="utf-8"))
            if isinstance(cfg, dict) and str(cfg.get("database_mode") or "").lower() in {"sql", "mariadb", "mysql"}:
                return False
            raw = cfg.get("data_dir") if isinstance(cfg, dict) else None
            if raw:
                active = _safe_data_path_v808(raw)
                markers = [
                    active / "stock_assets.db",
                    active / "referentiel_stock.xlsx",
                    active / "activity_log.jsonl",
                    active / "ui_settings.json",
                    active / "update_history.jsonl",
                ]
                if any(p.exists() and (not p.is_file() or p.stat().st_size >= 0) for p in markers):
                    return False
    except Exception:
        pass

    # Dernière récupération : si le dossier actif contient déjà une base ou un
    # référentiel, c'est une mise à jour ou une installation existante.
    try:
        markers = [DB_PATH, EXCEL_PATH, LOG_PATH, UI_SETTINGS_PATH, UPDATE_HISTORY_PATH]
        if any(p.exists() and (not p.is_file() or p.stat().st_size >= 0) for p in markers):
            return False
    except Exception:
        pass

    # Nouvelle installation réelle : aucun choix, aucun dossier actif connu.
    return True


def mark_setup_choice(choice: str) -> None:
    SETUP_CHOICE_PATH.write_text(
        json.dumps({"app_version": APP_VERSION, "choice": choice, "chosen_at": datetime.now().isoformat(timespec="seconds")}, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )


# --- V8.0.6 : nouvelle base avec référentiel conservé ---
REFERENCE_PRESERVE_FILE_NAMES = [
    "referentiel_stock.xlsx",
    "material_connection_profiles.json",
    "drawing_layout_settings.json",
    "connection_schemas.json",
    "deleted_status_values.json",
]
REFERENCE_PRESERVE_DIR_NAMES = ["material_connection_images"]


def _sqlite_rows_for_reference_preserve(source_db: Path) -> dict[str, list[dict[str, Any]]]:
    """Capture uniquement les tables de référentiel à conserver lors d'une nouvelle base."""
    payload: dict[str, list[dict[str, Any]]] = {"reference_rows": [], "model_prices": []}
    if not source_db.exists():
        return payload
    try:
        conn = sqlite3.connect(source_db)
        conn.row_factory = sqlite3.Row
        try:
            tables = {row["name"] for row in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()}
            if "reference_rows" in tables:
                payload["reference_rows"] = [dict(row) for row in conn.execute(
                    "SELECT sheet_name, row_id, data_json, created_at, updated_at FROM reference_rows ORDER BY sheet_name, row_id"
                ).fetchall()]
            if "model_prices" in tables:
                payload["model_prices"] = [dict(row) for row in conn.execute(
                    "SELECT model_id, default_price_eur, updated_at FROM model_prices ORDER BY model_id"
                ).fetchall()]
        finally:
            conn.close()
    except Exception as exc:
        safe_log(f"Capture référentiel SQLite impossible : {exc}")
    return payload


def capture_reference_preserve_payload(source_dir: Path | None = None) -> dict[str, Any]:
    """Capture le référentiel courant avant création d'une nouvelle base.

    La nouvelle base doit vider clients/matériels, mais conserver la configuration métier :
    modèles, fournisseurs, règles, statuts, motifs retour, dessins et images de connexion.
    """
    source = Path(source_dir or DATA_DIR).expanduser().resolve()
    payload: dict[str, Any] = {
        "source_dir": str(source),
        "captured_at": now_iso(),
        "tables": _sqlite_rows_for_reference_preserve(source / "stock_assets.db"),
        "files": {},
        "dirs": {},
    }
    for name in REFERENCE_PRESERVE_FILE_NAMES:
        path = source / name
        try:
            if path.exists() and path.is_file():
                payload["files"][name] = path.read_bytes()
        except Exception as exc:
            safe_log(f"Capture fichier référentiel impossible {path}: {exc}")
    for dirname in REFERENCE_PRESERVE_DIR_NAMES:
        root = source / dirname
        entries: dict[str, bytes] = {}
        if root.exists() and root.is_dir():
            for file_path in root.rglob("*"):
                if not file_path.is_file():
                    continue
                try:
                    rel = str(file_path.relative_to(root)).replace("\\", "/")
                    entries[rel] = file_path.read_bytes()
                except Exception as exc:
                    safe_log(f"Capture fichier dessin impossible {file_path}: {exc}")
        payload["dirs"][dirname] = entries
    return payload


def restore_reference_preserve_payload(payload: dict[str, Any] | None, target_dir: Path | None = None) -> dict[str, Any]:
    """Réinjecte le référentiel capturé dans une nouvelle base vide."""
    if not payload:
        return {"files": 0, "dirs": 0, "reference_rows": 0, "model_prices": 0}
    target = Path(target_dir or DATA_DIR).expanduser().resolve()
    target.mkdir(parents=True, exist_ok=True)
    restored_files = 0
    restored_dirs = 0
    for name, data in (payload.get("files") or {}).items():
        try:
            if isinstance(data, str):
                # Compatibilité éventuelle si un futur appel sérialise en texte.
                data = data.encode("utf-8")
            dest = target / name
            dest.parent.mkdir(parents=True, exist_ok=True)
            dest.write_bytes(data)
            restored_files += 1
        except Exception as exc:
            safe_log(f"Restauration fichier référentiel impossible {name}: {exc}")
    for dirname, entries in (payload.get("dirs") or {}).items():
        dest_root = target / dirname
        try:
            dest_root.mkdir(parents=True, exist_ok=True)
        except Exception as exc:
            safe_log(f"Création dossier référentiel impossible {dest_root}: {exc}")
            continue
        for rel, data in (entries or {}).items():
            try:
                dest = dest_root / str(rel)
                dest.parent.mkdir(parents=True, exist_ok=True)
                dest.write_bytes(data)
                restored_dirs += 1
            except Exception as exc:
                safe_log(f"Restauration image référentiel impossible {dirname}/{rel}: {exc}")
    tables = payload.get("tables") or {}
    restored_reference_rows = 0
    restored_model_prices = 0
    target_db = target / "stock_assets.db"
    try:
        conn = sqlite3.connect(target_db)
        try:
            conn.execute(
                """
                CREATE TABLE IF NOT EXISTS reference_rows (
                    sheet_name TEXT NOT NULL,
                    row_id INTEGER NOT NULL,
                    data_json TEXT NOT NULL,
                    created_at TEXT NOT NULL,
                    updated_at TEXT NOT NULL,
                    PRIMARY KEY(sheet_name, row_id)
                )
                """
            )
            conn.execute("CREATE INDEX IF NOT EXISTS idx_reference_rows_sheet ON reference_rows(sheet_name)")
            conn.execute(
                """
                CREATE TABLE IF NOT EXISTS model_prices (
                    model_id INTEGER PRIMARY KEY,
                    default_price_eur REAL,
                    updated_at TEXT NOT NULL
                )
                """
            )
            conn.execute("DELETE FROM reference_rows")
            conn.execute("DELETE FROM model_prices")
            for row in tables.get("reference_rows") or []:
                conn.execute(
                    """
                    INSERT OR REPLACE INTO reference_rows(sheet_name, row_id, data_json, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?)
                    """,
                    (
                        row.get("sheet_name"),
                        int(row.get("row_id") or 0),
                        row.get("data_json") or "{}",
                        row.get("created_at") or now_iso(),
                        row.get("updated_at") or now_iso(),
                    ),
                )
                restored_reference_rows += 1
            for row in tables.get("model_prices") or []:
                conn.execute(
                    """
                    INSERT OR REPLACE INTO model_prices(model_id, default_price_eur, updated_at)
                    VALUES (?, ?, ?)
                    """,
                    (
                        int(row.get("model_id") or 0),
                        row.get("default_price_eur"),
                        row.get("updated_at") or now_iso(),
                    ),
                )
                restored_model_prices += 1
            conn.commit()
        finally:
            conn.close()
    except Exception as exc:
        safe_log(f"Restauration référentiel SQLite impossible : {exc}")
    return {
        "files": restored_files,
        "dirs": restored_dirs,
        "reference_rows": restored_reference_rows,
        "model_prices": restored_model_prices,
    }


def reset_application_data_for_new_base(reference_payload: dict[str, Any] | None = None) -> Path | None:
    """Archive les fichiers actifs du dossier sélectionné puis recrée une base vide.

    Les sauvegardes déjà présentes restent conservées. On ne supprime jamais le dossier
    de travail : seuls les fichiers actifs déjà présents sont déplacés dans archives.
    """
    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    paths_to_archive = [
        DB_PATH,
        DATA_DIR / "stock_assets.db-wal",
        DATA_DIR / "stock_assets.db-shm",
        EXCEL_PATH,
        LOG_PATH,
        UI_SETTINGS_PATH,
        DELETED_STATUS_VALUES_PATH,
        UPDATE_HISTORY_PATH,
    ]
    existing_paths = [path for path in paths_to_archive if path.exists()]
    target_dir: Path | None = None
    if existing_paths:
        target_dir = ARCHIVE_DIR / f"ancienne_base_{stamp}"
        target_dir.mkdir(parents=True, exist_ok=True)
        for path in existing_paths:
            shutil.move(str(path), str(target_dir / path.name))
    clear_excel_read_cache()
    ensure_reference_workbook()
    init_db()
    restore_reference_preserve_payload(reference_payload, DATA_DIR)
    clear_excel_read_cache()
    # Les statuts et motifs par défaut sont ajoutés seulement s'ils manquent.
    ensure_status_defaults()
    ensure_return_reason_defaults()
    ensure_superadmin_user()
    return target_dir


def archive_active_database(reason: str = "ancienne_base") -> Path:
    """Archive les fichiers actifs sans toucher aux sauvegardes existantes."""
    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    target_dir = ARCHIVE_DIR / f"{reason}_{stamp}"
    target_dir.mkdir(parents=True, exist_ok=True)
    for path in [DB_PATH, DATA_DIR / "stock_assets.db-wal", DATA_DIR / "stock_assets.db-shm", EXCEL_PATH, LOG_PATH, UI_SETTINGS_PATH]:
        if path.exists():
            shutil.move(str(path), str(target_dir / path.name))
    for dirname in ["qr_codes", "product_images"]:
        src = DATA_DIR / dirname
        if src.exists():
            shutil.move(str(src), str(target_dir / dirname))
    QR_DIR.mkdir(exist_ok=True)
    PRODUCT_IMAGES_DIR.mkdir(exist_ok=True)
    clear_excel_read_cache()
    return target_dir


def score_excel_file(path: Path) -> int:
    try:
        wb = load_workbook(path, read_only=True, data_only=True)
        score = path.stat().st_size // 1024
        for ws in wb.worksheets:
            score += 50
            # compte rapide des cellules non vides sans tout bloquer trop longtemps
            checked = 0
            for row in ws.iter_rows(max_row=min(ws.max_row or 1, 400), values_only=True):
                checked += 1
                score += sum(1 for v in row if v not in (None, ""))
                if checked >= 400:
                    break
        try:
            wb.close()
        except Exception:
            pass
        return int(score)
    except Exception:
        return -1


def score_json_file(path: Path) -> int:
    try:
        return int(path.stat().st_size + path.stat().st_mtime // 100)
    except Exception:
        return -1


def select_best_data_files_in_base_folder(base_dir: Path) -> dict[str, Any]:
    """Dans un dossier contenant plusieurs fichiers, sélectionne les plus riches.

    Objectif : si l'utilisateur choisit un dossier avec plusieurs Excel/configs, on garde
    automatiquement le tableur qui contient le plus d'informations et les configs les plus renseignées.
    """
    actions: list[str] = []
    base_dir.mkdir(parents=True, exist_ok=True)

    excel_files = [p for p in base_dir.glob('*.xlsx') if p.is_file() and not p.name.startswith('~$')]
    if excel_files:
        best_excel = max(excel_files, key=score_excel_file)
        target_excel = base_dir / 'referentiel_stock.xlsx'
        if best_excel.resolve() != target_excel.resolve():
            try:
                if target_excel.exists():
                    archive = base_dir / 'archives' / f"referentiel_stock_remplace_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
                    archive.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(target_excel, archive)
                shutil.copy2(best_excel, target_excel)
                actions.append(f"Excel retenu : {best_excel.name}")
            except Exception as exc:
                safe_log(f"Sélection Excel riche impossible : {exc}")

    db_files = [p for p in base_dir.glob('*.db') if p.is_file()]
    if db_files:
        best_db = max(db_files, key=lambda p: p.stat().st_size if p.exists() else 0)
        target_db = base_dir / 'stock_assets.db'
        if best_db.resolve() != target_db.resolve():
            try:
                if target_db.exists():
                    archive = base_dir / 'archives' / f"stock_assets_remplace_{datetime.now().strftime('%Y%m%d_%H%M%S')}.db"
                    archive.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(target_db, archive)
                shutil.copy2(best_db, target_db)
                actions.append(f"SQLite retenue : {best_db.name}")
            except Exception as exc:
                safe_log(f"Sélection SQLite riche impossible : {exc}")

    config_prefixes = ['ui_settings', 'material_connection_profiles', 'drawing_layout_settings', 'connection_schemas', 'deleted_status_values']
    for prefix in config_prefixes:
        candidates = [p for p in base_dir.glob(f'{prefix}*.json') if p.is_file()]
        if not candidates:
            continue
        best = max(candidates, key=score_json_file)
        target = base_dir / f'{prefix}.json'
        if best.resolve() != target.resolve():
            try:
                shutil.copy2(best, target)
                actions.append(f"Configuration retenue : {best.name}")
            except Exception as exc:
                safe_log(f"Sélection config {prefix} impossible : {exc}")
    return {"actions": actions}


def resolve_existing_base_path(raw_path: str | None) -> Path | None:
    if not raw_path or not raw_path.strip():
        return None
    cleaned = raw_path.strip().strip('"')
    p = Path(cleaned).expanduser()
    if not p.exists():
        raise HTTPException(status_code=400, detail=f"Chemin introuvable : {p}")
    if p.is_file():
        p = p.parent
    # L'utilisateur peut donner le dossier parent ou directement le dossier NexVandal.
    candidate = p / "NexVandal"
    if candidate.exists() and candidate.is_dir():
        return candidate
    return p


def is_file_locked_error(exc: BaseException) -> bool:
    """Détecte les erreurs Windows typiques quand Excel ou l'ancien EXE garde un fichier ouvert."""
    winerror = getattr(exc, "winerror", None)
    if winerror in {32, 33}:
        return True
    if isinstance(exc, PermissionError):
        return True
    text = str(exc).lower()
    return (
        "being used by another process" in text
        or "utilisé par un autre processus" in text
        or "winerror 32" in text
        or "verrouillé" in text
        or ("ouvert" in text and "excel" in text)
    )


def paths_are_same(left: Path, right: Path) -> bool:
    try:
        return left.resolve().samefile(right.resolve())
    except Exception:
        try:
            return str(left.resolve()).lower() == str(right.resolve()).lower()
        except Exception:
            return str(left).lower() == str(right).lower()


def archive_target_before_import(target: Path) -> str | None:
    """Archive l'ancienne base locale avant d'importer une base externe."""
    known_files = ["stock_assets.db", "stock_assets.db-wal", "stock_assets.db-shm", "referentiel_stock.xlsx", "activity_log.jsonl", "ui_settings.json"]
    known_dirs = ["qr_codes", "product_images"]
    existing = [target / name for name in known_files if (target / name).exists()]
    existing += [target / name for name in known_dirs if (target / name).exists()]
    if not existing:
        return None

    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    archive_dir = APP_DIR / "archives_import" / f"base_avant_import_{stamp}"
    archive_dir.mkdir(parents=True, exist_ok=True)
    for path in existing:
        try:
            shutil.move(str(path), str(archive_dir / path.name))
        except Exception as exc:
            safe_log(f"Archivage import impossible pour {path.name} : {exc}")
    return str(archive_dir)


def copy_sqlite_database_resilient(src_db: Path, dst_db: Path, warnings: list[str]) -> bool:
    """Copie la base SQLite même si l'ancien programme est encore ouvert, via l'API backup SQLite."""
    if not src_db.exists():
        return False
    dst_db.parent.mkdir(parents=True, exist_ok=True)
    dst_db.unlink(missing_ok=True)
    try:
        src_uri = src_db.resolve().as_uri() + "?mode=ro"
        with sqlite3.connect(src_uri, uri=True, timeout=15) as source, sqlite3.connect(dst_db, timeout=15) as dest:
            source.execute("PRAGMA busy_timeout=15000")
            source.backup(dest)
        return True
    except Exception as exc:
        warnings.append(f"Copie SQLite par backup indisponible, tentative de copie fichier : {exc}")
        try:
            shutil.copy2(src_db, dst_db)
            return True
        except Exception as copy_exc:
            raise HTTPException(status_code=423 if is_file_locked_error(copy_exc) else 500, detail=f"Impossible de copier l'ancienne base SQLite : {copy_exc}") from copy_exc


def clone_excel_values(src_excel: Path, dst_excel: Path) -> None:
    """Reconstruit un fichier Excel de travail à partir des valeurs de l'ancien classeur."""
    src_wb = load_workbook(src_excel, read_only=True, data_only=False)
    try:
        dst_wb = XLWorkbook()
        default_ws = dst_wb.active
        dst_wb.remove(default_ws)
        for src_ws in src_wb.worksheets:
            dst_ws = dst_wb.create_sheet(title=str(src_ws.title)[:31])
            for row in src_ws.iter_rows(values_only=True):
                dst_ws.append(list(row))
        dst_excel.parent.mkdir(parents=True, exist_ok=True)
        dst_wb.save(dst_excel)
    finally:
        try:
            src_wb.close()
        except Exception:
            pass


def copy_excel_workbook_resilient(src_excel: Path, dst_excel: Path, warnings: list[str]) -> bool:
    """Copie referentiel_stock.xlsx sans bloquer la récupération si l'ancien fichier est verrouillé."""
    if not src_excel.exists():
        return False
    dst_excel.parent.mkdir(parents=True, exist_ok=True)
    dst_excel.unlink(missing_ok=True)
    try:
        shutil.copy2(src_excel, dst_excel)
        return True
    except Exception as exc:
        warnings.append(f"Copie directe du référentiel Excel impossible : {exc}")
        try:
            clone_excel_values(src_excel, dst_excel)
            warnings.append("Référentiel Excel recréé depuis une lecture seule, car l'ancien fichier était verrouillé.")
            return True
        except Exception as clone_exc:
            warnings.append(f"Ancien référentiel Excel verrouillé ou illisible : {clone_exc}")
            return False


def copy_directory_resilient(src_dir: Path, dst_dir: Path, warnings: list[str]) -> bool:
    if not src_dir.exists() or not src_dir.is_dir():
        return False
    try:
        shutil.copytree(src_dir, dst_dir, dirs_exist_ok=True)
        return True
    except Exception as exc:
        warnings.append(f"Copie du dossier {src_dir.name} partielle ou impossible : {exc}")
        return False


def backup_active_data_before_update(backup_dir: Path) -> dict[str, Any]:
    """Sauvegarde obligatoire et vérifiée avant toute mise à jour/build.

    Cette sauvegarde est volontairement séparée des sauvegardes automatiques :
    elle se lance immédiatement au moment du build et elle bloque la mise à jour
    si la base principale ou les fichiers critiques ne peuvent pas être copiés.
    """
    ensure_data_directories()
    data_backup_dir = backup_dir / "NexVandal"
    data_backup_dir.mkdir(parents=True, exist_ok=True)
    copied: list[str] = []
    copied_dirs: list[str] = []
    warnings: list[str] = []
    errors: list[str] = []

    # Termine les écritures SQLite/WAL autant que possible avant la copie.
    try:
        with db() as conn:
            conn.execute("PRAGMA wal_checkpoint(FULL)")
    except Exception as exc:
        warnings.append(f"Checkpoint SQLite non bloquant impossible : {exc}")

    critical_files: list[tuple[Path, str, bool]] = [
        (DB_PATH, "stock_assets.db", True),
        (DATA_DIR / "stock_assets.db-wal", "stock_assets.db-wal", False),
        (DATA_DIR / "stock_assets.db-shm", "stock_assets.db-shm", False),
        (EXCEL_PATH, "referentiel_stock.xlsx", False),
        (LOG_PATH, "activity_log.jsonl", False),
        (UI_SETTINGS_PATH, "ui_settings.json", False),
        (ACTIVE_DATA_CONFIG_PATH, ACTIVE_DATA_CONFIG_PATH.name, False),
        (DELETED_STATUS_VALUES_PATH, "deleted_status_values.json", False),
        (UPDATE_HISTORY_PATH, "update_history.jsonl", False),
        (MATERIAL_CONNECTION_PROFILES_PATH, "material_connection_profiles.json", False),
        (DRAWING_LAYOUT_SETTINGS_PATH, "drawing_layout_settings.json", False),
        (CONNECTION_SCHEMAS_PATH, "connection_schemas.json", False),
    ]

    for path, target_name, required in critical_files:
        if not path.exists():
            if required:
                errors.append(f"Fichier critique absent : {path}")
            continue
        try:
            target = data_backup_dir / target_name
            if path == DB_PATH:
                ok = copy_sqlite_database_resilient(path, target, warnings)
                if not ok:
                    errors.append("Copie vérifiée de la base SQLite impossible.")
                    continue
            elif path == EXCEL_PATH:
                ok = copy_excel_workbook_resilient(path, target, warnings)
                if not ok:
                    warnings.append("Copie du fichier Excel non vérifiée.")
                    continue
            else:
                shutil.copy2(path, target)
            if target.exists() and target.stat().st_size >= 0:
                copied.append(target_name)
            else:
                errors.append(f"Sauvegarde non vérifiable pour {target_name}")
        except Exception as exc:
            msg = f"Copie de {target_name} impossible : {exc}"
            if required:
                errors.append(msg)
            else:
                warnings.append(msg)

    important_dirs = [
        QR_DIR,
        PRODUCT_IMAGES_DIR,
        DOCUMENT_TEMPLATES_DIR,
        GENERATED_DOCUMENTS_DIR,
        CONNECTION_SCHEMA_IMAGES_DIR,
        CONNECTION_EQUIPMENT_IMAGES_DIR,
        MATERIAL_CONNECTION_IMAGES_DIR,
        DRAWING_LAYOUT_IMAGES_DIR,
        DATA_DIR / "documents_generes",
    ]

    for src_dir in important_dirs:
        try:
            if not src_dir.exists() or not src_dir.is_dir():
                continue
            target_dir = data_backup_dir / src_dir.name
            shutil.copytree(src_dir, target_dir, dirs_exist_ok=True)
            copied_dirs.append(src_dir.name)
        except Exception as exc:
            warnings.append(f"Copie du dossier {src_dir.name} impossible : {exc}")

    meta = {
        "status": "failed" if errors else "ok",
        "saved_at": now_iso(),
        "active_data_folder": str(DATA_DIR),
        "database_path": str(DB_PATH),
        "copied": copied,
        "copied_dirs": copied_dirs,
        "warnings": warnings,
        "errors": errors,
        "mandatory_before_update": True,
    }
    try:
        (data_backup_dir / "sauvegarde_obligatoire_avant_update.json").write_text(json.dumps(meta, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        errors.append(f"Écriture du fichier de contrôle impossible : {exc}")

    if DB_PATH.exists():
        db_copy = data_backup_dir / "stock_assets.db"
        if not db_copy.exists() or db_copy.stat().st_size <= 0:
            errors.append("Base SQLite non sauvegardée ou sauvegarde vide.")

    if errors:
        safe_log("Sauvegarde obligatoire avant mise à jour échouée : " + " | ".join(errors))
        raise HTTPException(
            status_code=409,
            detail="Mise à jour annulée : sauvegarde de sécurité impossible. " + " | ".join(errors),
        )

    return {"status": "ok", "folder": str(data_backup_dir), "files": copied, "dirs": copied_dirs, "warnings": warnings}




def import_existing_base_from_path(raw_path: str | None) -> dict[str, Any]:
    """Active l'ancienne base sélectionnée comme dossier de travail principal.

    Depuis la v2.10.26, le dossier choisi pendant la récupération au lancement
    n'est plus copié vers le dossier de l'application : il devient directement
    le dossier utilisé pour la base SQLite, l'Excel, les sauvegardes, les QR codes
    et la synchronisation automatique.
    """
    global AUTO_SYNC_SUSPENDED
    AUTO_SYNC_SUSPENDED = True
    try:
        return _import_existing_base_from_path_locked(raw_path)
    finally:
        AUTO_SYNC_SUSPENDED = False


def _import_existing_base_from_path_locked(raw_path: str | None) -> dict[str, Any]:
    src = resolve_existing_base_path(raw_path)
    if src is None:
        src = DATA_DIR
    src = Path(src).expanduser().resolve()

    known_files = [
        "stock_assets.db",
        "stock_assets.db-wal",
        "stock_assets.db-shm",
        "referentiel_stock.xlsx",
        "activity_log.jsonl",
        "ui_settings.json",
        "deleted_status_values.json",
        "update_history.jsonl",
    ]
    known_dirs = ["qr_codes", "product_images", "backups", "archives"]
    found = [name for name in known_files if (src / name).exists()]
    found_dirs = [name for name in known_dirs if (src / name).exists()]
    if not found and not found_dirs:
        raise HTTPException(
            status_code=400,
            detail=(
                "Le chemin indiqué ne contient pas de base reconnue. "
                "Sélectionne le dossier NexVandal de ton ancienne installation, ou un dossier contenant "
                "stock_assets.db / referentiel_stock.xlsx. "
                f"Chemin reçu : {src}"
            ),
        )

    try:
        src.mkdir(parents=True, exist_ok=True)
        probe = src / ".clyo_write_test.tmp"
        probe.write_text("ok", encoding="utf-8")
        probe.unlink(missing_ok=True)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Le dossier sélectionné n'est pas accessible en écriture : {exc}") from exc

    switch_active_data_dir(src)
    clear_excel_read_cache()
    ensure_data_directories()

    files = found + [name + "/" for name in found_dirs]
    message = "Dossier sélectionné activé comme dossier principal de travail, sauvegarde et synchronisation."
    try:
        append_update_history_event({
            "event": "use_existing_base_direct",
            "version": APP_VERSION,
            "target_folder": str(DATA_DIR),
            "source_folder": str(src),
            "details": "Ancienne base utilisée directement comme dossier actif après mise à jour.",
        })
    except Exception as exc:
        safe_log(f"Historique récupération base impossible : {exc}")

    return {
        "imported": False,
        "used_directly": True,
        "source": str(src),
        "active_data_folder": str(DATA_DIR),
        "files": files,
        "warnings": [],
        "archived_previous_base": None,
        "message": message,
    }

def browse_existing_base_folder() -> dict[str, Any]:
    """Ouvre une fenêtre native Windows pour choisir l'ancienne base.

    Le navigateur ne peut pas fournir un chemin Windows fiable pour des raisons
    de sécurité. Comme l'application tourne localement, on ouvre donc la boîte
    de dialogue côté application puis on renvoie le chemin sélectionné au site.
    """
    try:
        import tkinter as tk
        from tkinter import filedialog
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Sélection de dossier indisponible : {exc}")

    try:
        root = tk.Tk()
        root.withdraw()
        root.attributes("-topmost", True)
        selected = filedialog.askdirectory(
            title="Sélectionner l'ancien dossier NexVandal ou son dossier parent",
            initialdir=str(Path.home()),
            mustexist=True,
        )
        root.destroy()
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Impossible d'ouvrir la sélection de dossier : {exc}")

    if not selected:
        return {"selected": False, "path": None, "valid": False, "message": "Sélection annulée."}

    resolved = resolve_existing_base_path(selected)
    if resolved is None:
        return {"selected": True, "path": selected, "valid": False, "message": "Aucun dossier sélectionné."}

    markers = ["stock_assets.db", "referentiel_stock.xlsx", "activity_log.jsonl", "qr_codes", "product_images"]
    found = [name for name in markers if (resolved / name).exists()]
    if not found:
        return {
            "selected": True,
            "path": str(resolved),
            "valid": False,
            "message": f"Le dossier choisi ne contient pas de base reconnue. Sélectionne le dossier NexVandal ou son dossier parent. Chemin contrôlé : {resolved}",
        }

    return {
        "selected": True,
        "path": str(resolved),
        "valid": True,
        "found": found,
        "message": "Base reconnue. Ce dossier deviendra le dossier principal de travail, sauvegarde et synchronisation.",
    }


def resolve_new_base_path(raw_path: str | None) -> Path:
    """Retourne le dossier exact qui deviendra le dossier de travail de la nouvelle base.

    V8.0.6 : l'utilisateur choisit un emplacement parent, puis l'application
    crée/réutilise automatiquement un sous-dossier clyoStock pour éviter de
    mélanger les fichiers de base avec d'autres documents du dossier choisi.
    Si l'utilisateur sélectionne déjà un dossier nommé clyoStock, on l'utilise
    directement pour éviter de créer clyoStock/clyoStock.
    """
    if not raw_path or not raw_path.strip():
        raise HTTPException(status_code=400, detail="Sélectionne le dossier où la nouvelle base doit être sauvegardée.")
    cleaned = raw_path.strip().strip('"')
    selected = Path(cleaned).expanduser()
    if selected.exists() and selected.is_file():
        raise HTTPException(status_code=400, detail="Le chemin sélectionné est un fichier. Sélectionne un dossier.")
    target = selected if selected.name.lower() == "clyostock" else (selected / "clyoStock")
    return target.resolve()


def validate_new_base_folder(target: Path) -> dict[str, Any]:
    """Vérifie que le dossier sélectionné peut devenir dossier actif de travail."""
    warnings: list[str] = []
    try:
        target.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Impossible de créer le dossier sélectionné : {exc}") from exc

    try:
        probe = target / ".clyo_write_test.tmp"
        probe.write_text("ok", encoding="utf-8")
        probe.unlink(missing_ok=True)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Le dossier sélectionné n'est pas accessible en écriture : {exc}") from exc

    markers = [
        "stock_assets.db",
        "stock_assets.db-wal",
        "stock_assets.db-shm",
        "referentiel_stock.xlsx",
        "activity_log.jsonl",
        "ui_settings.json",
        "deleted_status_values.json",
        "update_history.jsonl",
        "qr_codes",
        "product_images",
    ]
    existing = [name for name in markers if (target / name).exists()]
    if existing:
        warnings.append("Le dossier choisi contient déjà des fichiers de base CLYO. Ils seront archivés dans le sous-dossier archives avant la création de la nouvelle base.")
    return {"target": str(target), "existing": existing, "warnings": warnings}


def browse_new_base_folder() -> dict[str, Any]:
    """Ouvre une fenêtre native Windows pour choisir le dossier de la nouvelle base."""
    try:
        import tkinter as tk
        from tkinter import filedialog
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Sélection de dossier indisponible : {exc}")

    try:
        root = tk.Tk()
        root.withdraw()
        root.attributes("-topmost", True)
        selected = filedialog.askdirectory(
            title="Choisir l’emplacement parent de la nouvelle base CLYO",
            initialdir=str(Path.home()),
            mustexist=True,
        )
        root.destroy()
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Impossible d'ouvrir la sélection de dossier : {exc}")

    if not selected:
        return {"selected": False, "path": None, "valid": False, "message": "Sélection annulée."}

    target = resolve_new_base_path(selected)
    validation = validate_new_base_folder(target)
    message = "Dossier sélectionné. La base sera créée dans le sous-dossier clyoStock."
    if validation.get("existing"):
        message += " Des fichiers existants seront archivés avant création."
    return {
        "selected": True,
        "path": str(target),
        "valid": True,
        "message": message,
        **validation,
    }


def create_new_base_at_path(raw_path: str | None) -> dict[str, Any]:
    """Crée une base vide dans le dossier choisi et le définit comme dossier actif."""
    global AUTO_SYNC_SUSPENDED
    target = resolve_new_base_path(raw_path)
    validation = validate_new_base_folder(target)
    previous_data_folder = DATA_DIR
    reference_payload = capture_reference_preserve_payload(previous_data_folder)
    AUTO_SYNC_SUSPENDED = True
    try:
        switch_active_data_dir(target)
        archived_to = reset_application_data_for_new_base(reference_payload)
        preserved = restore_reference_preserve_payload(reference_payload, DATA_DIR)
        append_update_history_event({
            "event": "create_new_base",
            "version": APP_VERSION,
            "target_folder": str(DATA_DIR),
            "previous_data_folder": str(previous_data_folder),
            "archived_existing_files_to": str(archived_to) if archived_to else None,
            "referentiel_conserve": preserved,
        })
    finally:
        AUTO_SYNC_SUSPENDED = False

    return {
        "created": True,
        "previous_data_folder": str(previous_data_folder),
        "active_data_folder": str(DATA_DIR),
        "archived_existing_files_to": str(archived_to) if archived_to else None,
        "existing_files_archived": validation.get("existing", []),
        "referentiel_conserve": preserved if 'preserved' in locals() else None,
        "warnings": validation.get("warnings", []),
        "message": "Nouvelle base créée dans le dossier clyoStock. Ce dossier est maintenant le dossier de travail, de sauvegarde et de synchronisation. Le référentiel a été conservé.",
    }



# --- V8.1.0 : préparation base SQL / MariaDB ---
def load_sql_config_v810(include_password: bool = False) -> dict[str, Any]:
    try:
        if SQL_CONFIG_PATH_V810.exists():
            data = json.loads(SQL_CONFIG_PATH_V810.read_text(encoding="utf-8", errors="ignore") or "{}")
            if not isinstance(data, dict):
                data = {}
        else:
            data = {}
    except Exception:
        data = {}
    cfg = {
        "engine": str(data.get("engine") or "mariadb"),
        "host": str(data.get("host") or "127.0.0.1"),
        "port": int(data.get("port") or 3307),
        "database": str(data.get("database") or "clyo_stock_atelier_test"),
        "user": str(data.get("user") or "clyo_stock"),
        "enabled": bool(data.get("enabled", False)),
        "mode": str(data.get("mode") or "sql_test"),
        "saved_at": data.get("saved_at"),
        "last_test_at": data.get("last_test_at"),
        "last_test_ok": bool(data.get("last_test_ok", False)),
        "last_migration_at": data.get("last_migration_at"),
    }
    if include_password:
        cfg["password"] = str(data.get("password") or "")
    return cfg


def save_sql_config_v810(payload: dict[str, Any], *, test_ok: bool | None = None, enabled: bool | None = None) -> dict[str, Any]:
    cfg = load_sql_config_v810(include_password=True)
    for key in ["engine", "host", "database", "user", "password", "mode", "last_migration_at"]:
        if key in payload and payload.get(key) is not None:
            cfg[key] = str(payload.get(key) or "").strip()
    if "port" in payload:
        try:
            cfg["port"] = int(payload.get("port") or 3307)
        except Exception:
            cfg["port"] = 3307
    if enabled is not None:
        cfg["enabled"] = bool(enabled)
    if test_ok is not None:
        cfg["last_test_ok"] = bool(test_ok)
        cfg["last_test_at"] = now_iso()
    cfg["saved_at"] = now_iso()
    SQL_CONFIG_PATH_V810.parent.mkdir(parents=True, exist_ok=True)
    SQL_CONFIG_PATH_V810.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    public = dict(cfg)
    public.pop("password", None)
    public["config_path"] = str(SQL_CONFIG_PATH_V810)
    return public


def mark_sql_database_mode_v810() -> None:
    """Mémorise que le poste a été configuré pour SQL, sans supprimer la base locale/NAS."""
    try:
        current: dict[str, Any] = {}
        if ACTIVE_DATA_CONFIG_PATH.exists():
            raw = json.loads(ACTIVE_DATA_CONFIG_PATH.read_text(encoding="utf-8", errors="ignore") or "{}")
            if isinstance(raw, dict):
                current = raw
        current.update({
            "data_dir": str(DATA_DIR),
            "database_mode": "sql",
            "sql_config_path": str(SQL_CONFIG_PATH_V810),
            "updated_at": now_iso(),
        })
        ACTIVE_DATA_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
        ACTIVE_DATA_CONFIG_PATH.write_text(json.dumps(current, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        safe_log(f"Mode SQL non mémorisé : {exc}")


def _import_pymysql_v810():
    try:
        import pymysql  # type: ignore
        import pymysql.cursors  # type: ignore
        return pymysql
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail="Module PyMySQL absent. Relance le build GitHub Actions avec le requirements.txt V8.1.0, puis réinstalle l'EXE généré.",
        ) from exc


def sql_connect_v810(config: dict[str, Any] | None = None, *, with_database: bool = True):
    cfg = {**load_sql_config_v810(include_password=True), **(config or {})}
    host = str(cfg.get("host") or "127.0.0.1").strip()
    database = str(cfg.get("database") or "").strip()
    user = str(cfg.get("user") or "").strip()
    password = str(cfg.get("password") or "")
    try:
        port = int(cfg.get("port") or 3307)
    except Exception:
        port = 3307
    if not host or not user:
        raise HTTPException(status_code=400, detail="Serveur SQL et utilisateur obligatoires.")
    if with_database and not database:
        raise HTTPException(status_code=400, detail="Nom de base SQL obligatoire.")
    pymysql = _import_pymysql_v810()
    kwargs = {
        "host": host,
        "port": port,
        "user": user,
        "password": password,
        "charset": "utf8mb4",
        "cursorclass": pymysql.cursors.DictCursor,
        "connect_timeout": 8,
        "read_timeout": 20,
        "write_timeout": 20,
        "autocommit": False,
    }
    if with_database:
        kwargs["database"] = database
    try:
        return pymysql.connect(**kwargs)
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Connexion MariaDB impossible : {exc}") from exc


def normalize_sql_payload_v810(payload: dict[str, Any] | None) -> dict[str, Any]:
    payload = payload if isinstance(payload, dict) else {}
    try:
        port = int(payload.get("port") or 3307)
    except Exception:
        port = 3307
    return {
        "engine": "mariadb",
        "host": str(payload.get("host") or "127.0.0.1").strip(),
        "port": port,
        "database": str(payload.get("database") or "clyo_stock_atelier_test").strip(),
        "user": str(payload.get("user") or "clyo_stock").strip(),
        "password": str(payload.get("password") or ""),
        "mode": "sql_test",
    }


def test_sql_connection_v810(payload: dict[str, Any] | None = None) -> dict[str, Any]:
    cfg = normalize_sql_payload_v810(payload) if payload is not None else load_sql_config_v810(include_password=True)
    conn = sql_connect_v810(cfg, with_database=False)
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT VERSION() AS version")
            version_row = cur.fetchone() or {}
            db_name = str(cfg.get("database") or "").strip()
            if not db_name:
                raise HTTPException(status_code=400, detail="Nom de base SQL obligatoire.")
            safe_db = db_name.replace("`", "")
            cur.execute(f"CREATE DATABASE IF NOT EXISTS `{safe_db}` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci")
        conn.commit()
    finally:
        conn.close()
    conn = sql_connect_v810(cfg, with_database=True)
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT DATABASE() AS db_name, NOW() AS server_time")
            row = cur.fetchone() or {}
        conn.commit()
    finally:
        conn.close()
    public = save_sql_config_v810(cfg, test_ok=True, enabled=bool(payload.get("enabled", False)) if isinstance(payload, dict) else None)
    return {
        "status": "ok",
        "message": "Connexion MariaDB réussie.",
        "server_version": str(version_row.get("version") or ""),
        "database": public.get("database"),
        "host": public.get("host"),
        "port": public.get("port"),
        "server_time": str(row.get("server_time") or ""),
        "config": public,
    }


def mysql_type_from_sqlite_v810(declared: str, pk: bool = False) -> str:
    t = str(declared or "TEXT").upper()
    if pk:
        return "INT NOT NULL AUTO_INCREMENT PRIMARY KEY"
    if "INT" in t:
        return "INT"
    if any(x in t for x in ["REAL", "FLOA", "DOUB", "NUM", "DEC"]):
        return "DOUBLE"
    if "BLOB" in t:
        return "LONGBLOB"
    return "LONGTEXT"


def create_mysql_table_like_sqlite_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str) -> int:
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return 0
    cols = []
    for col in info:
        name = str(col["name"])
        pk = bool(col["pk"])
        cols.append(f"`{name}` {mysql_type_from_sqlite_v810(str(col['type'] or ''), pk)}")
    sql = f"CREATE TABLE IF NOT EXISTS `{table_name}` (" + ", ".join(cols) + ") ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci"
    with mysql_conn.cursor() as cur:
        cur.execute(sql)
    return len(info)


def migrate_sqlite_table_to_mysql_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str) -> dict[str, Any]:
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return {"table": table_name, "columns": 0, "rows": 0, "skipped": True}
    create_mysql_table_like_sqlite_v810(mysql_conn, sqlite_conn, table_name)
    col_names = [str(c["name"]) for c in info]
    rows = sqlite_conn.execute(f"SELECT * FROM {table_name}").fetchall()
    with mysql_conn.cursor() as cur:
        cur.execute(f"DELETE FROM `{table_name}`")
        if rows:
            placeholders = ", ".join(["%s"] * len(col_names))
            cols_sql = ", ".join(f"`{c}`" for c in col_names)
            insert_sql = f"INSERT INTO `{table_name}` ({cols_sql}) VALUES ({placeholders})"
            batch = [tuple(row[c] for c in col_names) for row in rows]
            cur.executemany(insert_sql, batch)
    return {"table": table_name, "columns": len(col_names), "rows": len(rows), "skipped": False}


def ensure_mysql_meta_tables_v810(mysql_conn: Any) -> None:
    with mysql_conn.cursor() as cur:
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS clyo_sql_meta (
                meta_key VARCHAR(120) NOT NULL PRIMARY KEY,
                meta_value LONGTEXT,
                updated_at VARCHAR(32)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
            """
        )


def migrate_current_database_to_sql_v810() -> dict[str, Any]:
    """Copie la base locale active vers MariaDB pour valider la migration.

    V8.1.0 reste volontairement non destructif : la base locale/NAS reste conservée.
    Cela permet de tester MariaDB avant de basculer définitivement le runtime.
    """
    init_db()
    try:
        migrate_excel_references_to_sqlite()
    except Exception as exc:
        safe_log(f"Migration référentiel avant SQL incomplète : {exc}")
    cfg = load_sql_config_v810(include_password=True)
    if not cfg.get("last_test_ok"):
        test_sql_connection_v810(cfg)
    mysql_conn = sql_connect_v810(cfg, with_database=True)
    migrated: list[dict[str, Any]] = []
    try:
        with sqlite3.connect(DB_PATH, timeout=20) as sqlite_conn:
            sqlite_conn.row_factory = sqlite3.Row
            table_rows = sqlite_conn.execute("SELECT name FROM sqlite_master WHERE type='table' ORDER BY name").fetchall()
            table_names = [str(r["name"]) for r in table_rows if not str(r["name"]).startswith("sqlite_")]
            for table_name in table_names:
                migrated.append(migrate_sqlite_table_to_mysql_v810(mysql_conn, sqlite_conn, table_name))
        ensure_mysql_meta_tables_v810(mysql_conn)
        with mysql_conn.cursor() as cur:
            cur.execute(
                "REPLACE INTO clyo_sql_meta(meta_key, meta_value, updated_at) VALUES(%s, %s, %s)",
                ("last_migration", json.dumps({"app_version": APP_VERSION, "source_db": str(DB_PATH), "tables": migrated}, ensure_ascii=False), now_iso()),
            )
        mysql_conn.commit()
    except Exception:
        mysql_conn.rollback()
        raise
    finally:
        mysql_conn.close()
    cfg_public = save_sql_config_v810({**cfg, "last_migration_at": now_iso()}, enabled=True)
    try:
        mark_sql_database_mode_v810()
        mark_setup_choice("use_sql")
        append_update_history_event({"event": "sql_migration_test", "version": APP_VERSION, "tables": migrated, "database": cfg_public.get("database")})
    except Exception:
        pass
    return {
        "status": "ok",
        "message": "Migration de test vers MariaDB terminée. La base locale/NAS est conservée.",
        "database": cfg_public.get("database"),
        "host": cfg_public.get("host"),
        "port": cfg_public.get("port"),
        "tables": migrated,
        "runtime_note": "V8.1.0 prépare et valide MariaDB. La bascule complète de toutes les requêtes sera activée après validation de la migration.",
    }

def version_sort_key(version: str) -> tuple[int, ...]:
    parts = re.findall(r"\d+", str(version or ""))
    return tuple(int(part) for part in parts) if parts else (0,)


def extract_release_notes_from_readme(path: Path) -> dict[str, Any] | None:
    match = re.match(r"README_v(.+)\.md$", path.name, flags=re.IGNORECASE)
    if not match:
        return None
    version = match.group(1).replace("_", ".")
    try:
        text = path.read_text(encoding="utf-8", errors="ignore")
    except Exception:
        return None
    lines = [line.rstrip() for line in text.splitlines()]
    title = next((line.lstrip("# ").strip() for line in lines if line.strip().startswith("#")), f"Version {version}")
    notes: list[str] = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith("- "):
            notes.append(stripped[2:].strip())
    if not notes:
        for line in lines:
            stripped = line.strip()
            if stripped and not stripped.startswith("#"):
                notes.append(stripped)
            if len(notes) >= 6:
                break
    return {
        "version": version,
        "title": title,
        "notes": notes[:20],
        "file": path.name,
        "modified_at": datetime.fromtimestamp(path.stat().st_mtime).isoformat(timespec="seconds") if path.exists() else None,
    }


def collect_release_notes() -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for path in APP_DIR.glob("README_v*.md"):
        item = extract_release_notes_from_readme(path)
        if item:
            items.append(item)
    items.sort(key=lambda item: version_sort_key(item.get("version", "")), reverse=True)
    return items


def append_update_history_event(event: dict[str, Any]) -> None:
    """Journal local des actions de mise à jour/base, conservé dans le dossier actif."""
    try:
        UPDATE_HISTORY_PATH.parent.mkdir(parents=True, exist_ok=True)
        payload = {"created_at": now_iso(), **event}
        with UPDATE_HISTORY_PATH.open("a", encoding="utf-8") as fh:
            fh.write(json.dumps(payload, ensure_ascii=False) + "\n")
    except Exception as exc:
        safe_log(f"Historique mise à jour non écrit : {exc}")


def read_update_history_events(limit: int = 100) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    try:
        if UPDATE_HISTORY_PATH.exists():
            for line in UPDATE_HISTORY_PATH.read_text(encoding="utf-8", errors="ignore").splitlines():
                line = line.strip()
                if not line:
                    continue
                try:
                    item = json.loads(line)
                    if isinstance(item, dict):
                        events.append(item)
                except Exception:
                    continue
    except Exception:
        pass
    events.sort(key=lambda item: str(item.get("created_at") or ""), reverse=True)
    return events[:limit]


def now_iso() -> str:
    return datetime.now().isoformat(timespec="seconds")


def safe_log(message: str) -> None:
    """Évite les erreurs de print quand l'EXE est lancé sans console Windows."""
    try:
        print(message)
    except Exception:
        pass


class DataIntegrityError(RuntimeError):
    """Erreur de validation Excel/SQLite journalisée sans suspension globale."""


AUTO_SYNC_BLOCKED = False
AUTO_SYNC_BLOCK_REASON = ""
AUTO_SYNC_BLOCKED_AT: str | None = None
AUTO_SYNC_BLOCK_STAGE = ""
AUTO_SYNC_LAST_OK_AT: str | None = None
AUTO_SYNC_LAST_ERROR = ""
AUTO_SYNC_STATE_LOCK = RLock()


def get_auto_sync_state() -> dict[str, Any]:
    with AUTO_SYNC_STATE_LOCK:
        return {
            "blocked": False,
            "reason": "",
            "blocked_at": None,
            "stage": AUTO_SYNC_BLOCK_STAGE,
            "last_ok_at": AUTO_SYNC_LAST_OK_AT,
            "last_error": AUTO_SYNC_LAST_ERROR,
            "suspended": AUTO_SYNC_SUSPENDED if "AUTO_SYNC_SUSPENDED" in globals() else False,
        }


def block_auto_sync(reason: str, stage: str = "integrity") -> None:
    """Compatibilité v2.10.20-23 : journalise l'erreur sans bloquer la synchro/sauvegarde."""
    global AUTO_SYNC_BLOCKED, AUTO_SYNC_BLOCK_REASON, AUTO_SYNC_BLOCKED_AT, AUTO_SYNC_BLOCK_STAGE, AUTO_SYNC_LAST_ERROR
    with AUTO_SYNC_STATE_LOCK:
        AUTO_SYNC_BLOCKED = False
        AUTO_SYNC_BLOCK_REASON = ""
        AUTO_SYNC_BLOCKED_AT = None
        AUTO_SYNC_BLOCK_STAGE = stage
        AUTO_SYNC_LAST_ERROR = str(reason or "Erreur synchronisation/sauvegarde")
    safe_log(f"Synchronisation/sauvegarde auto : erreur journalisée sans suspension : {AUTO_SYNC_LAST_ERROR}")


def unblock_auto_sync() -> None:
    global AUTO_SYNC_BLOCKED, AUTO_SYNC_BLOCK_REASON, AUTO_SYNC_BLOCKED_AT, AUTO_SYNC_BLOCK_STAGE, AUTO_SYNC_LAST_ERROR, AUTO_SYNC_LAST_OK_AT
    with AUTO_SYNC_STATE_LOCK:
        AUTO_SYNC_BLOCKED = False
        AUTO_SYNC_BLOCK_REASON = ""
        AUTO_SYNC_BLOCKED_AT = None
        AUTO_SYNC_BLOCK_STAGE = ""
        AUTO_SYNC_LAST_ERROR = ""
        AUTO_SYNC_LAST_OK_AT = now_iso()


def mark_auto_sync_ok() -> None:
    global AUTO_SYNC_LAST_OK_AT
    with AUTO_SYNC_STATE_LOCK:
        AUTO_SYNC_LAST_OK_AT = now_iso()


def is_data_corruption_error(exc: BaseException) -> bool:
    if isinstance(exc, DataIntegrityError):
        return True
    if isinstance(exc, zipfile.BadZipFile):
        return True
    if isinstance(exc, sqlite3.DatabaseError):
        text = str(exc).lower()
        return any(token in text for token in [
            "malformed", "not a database", "file is not a database", "database disk image",
            "database schema is corrupt", "file is encrypted", "disk i/o error",
        ])
    if isinstance(exc, HTTPException):
        detail = str(exc.detail).lower()
        return exc.status_code >= 500 and any(token in detail for token in [
            "corrompu", "corrompue", "en-têtes", "entêtes", "onglet", "xlsx", "référentiel excel",
        ])
    text = str(exc).lower()
    return any(token in text for token in [
        "file is not a zip file", "badzipfile", "corrompu", "corrompue",
        "database disk image is malformed", "file is not a database",
    ])


def validate_sqlite_integrity() -> None:
    if not DB_PATH.exists():
        return
    try:
        with sqlite3.connect(DB_PATH, timeout=5) as conn:
            conn.row_factory = sqlite3.Row
            row = conn.execute("PRAGMA quick_check").fetchone()
            result = str(row[0] if row else "").strip().lower()
            if result != "ok":
                raise DataIntegrityError(f"Base SQLite corrompue : PRAGMA quick_check = {result or 'vide'}")
            required_tables = {"assets", "customers", "app_users", "app_sessions", "app_logs", "asset_events", "model_prices"}
            existing = {str(r[0]) for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()}
            missing = sorted(required_tables - existing)
            if missing:
                raise DataIntegrityError("Base SQLite incomplète, table(s) manquante(s) : " + ", ".join(missing))
    except DataIntegrityError:
        raise
    except sqlite3.DatabaseError as exc:
        raise DataIntegrityError(f"Base SQLite illisible ou corrompue : {exc}") from exc


def clean_excel_headers(headers: list[Any]) -> list[str]:
    cleaned = [str(header or "").strip() for header in headers]
    while cleaned and not cleaned[-1]:
        cleaned.pop()
    return cleaned


def excel_headers_need_upgrade(sheet_name: str, current_headers: list[Any], expected_headers: list[str]) -> bool:
    """Détecte les anciens référentiels valides auxquels il manque seulement des colonnes ajoutées par une mise à jour."""
    current = clean_excel_headers(current_headers)
    expected = [str(header).strip() for header in expected_headers]
    if current == expected or not current:
        return False

    # V8.0.6 : tous les onglets du référentiel peuvent être migrés automatiquement
    # lorsqu'il s'agit uniquement d'un ancien ordre de colonnes ou de colonnes ajoutées
    # par une version plus récente.
    if sheet_name not in AUTO_REPAIRABLE_EXCEL_SHEETS:
        return False

    known_current = [header for header in current if header in expected]
    expected_projection = [header for header in expected if header in current]
    unknown_headers = [header for header in current if header and header not in expected]

    if known_current != expected_projection:
        return False
    # Les colonnes ajoutées manuellement sont acceptées seulement si elles sont à droite des colonnes CLYO connues.
    if unknown_headers:
        last_known_index = max((current.index(header) for header in known_current), default=-1)
        if any(current.index(header) < last_known_index for header in unknown_headers):
            return False
    return any(header not in current for header in expected)


def excel_headers_match_or_upgradeable(sheet_name: str, current_headers: list[Any], expected_headers: list[str]) -> bool:
    current = clean_excel_headers(current_headers)
    expected = [str(header).strip() for header in expected_headers]
    return current[: len(expected)] == expected or excel_headers_need_upgrade(sheet_name, current, expected)


def excel_integrity_signature() -> tuple[Any, ...]:
    def file_signature(path: Path) -> tuple[Any, ...]:
        try:
            resolved = str(path.resolve())
        except Exception:
            resolved = str(path)
        try:
            stat = path.stat()
            return (resolved, True, stat.st_size, stat.st_mtime_ns)
        except FileNotFoundError:
            return (resolved, False, 0, 0)
    return (file_signature(DB_PATH), file_signature(EXCEL_PATH))


def validate_excel_integrity() -> None:
    """Contrôle Excel en réparant les anciens schémas migrables avant blocage."""
    if not EXCEL_PATH.exists():
        return
    last_bad_zip: zipfile.BadZipFile | None = None
    with excel_lock:
        for attempt in range(3):
            try:
                wb = load_workbook(EXCEL_PATH)
                try:
                    changed, _actions = repair_excel_schema_in_workbook(wb, strict_reference_headers=True)
                    if changed:
                        backup_excel_before_schema_repair("validation_schema_excel")
                        save_reference_workbook(wb)
                    else:
                        try:
                            wb.close()
                        except Exception:
                            pass
                except Exception:
                    try:
                        wb.close()
                    except Exception:
                        pass
                    raise

                wb_ro = load_workbook(EXCEL_PATH, read_only=True, data_only=True)
                try:
                    for sheet_name, expected in EXCEL_SCHEMAS.items():
                        if sheet_name not in wb_ro.sheetnames:
                            raise DataIntegrityError(f"Référentiel Excel corrompu : onglet manquant {sheet_name}")
                        ws = wb_ro[sheet_name]
                        headers = [normalize_excel_header(cell.value) for cell in next(ws.iter_rows(min_row=1, max_row=1))]
                        if not excel_headers_match_expected(headers, expected):
                            raise DataIntegrityError(
                                f"Référentiel Excel corrompu : en-têtes modifiés dans {sheet_name}. Attendu : {expected}. Trouvé : {clean_excel_headers(headers)}"
                            )
                finally:
                    try:
                        wb_ro.close()
                    except Exception:
                        pass
                return
            except DataIntegrityError:
                raise
            except PermissionError:
                raise
            except zipfile.BadZipFile as exc:
                last_bad_zip = exc
                if attempt < 2:
                    time.sleep(0.25)
                    continue
                recover_reference_workbook("xlsx_illisible_validation")
                return validate_excel_integrity()
            except Exception as exc:
                if is_file_locked_error(exc):
                    raise
                if is_excel_load_failure(exc):
                    recover_reference_workbook("xlsx_illisible_validation")
                    return validate_excel_integrity()
                raise DataIntegrityError(f"Référentiel Excel illisible : {exc}") from exc
    if last_bad_zip is not None:
        raise DataIntegrityError("Référentiel Excel corrompu : le fichier XLSX n'est pas lisible") from last_bad_zip


def validate_data_integrity(force: bool = False) -> None:
    global INTEGRITY_LAST_OK_SIGNATURE
    signature = excel_integrity_signature()
    with INTEGRITY_CACHE_LOCK:
        if not force and INTEGRITY_LAST_OK_SIGNATURE == signature:
            return
    validate_sqlite_integrity()
    validate_excel_integrity()
    signature = excel_integrity_signature()
    with INTEGRITY_CACHE_LOCK:
        INTEGRITY_LAST_OK_SIGNATURE = signature

def ensure_auto_operations_allowed(operation: str = "sync") -> None:
    """Depuis v2.10.24, aucune suspension globale n'est appliquée sur détection d'erreur."""
    return


def collapse_pair_duplicated_scan_value(value: str) -> str:
    """Corrige les scans où chaque caractère est reçu deux fois.

    Exemple : KKYY221155WW2200226600220033005588 -> KY215W20260203058.
    La correction ne s'applique que si toute la chaîne est composée de paires identiques,
    afin d'éviter de modifier une saisie manuelle ou un SN qui contient seulement quelques doublons réels.
    """
    raw = str(value or "")
    if len(raw) < 8 or len(raw) % 2 != 0:
        return raw
    if all(raw[i] == raw[i + 1] for i in range(0, len(raw), 2)):
        return "".join(raw[i] for i in range(0, len(raw), 2))
    return raw


def normalize_sn(sn: str) -> str:
    """Normalise le SN pour fiabiliser la recherche exacte.
    On conserve les caractères utiles comme / et -, mais on retire les espaces,
    les caractères invisibles et les suffixes clavier envoyés par certains lecteurs.
    """
    value = str(sn or "")
    value = re.sub(r"[\x00-\x1F\x7F\u200B\u200C\u200D\uFEFF]", "", value)
    value = re.sub(r"\s+", "", value.strip().upper())
    return collapse_pair_duplicated_scan_value(value)


def find_asset_id_by_scan_sn(conn: sqlite3.Connection, sn_norm: str) -> int | None:
    """Retrouve un matériel même si le lecteur a collé un ancien contenu autour du SN.
    Exemple : ancien champ + scan rapide = 123456 + SNREEL. On privilégie toujours
    la correspondance exacte, puis une correspondance par sous-chaîne longue.
    """
    clean = normalize_sn(sn_norm)
    if not clean:
        return None

    exact = conn.execute("SELECT id FROM assets WHERE serial_number_norm = ?", (clean,)).fetchone()
    if exact:
        return int(exact["id"])

    if len(clean) < 6:
        return None

    candidates: list[tuple[int, int]] = []
    rows = conn.execute(
        "SELECT id, serial_number_norm FROM assets WHERE serial_number_norm IS NOT NULL AND serial_number_norm <> ''"
    ).fetchall()
    for row in rows:
        stored = normalize_sn(row["serial_number_norm"])
        if len(stored) < 5:
            continue
        if clean == stored or clean.endswith(stored) or clean.startswith(stored) or stored in clean:
            candidates.append((len(stored), int(row["id"])))

    if not candidates:
        return None
    candidates.sort(reverse=True)
    return candidates[0][1]


def normalize_text(value: Any) -> str:
    """Normalise un libellé métier pour les comparaisons simples."""
    return re.sub(r"\s+", " ", str(value or "").strip().upper())


def canonical_category_label(value: Any) -> str:
    """Retourne un libellé canonique pour regrouper les catégories proches.

    Permet par exemple de fusionner automatiquement :
    - TIROIR CAISSE / TIRROIR CAISSE / DRAWER
    - IMPRIMANTE TICKET / PRINTER
    - POINT D'ACCES / ACCESS POINT
    """
    raw = str(value or "").strip()
    if not raw:
        return "Sans catégorie"
    normalized = unicodedata.normalize("NFD", raw)
    normalized = "".join(ch for ch in normalized if unicodedata.category(ch) != "Mn")
    normalized = re.sub(r"[^A-Z0-9]+", " ", normalized.upper()).strip()
    if any(token in normalized for token in ("TIROIR", "TIRROIR", "DRAWER")):
        return "Tiroir caisse"
    if "POINT" in normalized and "ACCES" in normalized:
        return "Point d'accès"
    if any(token in normalized for token in ("IMPRIMANTE", "TICKET", "PRINTER", "RECEIPT")):
        return "Imprimante ticket"
    if any(token in normalized for token in ("AFFICHEUR", "DISPLAY", "GLANCETRON")):
        return "Afficheur client"
    if any(token in normalized for token in ("BALANCE", "METTLER", "SCALE")):
        return "Balance"
    if "CAISSE" in normalized or normalized == "POS" or normalized.endswith(" POS") or normalized.startswith("POS "):
        return "Caisse"
    return raw


def build_image_query_from_parts(*parts: Any) -> str:
    cleaned: list[str] = []
    for part in parts:
        value = str(part or "").strip()
        if value and value.lower() not in {"none", "null", "non renseigné", "modèle supprimé"}:
            cleaned.append(value)
    return " ".join(cleaned).strip()


def google_image_search_url(query: str) -> str:
    return "https://www.google.com/search?tbm=isch&q=" + urllib.parse.quote_plus(query)


def product_thumbnail_url(query: str) -> str:
    # Image automatique via une URL de vignette de recherche.
    # Si le poste n'a pas Internet ou si le service bloque la miniature, le lien Google Images reste disponible.
    return "https://tse.mm.bing.net/th?q=" + urllib.parse.quote_plus(query) + "&w=360&h=260&c=7&rs=1&p=0"


def build_product_image_query(asset: dict[str, Any]) -> str:
    """Construit une recherche image priorisée sur le type et le modèle réel.

    On évite de mettre le numéro de série en priorité, car il donne souvent des
    résultats pauvres ou hors sujet. L'image doit surtout suivre : catégorie/type,
    marque et modèle. Le fournisseur et le SN ne servent qu'en dernier recours.
    """
    brand = asset.get("brand")
    model_name = asset.get("model_name")
    category = asset.get("category")
    query = build_image_query_from_parts(category, brand, model_name, "photo produit")
    if query.strip() == "photo produit":
        query = build_image_query_from_parts(brand, model_name, "photo produit")
    if not query:
        query = build_image_query_from_parts(asset.get("supplier_name"), asset.get("serial_number_raw"), "photo matériel")
    if not query:
        query = build_image_query_from_parts(asset.get("serial_number_raw"), asset.get("asset_code"))
    return query


def enrich_asset_image_fields(asset: dict[str, Any]) -> dict[str, Any]:
    query = build_product_image_query(asset)
    search_url = google_image_search_url(query) if query else ""
    image_url = asset.get("image_url") or (product_thumbnail_url(query) if query else "")
    return {**asset, "image_url": image_url, "image_search_url": search_url, "image_query": query}


def empty_to_none(value: Any) -> Any:
    if value == "":
        return None
    return value


def validate_status(status: str) -> str:
    status = (status or "").strip().lower()
    if status == "perdu":
        status = "endommage"
    options = get_status_options_map()
    if status not in options:
        allowed = ", ".join(options.keys())
        raise HTTPException(status_code=400, detail=f"Statut invalide. Statuts acceptés : {allowed}")
    return status


def validate_return_reason_value(value: str | None, *, required: bool = False) -> str | None:
    value = str(value or "").strip()
    if not value:
        if required:
            raise HTTPException(status_code=400, detail="Motif retour fournisseur obligatoire.")
        return None
    reasons = get_return_reasons_map()
    if value not in reasons:
        # On accepte aussi un libellé existant, puis on le convertit en code interne.
        lowered = value.lower()
        for reason_value, label in reasons.items():
            if str(label).strip().lower() == lowered:
                return reason_value
        allowed = ", ".join(reasons.values())
        raise HTTPException(status_code=400, detail=f"Motif retour fournisseur invalide. Motifs acceptés : {allowed}")
    return value


def is_caisse_category(category: str | None) -> bool:
    return normalize_text(category or "") == "CAISSE"


def build_return_supplier_client_name(supplier_name: str | None) -> str:
    return f"Retour fournisseur : {supplier_name or 'Fournisseur non renseigné'}"


def normalize_asset_assignment_fields(
    *,
    status: str,
    client_name: str | None,
    customer_id: int | None,
    sale_date: str | None,
    teamviewer_id: str | None,
    teamviewer_password: str | None,
    return_reason: str | None,
    supplier_name: str | None,
    category: str | None,
) -> dict[str, Any]:
    """Applique les règles métier de stock, client et retour fournisseur."""
    cleaned_client_name = str(client_name or "").strip() or None
    cleaned_teamviewer_id = str(teamviewer_id or "").strip() or None
    cleaned_teamviewer_password = str(teamviewer_password or "").strip() or None
    cleaned_return_reason = validate_return_reason_value(return_reason, required=(status == "retour_fournisseur"))

    if status == "en_stock":
        # Retour en stock : on supprime l'attribution client, mais on conserve les identifiants TeamViewer des caisses.
        cleaned_client_name = None
        customer_id = None
        sale_date = None
        if not is_caisse_category(category):
            cleaned_teamviewer_id = None
            cleaned_teamviewer_password = None
        cleaned_return_reason = None
    elif status == "retour_fournisseur":
        cleaned_client_name = build_return_supplier_client_name(supplier_name)
        customer_id = None
        sale_date = None
        cleaned_return_reason = validate_return_reason_value(return_reason, required=True)
    elif status == "abime":
        # Matériel irréparable / abîmé : il sort du parc client actif mais conserve sa traçabilité.
        cleaned_client_name = None
        customer_id = None
        sale_date = None
        cleaned_teamviewer_id = None
        cleaned_teamviewer_password = None
        cleaned_return_reason = None
    else:
        if status == "vendu" and not customer_id:
            raise HTTPException(status_code=400, detail="Client obligatoire : choisissez un client enregistré dans la liste avant d'enregistrer un matériel Vendu.")
        cleaned_return_reason = None

    if status == "vendu" and is_caisse_category(category):
        if not cleaned_teamviewer_id:
            raise HTTPException(status_code=400, detail="Matériel de type CAISSE : renseigne le numéro TeamViewer avant la vente au client.")
        if not cleaned_teamviewer_password:
            cleaned_teamviewer_password = "clyo1234!"

    return {
        "status": status,
        "client_name": cleaned_client_name,
        "customer_id": customer_id,
        "sale_date": sale_date,
        "teamviewer_id": cleaned_teamviewer_id,
        "teamviewer_password": cleaned_teamviewer_password,
        "return_reason": cleaned_return_reason,
    }


@contextmanager
def db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, timeout=10)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA busy_timeout=10000")
    conn.execute("PRAGMA foreign_keys=ON")
    try:
        yield conn
        conn.commit()
    finally:
        conn.close()


def row_to_dict(row: sqlite3.Row | None) -> dict[str, Any] | None:
    return dict(row) if row else None


def get_request_user_for_trace(request: Request | None) -> dict[str, Any] | None:
    if request is None:
        return None
    try:
        return get_request_user(request)
    except Exception:
        try:
            return get_request_user_optional(request)
        except Exception:
            return None


def insert_asset_event(
    conn: sqlite3.Connection,
    asset_id: int,
    event_type: str,
    details: str | None,
    created_at: str | None = None,
    request: Request | None = None,
    source: str | None = None,
    field_name: str | None = None,
    old_value: Any | None = None,
    new_value: Any | None = None,
    customer_id: int | None = None,
    customer_site_id: int | None = None,
) -> None:
    """Ajoute une ligne de traçabilité matériel, compatible avec les anciennes bases."""
    event_time = created_at or now_iso()
    user = get_request_user_for_trace(request)
    username = user.get("username") if isinstance(user, dict) else None
    role = user.get("role") if isinstance(user, dict) else None
    try:
        conn.execute(
            """
            INSERT INTO asset_events(
                asset_id, event_type, details, created_at,
                username, role, source, field_name, old_value, new_value, customer_id, customer_site_id
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                asset_id,
                event_type,
                details,
                event_time,
                username,
                role,
                source,
                field_name,
                None if old_value is None else str(old_value),
                None if new_value is None else str(new_value),
                customer_id,
                customer_site_id,
            ),
        )
    except sqlite3.OperationalError:
        conn.execute(
            "INSERT INTO asset_events(asset_id, event_type, details, created_at) VALUES (?, ?, ?, ?)",
            (asset_id, event_type, details, event_time),
        )


def init_db() -> None:
    """Base SQLite uniquement pour les matériels et l'historique.
    Les fournisseurs, modèles et règles sont dans referentiel_stock.xlsx.
    """
    with db() as conn:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS assets (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                asset_code TEXT NOT NULL UNIQUE,
                serial_number_raw TEXT NOT NULL,
                serial_number_norm TEXT NOT NULL UNIQUE,
                model_id INTEGER NOT NULL,
                supplier_id INTEGER,
                purchase_date TEXT,
                purchase_price_eur REAL,
                warranty_end_date TEXT,
                status TEXT NOT NULL DEFAULT 'en_stock',
                location TEXT,
                client_name TEXT,
                customer_id INTEGER,
                sale_date TEXT,
                teamviewer_id TEXT,
                teamviewer_password TEXT,
                return_reason TEXT,
                return_supplier_sent_at TEXT,
                return_supplier_back_at TEXT,
                damaged_reason TEXT,
                replacement_of_asset_id INTEGER,
                replaced_by_asset_id INTEGER,
                replacement_date TEXT,
                replacement_reason TEXT,
                image_url TEXT,
                image_local_path TEXT,
                notes TEXT,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            );

            CREATE TABLE IF NOT EXISTS customers (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                customer_code TEXT NOT NULL UNIQUE,
                name TEXT NOT NULL,
                company TEXT,
                email TEXT,
                phone TEXT,
                address TEXT,
                crm_url TEXT,
                preparateur TEXT,
                notes TEXT,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            );

            CREATE TABLE IF NOT EXISTS asset_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                asset_id INTEGER NOT NULL,
                event_type TEXT NOT NULL,
                details TEXT,
                created_at TEXT NOT NULL,
                username TEXT,
                role TEXT,
                source TEXT,
                field_name TEXT,
                old_value TEXT,
                new_value TEXT,
                customer_id INTEGER,
                customer_site_id INTEGER,
                FOREIGN KEY(asset_id) REFERENCES assets(id) ON DELETE CASCADE
            );

            CREATE TABLE IF NOT EXISTS app_users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT NOT NULL UNIQUE,
                password_salt TEXT NOT NULL,
                password_hash TEXT NOT NULL,
                role TEXT NOT NULL DEFAULT 'lecteur',
                is_admin INTEGER NOT NULL DEFAULT 0,
                birth_date TEXT,
                profile_photo_data_url TEXT,
                must_change_password INTEGER NOT NULL DEFAULT 0,
                created_at TEXT NOT NULL
            );

            CREATE TABLE IF NOT EXISTS app_sessions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                token_hash TEXT NOT NULL UNIQUE,
                user_id INTEGER NOT NULL,
                created_at TEXT NOT NULL,
                last_activity_at TEXT NOT NULL,
                expires_at TEXT NOT NULL,
                FOREIGN KEY(user_id) REFERENCES app_users(id) ON DELETE CASCADE
            );

            CREATE TABLE IF NOT EXISTS app_logs (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at TEXT NOT NULL,
                user_id INTEGER,
                username TEXT,
                role TEXT,
                action TEXT NOT NULL,
                target_type TEXT,
                target_id TEXT,
                details TEXT,
                ip TEXT,
                computer_name TEXT
            );

            CREATE TABLE IF NOT EXISTS model_prices (
                model_id INTEGER PRIMARY KEY,
                default_price_eur REAL,
                updated_at TEXT NOT NULL
            );
            """
        )



        conn.executescript(
            """
            PRAGMA journal_mode=WAL;
            PRAGMA synchronous=NORMAL;
            CREATE INDEX IF NOT EXISTS idx_assets_status ON assets(status);
            CREATE INDEX IF NOT EXISTS idx_assets_model_id ON assets(model_id);
            CREATE INDEX IF NOT EXISTS idx_assets_supplier_id ON assets(supplier_id);
            CREATE INDEX IF NOT EXISTS idx_assets_customer_id ON assets(customer_id);
            CREATE INDEX IF NOT EXISTS idx_assets_updated_at ON assets(updated_at);
            CREATE INDEX IF NOT EXISTS idx_customers_updated_at ON customers(updated_at);
            CREATE INDEX IF NOT EXISTS idx_app_logs_created_at ON app_logs(created_at);
            CREATE INDEX IF NOT EXISTS idx_app_sessions_token_hash ON app_sessions(token_hash);
            """
        )

        customer_columns = {row["name"] for row in conn.execute("PRAGMA table_info(customers)").fetchall()}
        if "crm_url" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN crm_url TEXT")
        if "preparateur" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN preparateur TEXT")
        if "sync_source" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN sync_source TEXT")
        if "sync_external_id" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN sync_external_id TEXT")
        if "sync_last_seen_at" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN sync_last_seen_at TEXT")
        if "sync_active" not in customer_columns:
            conn.execute("ALTER TABLE customers ADD COLUMN sync_active INTEGER NOT NULL DEFAULT 1")

        existing_columns = {row["name"] for row in conn.execute("PRAGMA table_info(assets)").fetchall()}
        if "purchase_price_eur" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN purchase_price_eur REAL")
        if "customer_id" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN customer_id INTEGER")
        if "sale_date" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN sale_date TEXT")
        if "teamviewer_id" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN teamviewer_id TEXT")
        if "teamviewer_password" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN teamviewer_password TEXT")
        if "return_reason" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN return_reason TEXT")
        if "image_url" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN image_url TEXT")
        if "image_local_path" not in existing_columns:
            conn.execute("ALTER TABLE assets ADD COLUMN image_local_path TEXT")

        asset_trace_extra_columns = {
            "return_supplier_sent_at": "TEXT",
            "return_supplier_back_at": "TEXT",
            "damaged_reason": "TEXT",
            "replacement_of_asset_id": "INTEGER",
            "replaced_by_asset_id": "INTEGER",
            "replacement_date": "TEXT",
            "replacement_reason": "TEXT",
        }
        for column_name, column_type in asset_trace_extra_columns.items():
            if column_name not in existing_columns:
                conn.execute(f"ALTER TABLE assets ADD COLUMN {column_name} {column_type}")

        log_columns = {row["name"] for row in conn.execute("PRAGMA table_info(app_logs)").fetchall()}
        if "computer_name" not in log_columns:
            conn.execute("ALTER TABLE app_logs ADD COLUMN computer_name TEXT")

        user_columns = {row["name"] for row in conn.execute("PRAGMA table_info(app_users)").fetchall()}
        if "birth_date" not in user_columns:
            conn.execute("ALTER TABLE app_users ADD COLUMN birth_date TEXT")
        if "profile_photo_data_url" not in user_columns:
            conn.execute("ALTER TABLE app_users ADD COLUMN profile_photo_data_url TEXT")
        if "must_change_password" not in user_columns:
            conn.execute("ALTER TABLE app_users ADD COLUMN must_change_password INTEGER NOT NULL DEFAULT 0")

        event_columns = {row["name"] for row in conn.execute("PRAGMA table_info(asset_events)").fetchall()}
        event_extra_columns = {
            "username": "TEXT",
            "role": "TEXT",
            "source": "TEXT",
            "field_name": "TEXT",
            "old_value": "TEXT",
            "new_value": "TEXT",
            "customer_id": "INTEGER",
            "customer_site_id": "INTEGER",
        }
        for column_name, column_type in event_extra_columns.items():
            if column_name not in event_columns:
                conn.execute(f"ALTER TABLE asset_events ADD COLUMN {column_name} {column_type}")


def style_sheet(ws: Any, table_name: str, max_col: int) -> None:
    header_fill = PatternFill("solid", fgColor="1F4E78")
    header_font = Font(bold=True, color="FFFFFF")
    for cell in ws[1]:
        cell.fill = header_fill
        cell.font = header_font
        cell.alignment = Alignment(horizontal="center", vertical="center")
    ws.freeze_panes = "A2"
    widths = {
        1: 8,
        2: 24,
        3: 24,
        4: 18,
        5: 18,
        6: 35,
        7: 24,
        8: 24,
    }
    for col_idx in range(1, max_col + 1):
        ws.column_dimensions[get_column_letter(col_idx)].width = widths.get(col_idx, 18)
    end_col = get_column_letter(max_col)
    end_row = max(ws.max_row, 2)
    if table_name not in ws.tables:
        tab = Table(displayName=table_name, ref=f"A1:{end_col}{end_row}")
        style = TableStyleInfo(name="TableStyleMedium2", showRowStripes=True, showColumnStripes=False)
        tab.tableStyleInfo = style
        ws.add_table(tab)


def refresh_table_ref(ws: Any) -> None:
    if not ws.tables:
        return
    max_col = ws.max_column
    max_row = max(ws.max_row, 2)
    ref = f"A1:{get_column_letter(max_col)}{max_row}"
    for table in ws.tables.values():
        table.ref = ref


def backup_excel_before_schema_repair(reason: str = "schema") -> Path | None:
    """Sauvegarde le référentiel avant réparation automatique des en-têtes."""
    try:
        if not EXCEL_PATH.exists():
            return None
        BACKUP_DIR.mkdir(parents=True, exist_ok=True)
        safe_reason = re.sub(r"[^a-zA-Z0-9_-]+", "_", reason or "schema").strip("_")[:60] or "schema"
        backup_path = BACKUP_DIR / f"referentiel_stock_avant_reparation_{safe_reason}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
        shutil.copy2(EXCEL_PATH, backup_path)
        return backup_path
    except Exception as exc:
        safe_log(f"Copie avant réparation Excel impossible : {exc}")
        return None


