def canonical_excel_header(sheet_name: str, header: Any) -> str:
    value = normalize_excel_header(header)
    if not value:
        return ""
    aliases = EXCEL_HEADER_ALIASES.get(sheet_name, {})
    return aliases.get(value, value)


def repair_generated_sheet_schema(ws: Any, sheet_name: str, table_name: str) -> bool:
    """Répare un onglet du référentiel sans supprimer les données utiles.

    Les colonnes attendues sont remises en premier et dans le bon ordre. Les colonnes
    inconnues sont conservées à droite pour ne pas perdre d'informations éventuelles.
    """
    expected = EXCEL_SCHEMAS[sheet_name]
    current_headers = [canonical_excel_header(sheet_name, cell.value) for cell in ws[1]] if ws.max_row >= 1 else []
    extra_headers: list[str] = []
    for header in current_headers:
        if header and header not in expected and header not in extra_headers:
            extra_headers.append(header)
    final_headers = expected + extra_headers

    if current_headers[: len(final_headers)] == final_headers:
        return False

    rows: list[dict[str, Any]] = []
    max_col = max(len(current_headers), ws.max_column)
    for raw_row in ws.iter_rows(min_row=2, max_col=max_col, values_only=True):
        if raw_row is None or all(value is None for value in raw_row):
            continue
        item: dict[str, Any] = {}
        for idx, header in enumerate(current_headers):
            if not header or idx >= len(raw_row):
                continue
            if header not in item or item.get(header) in (None, ""):
                item[header] = raw_row[idx]
        rows.append(item)

    try:
        ws.tables.clear()
    except Exception:
        pass
    if ws.max_row > 0:
        ws.delete_rows(1, ws.max_row)
    if ws.max_column > len(final_headers):
        ws.delete_cols(len(final_headers) + 1, ws.max_column - len(final_headers))
    ws.append(final_headers)
    for item in rows:
        ws.append([item.get(header) for header in final_headers])

    style_sheet(ws, table_name, len(final_headers))
    refresh_table_ref(ws)
    return True


def repair_excel_schema_in_workbook(wb: Any, *, strict_reference_headers: bool = True) -> tuple[bool, list[str]]:
    """Répare les schémas Excel compatibles avec les anciennes versions."""
    changed = False
    actions: list[str] = []
    for sheet_name, expected in EXCEL_SCHEMAS.items():
        table_name = EXCEL_TABLE_NAMES.get(sheet_name, f"Table{sheet_name}")
        if sheet_name not in wb.sheetnames:
            create_reference_sheet(wb, sheet_name, table_name)
            changed = True
            actions.append(f"onglet créé : {sheet_name}")
            continue

        ws = wb[sheet_name]
        headers = [normalize_excel_header(cell.value) for cell in ws[1]] if ws.max_row >= 1 else []
        if not any(headers):
            for col_idx, header in enumerate(expected, start=1):
                ws.cell(row=1, column=col_idx, value=header)
            style_sheet(ws, table_name, len(expected))
            refresh_table_ref(ws)
            changed = True
            actions.append(f"en-têtes ajoutés : {sheet_name}")
            continue

        if sheet_name in AUTO_REPAIRABLE_EXCEL_SHEETS:
            if not excel_headers_match_expected(headers, expected) or any(header not in headers for header in expected):
                if repair_generated_sheet_schema(ws, sheet_name, table_name):
                    changed = True
                    actions.append(f"en-têtes réparés : {sheet_name}")
            else:
                style_sheet(ws, table_name, max(ws.max_column, len(expected)))
                refresh_table_ref(ws)
            continue

        missing = [header for header in expected if header not in headers]
        if missing:
            for header in missing:
                ws.cell(row=1, column=ws.max_column + 1, value=header)
                headers.append(header)
            changed = True
            actions.append(f"colonnes ajoutées : {sheet_name} ({', '.join(missing)})")

        if strict_reference_headers and not excel_headers_match_expected(headers, expected):
            raise DataIntegrityError(
                f"Référentiel Excel corrompu : en-têtes modifiés dans {sheet_name}. Attendu : {expected}"
            )
        style_sheet(ws, table_name, max(ws.max_column, len(expected)))
        refresh_table_ref(ws)
    return changed, actions


def repair_excel_schema_if_possible(*, force: bool = False) -> dict[str, Any]:
    """Répare les en-têtes migrables et garde une copie avant correction."""
    if not EXCEL_PATH.exists():
        return {"status": "ok", "changed": False, "actions": [], "backup": None}
    with excel_lock:
        try:
            wb = load_workbook(EXCEL_PATH)
        except PermissionError as exc:
            raise HTTPException(status_code=423, detail="Le fichier referentiel_stock.xlsx est ouvert ou verrouillé par Excel. Fermez-le puis réessayez.") from exc
        except zipfile.BadZipFile as exc:
            return recover_reference_workbook("xlsx_illisible_schema_repair")
        try:
            changed, actions = repair_excel_schema_in_workbook(wb, strict_reference_headers=not force)
            backup_path: Path | None = None
            if changed:
                backup_path = backup_excel_before_schema_repair("schema_excel")
                save_reference_workbook(wb)
            else:
                try:
                    wb.close()
                except Exception:
                    pass
            return {
                "status": "ok",
                "changed": changed,
                "actions": actions,
                "backup": str(backup_path) if backup_path else None,
            }
        except Exception:
            try:
                wb.close()
            except Exception:
                pass
            raise


def create_reference_sheet(wb: Any, sheet_name: str, table_name: str, sample_row: list[Any] | None = None) -> Any:
    ws = wb.create_sheet(sheet_name)
    headers = EXCEL_SCHEMAS[sheet_name]
    ws.append(headers)
    if sample_row:
        ws.append(sample_row)
    style_sheet(ws, table_name, len(headers))
    return ws



def create_fresh_reference_workbook(path: Path | None = None) -> None:
    """Crée un référentiel Excel neuf sans toucher aux autres données."""
    target_path = Path(path or EXCEL_PATH)
    target_path.parent.mkdir(parents=True, exist_ok=True)
    wb = XLWorkbook()
    default = wb.active
    wb.remove(default)

    ws = wb.create_sheet("Instructions")
    ws.append(["Référentiel stock CLYO"])
    ws.merge_cells("A1:D1")
    ws["A1"].fill = PatternFill("solid", fgColor="1F4E78")
    ws["A1"].font = Font(bold=True, color="FFFFFF", size=14)
    ws["A1"].alignment = Alignment(horizontal="center")
    instructions = [
        ["Principe", "Ce fichier Excel est le référentiel maître lu et écrit par l'application."],
        ["Dossier de données", "Le fichier est stocké dans le dossier NexVandal/ afin de ne pas être écrasé lors des mises à jour."],
        ["Onglet Fournisseurs", "Liste des fournisseurs connus."],
        ["Onglet Modeles", "Liste des marques/modèles connus."],
        ["Onglet Regles", "Règles regex qui permettent de reconnaître un SN scanné."],
        ["Onglet Materiels", "Miroir Excel des matériels enregistrés dans l'application."],
        ["Onglet Clients", "Miroir Excel de la base clients créée dans l'application."],
        ["Onglet Logs", "Journal des actions utilisateurs synchronisé automatiquement."],
        ["Attention", "Ne pas renommer les onglets ni modifier les en-têtes de la ligne 1."],
        ["pattern", "Exemples : ^R4SH, ^50727/R4SH, R4SH[0-9]+"],
        ["model_id / supplier_id", "Doivent correspondre aux colonnes id des onglets Modeles et Fournisseurs."],
        ["Sauvegarde", "Sauvegarder tout le dossier NexVandal/ avant une migration ou une réinstallation."],
    ]
    for row in instructions:
        ws.append(row)
    ws.column_dimensions["A"].width = 24
    ws.column_dimensions["B"].width = 110

    create_reference_sheet(wb, "Fournisseurs", "TableFournisseurs", [1, "Fournisseur à définir", "", "", "", "Fournisseur temporaire", now_iso()])
    create_reference_sheet(wb, "Modeles", "TableModeles", [1, "Marque à définir", "Modèle à définir", "Non classé", 24, "", "Modèle temporaire", now_iso()])
    create_reference_sheet(wb, "Regles", "TableRegles", [1, "Exemple préfixe R4SH", "R4SH", 1, 1, 70, "Exemple à adapter ou supprimer", now_iso()])
    create_reference_sheet(wb, "Statuts", "TableStatuts")
    create_reference_sheet(wb, "MotifsRetourFournisseur", "TableMotifsRetourFournisseur")
    create_reference_sheet(wb, "Clients", "TableClients")
    create_reference_sheet(wb, "Materiels", "TableMateriels")
    create_reference_sheet(wb, "Logs", "TableLogs")
    create_reference_sheet(wb, "ProfilsConnexionMateriel", "TableProfilsConnexionMateriel")
    wb.save(target_path)
    try:
        wb.close()
    except Exception:
        pass


def is_excel_load_failure(exc: Exception) -> bool:
    """Identifie les erreurs qui signifient que le fichier n'est pas un vrai XLSX lisible."""
    message = str(exc).lower()
    names = {type(exc).__name__, type(getattr(exc, "__cause__", None)).__name__}
    return (
        isinstance(exc, zipfile.BadZipFile)
        or "BadZipFile" in names
        or "InvalidFileException" in names
        or "file is not a zip file" in message
        or "not a zip file" in message
        or "[content_types].xml" in message
        or "not supported" in message and "openpyxl" in message
    )


def iter_reference_excel_candidates() -> list[Path]:
    """Retourne les sauvegardes potentielles du référentiel, sans prendre le fichier actif."""
    roots = []
    for candidate_root in [
        BACKUP_DIR,
        BACKUP_DIR / "auto_1s_latest",
        ARCHIVE_DIR,
        DATA_DIR / "archives",
        APP_DIR / "NexVandal" / "backups",
        APP_DIR / "backups",
        DEFAULT_DATA_DIR / "backups",
    ]:
        try:
            root = Path(candidate_root).expanduser().resolve()
        except Exception:
            continue
        if root.exists() and root not in roots:
            roots.append(root)

    active = None
    try:
        active = EXCEL_PATH.resolve()
    except Exception:
        active = EXCEL_PATH

    found: list[Path] = []
    seen: set[str] = set()
    for root in roots:
        try:
            for path in root.rglob("*.xlsx"):
                if not path.is_file() or path.name.startswith("~$"):
                    continue
                try:
                    resolved = path.resolve()
                except Exception:
                    resolved = path
                if active is not None and resolved == active:
                    continue
                key = str(resolved).lower()
                if key in seen:
                    continue
                lname = path.name.lower()
                if "referentiel" not in lname and "stock" not in lname:
                    continue
                seen.add(key)
                found.append(path)
        except Exception as exc:
            safe_log(f"Recherche sauvegarde référentiel impossible dans {root} : {exc}")
    return found


def score_reference_excel_candidate(path: Path) -> int:
    """Score une sauvegarde Excel : négatif = inexploitable."""
    try:
        wb = load_workbook(path, read_only=True, data_only=True)
        score = max(1, int(path.stat().st_size // 1024))
        sheetnames = set(wb.sheetnames)
        for sheet_name in EXCEL_SCHEMAS:
            if sheet_name in sheetnames:
                score += 500
                try:
                    ws = wb[sheet_name]
                    headers = [normalize_excel_header(cell.value) for cell in next(ws.iter_rows(min_row=1, max_row=1))]
                    score += sum(20 for header in EXCEL_SCHEMAS[sheet_name] if header in headers)
                    score += min(ws.max_row or 0, 500)
                except Exception:
                    pass
        try:
            wb.close()
        except Exception:
            pass
        return int(score)
    except Exception:
        return -1


def archive_unreadable_reference_excel(reason: str) -> Path | None:
    """Déplace le référentiel illisible en archive pour ne pas le perdre."""
    if not EXCEL_PATH.exists():
        return None
    ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)
    stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    safe_reason = re.sub(r"[^A-Za-z0-9_-]+", "_", str(reason or "illisible"))[:60]
    target = ARCHIVE_DIR / f"referentiel_stock_{safe_reason}_{stamp}.xlsx"
    try:
        shutil.move(str(EXCEL_PATH), str(target))
        return target
    except Exception as exc:
        safe_log(f"Archivage du référentiel illisible impossible : {exc}")
        try:
            target = ARCHIVE_DIR / f"referentiel_stock_{safe_reason}_{stamp}_copie.xlsx"
            shutil.copy2(EXCEL_PATH, target)
            EXCEL_PATH.unlink(missing_ok=True)
            return target
        except Exception as copy_exc:
            safe_log(f"Copie du référentiel illisible impossible : {copy_exc}")
            return None


def recover_reference_workbook(reason: str = "reparation_auto") -> dict[str, Any]:
    """Répare un référentiel illisible : archive, restaure une sauvegarde valide ou recrée un XLSX propre."""
    with excel_lock:
        clear_excel_read_cache()
        archived = archive_unreadable_reference_excel(reason)
        candidates = []
        for candidate in iter_reference_excel_candidates():
            score = score_reference_excel_candidate(candidate)
            if score >= 0:
                candidates.append((score, candidate))
        candidates.sort(key=lambda item: item[0], reverse=True)

        restored_from: Path | None = None
        if candidates:
            restored_from = candidates[0][1]
            shutil.copy2(restored_from, EXCEL_PATH)
            action = "restored_backup"
        else:
            create_fresh_reference_workbook(EXCEL_PATH)
            action = "created_fresh"

        # Mise à niveau du schéma sans remplacer les données récupérées.
        wb = load_workbook(EXCEL_PATH)
        try:
            changed, actions = repair_excel_schema_in_workbook(wb, strict_reference_headers=False)
            if changed:
                save_reference_workbook(wb)
            else:
                try:
                    wb.close()
                except Exception:
                    pass
        except Exception:
            try:
                wb.close()
            except Exception:
                pass
            raise

        clear_excel_read_cache()
        result = {
            "status": "ok",
            "action": action,
            "archived_bad_file": str(archived) if archived else None,
            "restored_from": str(restored_from) if restored_from else None,
            "excel_path": str(EXCEL_PATH),
        }
        try:
            append_update_history_event({"event": "reference_excel_auto_repair", "version": APP_VERSION, **result})
        except Exception:
            pass
        try:
            safe_log(f"Référentiel Excel réparé automatiquement : {result}")
        except Exception:
            pass
        return result

def ensure_sheet_schema(wb: Any, sheet_name: str, table_name: str) -> bool:
    """Garantit l'existence d'un onglet et de ses colonnes sans supprimer les données."""
    headers = EXCEL_SCHEMAS[sheet_name]

    if sheet_name not in wb.sheetnames:
        create_reference_sheet(wb, sheet_name, table_name)
        return True

    ws = wb[sheet_name]
    current_headers = [normalize_excel_header(cell.value) for cell in ws[1]] if ws.max_row >= 1 else []

    if not any(current_headers):
        for col_idx, header in enumerate(headers, start=1):
            ws.cell(row=1, column=col_idx, value=header)
        style_sheet(ws, table_name, len(headers))
        refresh_table_ref(ws)
        return True

    if sheet_name in AUTO_REPAIRABLE_EXCEL_SHEETS:
        if not excel_headers_match_expected(current_headers, headers) or any(header not in current_headers for header in headers):
            return repair_generated_sheet_schema(ws, sheet_name, table_name)
        style_sheet(ws, table_name, max(ws.max_column, len(headers)))
        refresh_table_ref(ws)
        return False

    missing = [header for header in headers if header not in current_headers]
    changed = False
    if missing:
        for header in missing:
            ws.cell(row=1, column=ws.max_column + 1, value=header)
            current_headers.append(header)
        changed = True

    if not excel_headers_match_expected(current_headers, headers):
        raise HTTPException(
            status_code=500,
            detail=f"Les en-têtes de l'onglet {sheet_name} ont été modifiés. Attendu : {headers}",
        )

    style_sheet(ws, table_name, max(ws.max_column, len(headers)))
    refresh_table_ref(ws)
    return changed


def ensure_reference_workbook() -> None:
    """Crée ou met à niveau le fichier Excel maître.

    Important : si le fichier existe déjà, il n'est jamais remplacé.
    On ajoute uniquement les onglets/colonnes manquants, notamment l'onglet Materiels.
    """
    with excel_lock:
        if not EXCEL_PATH.exists():
            create_fresh_reference_workbook(EXCEL_PATH)
            # Les statuts par défaut sont ajoutés après sauvegarde via ensure_status_defaults().
            return

        try:
            wb = load_workbook(EXCEL_PATH)
        except PermissionError as exc:
            raise HTTPException(status_code=423, detail="Le fichier referentiel_stock.xlsx est ouvert ou verrouillé par Excel. Fermez-le puis réessayez.") from exc
        except zipfile.BadZipFile as exc:
            try:
                recover_reference_workbook("xlsx_illisible_ensure")
                wb = load_workbook(EXCEL_PATH)
            except Exception as repair_exc:
                reason = f"Référentiel Excel illisible : réparation automatique impossible ({repair_exc})."
                block_auto_sync(reason, "excel")
                raise HTTPException(status_code=409, detail=reason) from exc
        except Exception as exc:
            if is_file_locked_error(exc):
                raise HTTPException(status_code=423, detail="Le fichier referentiel_stock.xlsx est ouvert ou verrouillé par Excel. Fermez-le puis réessayez.") from exc
            if is_excel_load_failure(exc):
                try:
                    recover_reference_workbook("xlsx_illisible_ensure")
                    wb = load_workbook(EXCEL_PATH)
                except Exception as repair_exc:
                    reason = f"Référentiel Excel illisible : réparation automatique impossible ({repair_exc})."
                    block_auto_sync(reason, "excel")
                    raise HTTPException(status_code=409, detail=reason) from exc
            else:
                raise

        changed = False
        changed |= ensure_sheet_schema(wb, "Fournisseurs", "TableFournisseurs")
        changed |= ensure_sheet_schema(wb, "Modeles", "TableModeles")
        changed |= ensure_sheet_schema(wb, "Regles", "TableRegles")
        changed |= ensure_sheet_schema(wb, "Statuts", "TableStatuts")
        changed |= ensure_sheet_schema(wb, "MotifsRetourFournisseur", "TableMotifsRetourFournisseur")
        changed |= ensure_sheet_schema(wb, "Clients", "TableClients")
        changed |= ensure_sheet_schema(wb, "Materiels", "TableMateriels")
        changed |= ensure_sheet_schema(wb, "Logs", "TableLogs")
        changed |= ensure_sheet_schema(wb, "ProfilsConnexionMateriel", "TableProfilsConnexionMateriel")

        if changed:
            backup_excel_before_schema_repair("ensure_reference_workbook")
            save_reference_workbook(wb)

def load_reference_workbook():
    ensure_reference_workbook()
    try:
        return load_workbook(EXCEL_PATH)
    except PermissionError as exc:
        raise HTTPException(status_code=423, detail="Le fichier referentiel_stock.xlsx est ouvert ou verrouillé par Excel. Fermez-le puis réessayez.") from exc
    except zipfile.BadZipFile as exc:
        try:
            recover_reference_workbook("xlsx_illisible_load")
            return load_workbook(EXCEL_PATH)
        except Exception as repair_exc:
            reason = f"Référentiel Excel illisible : réparation automatique impossible ({repair_exc})."
            block_auto_sync(reason, "excel")
            raise HTTPException(status_code=409, detail=reason) from exc
    except Exception as exc:
        if is_file_locked_error(exc):
            raise HTTPException(status_code=423, detail="Le fichier referentiel_stock.xlsx est ouvert ou verrouillé par Excel. Fermez-le puis réessayez.") from exc
        if is_excel_load_failure(exc):
            try:
                recover_reference_workbook("xlsx_illisible_load")
                return load_workbook(EXCEL_PATH)
            except Exception as repair_exc:
                reason = f"Référentiel Excel illisible : réparation automatique impossible ({repair_exc})."
                block_auto_sync(reason, "excel")
                raise HTTPException(status_code=409, detail=reason) from exc
        raise


def backup_excel_once_per_day() -> None:
    """Crée une sauvegarde quotidienne du référentiel avant écriture."""
    if not EXCEL_PATH.exists():
        return
    backup_path = BACKUP_DIR / f"referentiel_stock_{datetime.now().strftime('%Y%m%d')}.xlsx"
    if not backup_path.exists():
        shutil.copy2(EXCEL_PATH, backup_path)


def backup_active_data_snapshot() -> dict[str, Any]:
    ensure_auto_operations_allowed("backup")
    """Sauvegarde de travail actualisée toutes les secondes si les données changent.

    Pour éviter de créer des milliers de fichiers, cette sauvegarde 1 seconde
    remplace toujours le dernier instantané dans backups/auto_1s_latest. Les
    sauvegardes datées restent disponibles via le bouton Sauvegarde manuelle.
    """
    snapshot_dir = BACKUP_DIR / "auto_1s_latest"
    snapshot_dir.mkdir(parents=True, exist_ok=True)
    copied: list[str] = []
    for path in [EXCEL_PATH, DB_PATH, DATA_DIR / "stock_assets.db-wal", DATA_DIR / "stock_assets.db-shm", LOG_PATH, UI_SETTINGS_PATH]:
        try:
            if path.exists():
                shutil.copy2(path, snapshot_dir / path.name)
                copied.append(path.name)
        except Exception as exc:
            safe_log(f"Sauvegarde 1 seconde impossible pour {path.name} : {exc}")
    meta = {
        "saved_at": datetime.now().isoformat(timespec="seconds"),
        "source_folder": str(DATA_DIR),
        "copied": copied,
    }
    try:
        (snapshot_dir / "snapshot_info.json").write_text(json.dumps(meta, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass
    return {"status": "ok", "backup_folder": str(snapshot_dir), "files": copied}


def save_reference_workbook(wb: Any) -> None:
    try:
        backup_excel_once_per_day()
        wb.save(EXCEL_PATH)
        clear_excel_read_cache()
        clear_data_integrity_cache()
    except PermissionError as exc:
        raise HTTPException(status_code=423, detail="Impossible d'écrire dans referentiel_stock.xlsx : le fichier est probablement ouvert dans Excel.") from exc


def read_excel_sheet(sheet_name: str) -> list[dict[str, Any]]:
    with excel_lock:
        ensure_reference_workbook()
        try:
            mtime_ns = EXCEL_PATH.stat().st_mtime_ns
        except FileNotFoundError:
            mtime_ns = 0
        cached = EXCEL_READ_CACHE.get(sheet_name)
        if cached and cached[0] == mtime_ns:
            return [dict(row) for row in cached[1]]

        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            if sheet_name in EXCEL_SCHEMAS:
                wb = load_reference_workbook()
                if sheet_name not in wb.sheetnames:
                    raise HTTPException(status_code=500, detail=f"Onglet Excel manquant : {sheet_name}")
            else:
                raise HTTPException(status_code=500, detail=f"Onglet Excel manquant : {sheet_name}")
        ws = wb[sheet_name]
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        expected = EXCEL_SCHEMAS[sheet_name]
        if not excel_headers_match_expected(headers, expected):
            if sheet_name in AUTO_REPAIRABLE_EXCEL_SHEETS:
                repair_generated_sheet_schema(ws, sheet_name, EXCEL_TABLE_NAMES.get(sheet_name, f"Table{sheet_name}"))
                save_reference_workbook(wb)
                wb = load_reference_workbook()
                ws = wb[sheet_name]
                headers = clean_excel_headers([cell.value for cell in ws[1]])
            if not excel_headers_match_expected(headers, expected):
                raise HTTPException(
                    status_code=500,
                    detail=f"Les en-têtes de l'onglet {sheet_name} ont été modifiés. Attendu : {expected}",
                )
        rows: list[dict[str, Any]] = []
        header_positions = {str(header): idx for idx, header in enumerate(headers) if str(header or "").strip()}
        for row in ws.iter_rows(min_row=2, values_only=True):
            if all(value is None for value in row):
                continue
            item = {header: empty_to_none(row[header_positions[header]]) if header in header_positions and header_positions[header] < len(row) else None for header in expected}
            if item.get("id") is not None:
                try:
                    item["id"] = int(item["id"])
                except (TypeError, ValueError):
                    pass
            rows.append(item)
        EXCEL_READ_CACHE[sheet_name] = (mtime_ns, [dict(row) for row in rows])
        return [dict(row) for row in rows]


def append_excel_row(sheet_name: str, data: dict[str, Any]) -> dict[str, Any]:
    with excel_lock:
        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            raise HTTPException(status_code=500, detail=f"Onglet Excel manquant : {sheet_name}")
        ws = wb[sheet_name]
        headers = EXCEL_SCHEMAS[sheet_name]
        existing = read_excel_sheet(sheet_name)
        max_id = max([int(x.get("id") or 0) for x in existing] or [0])
        data = {**data, "id": max_id + 1, "created_at": now_iso()}
        ws.append([data.get(header) for header in headers])
        refresh_table_ref(ws)
        save_reference_workbook(wb)
        return data


def update_excel_row_by_id(sheet_name: str, item_id: int, data: dict[str, Any]) -> dict[str, Any]:
    """Modifie une ligne du référentiel Excel par son ID, sans changer l'ID ni created_at."""
    with excel_lock:
        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            raise HTTPException(status_code=500, detail=f"Onglet Excel manquant : {sheet_name}")
        ws = wb[sheet_name]
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        expected = EXCEL_SCHEMAS[sheet_name]
        if not excel_headers_match_expected(headers, expected):
            if sheet_name in AUTO_REPAIRABLE_EXCEL_SHEETS:
                repair_generated_sheet_schema(ws, sheet_name, EXCEL_TABLE_NAMES.get(sheet_name, f"Table{sheet_name}"))
                save_reference_workbook(wb)
                wb = load_reference_workbook()
                ws = wb[sheet_name]
                headers = clean_excel_headers([cell.value for cell in ws[1]])
            if not excel_headers_match_expected(headers, expected):
                raise HTTPException(status_code=500, detail=f"Les en-têtes de l'onglet {sheet_name} ont été modifiés.")
        if "id" not in headers:
            raise HTTPException(status_code=500, detail=f"Colonne id manquante dans {sheet_name}")
        id_idx = headers.index("id") + 1
        target_row = None
        for row_idx in range(2, ws.max_row + 1):
            try:
                current_id = int(ws.cell(row=row_idx, column=id_idx).value or 0)
            except (TypeError, ValueError):
                continue
            if current_id == int(item_id):
                target_row = row_idx
                break
        if target_row is None:
            raise HTTPException(status_code=404, detail="Ligne introuvable dans le référentiel Excel")

        existing: dict[str, Any] = {}
        for col_idx, header in enumerate(headers[: len(expected)], start=1):
            existing[str(header)] = empty_to_none(ws.cell(row=target_row, column=col_idx).value)

        updated = {**existing, **data, "id": int(item_id)}
        for header in expected:
            if header == "id" or header == "created_at":
                continue
            col_idx = headers.index(header) + 1
            ws.cell(row=target_row, column=col_idx, value=updated.get(header))

        refresh_table_ref(ws)
        save_reference_workbook(wb)
        return {header: updated.get(header) for header in expected}


def upsert_excel_row(sheet_name: str, key_column: str, key_value: Any, data: dict[str, Any]) -> dict[str, Any]:
    """Ajoute ou met à jour une ligne Excel sans effacer les autres données."""
    with excel_lock:
        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            raise HTTPException(status_code=500, detail=f"Onglet Excel manquant : {sheet_name}")
        ws = wb[sheet_name]
        headers = clean_excel_headers([cell.value for cell in ws[1]])

        # Si de nouvelles colonnes ont été ajoutées dans EXCEL_SCHEMAS, on les ajoute à droite.
        for header in EXCEL_SCHEMAS[sheet_name]:
            if header not in headers:
                ws.cell(row=1, column=ws.max_column + 1, value=header)
                headers.append(header)

        if key_column not in headers:
            raise HTTPException(status_code=500, detail=f"Colonne clé manquante dans {sheet_name} : {key_column}")

        key_idx = headers.index(key_column) + 1
        target_row: int | None = None
        for row_idx in range(2, ws.max_row + 1):
            if str(ws.cell(row=row_idx, column=key_idx).value or "") == str(key_value):
                target_row = row_idx
                break

        if target_row is None:
            target_row = ws.max_row + 1

        for header, value in data.items():
            if header not in headers:
                ws.cell(row=1, column=ws.max_column + 1, value=header)
                headers.append(header)
            col_idx = headers.index(header) + 1
            ws.cell(row=target_row, column=col_idx, value=value)

        refresh_table_ref(ws)
        save_reference_workbook(wb)
        return data




def delete_excel_row(sheet_name: str, key_column: str, key_value: Any) -> bool:
    """Supprime une ligne Excel par clé sans toucher aux autres onglets."""
    with excel_lock:
        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            return False
        ws = wb[sheet_name]
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        if key_column not in headers:
            return False
        key_idx = headers.index(key_column) + 1
        deleted = False
        for row_idx in range(2, ws.max_row + 1):
            if str(ws.cell(row=row_idx, column=key_idx).value or "") == str(key_value):
                ws.delete_rows(row_idx, 1)
                deleted = True
                break
        if deleted:
            refresh_table_ref(ws)
            save_reference_workbook(wb)
        return deleted

def delete_excel_rows(sheet_name: str, key_column: str, key_value: Any) -> int:
    """Supprime toutes les lignes Excel qui correspondent à une clé donnée."""
    with excel_lock:
        wb = load_reference_workbook()
        if sheet_name not in wb.sheetnames:
            return 0
        ws = wb[sheet_name]
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        if key_column not in headers:
            return 0
        key_idx = headers.index(key_column) + 1
        deleted = 0
        for row_idx in range(ws.max_row, 1, -1):
            if str(ws.cell(row=row_idx, column=key_idx).value or "") == str(key_value):
                ws.delete_rows(row_idx, 1)
                deleted += 1
        if deleted:
            refresh_table_ref(ws)
            save_reference_workbook(wb)
        return deleted



# --- V8.0.6 : vraie base SQLite pour le référentiel ---
# Les fonctions Excel d'origine restent disponibles en secours pour l'import initial,
# mais le fonctionnement courant utilise SQLite comme base principale.
_EXCEL_FILE_READ_SHEET_V734 = read_excel_sheet
_EXCEL_FILE_APPEND_ROW_V734 = append_excel_row
_EXCEL_FILE_UPDATE_ROW_BY_ID_V734 = update_excel_row_by_id
_EXCEL_FILE_DELETE_ROW_V734 = delete_excel_row
_EXCEL_FILE_DELETE_ROWS_V734 = delete_excel_rows


def sqlite_reference_store_enabled(sheet_name: str | None = None) -> bool:
    if not sheet_name:
        return True
    return str(sheet_name) in EXCEL_SCHEMAS


def ensure_sqlite_reference_store() -> None:
    with db() as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS reference_rows (
                sheet_name TEXT NOT NULL,
                row_id INTEGER NOT NULL,
                data_json TEXT NOT NULL,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL,
                PRIMARY KEY(sheet_name, row_id)
            )
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_reference_rows_sheet ON reference_rows(sheet_name)")


def json_safe_reference_value(value: Any) -> Any:
    if value is None:
        return None
    if isinstance(value, (str, int, float, bool)):
        return value
    try:
        if hasattr(value, "isoformat"):
            return value.isoformat()
    except Exception:
        pass
    return str(value)


def normalize_reference_row_for_sqlite(sheet_name: str, row: dict[str, Any], row_id: int | None = None) -> dict[str, Any]:
    expected = EXCEL_SCHEMAS.get(sheet_name, list(row.keys()))
    clean: dict[str, Any] = {}
    for key in expected:
        clean[key] = json_safe_reference_value(row.get(key))
    if "id" in expected:
        try:
            clean["id"] = int(row_id if row_id is not None else (clean.get("id") or 0))
        except Exception:
            clean["id"] = int(row_id or 0)
    return clean


def import_excel_sheet_to_sqlite_if_needed(sheet_name: str) -> None:
    if not sqlite_reference_store_enabled(sheet_name):
        return
    ensure_sqlite_reference_store()
    with db() as conn:
        existing = conn.execute("SELECT COUNT(*) AS c FROM reference_rows WHERE sheet_name = ?", (sheet_name,)).fetchone()
        if int(existing["c"] or 0) > 0:
            return
    try:
        rows = _EXCEL_FILE_READ_SHEET_V734(sheet_name)
    except Exception as exc:
        safe_log(f"Import initial Excel vers SQLite impossible pour {sheet_name}: {exc}")
        rows = []
    if not rows:
        return
    now = now_iso()
    with db() as conn:
        for idx, row in enumerate(rows, start=1):
            try:
                row_id = int(row.get("id") or idx)
            except Exception:
                row_id = idx
            clean = normalize_reference_row_for_sqlite(sheet_name, row, row_id)
            if clean.get("created_at") in (None, ""):
                clean["created_at"] = now
            clean["updated_at"] = now
            conn.execute(
                """
                INSERT OR REPLACE INTO reference_rows(sheet_name, row_id, data_json, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?)
                """,
                (sheet_name, row_id, json.dumps(clean, ensure_ascii=False, default=str), str(clean.get("created_at") or now), now),
            )


def read_excel_sheet(sheet_name: str) -> list[dict[str, Any]]:
    """Compatibilité API : lit désormais le référentiel depuis SQLite.

    Le nom reste read_excel_sheet pour éviter de modifier tout le reste du code,
    mais la source principale est la table SQLite reference_rows.
    """
    if not sqlite_reference_store_enabled(sheet_name):
        return _EXCEL_FILE_READ_SHEET_V734(sheet_name)
    import_excel_sheet_to_sqlite_if_needed(sheet_name)
    expected = EXCEL_SCHEMAS.get(sheet_name, [])
    ensure_sqlite_reference_store()
    with db() as conn:
        rows = conn.execute(
            "SELECT row_id, data_json FROM reference_rows WHERE sheet_name = ? ORDER BY row_id ASC",
            (sheet_name,),
        ).fetchall()
    result: list[dict[str, Any]] = []
    for row in rows:
        try:
            data = json.loads(row["data_json"] or "{}")
        except Exception:
            data = {}
        if "id" in expected:
            try:
                data["id"] = int(data.get("id") or row["row_id"])
            except Exception:
                data["id"] = int(row["row_id"])
        normalized = {key: data.get(key) for key in expected} if expected else data
        result.append(normalized)
    return [dict(item) for item in result]


def append_excel_row(sheet_name: str, data: dict[str, Any]) -> dict[str, Any]:
    if not sqlite_reference_store_enabled(sheet_name):
        return _EXCEL_FILE_APPEND_ROW_V734(sheet_name, data)
    ensure_sqlite_reference_store()
    import_excel_sheet_to_sqlite_if_needed(sheet_name)
    now = now_iso()
    with db() as conn:
        row = conn.execute(
            "SELECT COALESCE(MAX(row_id), 0) AS max_id FROM reference_rows WHERE sheet_name = ?",
            (sheet_name,),
        ).fetchone()
        next_id = int(row["max_id"] or 0) + 1
        payload = {**data, "id": next_id, "created_at": data.get("created_at") or now, "updated_at": data.get("updated_at") or now}
        payload = normalize_reference_row_for_sqlite(sheet_name, payload, next_id)
        conn.execute(
            """
            INSERT INTO reference_rows(sheet_name, row_id, data_json, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?)
            """,
            (sheet_name, next_id, json.dumps(payload, ensure_ascii=False, default=str), str(payload.get("created_at") or now), str(payload.get("updated_at") or now)),
        )
    clear_excel_read_cache()
    return payload


def update_excel_row_by_id(sheet_name: str, item_id: int, data: dict[str, Any]) -> dict[str, Any]:
    if not sqlite_reference_store_enabled(sheet_name):
        return _EXCEL_FILE_UPDATE_ROW_BY_ID_V734(sheet_name, item_id, data)
    ensure_sqlite_reference_store()
    import_excel_sheet_to_sqlite_if_needed(sheet_name)
    item_id = int(item_id)
    with db() as conn:
        row = conn.execute(
            "SELECT data_json FROM reference_rows WHERE sheet_name = ? AND row_id = ?",
            (sheet_name, item_id),
        ).fetchone()
        if not row:
            raise HTTPException(status_code=404, detail=f"Ligne introuvable dans {sheet_name}")
        try:
            current = json.loads(row["data_json"] or "{}")
        except Exception:
            current = {}
        now = now_iso()
        merged = {**current, **data, "id": item_id, "updated_at": data.get("updated_at") or now}
        if not merged.get("created_at"):
            merged["created_at"] = current.get("created_at") or now
        merged = normalize_reference_row_for_sqlite(sheet_name, merged, item_id)
        conn.execute(
            "UPDATE reference_rows SET data_json = ?, updated_at = ? WHERE sheet_name = ? AND row_id = ?",
            (json.dumps(merged, ensure_ascii=False, default=str), str(merged.get("updated_at") or now), sheet_name, item_id),
        )
    clear_excel_read_cache()
    return merged


def delete_excel_row(sheet_name: str, key_column: str, key_value: Any) -> bool:
    if not sqlite_reference_store_enabled(sheet_name):
        return _EXCEL_FILE_DELETE_ROW_V734(sheet_name, key_column, key_value)
    rows = read_excel_sheet(sheet_name)
    target = next((row for row in rows if str(row.get(key_column) or "") == str(key_value)), None)
    if not target:
        return False
    row_id = int(target.get("id") or 0)
    if not row_id:
        return False
    with db() as conn:
        cur = conn.execute("DELETE FROM reference_rows WHERE sheet_name = ? AND row_id = ?", (sheet_name, row_id))
    clear_excel_read_cache()
    return cur.rowcount > 0


def delete_excel_rows(sheet_name: str, key_column: str, key_value: Any) -> int:
    if not sqlite_reference_store_enabled(sheet_name):
        return _EXCEL_FILE_DELETE_ROWS_V734(sheet_name, key_column, key_value)
    rows = read_excel_sheet(sheet_name)
    ids = [int(row.get("id") or 0) for row in rows if str(row.get(key_column) or "") == str(key_value) and int(row.get("id") or 0)]
    if not ids:
        return 0
    with db() as conn:
        for row_id in ids:
            conn.execute("DELETE FROM reference_rows WHERE sheet_name = ? AND row_id = ?", (sheet_name, row_id))
    clear_excel_read_cache()
    return len(ids)


def migrate_excel_references_to_sqlite() -> dict[str, Any]:
    ensure_sqlite_reference_store()
    migrated: dict[str, int] = {}
    for sheet_name in EXCEL_SCHEMAS.keys():
        try:
            import_excel_sheet_to_sqlite_if_needed(sheet_name)
            migrated[sheet_name] = len(read_excel_sheet(sheet_name))
        except Exception as exc:
            safe_log(f"Migration référentiel SQLite impossible pour {sheet_name}: {exc}")
            migrated[sheet_name] = -1
    return {"status": "ok", "database": str(DB_PATH), "migrated": migrated}


def excel_safe_status_label(status: str | None) -> str:
    return get_status_options_map().get(status or "", status or "")


def asset_to_excel_data(
    asset: dict[str, Any],
    models: dict[int, dict[str, Any]] | None = None,
    suppliers: dict[int, dict[str, Any]] | None = None,
    status_options_map: dict[str, str] | None = None,
    customers: dict[int, dict[str, Any]] | None = None,
) -> dict[str, Any]:
    """Transforme un matériel en ligne lisible pour l'onglet Materiels.

    Les index optionnels évitent de relire le classeur Excel pour chaque matériel
    pendant une synchronisation complète.
    """
    model = None
    supplier = None
    customer = None

    if asset.get("model_id") is not None:
        try:
            model_id = int(asset.get("model_id"))
            model = models.get(model_id) if models is not None else get_reference_by_id("Modeles", model_id)
        except (TypeError, ValueError):
            model = None

    if asset.get("supplier_id") is not None:
        try:
            supplier_id = int(asset.get("supplier_id"))
            supplier = suppliers.get(supplier_id) if suppliers is not None else get_reference_by_id("Fournisseurs", supplier_id)
        except (TypeError, ValueError):
            supplier = None

    if asset.get("customer_id"):
        try:
            customer_id = int(asset.get("customer_id"))
            customer = customers.get(customer_id) if customers is not None else get_customer_by_id(customer_id)
        except (TypeError, ValueError):
            customer = None

    status_map = status_options_map if status_options_map is not None else get_status_options_map()
    customer_name = asset.get("customer_display_name") or customer_display_name(customer)
    image_context = {
        **asset,
        "brand": model.get("brand") if model else None,
        "model_name": model.get("model_name") if model else None,
        "category": model.get("category") if model else None,
        "supplier_name": supplier.get("name") if supplier else None,
    }
    image_fields = enrich_asset_image_fields(image_context)

    return {
        "id": asset.get("id"),
        "asset_code": asset.get("asset_code"),
        "serial_number_raw": asset.get("serial_number_raw"),
        "serial_number_norm": asset.get("serial_number_norm"),
        "model_id": asset.get("model_id"),
        "brand": model.get("brand") if model else "",
        "model_name": model.get("model_name") if model else "",
        "category": model.get("category") if model else "",
        "supplier_id": asset.get("supplier_id"),
        "supplier_name": supplier.get("name") if supplier else "",
        "purchase_date": asset.get("purchase_date"),
        "purchase_price_eur": asset.get("purchase_price_eur"),
        "warranty_end_date": asset.get("warranty_end_date"),
        "status": asset.get("status"),
        "status_label": status_map.get(asset.get("status") or "", asset.get("status") or ""),
        "location": asset.get("location"),
        "client_name": asset.get("client_name") or customer_name,
        "customer_id": asset.get("customer_id"),
        "customer_code": asset.get("customer_code") or (customer.get("customer_code") if customer else None),
        "customer_company": asset.get("customer_company") or (customer.get("company") if customer else None),
        "customer_email": asset.get("customer_email") or (customer.get("email") if customer else None),
        "customer_phone": asset.get("customer_phone") or (customer.get("phone") if customer else None),
        "teamviewer_id": asset.get("teamviewer_id"),
        "teamviewer_password": asset.get("teamviewer_password"),
        "return_reason": return_reason_label(asset.get("return_reason")),
        "return_supplier_sent_at": asset.get("return_supplier_sent_at"),
        "return_supplier_back_at": asset.get("return_supplier_back_at"),
        "damaged_reason": asset.get("damaged_reason"),
        "replacement_of_asset_id": asset.get("replacement_of_asset_id"),
        "replaced_by_asset_id": asset.get("replaced_by_asset_id"),
        "replacement_date": asset.get("replacement_date"),
        "replacement_reason": asset.get("replacement_reason"),
        "sale_date": asset.get("sale_date"),
        "image_url": asset.get("image_url") or image_fields.get("image_url"),
        "image_search_url": image_fields.get("image_search_url"),
        "image_local_path": asset.get("image_local_path"),
        "notes": asset.get("notes"),
        "created_at": asset.get("created_at"),
        "updated_at": asset.get("updated_at"),
        "last_excel_sync_at": now_iso(),
    }

def sync_asset_to_excel(asset: dict[str, Any]) -> None:
    """Synchronise un matériel unique vers l'onglet Materiels."""
    ensure_auto_operations_allowed("sync_asset")
    ensure_reference_workbook()
    data = asset_to_excel_data(asset)
    upsert_excel_row("Materiels", "asset_code", data["asset_code"], data)


def sync_all_assets_to_excel() -> dict[str, Any]:
    """Synchronise tous les matériels SQLite vers l'onglet Materiels en une seule écriture Excel."""
    ensure_auto_operations_allowed("sync_assets")
    ensure_reference_workbook()
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    status_map = get_status_options_map()
    with db() as conn:
        rows = [dict(row) for row in conn.execute("SELECT * FROM assets ORDER BY id ASC").fetchall()]
        customer_rows = [dict(row) for row in conn.execute("SELECT * FROM customers").fetchall()]
    customers = {int(row["id"]): row for row in customer_rows if row.get("id") is not None}
    data_rows = [
        asset_to_excel_data(row, models=models, suppliers=suppliers, status_options_map=status_map, customers=customers)
        for row in rows
    ]

    with excel_lock:
        wb = load_reference_workbook()
        if "Materiels" not in wb.sheetnames:
            create_reference_sheet(wb, "Materiels", "TableMateriels")
        ws = wb["Materiels"]
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        expected = EXCEL_SCHEMAS["Materiels"]
        if not any(headers):
            for col_idx, header in enumerate(expected, start=1):
                ws.cell(row=1, column=col_idx, value=header)
            headers = expected[:]
        if not excel_headers_match_expected(headers, expected):
            repair_generated_sheet_schema(ws, "Materiels", "TableMateriels")
            headers = clean_excel_headers([cell.value for cell in ws[1]])
        if not excel_headers_match_expected(headers, expected):
            raise DataIntegrityError(f"Référentiel Excel corrompu : en-têtes modifiés dans Materiels. Attendu : {expected}. Trouvé : {headers}")
        for header in expected:
            if header not in headers:
                ws.cell(row=1, column=ws.max_column + 1, value=header)
                headers.append(header)

        if ws.max_row > 1:
            ws.delete_rows(2, ws.max_row - 1)
        headers = clean_excel_headers([cell.value for cell in ws[1]])
        for data in data_rows:
            ws.append([data.get(header) for header in headers])
        style_sheet(ws, "TableMateriels", max(ws.max_column, len(expected)))
        refresh_table_ref(ws)
        save_reference_workbook(wb)
    return {"status": "ok", "synced_assets": len(data_rows), "excel_path": str(EXCEL_PATH), "mode": "batch"}


CONNECTED_CLIENT_LOG_CACHE: dict[str, float] = {}
CLIENT_NAME_CACHE_V7753: dict[str, str] = {}


def get_local_computer_name_v7753() -> str | None:
    """Retourne le nom du poste serveur quand le navigateur est local."""
    for key in ("COMPUTERNAME", "HOSTNAME"):
        value = os.environ.get(key)
        if value:
            return str(value).strip()
    try:
        return socket.gethostname()
    except Exception:
        return None


def get_client_ip_v7753(request: Request | None) -> str | None:
    if request is None:
        return None
    try:
        forwarded = str(request.headers.get("x-forwarded-for") or "").split(",")[0].strip()
        if forwarded:
            return forwarded
    except Exception:
        pass
    try:
        return request.client.host if request.client else None
    except Exception:
        return None


def resolve_client_computer_name_v7753(request: Request | None = None, ip: str | None = None) -> str | None:
    """Nom de poste pour les logs.

    Un navigateur standard ne donne pas directement le nom Windows du poste.
    L'application exploite donc, dans l'ordre : un éventuel en-tête interne,
    le nom local pour localhost, puis la résolution DNS inverse du réseau.
    """
    header_candidates = []
    if request is not None:
        for header in ("x-clyo-computer-name", "x-computer-name", "x-hostname"):
            try:
                value = str(request.headers.get(header) or "").strip()
            except Exception:
                value = ""
            if value:
                header_candidates.append(value)
    if header_candidates:
        return header_candidates[0][:120]
    ip = ip or get_client_ip_v7753(request)
    if not ip:
        return get_local_computer_name_v7753()
    if ip in CLIENT_NAME_CACHE_V7753:
        return CLIENT_NAME_CACHE_V7753[ip]
    if ip in {"127.0.0.1", "::1", "localhost"}:
        name = get_local_computer_name_v7753() or f"Poste {ip}"
        CLIENT_NAME_CACHE_V7753[ip] = name
        return name
    resolved = ""
    try:
        name = socket.gethostbyaddr(ip)[0]
        if name and name != ip:
            resolved = str(name).split(".")[0][:120]
    except Exception:
        resolved = ""
    if not resolved:
        resolved = f"Poste {ip}"
    CLIENT_NAME_CACHE_V7753[ip] = resolved
    return resolved


def log_site_connection_once_v7753(request: Request | None, username: str | None = None, role: str | None = None) -> None:
    """Journalise une connexion poste/site sans spammer le journal à chaque heartbeat."""
    try:
        ip = get_client_ip_v7753(request)
        computer_name = resolve_client_computer_name_v7753(request, ip)
        key = f"{username or ''}|{ip or ''}|{computer_name or ''}"
        now_ts = time.monotonic()
        last_ts = CONNECTED_CLIENT_LOG_CACHE.get(key)
        if last_ts and (now_ts - last_ts) < 3600:
            return
        CONNECTED_CLIENT_LOG_CACHE[key] = now_ts
        detail_parts = ["Ordinateur connecté au site"]
        if computer_name:
            detail_parts.append(f"poste={computer_name}")
        if ip:
            detail_parts.append(f"ip={ip}")
        write_app_log("site_connected", "client_computer", computer_name or ip or "unknown", " · ".join(detail_parts), request=request, username=username, role=role)
    except Exception as exc:
        safe_log(f"Journalisation connexion poste impossible : {exc}")


def log_to_excel_data(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": row.get("id"),
        "created_at": row.get("created_at"),
        "username": row.get("username"),
        "role": row.get("role"),
        "action": row.get("action"),
        "target_type": row.get("target_type"),
        "target_id": row.get("target_id"),
        "details": row.get("details"),
        "ip": row.get("ip"),
        "computer_name": row.get("computer_name"),
    }


def write_app_log(
    action: str,
    target_type: str | None = None,
    target_id: Any | None = None,
    details: str | None = None,
    request: Request | None = None,
    username: str | None = None,
    role: str | None = None,
) -> None:
    """Journalise les actions importantes dans SQLite et dans un fichier JSONL.

    L'export Excel de ce journal est vérifié automatiquement toutes les 1 seconde,
    en même temps que la synchronisation des matériels.
    """
    try:
        user = None
        ip = None
        computer_name = None
        if request is not None:
            try:
                user = get_request_user(request, touch=False)
            except Exception:
                user = None
            try:
                ip = get_client_ip_v7753(request)
            except Exception:
                ip = None
            try:
                computer_name = resolve_client_computer_name_v7753(request, ip)
            except Exception:
                computer_name = None
        if user:
            username = username or str(user.get("username") or "")
            role = role or str(user.get("role") or "")
            user_id = user.get("id")
        else:
            user_id = None
        created_at = now_iso()
        with db() as conn:
            cur = conn.execute(
                """
                INSERT INTO app_logs(created_at, user_id, username, role, action, target_type, target_id, details, ip, computer_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (created_at, user_id, username, role, action, target_type, str(target_id) if target_id is not None else None, details, ip, computer_name),
            )
            log_id = cur.lastrowid
        LOG_PATH.parent.mkdir(exist_ok=True)
        with LOG_PATH.open("a", encoding="utf-8") as f:
            f.write(json.dumps({
                "id": log_id,
                "created_at": created_at,
                "username": username,
                "role": role,
                "action": action,
                "target_type": target_type,
                "target_id": str(target_id) if target_id is not None else None,
                "details": details,
                "ip": ip,
                "computer_name": computer_name,
            }, ensure_ascii=False) + "\n")
    except Exception as exc:
        safe_log(f"Journalisation impossible : {exc}")


def sync_logs_to_excel(limit: int = 5000) -> dict[str, Any]:
    ensure_auto_operations_allowed("sync_logs")
    ensure_reference_workbook()
    with db() as conn:
        rows = conn.execute(
            "SELECT id, created_at, username, role, action, target_type, target_id, details, ip, computer_name FROM app_logs ORDER BY id DESC LIMIT ?",
            (limit,),
        ).fetchall()
    rows = list(reversed(rows))
    with excel_lock:
        wb = load_reference_workbook()
        ws = wb["Logs"]
        expected = EXCEL_SCHEMAS["Logs"]
        headers = clean_excel_headers([cell.value for cell in ws[1]]) or expected[:]
        for header in expected:
            if header not in headers:
                ws.cell(row=1, column=ws.max_column + 1, value=header)
                headers.append(header)
        if ws.max_row > 1:
            ws.delete_rows(2, ws.max_row - 1)
        for row in rows:
            data = log_to_excel_data(dict(row))
            ws.append([data.get(header) for header in headers])
        refresh_table_ref(ws)
        save_reference_workbook(wb)
    return {"status": "ok", "synced_logs": len(rows), "excel_path": str(EXCEL_PATH)}


def get_logs_sync_signature() -> str:
    if not DB_PATH.exists():
        return "empty"
    with db() as conn:
        row = conn.execute("SELECT COUNT(*) AS count_logs, COALESCE(MAX(id), 0) AS last_id FROM app_logs WHERE action <> 'auto_backup_snapshot'").fetchone()
    return f"{row['count_logs']}|{row['last_id']}"


AUTO_SYNC_STARTED = False
AUTO_SYNC_LAST_SIGNATURE = ""
AUTO_SYNC_LAST_ASSETS_SIGNATURE = ""
AUTO_SYNC_LAST_LOGS_SIGNATURE = ""
AUTO_SYNC_SUSPENDED = False


def get_assets_sync_signature() -> str:
    if not DB_PATH.exists():
        return "empty"
    with db() as conn:
        row = conn.execute("SELECT COUNT(*) AS count_assets, COALESCE(MAX(updated_at), '') AS last_update FROM assets").fetchone()
    return f"{row['count_assets']}|{row['last_update']}"


def get_auto_sync_signature() -> str:
    return f"assets={get_assets_sync_signature()}|logs={get_logs_sync_signature()}"


def start_auto_excel_sync(interval_seconds: int = 1) -> None:
    """Lance la synchronisation automatique sans écrire inutilement dans Excel.

    La boucle vérifie les changements toutes les secondes, mais elle ne réécrit
    que ce qui a réellement changé : les matériels, les logs ou l'instantané de sauvegarde.
    """
    global AUTO_SYNC_STARTED, AUTO_SYNC_LAST_SIGNATURE, AUTO_SYNC_LAST_ASSETS_SIGNATURE, AUTO_SYNC_LAST_LOGS_SIGNATURE
    if AUTO_SYNC_STARTED:
        return
    AUTO_SYNC_STARTED = True

    def worker() -> None:
        global AUTO_SYNC_LAST_SIGNATURE, AUTO_SYNC_LAST_ASSETS_SIGNATURE, AUTO_SYNC_LAST_LOGS_SIGNATURE, AUTO_SYNC_LAST_ERROR
        last_backup_ts = 0.0
        last_backup_log_ts = 0.0
        last_logged_signature = ""
        while True:
            time.sleep(interval_seconds)
            if AUTO_SYNC_SUSPENDED:
                continue
            try:
                assets_signature = get_assets_sync_signature()
                logs_signature = get_logs_sync_signature()
                assets_changed = assets_signature != AUTO_SYNC_LAST_ASSETS_SIGNATURE
                logs_changed = logs_signature != AUTO_SYNC_LAST_LOGS_SIGNATURE
                signature = f"assets={assets_signature}|logs={logs_signature}"
                changed = assets_changed or logs_changed
                backup_result = {"files": []}

                if assets_changed:
                    sync_all_assets_to_excel()
                    AUTO_SYNC_LAST_ASSETS_SIGNATURE = assets_signature

                if logs_changed:
                    sync_logs_to_excel()
                    AUTO_SYNC_LAST_LOGS_SIGNATURE = logs_signature

                if changed:
                    AUTO_SYNC_LAST_SIGNATURE = signature

                now_ts = time.time()
                should_refresh_backup = changed or (now_ts - last_backup_ts >= 60)
                if should_refresh_backup:
                    backup_result = backup_active_data_snapshot()
                    last_backup_ts = now_ts

                should_log_backup = changed or (signature != last_logged_signature) or (now_ts - last_backup_log_ts >= 60)
                if should_log_backup:
                    write_app_log(
                        "auto_backup_snapshot",
                        "backup",
                        "auto_1s_latest",
                        f"Sauvegarde automatique active : {len(backup_result.get('files', []))} fichier(s) actualisé(s)",
                        username="system",
                        role="system",
                    )
                    logs_signature_after = get_logs_sync_signature()
                    if logs_signature_after != AUTO_SYNC_LAST_LOGS_SIGNATURE:
                        sync_logs_to_excel()
                        AUTO_SYNC_LAST_LOGS_SIGNATURE = logs_signature_after
                    AUTO_SYNC_LAST_SIGNATURE = f"assets={AUTO_SYNC_LAST_ASSETS_SIGNATURE}|logs={AUTO_SYNC_LAST_LOGS_SIGNATURE}"
                    last_backup_log_ts = now_ts
                    last_logged_signature = AUTO_SYNC_LAST_SIGNATURE
                    mark_auto_sync_ok()
            except Exception as exc:
                with AUTO_SYNC_STATE_LOCK:
                    AUTO_SYNC_LAST_ERROR = str(exc)
                safe_log(f"Synchronisation/sauvegarde automatique impossible, nouvel essai au prochain cycle : {exc}")
                try:
                    now_ts = time.time()
                    if now_ts - last_backup_ts >= 60:
                        backup_active_data_snapshot()
                        last_backup_ts = now_ts
                except Exception as backup_exc:
                    safe_log(f"Sauvegarde automatique impossible après erreur de sync : {backup_exc}")

    threading.Thread(target=worker, daemon=True, name="nexvandal-excel-sync").start()

def get_reference_by_id(sheet_name: str, item_id: int | None) -> dict[str, Any] | None:
    if item_id is None:
        return None
    for item in read_excel_sheet(sheet_name):
        try:
            if int(item.get("id")) == int(item_id):
                return item
        except (TypeError, ValueError):
            continue
    return None


def get_references_index(sheet_name: str) -> dict[int, dict[str, Any]]:
    out: dict[int, dict[str, Any]] = {}
    for item in read_excel_sheet(sheet_name):
        try:
            out[int(item["id"])] = item
        except (KeyError, TypeError, ValueError):
            continue
    return out


def enrich_rule(rule: dict[str, Any], models: dict[int, dict[str, Any]] | None = None, suppliers: dict[int, dict[str, Any]] | None = None) -> dict[str, Any]:
    models = models if models is not None else get_references_index("Modeles")
    suppliers = suppliers if suppliers is not None else get_references_index("Fournisseurs")
    model = models.get(int(rule["model_id"])) if rule.get("model_id") else None
    supplier = suppliers.get(int(rule["supplier_id"])) if rule.get("supplier_id") else None
    return {
        **rule,
        "brand": model.get("brand") if model else None,
        "model_name": model.get("model_name") if model else None,
        "category": model.get("category") if model else None,
        "supplier_name": supplier.get("name") if supplier else None,
    }


def next_customer_code(conn: sqlite3.Connection) -> str:
    """Code client : AAMM + numéro client sur 3 chiffres minimum.

    Exemple : juin 2026 + client n°20 => 2606020.
    """
    next_id = conn.execute("SELECT COALESCE(MAX(id), 0) + 1 AS next_id FROM customers").fetchone()["next_id"]
    prefix = date.today().strftime("%y%m")
    return f"{prefix}{int(next_id):03d}"


def get_customer_by_id(customer_id: int | None, conn: sqlite3.Connection | None = None) -> dict[str, Any] | None:
    if not customer_id:
        return None
    if conn is not None:
        row = conn.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
        return dict(row) if row else None
    with db() as c:
        row = c.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
        return dict(row) if row else None


def customer_display_name(customer: dict[str, Any] | None) -> str | None:
    if not customer:
        return None
    company = str(customer.get("company") or "").strip()
    name = str(customer.get("name") or "").strip()
    if company and name:
        return f"{company} - {name}"
    return company or name or None


