def get_assets_for_customer(conn: sqlite3.Connection, customer_id: int | None, exclude_asset_id: int | None = None) -> list[dict[str, Any]]:
    """Retourne les autres matériels liés au même client, sans recursion lourde."""
    if not customer_id:
        return []
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    rows = conn.execute(
        """
        SELECT id, asset_code, serial_number_raw, status, customer_id, sale_date,
               purchase_date, purchase_price_eur, warranty_end_date, model_id, supplier_id,
               teamviewer_id, teamviewer_password, return_reason, updated_at
        FROM assets
        WHERE customer_id = ?
          AND (? IS NULL OR id <> ?)
        ORDER BY updated_at DESC, id DESC
        LIMIT 50
        """,
        (customer_id, exclude_asset_id, exclude_asset_id),
    ).fetchall()
    out: list[dict[str, Any]] = []
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        out.append(enrich_asset_image_fields({
            **asset,
            "brand": model.get("brand") if model else "Modèle supprimé du référentiel",
            "model_name": model.get("model_name") if model else "",
            "category": model.get("category") if model else "",
            "supplier_name": supplier.get("name") if supplier else None,
            "status_label": excel_safe_status_label(asset.get("status")),
                "return_reason_label": return_reason_label(asset.get("return_reason")),
        }))
    return out


def get_asset_full(conn: sqlite3.Connection, asset_id: int) -> dict[str, Any]:
    row = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="Matériel introuvable")
    asset = dict(row)
    model = get_reference_by_id("Modeles", asset.get("model_id"))
    supplier = get_reference_by_id("Fournisseurs", asset.get("supplier_id"))
    customer = get_customer_by_id(asset.get("customer_id"), conn)
    result = {
        **asset,
        "brand": model.get("brand") if model else "Modèle supprimé du référentiel",
        "model_name": model.get("model_name") if model else "",
        "category": model.get("category") if model else "",
        "supplier_name": supplier.get("name") if supplier else None,
        "supplier_email": supplier.get("email") if supplier else None,
        "supplier_phone": supplier.get("phone") if supplier else None,
        "customer_code": customer.get("customer_code") if customer else None,
        "customer_display_name": customer_display_name(customer),
        "customer_company": customer.get("company") if customer else None,
        "customer_email": customer.get("email") if customer else None,
        "customer_phone": customer.get("phone") if customer else None,
        "customer_address": customer.get("address") if customer else None,
        "customer_notes": customer.get("notes") if customer else None,
        "other_customer_assets": get_assets_for_customer(conn, asset.get("customer_id"), asset_id),
        "return_reason_label": return_reason_label(asset.get("return_reason")),
    }
    return enrich_asset_image_fields(result)


def next_asset_code(conn: sqlite3.Connection) -> str:
    next_id = conn.execute("SELECT COALESCE(MAX(id), 0) + 1 AS next_id FROM assets").fetchone()["next_id"]
    return f"CLYO-STOCK-{next_id:06d}"


def compute_warranty_end(model_id: int, purchase_date: str | None) -> str | None:
    if not purchase_date:
        return None
    model = get_reference_by_id("Modeles", model_id)
    months = int(model.get("default_warranty_months") or 24) if model else 24
    try:
        d = date.fromisoformat(purchase_date)
        return (d + relativedelta(months=months)).isoformat()
    except ValueError:
        return None


def get_model_default_price(model_id: int | None) -> float | None:
    if not model_id:
        return None
    with db() as conn:
        row = conn.execute("SELECT default_price_eur FROM model_prices WHERE model_id = ?", (int(model_id),)).fetchone()
    if not row or row["default_price_eur"] is None:
        return None
    try:
        return float(row["default_price_eur"])
    except (TypeError, ValueError):
        return None


def set_model_default_price(model_id: int | None, price: float | None) -> None:
    if not model_id or price is None:
        return
    with db() as conn:
        conn.execute(
            """
            INSERT INTO model_prices(model_id, default_price_eur, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(model_id) DO UPDATE SET
                default_price_eur = excluded.default_price_eur,
                updated_at = excluded.updated_at
            """,
            (int(model_id), float(price), now_iso()),
        )


def enrich_model_prices(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    prices: dict[int, float | None] = {}
    with db() as conn:
        for row in conn.execute("SELECT model_id, default_price_eur FROM model_prices").fetchall():
            try:
                prices[int(row["model_id"])] = float(row["default_price_eur"]) if row["default_price_eur"] is not None else None
            except (TypeError, ValueError):
                pass
    enriched = []
    for item in rows:
        try:
            model_id = int(item.get("id"))
        except (TypeError, ValueError):
            model_id = 0
        enriched.append({**item, "default_price_eur": prices.get(model_id)})
    return enriched


def default_purchase_date() -> str:
    return date.today().isoformat()


def hash_password(password: str, salt: str | None = None) -> tuple[str, str]:
    salt = salt or secrets.token_hex(16)
    digest = hashlib.sha256((salt + password).encode("utf-8")).hexdigest()
    return salt, digest


def validate_pin_password(value: str | None, label: str = "mot de passe") -> str:
    code = str(value or "").strip()
    if len(code) < 4:
        raise HTTPException(status_code=400, detail=f"Le {label} doit contenir au minimum 4 caractères.")
    return code


def random_pin_code() -> str:
    return f"{secrets.randbelow(10000):04d}"


def normalize_role(role: str, is_admin: bool = False) -> tuple[str, int]:
    clean = (role or "").strip().lower()
    if clean in {"superadmin", "super_admin", "super administrateur"}:
        return "superadmin", 1
    if clean in {"admin", "administrateur", "administrator"}:
        return "administrateur", 1
    # Tous les autres rôles sont traités en lecture seule.
    return "lecteur", 0


def user_is_superadmin(user: dict[str, Any]) -> bool:
    return str(user.get("role") or "").lower() == "superadmin"


def user_can_write_assets(user: dict[str, Any]) -> bool:
    return str(user.get("role") or "").lower() in {"administrateur", "superadmin"}


def require_superadmin(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    if not user_is_superadmin(user):
        raise HTTPException(status_code=403, detail="Droits superadmin requis")
    return user


def require_asset_write(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    if not user_can_write_assets(user):
        raise HTTPException(status_code=403, detail="Compte en lecture seule : modification non autorisée")
    return user




def hash_token(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


def session_expiry_iso() -> str:
    return (datetime.now() + timedelta(minutes=SESSION_TIMEOUT_MINUTES)).isoformat(timespec="seconds")


def ensure_superadmin_user() -> None:
    """Crée le compte superadmin demandé si absent, sans supprimer les comptes existants."""
    salt, digest = hash_password(SUPERADMIN_PASSWORD)
    with db() as conn:
        existing = conn.execute(
            "SELECT id FROM app_users WHERE LOWER(username) = LOWER(?)",
            (SUPERADMIN_USERNAME,),
        ).fetchone()
        if existing:
            conn.execute(
                "UPDATE app_users SET password_salt = ?, password_hash = ?, role = 'superadmin', is_admin = 1, must_change_password = 0 WHERE id = ?",
                (salt, digest, existing["id"]),
            )
            return
        conn.execute(
            """
            INSERT INTO app_users(username, password_salt, password_hash, role, is_admin, birth_date, must_change_password, created_at)
            VALUES (?, ?, ?, 'superadmin', 1, NULL, 0, ?)
            """,
            (SUPERADMIN_USERNAME, salt, digest, now_iso()),
        )


def verify_password(password: str, salt: str, expected_hash: str) -> bool:
    _, digest = hash_password(password, salt)
    return secrets.compare_digest(digest, expected_hash)


def create_session(user_id: int) -> str:
    token = secrets.token_urlsafe(48)
    current = now_iso()
    expires = session_expiry_iso()
    with db() as conn:
        conn.execute("DELETE FROM app_sessions WHERE expires_at < ?", (current,))
        conn.execute(
            """
            INSERT INTO app_sessions(token_hash, user_id, created_at, last_activity_at, expires_at)
            VALUES (?, ?, ?, ?, ?)
            """,
            (hash_token(token), user_id, current, current, expires),
        )
    return token


def get_user_from_session_token(token: str | None, touch: bool = True) -> dict[str, Any] | None:
    if not token:
        return None
    current = now_iso()
    token_digest = hash_token(token)
    with db() as conn:
        row = conn.execute(
            """
            SELECT s.id AS session_id, s.expires_at,
                   u.id, u.username, u.role, u.is_admin, u.birth_date, u.profile_photo_data_url, u.must_change_password, u.created_at
            FROM app_sessions s
            JOIN app_users u ON u.id = s.user_id
            WHERE s.token_hash = ?
            """,
            (token_digest,),
        ).fetchone()
        if not row:
            return None
        if str(row["expires_at"] or "") < current:
            conn.execute("DELETE FROM app_sessions WHERE id = ?", (row["session_id"],))
            return None
        if touch:
            conn.execute(
                "UPDATE app_sessions SET last_activity_at = ?, expires_at = ? WHERE id = ?",
                (current, session_expiry_iso(), row["session_id"]),
            )
        return {
            "id": row["id"],
            "username": row["username"],
            "role": row["role"],
            "is_admin": bool(row["is_admin"]),
            "must_change_password": bool(row["must_change_password"]),
            "profile_photo_data_url": row["profile_photo_data_url"] if "profile_photo_data_url" in row.keys() else None,
            "created_at": row["created_at"],
        }


def get_request_user(request: Request, touch: bool = True) -> dict[str, Any] | None:
    user = getattr(request.state, "user", None)
    if user:
        return user
    return get_user_from_session_token(request.cookies.get(SESSION_COOKIE_NAME), touch=touch)


def require_admin(request: Request) -> dict[str, Any]:
    # Compatibilité : administrateur ou superadmin.
    return require_asset_write(request)


@app.middleware("http")
async def require_login_middleware(request: Request, call_next):
    path = request.url.path
    if path in {"/", "/api/health", "/api/auth/login", "/api/auth/usernames", "/api/auth/me", "/api/heartbeat", "/favicon.ico", "/api/setup/state", "/api/setup/use-existing", "/api/setup/create-new", "/api/setup/browse-existing-base", "/api/setup/browse-new-base-location", "/api/setup/use-sql", "/api/sql/test", "/api/sql/browse-old-base", "/api/sql/import-old-base"}:
        return await call_next(request)
    if path.startswith("/api/auth/"):
        return await call_next(request)
    if path.startswith("/api/") or path == "/referentiel":
        try:
            user = get_user_from_session_token(request.cookies.get(SESSION_COOKIE_NAME), touch=True)
        except Exception:
            user = None
        if not user:
            return JSONResponse({"detail": "Session expirée ou connexion requise"}, status_code=401)
        request.state.user = user
    return await call_next(request)


