@app.on_event("startup")
def on_startup() -> None:
    global AUTO_SYNC_LAST_SIGNATURE, AUTO_SYNC_LAST_ASSETS_SIGNATURE, AUTO_SYNC_LAST_LOGS_SIGNATURE
    try:
        ensure_reference_workbook()
    except Exception as exc:
        # Ne pas empêcher le lancement de l'application si Excel est ouvert/verrouillé.
        safe_log(f"Préparation du référentiel Excel impossible au démarrage : {exc}")
    try:
        init_db()
    except Exception as exc:
        safe_log(f"Initialisation SQLite impossible au démarrage : {exc}")
        return
    try:
        migrate_excel_references_to_sqlite()
    except Exception as exc:
        safe_log(f"Migration Excel vers SQLite impossible au démarrage : {exc}")
    for startup_task, label in [
        (ensure_status_defaults, "statuts par défaut"),
        (ensure_return_reason_defaults, "motifs de retour"),
        (ensure_superadmin_user, "compte superadmin"),
    ]:
        try:
            startup_task()
        except Exception as exc:
            safe_log(f"Préparation {label} impossible au démarrage : {exc}")
    try:
        # SQLite est désormais la base principale. Excel reste un export/sauvegarde, non bloquant.
        backup_active_data_snapshot()
        AUTO_SYNC_LAST_ASSETS_SIGNATURE = get_assets_sync_signature()
        AUTO_SYNC_LAST_LOGS_SIGNATURE = get_logs_sync_signature()
        AUTO_SYNC_LAST_SIGNATURE = f"assets={AUTO_SYNC_LAST_ASSETS_SIGNATURE}|logs={AUTO_SYNC_LAST_LOGS_SIGNATURE}"
    except Exception as exc:
        safe_log(f"Synchronisation Excel au démarrage impossible : {exc}")
    try:
        start_auto_excel_sync(15)
    except Exception as exc:
        safe_log(f"Démarrage synchro automatique impossible : {exc}")


