@app.get("/api/update/progress-state")
def update_progress_state() -> dict[str, Any]:
    """État lisible par la page de jauge pendant une mise à jour."""
    log_candidates = []
    for candidate in (APP_DIR / "update_autobuild.log", FIXED_APP_INSTALL_DIR / "update_autobuild.log"):
        if candidate not in log_candidates:
            log_candidates.append(candidate)
    lines: list[str] = []
    log_path = log_candidates[0]
    for candidate in log_candidates:
        if candidate.exists():
            log_path = candidate
            try:
                content = candidate.read_text(encoding="utf-8", errors="ignore")
                lines = content.splitlines()[-100:]
            except Exception as exc:
                lines = [f"Lecture du log impossible : {exc}"]
            break

    joined = "\n".join(lines).lower()
    percent = 6
    status = "Préparation de la mise à jour..."
    failed = False

    markers = [
        ("mise a jour automatique demandee", 8, "Mise à jour demandée."),
        ("sauvegarde obligatoire avant mise", 14, "Sauvegarde de sécurité obligatoire en cours."),
        ("sauvegarde obligatoire validée", 18, "Sauvegarde de sécurité validée."),
        ("ancienne application conservee active", 12, "Ancienne version maintenue ouverte pour alimenter la jauge."),
        ("lancement du build exe automatique", 20, "Updater autonome lancé."),
        ("creation de l'environnement python", 28, "Création / vérification de l'environnement Python."),
        ("installation des dependances", 38, "Installation des dépendances."),
        ("installation des dépendances", 38, "Installation des dépendances."),
        ("compilation de l'exe", 55, "Compilation de l'EXE en cours."),
        ("compilation de l exe", 55, "Compilation de l'EXE en cours."),
        ("building exe", 62, "Construction PyInstaller en cours."),
        ("exe pret", 74, "EXE portable généré."),
        ("exe prêt", 74, "EXE portable généré."),
        ("build exe termine", 78, "Build EXE terminé."),
        ("arret de l ancienne application", 84, "Fermeture de l'ancienne application."),
        ("remplacement de l application courante", 90, "Remplacement des fichiers applicatifs."),
        ("relance de la nouvelle version", 96, "Relance de la nouvelle version."),
        ("lancement de l exe compile", 96, "Lancement de la nouvelle version."),
        ("nouvelle version lancee", 98, "Nouvelle version lancée."),
        ("mise_a_jour_terminee", 100, "Mise à jour terminée."),
        ("mise a jour terminee", 100, "Mise à jour terminée."),
    ]
    for needle, pct, label in markers:
        if needle in joined:
            percent = max(percent, pct)
            status = label

    done = ("mise_a_jour_terminee" in joined) or ("mise a jour terminee" in joined)
    if done:
        percent = 100
        status = "Mise à jour terminée. Ouverture de la nouvelle version..."
    if "echec update automatique" in joined or ("failed" in joined and "error" in joined):
        failed = True
        percent = max(percent, 99)
        status = "Erreur pendant la mise à jour. Consulte update_autobuild.log."

    return {
        "status": "failed" if failed else ("done" if done else "running"),
        "percent": percent,
        "message": status,
        "app_version": APP_VERSION,
        "log_exists": log_path.exists(),
        "log_path": str(log_path),
        "lines": [str(line) for line in lines[-18:]],
        "time": datetime.now().isoformat(timespec="seconds"),
    }



