@app.post("/api/setup/use-existing")
async def setup_use_existing(request: Request) -> dict[str, Any]:
    """Utilise un ancien dossier de données comme base active.

    La lecture du JSON est volontairement manuelle pour éviter les erreurs FastAPI
    422 peu lisibles quand le navigateur envoie un corps vide ou mal formé.
    En cas d'échec, l'utilisateur reçoit maintenant la cause exacte au lieu du
    message générique "Action impossible".
    """
    try:
        payload_json = await request.json()
        if not isinstance(payload_json, dict):
            payload_json = {}
    except Exception:
        payload_json = {}

    old_base_path = payload_json.get("old_base_path") or payload_json.get("path")
    try:
        import_result = import_existing_base_from_path(old_base_path)
        warnings = list(import_result.get("warnings") or [])
        try:
            ensure_reference_workbook()
        except Exception as exc:
            warnings.append(f"Référentiel Excel non préparé immédiatement : {exc}")
            safe_log(f"Préparation Excel après récupération directe impossible : {exc}")
        init_db()
        ensure_superadmin_user()
        try:
            existing_payload = _PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7753(DATA_DIR)
            if reference_payload_has_content_v7753(existing_payload):
                save_application_reference_store_v7753(existing_payload, reason="use_existing_base_source_of_truth")
        except Exception as exc:
            safe_log(f"Sauvegarde référentiel depuis base existante impossible : {exc}")
        mark_setup_choice("use_existing")
        import_result["warnings"] = warnings
        return {
            "status": "ok",
            "choice": "use_existing",
            "message": "Ancienne base utilisée directement comme dossier principal de travail, sauvegarde et synchronisation.",
            **import_result,
        }
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Impossible d'utiliser cette ancienne base : {exc}")


