@app.post("/api/data/use-existing")
async def data_use_existing(request: Request) -> dict[str, Any]:
    require_superadmin(request)
    try:
        payload_json = await request.json()
        if not isinstance(payload_json, dict):
            payload_json = {}
    except Exception:
        payload_json = {}
    old_base_path = payload_json.get("old_base_path") or payload_json.get("path")
    try:
        src = resolve_existing_base_path(old_base_path)
        if src is None:
            raise HTTPException(status_code=400, detail="Le chemin indiqué ne contient pas de base reconnue.")
        src = Path(src).expanduser().resolve()
        selection_info = select_best_data_files_in_base_folder(src)

        markers = ["stock_assets.db", "referentiel_stock.xlsx", "activity_log.jsonl", "qr_codes", "product_images"]
        found = [name for name in markers if (src / name).exists()]
        if not found:
            raise HTTPException(
                status_code=400,
                detail=f"Le dossier choisi ne contient pas de base reconnue. Chemin contrôlé : {src}",
            )

        try:
            probe = src / ".clyo_write_test.tmp"
            probe.write_text("ok", encoding="utf-8")
            probe.unlink(missing_ok=True)
        except Exception as exc:
            raise HTTPException(status_code=400, detail=f"Le dossier sélectionné n'est pas accessible en écriture : {exc}") from exc

        # Correctif V8.0.6 :
        # On ne bascule plus la base active en mémoire pendant la réponse API.
        # Le changement est enregistré pour le prochain démarrage afin d'éviter
        # que le serveur local coupe la connexion avant que le navigateur reçoive le JSON.
        save_active_data_dir(src)
        try:
            append_update_history_event({
                "event": "select_startup_base",
                "version": APP_VERSION,
                "target_folder": str(src),
                "previous_data_folder": str(DATA_DIR),
                "details": "Base sélectionnée comme base de démarrage au prochain lancement.",
            })
        except Exception as exc:
            safe_log(f"Historique changement base démarrage impossible : {exc}")

        return {
            "status": "ok",
            "choice": "use_existing",
            "used_directly": False,
            "requires_restart": True,
            "active_data_folder": str(src),
            "source": str(src),
            "files": found,
            "warnings": selection_info.get("actions", []),
            "message": "Base enregistrée comme base de démarrage. Ferme puis relance l'application pour démarrer dessus.",
        }
    except HTTPException:
        raise
    except Exception as exc:
        safe_log(f"Erreur sélection base de démarrage : {exc}")
        raise HTTPException(status_code=500, detail=f"Impossible de sélectionner cette base de démarrage : {exc}")


@app.post("/api/data/create-new")
async def data_create_new(request: Request) -> dict[str, Any]:
    require_superadmin(request)
    try:
        payload_json = await request.json()
        if not isinstance(payload_json, dict):
            payload_json = {}
    except Exception:
        payload_json = {}
    new_base_path = payload_json.get("new_base_path") or payload_json.get("path")
    try:
        target = resolve_new_base_path(new_base_path)
        validation = validate_new_base_folder(target)
        reference_payload = capture_reference_preserve_payload(DATA_DIR)
        archived_to = None
        existing = validation.get("existing", [])
        if existing:
            stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            archive_root = target / "archives" / f"ancienne_base_{stamp}"
            archive_root.mkdir(parents=True, exist_ok=True)
            for name in existing:
                source = target / name
                if source.exists():
                    try:
                        shutil.move(str(source), str(archive_root / name))
                    except Exception as exc:
                        safe_log(f"Archivage {source} impossible : {exc}")
            archived_to = archive_root

        target.mkdir(parents=True, exist_ok=True)
        preserved = restore_reference_preserve_payload(reference_payload, target)
        save_active_data_dir(target)
        try:
            append_update_history_event({
                "event": "select_new_startup_base",
                "version": APP_VERSION,
                "target_folder": str(target),
                "previous_data_folder": str(DATA_DIR),
                "details": "Nouvelle base sélectionnée comme base de démarrage au prochain lancement avec référentiel conservé.",
                "referentiel_conserve": preserved,
            })
        except Exception as exc:
            safe_log(f"Historique nouvelle base démarrage impossible : {exc}")

        return {
            "status": "ok",
            "choice": "create_new",
            "created": True,
            "requires_restart": True,
            "active_data_folder": str(target),
            "archived_existing_files_to": str(archived_to) if archived_to else None,
            "existing_files_archived": existing,
            "referentiel_conserve": preserved if 'preserved' in locals() else None,
            "warnings": validation.get("warnings", []),
            "message": "Nouvelle base enregistrée dans le dossier clyoStock comme base de démarrage. Ferme puis relance l'application pour démarrer dessus. Le référentiel actuel est conservé.",
        }
    except HTTPException:
        raise
    except Exception as exc:
        safe_log(f"Erreur création base de démarrage : {exc}")
        raise HTTPException(status_code=500, detail=f"Impossible de préparer cette nouvelle base : {exc}")



def normalize_profile_photo_data_url(value: str | None) -> str | None:
    value = str(value or "").strip()
    if not value:
        return None
    if not value.startswith("data:image/"):
        raise HTTPException(status_code=400, detail="Format photo invalide : image requise.")
    if ";base64," not in value:
        raise HTTPException(status_code=400, detail="Format photo invalide.")
    # Limite volontaire pour éviter de gonfler la base SQLite.
    if len(value) > 1_500_000:
        raise HTTPException(status_code=400, detail="Photo trop volumineuse. Utilise une image plus légère.")
    return value


@app.post("/api/auth/login")
def login(payload: LoginPayload, response: Response, request: Request) -> dict[str, Any]:
    username = payload.username.strip()
    with db() as conn:
        row = conn.execute("SELECT * FROM app_users WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
    if not row or not verify_password(payload.password, row["password_salt"], row["password_hash"]):
        write_app_log("login_failed", "user", username, "Échec de connexion", request=request, username=username)
        raise HTTPException(status_code=401, detail="Identifiant ou mot de passe incorrect")
    token = create_session(int(row["id"]))
    write_app_log("login_success", "user", row["id"], "Connexion réussie", request=request, username=row["username"], role=row["role"])
    log_site_connection_once_v7753(request, username=row["username"], role=row["role"])
    response.set_cookie(SESSION_COOKIE_NAME, token, max_age=SESSION_TIMEOUT_MINUTES * 60, httponly=True, samesite="lax")
    role = row["role"]
    return {
        "authenticated": True,
        "username": row["username"],
        "role": role,
        "is_admin": bool(row["is_admin"]),
        "can_write_assets": role in {"administrateur", "superadmin"},
        "is_superadmin": role == "superadmin",
        "must_change_password": bool(row["must_change_password"]),
        "timeout_minutes": SESSION_TIMEOUT_MINUTES,
    }


