@app.post("/api/auth/forgot-password")
def forgot_password(payload: ForgotPasswordPayload, request: Request) -> dict[str, Any]:
    username = payload.username.strip()
    birth_date = payload.birth_date.strip()
    with db() as conn:
        row = conn.execute("SELECT * FROM app_users WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
        if not row or str(row["birth_date"] or "") != birth_date:
            write_app_log("forgot_password_failed", "user", username, "Identifiant ou date de naissance incorrect", request=request, username=username)
            raise HTTPException(status_code=404, detail="Identifiant ou date de naissance incorrect")
        temp_password = random_pin_code()
        salt, digest = hash_password(temp_password)
        conn.execute(
            "UPDATE app_users SET password_salt = ?, password_hash = ?, must_change_password = 1 WHERE id = ?",
            (salt, digest, row["id"]),
        )
    write_app_log("forgot_password_temp_generated", "user", row["id"], "Mot de passe temporaire généré", request=request, username=row["username"], role=row["role"])
    return {
        "temporary_password": temp_password,
        "visible_seconds": 10,
        "warning": "Mot de passe temporaire : il sera visible 10 secondes et devra être changé à la prochaine connexion.",
    }


