@app.get("/api/status-options")
def list_status_options() -> list[dict[str, Any]]:
    ensure_status_defaults()
    rows = read_excel_sheet("Statuts")
    deleted_defaults = load_deleted_status_values()
    if not rows:
        return [
            {"id": idx + 1, "value": value, "label": label, "is_default": 1}
            for idx, (value, label) in enumerate(DEFAULT_STATUS_OPTIONS.items())
            if value not in deleted_defaults
        ]
    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    for row in rows:
        value = str(row.get("value") or "").strip()
        label = str(row.get("label") or "").strip()
        if value == "reserve":
            label = DEFAULT_STATUS_OPTIONS.get("reserve", "Attribué")
        if value and label and value not in seen and value not in deleted_defaults:
            item = dict(row)
            item["value"] = value
            item["label"] = label
            item["is_default"] = int(row.get("is_default") or 0)
            out.append(item)
            seen.add(value)
    return out

