@app.delete("/api/status-options/{status_id}")
def delete_status_option(status_id: int, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    rows = read_excel_sheet("Statuts")
    target = next((row for row in rows if int(row.get("id") or 0) == int(status_id)), None)
    if not target:
        raise HTTPException(status_code=404, detail="Statut introuvable")
    value = str(target.get("value") or "").strip()

    with db() as conn:
        used = conn.execute("SELECT COUNT(*) AS c FROM assets WHERE status = ?", (value,)).fetchone()["c"]
    if used:
        raise HTTPException(
            status_code=400,
            detail=f"Ce statut est utilisé par {used} matériel(s). Supprime ou modifie d'abord les matériels concernés avant de supprimer le statut.",
        )

    deleted_rows = delete_excel_rows("Statuts", "value", value)
    mark_status_value_deleted(value)
    clear_excel_read_cache()
    write_app_log("status_deleted", "status", value, f"Statut supprimé : {target.get('label')} — aucun matériel ne l'utilisait", request=request)
    sync_logs_to_excel()
    return {"status": "deleted", "id": status_id, "value": value, "deleted_rows": deleted_rows, "assets_using_status": used}


