@app.post("/api/users")
def create_user(payload: UserCreate, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    username = payload.username.strip()
    if not username:
        raise HTTPException(status_code=400, detail="Identifiant vide")
    role, is_admin = normalize_role(payload.role, payload.is_admin)
    code = validate_pin_password(payload.password, "code")
    salt, digest = hash_password(code)
    with db() as conn:
        try:
            cur = conn.execute(
                """
                INSERT INTO app_users(username, password_salt, password_hash, role, is_admin, birth_date, must_change_password, created_at)
                VALUES (?, ?, ?, ?, ?, ?, 0, ?)
                """,
                (username, salt, digest, role, is_admin, payload.birth_date, now_iso()),
            )
        except sqlite3.IntegrityError:
            raise HTTPException(status_code=409, detail="Cet identifiant existe déjà")
        row = conn.execute(
            "SELECT id, username, role, is_admin, birth_date, profile_photo_data_url, must_change_password, created_at FROM app_users WHERE id = ?",
            (cur.lastrowid,),
        ).fetchone()
        result = dict(row)
    write_app_log("user_created", "user", result.get("id"), f"Identifiant créé : {result.get('username')} ({result.get('role')})", request=request)
    return result


def count_superadmins(conn: sqlite3.Connection) -> int:
    return int(conn.execute("SELECT COUNT(*) AS c FROM app_users WHERE role = 'superadmin'").fetchone()["c"] or 0)


@app.patch("/api/users/{user_id}")
def update_user(user_id: int, payload: UserUpdate, request: Request) -> dict[str, Any]:
    current_user = require_superadmin(request)
    with db() as conn:
        existing = conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Identifiant introuvable")

        username = payload.username.strip() if payload.username is not None else existing["username"]
        if not username:
            raise HTTPException(status_code=400, detail="Identifiant vide")

        duplicate = conn.execute(
            "SELECT id FROM app_users WHERE LOWER(username) = LOWER(?) AND id <> ?",
            (username, user_id),
        ).fetchone()
        if duplicate:
            raise HTTPException(status_code=409, detail="Cet identifiant existe déjà")

        role_input = payload.role if payload.role is not None else existing["role"]
        role, is_admin = normalize_role(role_input, bool(payload.is_admin) if payload.is_admin is not None else bool(existing["is_admin"]))

        if existing["role"] == "superadmin" and role != "superadmin" and count_superadmins(conn) <= 1:
            raise HTTPException(status_code=400, detail="Impossible de retirer le dernier compte superadmin")

        birth_date = payload.birth_date if payload.birth_date is not None else existing["birth_date"]

        if payload.password:
            code = validate_pin_password(payload.password, "code")
            salt, digest = hash_password(code)
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, password_salt = ?, password_hash = ?, role = ?, is_admin = ?, birth_date = ?, must_change_password = 0
                WHERE id = ?
                """,
                (username, salt, digest, role, is_admin, birth_date, user_id),
            )
        else:
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, role = ?, is_admin = ?, birth_date = ?
                WHERE id = ?
                """,
                (username, role, is_admin, birth_date, user_id),
            )

        row = conn.execute(
            "SELECT id, username, role, is_admin, birth_date, must_change_password, created_at FROM app_users WHERE id = ?",
            (user_id,),
        ).fetchone()
        result = dict(row)
    write_app_log("user_updated", "user", user_id, f"Identifiant modifié : {result.get('username')} ({result.get('role')})", request=request)
    return result


@app.delete("/api/users/{user_id}")
def delete_user(user_id: int, request: Request) -> dict[str, Any]:
    current_user = require_superadmin(request)
    if int(current_user["id"]) == int(user_id):
        raise HTTPException(status_code=400, detail="Impossible de supprimer le compte actuellement connecté")
    with db() as conn:
        existing = conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Identifiant introuvable")
        if existing["role"] == "superadmin" and count_superadmins(conn) <= 1:
            raise HTTPException(status_code=400, detail="Impossible de supprimer le dernier compte superadmin")
        deleted_username = existing["username"]
        conn.execute("DELETE FROM app_sessions WHERE user_id = ?", (user_id,))
        conn.execute("DELETE FROM app_users WHERE id = ?", (user_id,))
    write_app_log("user_deleted", "user", user_id, f"Identifiant supprimé : {deleted_username}", request=request)
    return {"status": "deleted", "id": user_id}


@app.get("/api/dashboard")
def dashboard() -> dict[str, Any]:
    """Retourne les indicateurs principaux du tableau de bord."""
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    rules = read_excel_sheet("Regles")
    today = date.today()
    soon_limit = today + timedelta(days=30)

    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, asset_code, serial_number_raw, status, location, client_name, customer_id, sale_date, image_url, image_local_path, notes,
                   teamviewer_id, teamviewer_password, return_reason,
                   purchase_date, purchase_price_eur, warranty_end_date, created_at, updated_at, model_id, supplier_id
            FROM assets
            ORDER BY updated_at DESC, id DESC
            """
        ).fetchall()
        customer_rows = conn.execute("SELECT * FROM customers").fetchall()

    customers_by_id = {int(row["id"]): dict(row) for row in customer_rows}
    assets: list[dict[str, Any]] = []
    status_options_map = get_status_options_map()
    by_status: dict[str, int] = {key: 0 for key in status_options_map}
    by_category: dict[str, int] = {}
    category_stats: dict[str, dict[str, Any]] = {}
    model_stock_counts: dict[int, dict[str, Any]] = {}
    warranty_soon = 0
    warranty_expired = 0
    created_last_7_days = 0
    updated_last_7_days = 0
    total_value_eur = 0.0
    in_stock_value_eur = 0.0
    active_value_eur = 0.0
    sold_by_customer: dict[str, dict[str, Any]] = {}
    reserved_by_customer: dict[str, dict[str, Any]] = {}
    return_by_supplier: dict[str, dict[str, Any]] = {}
    limit_7 = datetime.now() - timedelta(days=7)

    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        category_raw = str(model.get("category") or "Non classé") if model else "Modèle supprimé"
        category = canonical_category_label(category_raw)
        status = str(asset.get("status") or "")
        by_status[status] = by_status.get(status, 0) + 1
        by_category[category] = by_category.get(category, 0) + 1
        try:
            price = float(asset.get("purchase_price_eur") or 0)
        except (TypeError, ValueError):
            price = 0.0
        cat_stat = category_stats.setdefault(category, {"category": category, "count": 0, "in_stock": 0, "sold": 0, "stock_value_eur": 0.0, "total_value_eur": 0.0})
        cat_stat["count"] += 1
        cat_stat["total_value_eur"] += price
        if status == "en_stock":
            cat_stat["in_stock"] += 1
            cat_stat["stock_value_eur"] += price
        if status == "vendu":
            cat_stat["sold"] += 1
            customer = customers_by_id.get(int(asset.get("customer_id") or 0)) if asset.get("customer_id") else None
            customer_key = customer_display_name(customer) or asset.get("client_name") or "Client non renseigné"
            customer_code = customer.get("customer_code") if customer else None
            sold_group = sold_by_customer.setdefault(str(customer_key), {
                "customer": str(customer_key),
                "customer_code": customer_code,
                "count": 0,
                "total_value_eur": 0.0,
                "assets": [],
            })
            sold_group["count"] += 1
            sold_group["total_value_eur"] += price
            sold_group["assets"].append({
                "asset_code": asset.get("asset_code"),
                "serial_number_raw": asset.get("serial_number_raw"),
                "brand": model.get("brand") if model else "Modèle supprimé",
                "model_name": model.get("model_name") if model else "",
                "category": category,
                "sale_date": asset.get("sale_date"),
                "purchase_price_eur": price,
            })
        if status == "reserve":
            customer = customers_by_id.get(int(asset.get("customer_id") or 0)) if asset.get("customer_id") else None
            customer_key = customer_display_name(customer) or asset.get("client_name") or "Client non renseigné"
            customer_code = customer.get("customer_code") if customer else None
            reserved_group = reserved_by_customer.setdefault(str(customer_key), {
                "customer": str(customer_key),
                "customer_code": customer_code,
                "count": 0,
                "total_value_eur": 0.0,
                "assets": [],
            })
            reserved_group["count"] += 1
            reserved_group["total_value_eur"] += price
            reserved_group["assets"].append({
                "asset_code": asset.get("asset_code"),
                "serial_number_raw": asset.get("serial_number_raw"),
                "brand": model.get("brand") if model else "Modèle supprimé",
                "model_name": model.get("model_name") if model else "",
                "category": category,
                "sale_date": asset.get("sale_date"),
                "purchase_price_eur": price,
                "teamviewer_id": asset.get("teamviewer_id"),
            })
        if status == "retour_fournisseur":
            supplier_name = supplier.get("name") if supplier else "Fournisseur non renseigné"
            return_group = return_by_supplier.setdefault(str(supplier_name), {
                "supplier": str(supplier_name),
                "count": 0,
                "by_reason": {},
                "assets": [],
            })
            return_group["count"] += 1
            reason_label = return_reason_label(asset.get("return_reason")) or "Non renseigné"
            return_group["by_reason"][reason_label] = int(return_group["by_reason"].get(reason_label, 0)) + 1
            return_group["assets"].append({
                "asset_code": asset.get("asset_code"),
                "serial_number_raw": asset.get("serial_number_raw"),
                "brand": model.get("brand") if model else "Modèle supprimé",
                "model_name": model.get("model_name") if model else "",
                "category": category,
                "return_reason": asset.get("return_reason"),
                "return_reason_label": return_reason_label(asset.get("return_reason")),
                "updated_at": asset.get("updated_at"),
            })
        if asset.get("model_id"):
            try:
                mid = int(asset.get("model_id"))
                model_stat = model_stock_counts.setdefault(mid, {"model_id": mid, "brand": model.get("brand") if model else "", "model_name": model.get("model_name") if model else "", "category": category, "in_stock": 0, "total": 0})
                model_stat["total"] += 1
                if status == "en_stock":
                    model_stat["in_stock"] += 1
            except (TypeError, ValueError):
                pass
        total_value_eur += price
        if status == "en_stock":
            in_stock_value_eur += price
        if status == "en_stock":
            active_value_eur += price

        warranty_raw = asset.get("warranty_end_date")
        if warranty_raw:
            try:
                warranty_date = date.fromisoformat(str(warranty_raw))
                if warranty_date < today:
                    warranty_expired += 1
                elif warranty_date <= soon_limit:
                    warranty_soon += 1
            except ValueError:
                pass

        for field, counter_name in (("created_at", "created"), ("updated_at", "updated")):
            raw = asset.get(field)
            if raw:
                try:
                    dt = datetime.fromisoformat(str(raw))
                    if dt >= limit_7:
                        if counter_name == "created":
                            created_last_7_days += 1
                        else:
                            updated_last_7_days += 1
                except ValueError:
                    pass

        assets.append(
            {
                **asset,
                "brand": model.get("brand") if model else "Modèle supprimé",
                "model_name": model.get("model_name") if model else "",
                "category": category,
                "supplier_name": supplier.get("name") if supplier else None,
                "status_label": excel_safe_status_label(status),
            }
        )

    total_assets = len(assets)
    in_stock = by_status.get("en_stock", 0)
    reserved_count = 0
    deployed = by_status.get("retour_fournisseur", 0)
    sav = 0
    sold_count = by_status.get("vendu", 0)

    status_breakdown = [
        {"value": key, "label": label, "count": by_status.get(key, 0)}
        for key, label in status_options_map.items()
        if by_status.get(key, 0) > 0
    ]
    category_breakdown = []
    for key, value in sorted(by_category.items(), key=lambda item: (-item[1], item[0])):
        stats = category_stats.get(key, {})
        category_breakdown.append({
            "category": key,
            "count": value,
            "in_stock": int(stats.get("in_stock") or 0),
            "sold": int(stats.get("sold") or 0),
            "stock_value_eur": round(float(stats.get("stock_value_eur") or 0), 2),
            "total_value_eur": round(float(stats.get("total_value_eur") or 0), 2),
            "low_stock": int(stats.get("in_stock") or 0) <= 5,
        })

    low_stock_alerts = [
        {**item, "stock_value_eur": round(float(item.get("stock_value_eur") or 0), 2), "total_value_eur": round(float(item.get("total_value_eur") or 0), 2)}
        for item in model_stock_counts.values()
        if int(item.get("in_stock") or 0) <= 5
    ]
    low_stock_alerts.sort(key=lambda item: (int(item.get("in_stock") or 0), str(item.get("brand") or ""), str(item.get("model_name") or "")))

    return {
        "total_assets": total_assets,
        "in_stock": in_stock,
        "stock_value_eur": round(in_stock_value_eur, 2),
        "total_value_eur": round(total_value_eur, 2),
        "active_value_eur": round(active_value_eur, 2),
        "sold_count": sold_count,
        "reserved_count": reserved_count,
        "reserved_by_customer": [
            {**item, "total_value_eur": round(float(item.get("total_value_eur") or 0), 2), "assets": item.get("assets", [])[:12]}
            for item in sorted(reserved_by_customer.values(), key=lambda x: (-int(x.get("count") or 0), str(x.get("customer") or "")))
        ][:8],
        "sold_by_customer": [
            {**item, "total_value_eur": round(float(item.get("total_value_eur") or 0), 2), "assets": item.get("assets", [])[:12]}
            for item in sorted(sold_by_customer.values(), key=lambda x: (-int(x.get("count") or 0), str(x.get("customer") or "")))
        ][:8],
        "deployed": deployed,
        "return_supplier_count": deployed,
        "return_by_supplier": [
            {**item, "assets": item.get("assets", [])[:12]}
            for item in sorted(return_by_supplier.values(), key=lambda x: (-int(x.get("count") or 0), str(x.get("supplier") or "")))
        ][:8],
        "sav": sav,
        "warranty_soon": warranty_soon,
        "warranty_expired": warranty_expired,
        "created_last_7_days": created_last_7_days,
        "updated_last_7_days": updated_last_7_days,
        "suppliers_count": len(suppliers),
        "models_count": len(models),
        "rules_count": len(rules),
        "statuses_count": len(status_options_map),
        "return_reasons_count": len(get_return_reasons_map()),
        "status_breakdown": status_breakdown,
        "category_breakdown": category_breakdown[:8],
        "low_stock_alerts": low_stock_alerts[:12],
        "recent_assets": assets[:10],
    }


@app.get("/api/dashboard/category/{category_name}")
def dashboard_category_detail(category_name: str) -> dict[str, Any]:
    category_name = urllib.parse.unquote(category_name).strip()
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, asset_code, serial_number_raw, status, location, client_name, customer_id, sale_date, image_url, image_local_path, notes,
                   teamviewer_id, teamviewer_password, return_reason,
                   purchase_date, purchase_price_eur, warranty_end_date, created_at, updated_at, model_id, supplier_id
            FROM assets
            ORDER BY updated_at DESC, id DESC
            """
        ).fetchall()
    out: list[dict[str, Any]] = []
    stock_value = 0.0
    total_value = 0.0
    in_stock = 0
    sold = 0
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        category_raw = str(model.get("category") or "Non classé") if model else "Modèle supprimé"
        category = canonical_category_label(category_raw)
        if category != canonical_category_label(category_name):
            continue
        price = float(asset.get("purchase_price_eur") or 0)
        total_value += price
        if asset.get("status") == "en_stock":
            in_stock += 1
            stock_value += price
        if asset.get("status") == "vendu":
            sold += 1
        out.append(enrich_asset_image_fields({
            **asset,
            "brand": model.get("brand") if model else "Modèle supprimé",
            "model_name": model.get("model_name") if model else "",
            "category": category,
            "supplier_name": supplier.get("name") if supplier else None,
            "status_label": excel_safe_status_label(asset.get("status")),
                "return_reason_label": return_reason_label(asset.get("return_reason")),
        }))
    return {
        "category": canonical_category_label(category_name),
        "count": len(out),
        "in_stock": in_stock,
        "sold": sold,
        "stock_value_eur": round(stock_value, 2),
        "total_value_eur": round(total_value, 2),
        "low_stock": in_stock <= 5,
        "rows": sort_assets_category_model_v7741(out),
    }


@app.get("/api/dashboard/status/{status_value}")
def dashboard_status_detail(status_value: str) -> dict[str, Any]:
    """Détail complet d'un statut pour le tableau de bord."""
    status_value = urllib.parse.unquote(status_value).strip()
    status_options_map = get_status_options_map()
    if status_value not in status_options_map:
        raise HTTPException(status_code=404, detail="Statut inconnu")
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, asset_code, serial_number_raw, status, location, client_name, customer_id, sale_date, image_url, image_local_path, notes,
                   teamviewer_id, teamviewer_password, return_reason,
                   purchase_date, purchase_price_eur, warranty_end_date, created_at, updated_at, model_id, supplier_id
            FROM assets
            WHERE status = ?
            ORDER BY updated_at DESC, id DESC
            """,
            (status_value,),
        ).fetchall()
    out: list[dict[str, Any]] = []
    total_value = 0.0
    categories: dict[str, int] = {}
    supplier_counts: dict[str, int] = {}
    customer_count = 0
    warranty_expired = 0
    today = date.today()
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        customer = get_customer_by_id(asset.get("customer_id"))
        category_raw = str(model.get("category") or "Non classé") if model else "Modèle supprimé"
        category = canonical_category_label(category_raw)
        supplier_name = str(supplier.get("name") or "Non renseigné") if supplier else "Non renseigné"
        categories[category] = categories.get(category, 0) + 1
        supplier_counts[supplier_name] = supplier_counts.get(supplier_name, 0) + 1
        if customer:
            customer_count += 1
        try:
            total_value += float(asset.get("purchase_price_eur") or 0)
        except (TypeError, ValueError):
            pass
        if asset.get("warranty_end_date"):
            try:
                if date.fromisoformat(str(asset.get("warranty_end_date"))) < today:
                    warranty_expired += 1
            except ValueError:
                pass
        out.append(enrich_asset_image_fields({**asset, "brand": model.get("brand") if model else "Modèle supprimé", "model_name": model.get("model_name") if model else "", "category": category, "supplier_name": supplier_name, "customer_code": customer.get("customer_code") if customer else None, "customer_display_name": customer_display_name(customer), "customer_company": customer.get("company") if customer else None, "customer_email": customer.get("email") if customer else None, "customer_phone": customer.get("phone") if customer else None, "status_label": excel_safe_status_label(asset.get("status")), "return_reason_label": return_reason_label(asset.get("return_reason"))}))
    return {
        "status": status_value,
        "label": status_options_map[status_value],
        "count": len(out),
        "total_value_eur": round(total_value, 2),
        "customer_count": customer_count,
        "warranty_expired": warranty_expired,
        "categories": sorted([{"category": k, "count": v} for k, v in categories.items()], key=lambda x: (-x["count"], x["category"])),
        "suppliers": sorted([{"supplier": k, "count": v} for k, v in supplier_counts.items()], key=lambda x: (-x["count"], x["supplier"])),
        "rows": sort_assets_category_model_v7741(out),
    }


def enrich_assets_for_table(rows: list[sqlite3.Row]) -> list[dict[str, Any]]:
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    out: list[dict[str, Any]] = []
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        customer = get_customer_by_id(asset.get("customer_id"))
        out.append(enrich_asset_image_fields({**asset, "brand": model.get("brand") if model else "Modèle supprimé", "model_name": model.get("model_name") if model else "", "category": model.get("category") if model else "", "supplier_name": supplier.get("name") if supplier else None, "customer_code": customer.get("customer_code") if customer else None, "customer_display_name": customer_display_name(customer), "customer_company": customer.get("company") if customer else None, "customer_email": customer.get("email") if customer else None, "customer_phone": customer.get("phone") if customer else None, "status_label": excel_safe_status_label(asset.get("status")), "return_reason_label": return_reason_label(asset.get("return_reason"))}))
    return out


@app.get("/api/dashboard/detail/{kind}")
def dashboard_detail(kind: str) -> dict[str, Any]:
    kind = kind.strip().lower()
    if kind == "suppliers":
        return {"title": "Fournisseurs", "columns": ["id", "name", "email", "phone", "website", "created_at"], "rows": read_excel_sheet("Fournisseurs")}
    if kind == "statuses":
        rows = []
        for row in read_excel_sheet("Statuts"):
            item = dict(row)
            if str(item.get("value") or "").strip() == "reserve":
                item["value"] = "attribue"
                item["label"] = DEFAULT_STATUS_OPTIONS.get("reserve", "Attribué")
            rows.append(item)
        return {"title": "Statuts matériel", "columns": ["id", "value", "label", "is_default", "created_at", "updated_at"], "rows": rows}
    if kind in {"returnreasons", "return_reasons", "motifsretour"}:
        ensure_return_reason_defaults()
        return {"title": "Motifs retour fournisseur", "columns": ["id", "value", "label", "is_default", "created_at", "updated_at"], "rows": read_excel_sheet("MotifsRetourFournisseur")}
    if kind == "models":
        return {"title": "Modèles", "columns": ["id", "brand", "model_name", "category", "default_warranty_months", "default_price_eur", "tutorial_url", "created_at"], "rows": enrich_model_prices(read_excel_sheet("Modeles"))}
    if kind == "rules":
        models = get_references_index("Modeles")
        suppliers = get_references_index("Fournisseurs")
        rows = [enrich_rule(rule, models, suppliers) for rule in read_excel_sheet("Regles")]
        return {"title": "Règles de reconnaissance SN", "columns": ["id", "name", "pattern", "brand", "model_name", "supplier_name", "confidence", "created_at"], "rows": rows}
    limit_7 = datetime.now() - timedelta(days=7)
    today = date.today().isoformat()
    with db() as conn:
        if kind == "created7":
            rows = conn.execute("SELECT * FROM assets WHERE created_at >= ? ORDER BY created_at DESC", (limit_7.isoformat(timespec="seconds"),)).fetchall()
            title = "Matériels créés sur 7 jours"
        elif kind == "updated7":
            rows = conn.execute("SELECT * FROM assets WHERE updated_at >= ? ORDER BY updated_at DESC", (limit_7.isoformat(timespec="seconds"),)).fetchall()
            title = "Matériels modifiés sur 7 jours"
        elif kind == "warrantyexpired":
            rows = conn.execute("SELECT * FROM assets WHERE warranty_end_date IS NOT NULL AND warranty_end_date < ? ORDER BY warranty_end_date ASC", (today,)).fetchall()
            title = "Garanties expirées"
        else:
            raise HTTPException(status_code=404, detail="Section inconnue")
    return {"title": title, "columns": ["asset_code", "serial_number_raw", "brand", "model_name", "supplier_name", "purchase_date", "purchase_price_eur", "warranty_end_date", "status_label", "client_name", "updated_at"], "rows": enrich_assets_for_table(rows)}

@app.get("/referentiel")
def download_referentiel(request: Request) -> FileResponse:
    require_superadmin(request)
    ensure_reference_workbook()
    return FileResponse(
        EXCEL_PATH,
        media_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        filename="referentiel_stock.xlsx",
    )


@app.post("/api/open-excel-location")
def open_excel_location(request: Request) -> dict[str, Any]:
    require_superadmin(request)
    ensure_reference_workbook()
    folder = EXCEL_PATH.parent
    try:
        if sys.platform.startswith("win"):
            subprocess.Popen(["explorer", "/select,", str(EXCEL_PATH)])
        elif sys.platform == "darwin":
            subprocess.Popen(["open", str(folder)])
        else:
            subprocess.Popen(["xdg-open", str(folder)])
        write_app_log("open_excel_location", "excel", "referentiel_stock.xlsx", f"Ouverture du dossier Excel : {folder}", request=request)
        return {"status": "ok", "message": "Dossier Excel ouvert.", "excel_path": str(EXCEL_PATH), "folder": str(folder)}
    except Exception as exc:
        return {"status": "manual", "message": "Ouverture automatique impossible sur ce poste.", "excel_path": str(EXCEL_PATH), "folder": str(folder), "error": str(exc)}


