@app.patch("/api/models/{model_id}")
def update_model(model_id: int, payload: ModelCreate, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    rows = read_excel_sheet("Modeles")
    brand = payload.brand.strip().lower()
    model_name = payload.model_name.strip().lower()
    if any(int(row.get("id") or 0) != int(model_id) and str(row.get("brand") or "").strip().lower() == brand and str(row.get("model_name") or "").strip().lower() == model_name for row in rows):
        raise HTTPException(status_code=409, detail="Ce modèle existe déjà")
    model = update_excel_row_by_id("Modeles", model_id, {
        "brand": payload.brand.strip(),
        "model_name": payload.model_name.strip(),
        "category": payload.category,
        "default_warranty_months": payload.default_warranty_months,
        "tutorial_url": payload.tutorial_url,
        "notes": payload.notes,
    })
    set_model_default_price(model_id, payload.default_price_eur)
    model = {**model, "default_price_eur": payload.default_price_eur}
    write_app_log("model_updated", "model", model_id, f"Modèle modifié : {model.get('brand')} {model.get('model_name')}", request=request)
    return model


@app.patch("/api/rules/{rule_id}")
def update_rule(rule_id: int, payload: RuleCreate, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    try:
        re.compile(payload.pattern)
    except re.error as exc:
        raise HTTPException(status_code=400, detail=f"Regex invalide : {exc}")
    if payload.model_id and not get_reference_by_id("Modeles", payload.model_id):
        raise HTTPException(status_code=400, detail="model_id introuvable dans l'onglet Modeles")
    if payload.supplier_id and not get_reference_by_id("Fournisseurs", payload.supplier_id):
        raise HTTPException(status_code=400, detail="supplier_id introuvable dans l'onglet Fournisseurs")
    rule = update_excel_row_by_id("Regles", rule_id, {
        "name": payload.name.strip(),
        "pattern": payload.pattern.strip(),
        "model_id": payload.model_id,
        "supplier_id": payload.supplier_id,
        "confidence": payload.confidence,
        "notes": payload.notes,
    })
    enriched = enrich_rule(rule)
    write_app_log("rule_updated", "rule", rule_id, f"Règle modifiée : {rule.get('name')} / {rule.get('pattern')}", request=request)
    return enriched


def get_or_create_fallback_model(exclude_id: int | None = None) -> dict[str, Any]:
    """Retourne un modèle générique utilisé quand un modèle supprimé était encore lié à des matériels."""
    fallback_brand = "Marque à définir"
    fallback_name = "Modèle à définir"
    for row in read_excel_sheet("Modeles"):
        try:
            if exclude_id is not None and int(row.get("id") or 0) == int(exclude_id):
                continue
        except (TypeError, ValueError):
            pass
        if str(row.get("brand") or "").strip().lower() == fallback_brand.lower() and str(row.get("model_name") or "").strip().lower() == fallback_name.lower():
            return row
    fallback = append_excel_row(
        "Modeles",
        {
            "brand": fallback_brand,
            "model_name": fallback_name,
            "category": "Non classé",
            "default_warranty_months": 24,
            "notes": "Modèle générique recréé automatiquement après suppression d'un modèle utilisé.",
        },
    )
    set_model_default_price(fallback.get("id"), None)
    clear_excel_read_cache()
    return fallback


@app.delete("/api/suppliers/{supplier_id}")
def delete_supplier(supplier_id: int, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    target = get_reference_by_id("Fournisseurs", supplier_id)
    if not target:
        raise HTTPException(status_code=404, detail="Fournisseur introuvable")

    now = now_iso()
    with db() as conn:
        used = conn.execute("SELECT COUNT(*) AS c FROM assets WHERE supplier_id = ?", (supplier_id,)).fetchone()["c"]
        conn.execute("UPDATE assets SET supplier_id = NULL, updated_at = ? WHERE supplier_id = ?", (now, supplier_id))

    rules_updated = 0
    for rule in read_excel_sheet("Regles"):
        try:
            if int(rule.get("supplier_id") or 0) == int(supplier_id):
                update_excel_row_by_id("Regles", int(rule.get("id")), {"supplier_id": None})
                rules_updated += 1
        except (TypeError, ValueError):
            continue

    if not delete_excel_row("Fournisseurs", "id", supplier_id):
        raise HTTPException(status_code=404, detail="Fournisseur introuvable")
    clear_excel_read_cache()
    sync_all_assets_to_excel()
    write_app_log("supplier_deleted", "supplier", supplier_id, f"Fournisseur supprimé : {target.get('name')} — {used} matériel(s) détaché(s), {rules_updated} règle(s) mise(s) à jour", request=request)
    sync_logs_to_excel()
    return {"status": "deleted", "id": supplier_id, "assets_detached": used, "rules_updated": rules_updated}


@app.delete("/api/models/{model_id}")
def delete_model(model_id: int, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    target = get_reference_by_id("Modeles", model_id)
    if not target:
        raise HTTPException(status_code=404, detail="Modèle introuvable")

    now = now_iso()
    fallback_id: int | None = None
    with db() as conn:
        used = conn.execute("SELECT COUNT(*) AS c FROM assets WHERE model_id = ?", (model_id,)).fetchone()["c"]

    if used:
        fallback = get_or_create_fallback_model(exclude_id=model_id)
        try:
            fallback_id = int(fallback.get("id"))
        except (TypeError, ValueError):
            raise HTTPException(status_code=500, detail="Impossible de créer le modèle générique de remplacement")
        with db() as conn:
            conn.execute("UPDATE assets SET model_id = ?, updated_at = ? WHERE model_id = ?", (fallback_id, now, model_id))

    rules_updated = 0
    for rule in read_excel_sheet("Regles"):
        try:
            if int(rule.get("model_id") or 0) == int(model_id):
                update_excel_row_by_id("Regles", int(rule.get("id")), {"model_id": None})
                rules_updated += 1
        except (TypeError, ValueError):
            continue

    with db() as conn:
        conn.execute("DELETE FROM model_prices WHERE model_id = ?", (model_id,))

    if not delete_excel_row("Modeles", "id", model_id):
        raise HTTPException(status_code=404, detail="Modèle introuvable")
    clear_excel_read_cache()
    sync_all_assets_to_excel()
    label = f"{target.get('brand') or ''} {target.get('model_name') or ''}".strip()
    detail = f"Modèle supprimé : {label} — {used} matériel(s) réaffecté(s)"
    if fallback_id:
        detail += f" vers le modèle générique #{fallback_id}"
    detail += f", {rules_updated} règle(s) mise(s) à jour"
    write_app_log("model_deleted", "model", model_id, detail, request=request)
    sync_logs_to_excel()
    return {"status": "deleted", "id": model_id, "assets_reassigned": used, "fallback_model_id": fallback_id, "rules_updated": rules_updated}


@app.delete("/api/rules/{rule_id}")
def delete_rule(rule_id: int, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    target = get_reference_by_id("Regles", rule_id)
