@app.get("/api/assets/search")
def search_assets(q: str = Query(min_length=1), limit: int = Query(default=100, ge=1, le=500)) -> list[dict[str, Any]]:
    query = f"%{normalize_sn(q)}%"
    raw_query = f"%{q.strip()}%"
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, asset_code, serial_number_raw, status, location, client_name, customer_id, sale_date, image_url, image_local_path, notes,
                   teamviewer_id, teamviewer_password, return_reason,
                   purchase_date, purchase_price_eur, warranty_end_date, created_at, updated_at, model_id, supplier_id
            FROM assets
            WHERE serial_number_norm LIKE ?
               OR UPPER(asset_code) LIKE ?
               OR UPPER(COALESCE(location, '')) LIKE ?
               OR UPPER(COALESCE(client_name, '')) LIKE ?
            ORDER BY updated_at DESC, id DESC
            LIMIT ?
            """,
            (query, query, raw_query.upper(), raw_query.upper(), limit),
        ).fetchall()
    out: list[dict[str, Any]] = []
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        out.append(enrich_asset_image_fields({
                **asset,
                "brand": model.get("brand") if model else "Modèle supprimé",
                "model_name": model.get("model_name") if model else "",
                "category": model.get("category") if model else "",
                "supplier_name": supplier.get("name") if supplier else None,
                "customer_code": (get_customer_by_id(asset.get("customer_id")) or {}).get("customer_code"),
                "customer_display_name": customer_display_name(get_customer_by_id(asset.get("customer_id"))),
                "customer_company": (get_customer_by_id(asset.get("customer_id")) or {}).get("company"),
                "customer_email": (get_customer_by_id(asset.get("customer_id")) or {}).get("email"),
                "customer_phone": (get_customer_by_id(asset.get("customer_id")) or {}).get("phone"),
                "status_label": excel_safe_status_label(asset.get("status")),
                "return_reason_label": return_reason_label(asset.get("return_reason")),
            }))
    return out


