@app.post("/api/assets")
def create_asset(payload: AssetCreate, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    sn_norm = normalize_sn(payload.serial_number)
    status = validate_status(payload.status)
    if status == "en_stock" and str(payload.client_name or "").strip():
        status = "vendu"
    model_ref = get_reference_by_id("Modeles", payload.model_id)
    if not model_ref:
        raise HTTPException(status_code=400, detail="Modèle invalide ou absent du fichier Excel")
    supplier_ref = get_reference_by_id("Fournisseurs", payload.supplier_id) if payload.supplier_id else None
    if payload.supplier_id and not supplier_ref:
        raise HTTPException(status_code=400, detail="Fournisseur invalide ou absent du fichier Excel")

    with db() as conn:
        purchase_date = payload.purchase_date or default_purchase_date()
        purchase_price = payload.purchase_price_eur
        if purchase_price is None:
            purchase_price = get_model_default_price(payload.model_id)
        warranty_end = compute_warranty_end(payload.model_id, purchase_date)
        code = next_asset_code(conn)
        normalized = normalize_asset_assignment_fields(
            status=status,
            client_name=payload.client_name,
            customer_id=None,
            sale_date=None,
            teamviewer_id=payload.teamviewer_id,
            teamviewer_password=payload.teamviewer_password,
            return_reason=payload.return_reason,
            supplier_name=supplier_ref.get("name") if supplier_ref else None,
            category=model_ref.get("category") if model_ref else None,
        )
        status = normalized["status"]
        try:
            cur = conn.execute(
                """
                INSERT INTO assets(
                    asset_code, serial_number_raw, serial_number_norm, model_id, supplier_id,
                    purchase_date, purchase_price_eur, warranty_end_date, status, location, client_name, sale_date,
                    teamviewer_id, teamviewer_password, return_reason, notes, created_at, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    code,
                    payload.serial_number.strip(),
                    sn_norm,
                    payload.model_id,
                    payload.supplier_id,
                    purchase_date,
                    purchase_price,
                    warranty_end,
                    status,
                    payload.location,
                    normalized["client_name"],
                    normalized["sale_date"],
                    normalized["teamviewer_id"],
                    normalized["teamviewer_password"],
                    normalized["return_reason"],
                    payload.notes,
                    now_iso(),
                    now_iso(),
                ),
            )
        except sqlite3.IntegrityError:
            raise HTTPException(status_code=409, detail="Ce numéro de série existe déjà dans le stock")

        asset_id = cur.lastrowid
        creation_details = "Création du matériel"
        if normalized.get("return_reason"):
            creation_details += f" | Motif retour fournisseur : {return_reason_label(normalized.get('return_reason'))}"
        insert_asset_event(
            conn,
            asset_id,
            "creation",
            creation_details,
            now_iso(),
            request=request,
            source="creation_manuelle",
            new_value=status,
        )
        asset = get_asset_full(conn, asset_id)
    if get_model_default_price(payload.model_id) is None and purchase_price is not None:
        set_model_default_price(payload.model_id, purchase_price)
    sync_asset_to_excel(asset)
    write_app_log("asset_created", "asset", asset_id, f"Matériel créé : {asset.get('asset_code')} / {asset.get('serial_number_raw')}", request=request)
    return asset


@app.patch("/api/assets/{asset_id}")
def update_asset(asset_id: int, payload: AssetUpdate, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    """Modifie un matériel existant avec les règles stock/client/retour fournisseur."""
    status = validate_status(payload.status)

    with db() as conn:
        existing = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Matériel introuvable")

        existing_full = get_asset_full(conn, asset_id)
        fields_set = getattr(payload, "model_fields_set", getattr(payload, "__fields_set__", set()))
        new_model_id = payload.model_id if "model_id" in fields_set and payload.model_id else existing["model_id"]
        new_supplier_id = payload.supplier_id if "supplier_id" in fields_set else existing["supplier_id"]
        new_purchase_date = payload.purchase_date if "purchase_date" in fields_set else existing["purchase_date"]
        new_warranty_end_date = payload.warranty_end_date if "warranty_end_date" in fields_set else existing["warranty_end_date"]
        if ("model_id" in fields_set or "purchase_date" in fields_set) and "warranty_end_date" not in fields_set:
            new_warranty_end_date = compute_warranty_end(new_model_id, new_purchase_date)
        model_ref = get_reference_by_id("Modeles", new_model_id)
        if not model_ref:
            raise HTTPException(status_code=400, detail="Modèle invalide ou absent du fichier Excel")
        supplier_ref = get_reference_by_id("Fournisseurs", new_supplier_id) if new_supplier_id else None
        if new_supplier_id and not supplier_ref:
            raise HTTPException(status_code=400, detail="Fournisseur invalide ou absent du fichier Excel")
        new_location = payload.location if "location" in fields_set else existing["location"]
        new_client_name = payload.client_name if "client_name" in fields_set else existing["client_name"]
        new_customer_id = payload.customer_id if "customer_id" in fields_set else existing["customer_id"]
        new_sale_date = existing["sale_date"]
        new_teamviewer_id = payload.teamviewer_id if "teamviewer_id" in fields_set else existing["teamviewer_id"]
        new_teamviewer_password = payload.teamviewer_password if "teamviewer_password" in fields_set else existing["teamviewer_password"]
        new_return_reason = payload.return_reason if "return_reason" in fields_set else existing["return_reason"]
        new_notes = payload.notes if "notes" in fields_set else existing["notes"]

        if existing["status"] == "en_stock" and status == "en_stock" and "client_name" in fields_set and str(payload.client_name or "").strip():
            status = "vendu"
            new_sale_date = new_sale_date or now_iso()

        if status == "vendu":
            if not new_customer_id:
                raise HTTPException(status_code=400, detail="Client obligatoire : choisissez un client enregistré avant de passer le matériel en Vendu.")
            customer_row = conn.execute("SELECT * FROM customers WHERE id = ?", (new_customer_id,)).fetchone()
            if not customer_row:
                raise HTTPException(status_code=400, detail="Client introuvable : sélectionnez un client enregistré existant.")
            new_client_name = customer_display_name(dict(customer_row))
            new_sale_date = new_sale_date or now_iso()

        normalized = normalize_asset_assignment_fields(
            status=status,
            client_name=new_client_name,
            customer_id=new_customer_id,
            sale_date=new_sale_date,
            teamviewer_id=new_teamviewer_id,
            teamviewer_password=new_teamviewer_password,
            return_reason=new_return_reason,
            supplier_name=supplier_ref.get("name") if supplier_ref else None,
            category=model_ref.get("category") if model_ref else existing_full.get("category"),
        )
        status = normalized["status"]
        new_client_name = normalized["client_name"]
        new_customer_id = normalized["customer_id"]
        new_sale_date = normalized["sale_date"]
        new_teamviewer_id = normalized["teamviewer_id"]
        new_teamviewer_password = normalized["teamviewer_password"]
        new_return_reason = normalized["return_reason"]

        comparisons = [
            ("Modèle", existing["model_id"], new_model_id),
            ("Fournisseur", existing["supplier_id"], new_supplier_id),
            ("Date achat", existing["purchase_date"], new_purchase_date),
            ("Fin garantie", existing["warranty_end_date"], new_warranty_end_date),
            ("Prix €", existing["purchase_price_eur"], payload.purchase_price_eur),
            ("Statut", existing["status"], status),
            ("Client", existing["client_name"], new_client_name),
            ("Attribution client", existing["customer_id"], new_customer_id),
            ("Date vente", existing["sale_date"], new_sale_date),
            ("TeamViewer ID", existing["teamviewer_id"], new_teamviewer_id),
            ("TeamViewer MDP", existing["teamviewer_password"], new_teamviewer_password),
            ("Motif retour fournisseur", existing["return_reason"], new_return_reason),
            ("Notes", existing["notes"], new_notes),
        ]
        if "location" in fields_set:
            comparisons.append(("Emplacement", existing["location"], new_location))

        changes: list[str] = []
        for label, old, new_value in comparisons:
            if str(old or "") != str(new_value or ""):
                if label == "Motif retour fournisseur":
                    changes.append(f"{label} : {return_reason_label(old)} -> {return_reason_label(new_value)}")
                else:
                    changes.append(f"{label} : {old or ''} -> {new_value or ''}")

        if not changes:
            raise HTTPException(status_code=400, detail="Aucune modification détectée : rien n'a été enregistré.")

        updated_at = now_iso()
        new_return_supplier_sent_at = getattr(payload, "return_supplier_sent_at", None) or existing["return_supplier_sent_at"] if "return_supplier_sent_at" in existing.keys() else None
        new_return_supplier_back_at = getattr(payload, "return_supplier_back_at", None) or existing["return_supplier_back_at"] if "return_supplier_back_at" in existing.keys() else None
        new_damaged_reason = getattr(payload, "damaged_reason", None) or existing["damaged_reason"] if "damaged_reason" in existing.keys() else None
        if existing["status"] != "retour_fournisseur" and status == "retour_fournisseur":
            new_return_supplier_sent_at = new_return_supplier_sent_at or updated_at
            new_return_supplier_back_at = None
        if existing["status"] == "retour_fournisseur" and status != "retour_fournisseur":
            new_return_supplier_back_at = new_return_supplier_back_at or updated_at
        if status == "abime" and not new_damaged_reason:
            new_damaged_reason = payload.details or "Matériel marqué abîmé / irréparable"
        conn.execute(
            """
            UPDATE assets
            SET model_id = ?,
                supplier_id = ?,
                purchase_date = ?,
                purchase_price_eur = ?,
                warranty_end_date = ?,
                status = ?,
                location = ?,
                client_name = ?,
                customer_id = ?,
                sale_date = ?,
                teamviewer_id = ?,
                teamviewer_password = ?,
                return_reason = ?,
                return_supplier_sent_at = ?,
                return_supplier_back_at = ?,
                damaged_reason = ?,
                notes = ?,
                updated_at = ?
            WHERE id = ?
            """,
            (
                new_model_id,
                new_supplier_id,
                new_purchase_date,
                payload.purchase_price_eur,
                new_warranty_end_date,
                status,
                new_location,
                new_client_name,
                new_customer_id,
                new_sale_date,
                new_teamviewer_id,
                new_teamviewer_password,
                new_return_reason,
                new_return_supplier_sent_at,
                new_return_supplier_back_at,
                new_damaged_reason,
                new_notes,
                updated_at,
                asset_id,
            ),
        )

        details = " | ".join(changes)
        if payload.details:
            details = f"{details} | {payload.details}"

        insert_asset_event(
            conn,
            asset_id,
            "modification",
            details,
            now_iso(),
            request=request,
            source="modification_manuelle",
            old_value=" | ".join([str(x[1] or '') for x in comparisons if str(x[1] or '') != str(x[2] or '')]),
            new_value=" | ".join([str(x[2] or '') for x in comparisons if str(x[1] or '') != str(x[2] or '')]),
        )

        asset = get_asset_full(conn, asset_id)
    sync_asset_to_excel(asset)
    write_app_log("asset_updated", "asset", asset_id, details, request=request)
    return asset


@app.patch("/api/assets/{asset_id}/status")
def update_asset_status(asset_id: int, payload: AssetStatusUpdate, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    new_status = validate_status(payload.status)
    with db() as conn:
        existing = conn.execute(
            "SELECT id, status, location, client_name, customer_id, sale_date, supplier_id, teamviewer_id, teamviewer_password, return_reason, return_supplier_sent_at, return_supplier_back_at, damaged_reason, model_id FROM assets WHERE id = ?",
            (asset_id,),
        ).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Matériel introuvable")

        old_status = existing["status"]
        location = payload.location if payload.location is not None else existing["location"]
        client_name = payload.client_name if payload.client_name is not None else existing["client_name"]
        customer_id = payload.customer_id if payload.customer_id is not None else existing["customer_id"]
        sale_date = existing["sale_date"]
        teamviewer_id = existing["teamviewer_id"]
        teamviewer_password = existing["teamviewer_password"]
        existing_full = get_asset_full(conn, asset_id)
        model_ref = get_reference_by_id("Modeles", existing["model_id"]) if existing["model_id"] else None
        supplier_ref = get_reference_by_id("Fournisseurs", existing["supplier_id"]) if existing["supplier_id"] else None
        return_reason = payload.return_reason if payload.return_reason is not None else existing["return_reason"]

        if new_status == "vendu":
            if not customer_id:
                raise HTTPException(status_code=400, detail="Client obligatoire : choisissez un client enregistré avant de passer le matériel en Vendu.")
            customer_row = conn.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
            if not customer_row:
                raise HTTPException(status_code=400, detail="Client introuvable : sélectionnez un client enregistré existant.")
            client_name = customer_display_name(dict(customer_row))
            sale_date = sale_date or now_iso()

        normalized = normalize_asset_assignment_fields(
            status=new_status,
            client_name=client_name,
            customer_id=customer_id,
            sale_date=sale_date,
            teamviewer_id=teamviewer_id,
            teamviewer_password=teamviewer_password,
            return_reason=return_reason,
            supplier_name=supplier_ref.get("name") if supplier_ref else None,
            category=model_ref.get("category") if model_ref else existing_full.get("category"),
        )
        new_status = normalized["status"]
        client_name = normalized["client_name"]
        customer_id = normalized["customer_id"]
        sale_date = normalized["sale_date"]
        teamviewer_id = normalized["teamviewer_id"]
        teamviewer_password = normalized["teamviewer_password"]
        return_reason = normalized["return_reason"]

        updated_at_status = now_iso()
        return_supplier_sent_at = payload.return_supplier_sent_at or existing["return_supplier_sent_at"]
        return_supplier_back_at = payload.return_supplier_back_at or existing["return_supplier_back_at"]
        damaged_reason = payload.damaged_reason or existing["damaged_reason"]
        if old_status != "retour_fournisseur" and new_status == "retour_fournisseur":
            return_supplier_sent_at = return_supplier_sent_at or updated_at_status
            return_supplier_back_at = None
        if old_status == "retour_fournisseur" and new_status != "retour_fournisseur":
            return_supplier_back_at = return_supplier_back_at or updated_at_status
        if new_status == "abime" and not damaged_reason:
            damaged_reason = payload.details or "Matériel marqué abîmé / irréparable"
        conn.execute(
            """
            UPDATE assets
            SET status = ?, location = ?, client_name = ?, customer_id = ?, sale_date = ?,
                teamviewer_id = ?, teamviewer_password = ?, return_reason = ?,
                return_supplier_sent_at = ?, return_supplier_back_at = ?, damaged_reason = ?, updated_at = ?
            WHERE id = ?
            """,
            (new_status, location, client_name, customer_id, sale_date, teamviewer_id, teamviewer_password, return_reason, return_supplier_sent_at, return_supplier_back_at, damaged_reason, updated_at_status, asset_id),
        )

        details_parts = [f"Statut : {old_status} -> {new_status}"]
        if payload.details:
            details_parts.append(payload.details)
        if location != existing["location"]:
            details_parts.append(f"Emplacement : {existing['location'] or ''} -> {location or ''}")
        if client_name != existing["client_name"]:
            details_parts.append(f"Client : {existing['client_name'] or ''} -> {client_name or ''}")
        if customer_id != existing["customer_id"]:
            details_parts.append("Attribution client supprimée")
        if return_reason != existing["return_reason"]:
            details_parts.append(f"Motif retour fournisseur : {return_reason_label(existing['return_reason'])} -> {return_reason_label(return_reason)}")

        insert_asset_event(
            conn,
            asset_id,
            f"status:{new_status}",
            " | ".join(details_parts),
            now_iso(),
            request=request,
            source="changement_statut",
            field_name="status",
            old_value=old_status,
            new_value=new_status,
            customer_id=customer_id,
        )
        asset = get_asset_full(conn, asset_id)
    sync_asset_to_excel(asset)
    write_app_log("asset_status_updated", "asset", asset_id, " | ".join(details_parts), request=request)
    return asset


@app.get("/api/scan")
def scan(request: Request, sn: str = Query(min_length=1)) -> dict[str, Any]:
    sn_norm = normalize_sn(sn)
    write_app_log("asset_scan", "scan", sn_norm, "Scan SN", request=request)
    with db() as conn:
        exact_asset_id = find_asset_id_by_scan_sn(conn, sn_norm)
        if exact_asset_id:
            return {
                "status": "found",
                "source": "base_exacte",
                "serial_number_norm": sn_norm,
                "asset": get_asset_full(conn, exact_asset_id),
            }

    matches: list[dict[str, Any]] = []
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    rules = read_excel_sheet("Regles")
    for rule in rules:
        try:
            if re.search(str(rule.get("pattern") or ""), sn_norm):
                matches.append(enrich_rule(rule, models, suppliers))
        except re.error:
            # Une mauvaise règle ne doit pas bloquer le scan.
            continue

    matches.sort(key=lambda x: -(int(x.get("confidence") or 0)))
    if matches:
        best = enrich_asset_image_fields({**matches[0], "serial_number_raw": sn, "supplier_name": matches[0].get("supplier_name")})

        # Si la règle identifie déjà un modèle, on crée directement le matériel.
        # L'utilisateur n'a plus besoin de ressaisir modèle/fournisseur : on reprend
        # les informations de la règle SN et du référentiel Excel.
        current_user = get_request_user(request)
        model_id = best.get("model_id")
        supplier_id = best.get("supplier_id")
        if current_user and user_can_write_assets(current_user) and model_id:
            try:
                model_id_int = int(model_id)
                supplier_id_int = int(supplier_id) if supplier_id not in {None, ""} else None
            except (TypeError, ValueError):
                model_id_int = 0
                supplier_id_int = None

            if model_id_int and get_reference_by_id("Modeles", model_id_int):
                with db() as conn:
                    # Double vérification après la phase règle, pour éviter les doublons si deux scans arrivent ensemble.
                    existing_asset_id = find_asset_id_by_scan_sn(conn, sn_norm)
                    if existing_asset_id:
                        return {
                            "status": "found",
                            "source": "base_exacte",
                            "serial_number_norm": sn_norm,
                            "asset": get_asset_full(conn, existing_asset_id),
                        }

                    code = next_asset_code(conn)
                    purchase_date = default_purchase_date()
                    purchase_price = get_model_default_price(model_id_int)
                    warranty_end = compute_warranty_end(model_id_int, purchase_date)
                    try:
                        cur = conn.execute(
                            """
                            INSERT INTO assets(
                                asset_code, serial_number_raw, serial_number_norm, model_id, supplier_id,
                                purchase_date, purchase_price_eur, warranty_end_date, status, location, client_name, notes,
                                created_at, updated_at
                            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                            """,
                            (
                                code,
                                sn.strip(),
                                sn_norm,
                                model_id_int,
                                supplier_id_int,
                                purchase_date,
                                purchase_price,
                                warranty_end,
                                "en_stock",
                                None,
                                None,
                                None,
                                now_iso(),
                                now_iso(),
                            ),
                        )
                    except sqlite3.IntegrityError:
                        raise HTTPException(status_code=409, detail="Ce numéro de série existe déjà dans le stock")

                    asset_id = cur.lastrowid
                    insert_asset_event(
                        conn,
                        asset_id,
                        "creation_auto_regle_sn",
                        f"Création automatique via règle : {best.get('name') or ''}",
                        now_iso(),
                        request=request,
                        source="scan_regle_sn",
                        new_value=sn_norm,
                    )
                    asset = get_asset_full(conn, asset_id)
                sync_asset_to_excel(asset)
                write_app_log("asset_auto_created_from_scan", "asset", asset_id, f"Matériel auto-créé par scan SN : {sn_norm}", request=request)
                return {
                    "status": "created_from_rule",
                    "source": "regle_reconnaissance_excel",
                    "serial_number_norm": sn_norm,
                    "best_match": best,
                    "asset": asset,
                }

        return {
            "status": "probable",
            "source": "regle_reconnaissance_excel",
            "serial_number_norm": sn_norm,
            "best_match": best,
            "matches": matches,
        }

    unknown_asset = enrich_asset_image_fields({"serial_number_raw": sn_norm, "asset_code": sn_norm})
    return {
        "status": "unknown",
        "source": "aucune_correspondance",
        "serial_number_norm": sn_norm,
        "message": "SN inconnu : création manuelle nécessaire.",
        "image_url": unknown_asset.get("image_url"),
        "image_search_url": unknown_asset.get("image_search_url"),
    }


@app.delete("/api/assets/{asset_id}")
def delete_asset(asset_id: int, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    with db() as conn:
        existing = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        asset = dict(existing)
        if asset.get("customer_id") or str(asset.get("client_name") or "").strip():
            customer_label = str(asset.get("client_name") or "client attribué").strip() or "client attribué"
            raise HTTPException(
                status_code=409,
                detail=(
                    "Suppression impossible : ce matériel est attribué à un client. "
                    "Retire d'abord l'attribution client ou passe le matériel en stock depuis le volet client / matériel. "
                    f"Client actuel : {customer_label}"
                ),
            )
        conn.execute("DELETE FROM asset_events WHERE asset_id = ?", (asset_id,))
        conn.execute("DELETE FROM assets WHERE id = ?", (asset_id,))
    try:
        delete_excel_row("Materiels", "asset_code", asset.get("asset_code"))
    except Exception:
        sync_all_assets_to_excel()
    write_app_log("asset_deleted", "asset", asset_id, f"Matériel supprimé : {asset.get('asset_code')} / {asset.get('serial_number_raw')}", request=request)
    return {"status": "deleted", "id": asset_id, "asset_code": asset.get("asset_code")}


@app.get("/api/assets/{asset_id}/qr")
def asset_qr(asset_id: int) -> FileResponse:
    with db() as conn:
        asset = get_asset_full(conn, asset_id)
    payload = asset["asset_code"]
    qr_path = QR_DIR / f"{payload}.png"
    if not qr_path.exists():
        img = qrcode.make(payload)
        img.save(qr_path)
    return FileResponse(qr_path, media_type="image/png", filename=f"{payload}.png")



@app.get("/api/customers")
def list_customers(q: str | None = None, limit: int = Query(default=200, ge=1, le=1000)) -> list[dict[str, Any]]:
    where = ""
    params: list[Any] = []
    if q:
        like = f"%{q.strip()}%"
        where = "WHERE name LIKE ? OR COALESCE(company,'') LIKE ? OR COALESCE(email,'') LIKE ? OR COALESCE(phone,'') LIKE ? OR COALESCE(crm_url,'') LIKE ? OR customer_code LIKE ?"
        params.extend([like, like, like, like, like, like])
    params.append(limit)
    with db() as conn:
        rows = conn.execute(
            f"SELECT * FROM customers {where} ORDER BY updated_at DESC, id DESC LIMIT ?",
            params,
        ).fetchall()
    return [dict(row) for row in rows]


