    require_asset_write(request)
    with db() as conn:
        existing = conn.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Client introuvable")
        customer = dict(existing)
        assigned = conn.execute("SELECT COUNT(*) AS c FROM assets WHERE customer_id = ?", (customer_id,)).fetchone()["c"]
        if assigned:
            raise HTTPException(status_code=400, detail=f"Suppression impossible : {assigned} matériel(s) sont encore lié(s) à ce client.")
