@app.get("/api/customers/asset-info")
def get_asset_customer_info(sn: str = Query(min_length=1)) -> dict[str, Any]:
    sn_norm = normalize_sn(sn)
    with db() as conn:
        asset_id = find_asset_id_by_scan_sn(conn, sn_norm)
        if not asset_id:
            raise HTTPException(status_code=404, detail="Matériel non enregistré")
