@app.post("/api/drawing-page-layout/{kind}/image")
async def api_upload_drawing_page_layout_image(kind: str, request: Request, file: UploadFile = File(...)) -> dict[str, Any]:
    require_asset_write(request)
    kind = str(kind or "").strip().lower()
    if kind not in {"header", "footer"}:
        raise HTTPException(status_code=400, detail="Type d'image invalide : utilise header ou footer")
    suffix = Path(file.filename or "image.png").suffix.lower()
    if suffix not in {".png", ".jpg", ".jpeg", ".webp", ".bmp"}:
        raise HTTPException(status_code=400, detail="Format image non accepté. Utilise PNG, JPG, WEBP ou BMP.")
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Image vide")
    if len(content) > 8 * 1024 * 1024:
        raise HTTPException(status_code=400, detail="Image trop volumineuse : maximum 8 Mo")
    DRAWING_LAYOUT_IMAGES_DIR.mkdir(parents=True, exist_ok=True)
    image_name = f"dessin_{kind}_{datetime.now().strftime('%Y%m%d_%H%M%S')}{suffix}"
    target = DRAWING_LAYOUT_IMAGES_DIR / image_name
    target.write_bytes(content)
    settings = load_drawing_layout_settings()
    settings[f"{kind}_image_path"] = image_name
    saved = save_drawing_layout_settings(settings)
    write_app_log("drawing_layout_image_uploaded", "drawing_layout", None, f"Image {kind} feuille dessin importée : {image_name}", request=request)
    return {"status": "ok", "file_name": image_name, "layout": enrich_drawing_layout_settings(saved)}


