@app.post("/api/connection-schemas")
def api_save_connection_schema(payload: ConnectionSchemaSavePayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    model = get_reference_by_id("Modeles", payload.model_id)
    if not model:
        raise HTTPException(status_code=404, detail="Modèle introuvable dans le référentiel")
    current = load_connection_schemas()
    schemas = current.get("schemas", {})
    previous = schemas.get(str(payload.model_id), {})
    schema = normalize_connection_schema({
        "model_id": payload.model_id,
        "title": payload.title or f"Schéma {model_display_label(model)}",
        "base_image_path": payload.base_image_path if payload.base_image_path is not None else previous.get("base_image_path", ""),
        "ports": payload.ports or previous.get("ports") or DEFAULT_CONNECTION_PORTS,
        "equipment": payload.equipment or previous.get("equipment") or DEFAULT_CONNECTION_EQUIPMENT,
        "updated_at": now_iso(),
    }, payload.model_id)
    schema["updated_at"] = now_iso()
    schemas[str(payload.model_id)] = schema
    saved = save_connection_schemas({"schemas": schemas})
    write_app_log("connection_schema_saved", "model", payload.model_id, f"Schéma de branchement enregistré : {model_display_label(model)}", request=request)
    return {"status": "ok", "schema": {**enrich_connection_schema_for_api(schema, payload.model_id), "model_label": model_display_label(model)}, "updated_at": saved.get("updated_at")}


