@app.post("/api/connection-schemas/{model_id}/equipment-image/{equipment_key}")
async def api_upload_connection_equipment_image(model_id: int, equipment_key: str, request: Request, file: UploadFile = File(...)) -> dict[str, Any]:
    require_asset_write(request)
    model = get_reference_by_id("Modeles", model_id)
    if not model:
        raise HTTPException(status_code=404, detail="Modèle introuvable dans le référentiel")
    suffix = Path(file.filename or "image.png").suffix.lower()
    if suffix not in {".png", ".jpg", ".jpeg", ".webp", ".bmp"}:
        raise HTTPException(status_code=400, detail="Format image non accepté. Utilise PNG, JPG, WEBP ou BMP.")
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Image vide")
    CONNECTION_EQUIPMENT_IMAGES_DIR.mkdir(parents=True, exist_ok=True)
    MATERIAL_CONNECTION_IMAGES_DIR.mkdir(parents=True, exist_ok=True)
    DRAWING_LAYOUT_IMAGES_DIR.mkdir(parents=True, exist_ok=True)
    safe_key = safe_filename_part(equipment_key, "materiel")
    image_name = f"equip_{model_id}_{safe_key}_{datetime.now().strftime('%Y%m%d_%H%M%S')}{suffix}"
    target = CONNECTION_EQUIPMENT_IMAGES_DIR / image_name
    target.write_bytes(content)
    current = load_connection_schemas()
    schemas = current.get("schemas", {})
    schema = normalize_connection_schema(schemas.get(str(model_id)), model_id)
    equipment = []
    found = False
    for item in schema.get("equipment") or []:
        row = dict(item)
        if str(row.get("key") or "") == str(equipment_key):
            row["image_path"] = image_name
            found = True
        equipment.append(row)
    if not found:
        equipment.append({"key": equipment_key, "label": equipment_key, "port": "USB", "x": 50, "y": 72, "color": "#2563eb", "aliases": [], "default_show": False, "image_path": image_name})
    schema["equipment"] = equipment
    schema["updated_at"] = now_iso()
    schemas[str(model_id)] = schema
    save_connection_schemas({"schemas": schemas})
    write_app_log("connection_equipment_image_uploaded", "model", model_id, f"Image matériel schéma importée : {equipment_key}", request=request)
    item = next((x for x in equipment if str(x.get("key") or "") == str(equipment_key)), None) or {}
    return {"status": "ok", "file_name": image_name, "equipment_key": equipment_key, "image_url": schema_equipment_image_url(image_name), "equipment": {**item, "image_url": schema_equipment_image_url(item.get("image_path"))}}


