@app.get("/api/material-connection-profiles")
def api_list_material_connection_profiles(request: Request) -> dict[str, Any]:
    get_request_user(request)
    models = enrich_model_prices(read_excel_sheet("Modeles"))
    current = load_material_connection_profiles()
    profiles = current.get("profiles", {}) if isinstance(current, dict) else {}
    rows: list[dict[str, Any]] = []
    for model in models:
        try:
            model_id = int(model.get("id") or 0)
        except Exception:
            continue
        if not model_id:
            continue
        profile = enrich_material_connection_profile_for_api(normalize_material_connection_profile(profiles.get(str(model_id)), model_id), model_id)
        point_count = len(profile.get("points") or [])
        has_image = bool(profile.get("image_path") or profile.get("image_url"))
        rows.append({
            "model_id": model_id,
            "brand": model.get("brand"),
            "model_name": model.get("model_name"),
            "category": model.get("category"),
            "label": model_display_label(model),
            "profile": profile,
            "point_count": point_count,
            "has_image": has_image,
            "is_completed": bool(has_image or point_count),
        })
    rows.sort(key=lambda item: normalize_text(item.get("label") or ""))
    return {"status": "ok", "rows": rows, "updated_at": current.get("updated_at") if isinstance(current, dict) else None}


