@app.post("/api/material-connection-profiles")
def api_save_material_connection_profile(payload: MaterialConnectionProfilePayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    model = get_reference_by_id("Modeles", payload.model_id)
    if not model:
        raise HTTPException(status_code=404, detail="Modèle introuvable")
    try:
        current = load_material_connection_profiles()
        profiles = current.get("profiles", {})
        existing = normalize_material_connection_profile(profiles.get(str(payload.model_id)), payload.model_id)
        normalized_points = []
        for idx, point in enumerate(payload.points or []):
            normalized_points.append(normalize_material_connection_point(point.model_dump(), idx))
        profile = {
            "model_id": payload.model_id,
            "image_path": str(payload.image_path or existing.get("image_path") or "").strip(),
            "points": normalized_points,
            "updated_at": now_iso(),
        }
        profiles[str(payload.model_id)] = profile
        saved = save_material_connection_profiles({"profiles": profiles})
        # Sauvegarde miroir dans la base Excel pour récupération lors de l'utilisation d'une ancienne base.
        upsert_material_connection_profile_excel(profile)
        write_app_log("material_connection_profile_saved", "model", payload.model_id, f"Profil connexion matériel enregistré : {model_display_label(model)}", request=request)
        return {"status": "ok", "profile": enrich_material_connection_profile_for_api(profile, payload.model_id), "updated_at": saved.get("updated_at")}
    except HTTPException:
        raise
    except Exception as exc:
        safe_log(f"Erreur sauvegarde profil connexion matériel {payload.model_id}: {exc}")
        raise HTTPException(status_code=500, detail=f"Impossible d'enregistrer le profil matériel : {exc}")


