@app.delete("/api/material-connection-profiles/{model_id}/image")
def api_delete_material_connection_image(model_id: int, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    model = get_reference_by_id("Modeles", model_id)
    if not model:
        raise HTTPException(status_code=404, detail="Modèle introuvable")
    current = load_material_connection_profiles()
    profiles = current.get("profiles", {})
    profile = normalize_material_connection_profile(profiles.get(str(model_id)), model_id)
    old_path = resolve_material_connection_image_path(profile.get("image_path"))
    profile["image_path"] = ""
    profile["updated_at"] = now_iso()
    profiles[str(model_id)] = profile
    save_material_connection_profiles({"profiles": profiles})
    try:
        upsert_material_connection_profile_excel(profile)
    except Exception as exc:
        safe_log(f"Synchronisation Excel suppression image profil matériel impossible {model_id}: {exc}")
    if old_path and old_path.exists():
        try:
            old_path.unlink()
        except Exception as exc:
            safe_log(f"Suppression image profil matériel impossible {old_path}: {exc}")
    write_app_log("material_connection_image_deleted", "model", model_id, f"Image bas matériel supprimée : {model_display_label(model)}", request=request)
    return {"status": "ok", "profile": enrich_material_connection_profile_for_api(profile, model_id)}


@app.delete("/api/material-connection-profiles/{model_id}")
def api_delete_material_connection_profile(model_id: int, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    model = get_reference_by_id("Modeles", model_id)
    if not model:
        raise HTTPException(status_code=404, detail="Modèle introuvable")
    current = load_material_connection_profiles()
    profiles = current.get("profiles", {}) if isinstance(current, dict) else {}
    profile = normalize_material_connection_profile(profiles.get(str(model_id)), model_id)
    old_path = resolve_material_connection_image_path(profile.get("image_path"))
    if str(model_id) in profiles:
        profiles.pop(str(model_id), None)
        save_material_connection_profiles({"profiles": profiles})
    clear_material_connection_profile_excel(model_id)
    if old_path and old_path.exists():
        try:
            old_path.unlink()
        except Exception as exc:
            safe_log(f"Suppression image profil matériel impossible {old_path}: {exc}")
    write_app_log("material_connection_profile_deleted", "model", model_id, f"Profil connexion matériel supprimé : {model_display_label(model)}", request=request)
    return {"status": "ok", "model_id": model_id}


