class CustomerSitePayload(BaseModel):
    name: str = Field(min_length=1, max_length=180)
    address: str | None = None
    contact_name: str | None = None
    phone: str | None = None
    email: str | None = None
    notes: str | None = None


class AssetCustomerSitePayload(BaseModel):
    customer_site_id: int | None = None


def ensure_customer_sites_v713() -> None:
    with db() as conn:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS customer_sites (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                customer_id INTEGER NOT NULL,
                name TEXT NOT NULL,
                address TEXT,
                contact_name TEXT,
                phone TEXT,
                email TEXT,
                notes TEXT,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL,
                FOREIGN KEY(customer_id) REFERENCES customers(id) ON DELETE CASCADE
            );
            CREATE INDEX IF NOT EXISTS idx_customer_sites_customer_id ON customer_sites(customer_id);
            """
        )
        # Au démarrage d’une nouvelle installation, cette migration peut être appelée
        # avant la création effective de la table assets. Dans ce cas on prépare seulement
        # customer_sites et on laisse l’ajout de customer_site_id se faire au prochain appel,
        # quand la base principale est initialisée.
        assets_table_exists = conn.execute(
            "SELECT name FROM sqlite_master WHERE type='table' AND name='assets'"
        ).fetchone()
        if assets_table_exists:
            asset_columns = {row["name"] for row in conn.execute("PRAGMA table_info(assets)").fetchall()}
            if "customer_site_id" not in asset_columns:
                conn.execute("ALTER TABLE assets ADD COLUMN customer_site_id INTEGER")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_assets_customer_site_id ON assets(customer_site_id)")


def customer_site_to_dict(row: sqlite3.Row | None) -> dict[str, Any] | None:
    return dict(row) if row else None


ensure_customer_sites_v713()


@app.get("/api/customers/{customer_id}/sites")
def api_list_customer_sites_v713(customer_id: int, request: Request) -> dict[str, Any]:
    get_request_user(request)
    ensure_customer_sites_v713()
    with db() as conn:
        customer = conn.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
        if not customer:
            raise HTTPException(status_code=404, detail="Client introuvable")
        rows = conn.execute(
            "SELECT * FROM customer_sites WHERE customer_id = ? ORDER BY name COLLATE NOCASE, id",
            (customer_id,),
        ).fetchall()
    return {"customer": dict(customer), "sites": [dict(row) for row in rows]}


@app.post("/api/customers/{customer_id}/sites")
def api_create_customer_site_v713(customer_id: int, payload: CustomerSitePayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_customer_sites_v713()
    with db() as conn:
        customer = conn.execute("SELECT * FROM customers WHERE id = ?", (customer_id,)).fetchone()
        if not customer:
            raise HTTPException(status_code=404, detail="Client introuvable")
        now = now_iso()
        cur = conn.execute(
            """
            INSERT INTO customer_sites(customer_id, name, address, contact_name, phone, email, notes, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (customer_id, payload.name.strip(), payload.address, payload.contact_name, payload.phone, payload.email, payload.notes, now, now),
        )
        site = dict(conn.execute("SELECT * FROM customer_sites WHERE id = ?", (cur.lastrowid,)).fetchone())
    write_app_log("customer_site_created", "customer", customer_id, f"Site client créé : {site.get('name')}", request=request)
    return {"status": "created", "site": site}


@app.patch("/api/customers/{customer_id}/sites/{site_id}")
def api_update_customer_site_v713(customer_id: int, site_id: int, payload: CustomerSitePayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_customer_sites_v713()
    with db() as conn:
        site_row = conn.execute("SELECT * FROM customer_sites WHERE id = ? AND customer_id = ?", (site_id, customer_id)).fetchone()
        if not site_row:
            raise HTTPException(status_code=404, detail="Site client introuvable")
        now = now_iso()
        conn.execute(
            """
            UPDATE customer_sites
            SET name = ?, address = ?, contact_name = ?, phone = ?, email = ?, notes = ?, updated_at = ?
            WHERE id = ? AND customer_id = ?
            """,
            (payload.name.strip(), payload.address, payload.contact_name, payload.phone, payload.email, payload.notes, now, site_id, customer_id),
        )
        site = dict(conn.execute("SELECT * FROM customer_sites WHERE id = ?", (site_id,)).fetchone())
    write_app_log("customer_site_updated", "customer", customer_id, f"Site client modifié : {site.get('name')}", request=request)
    return {"status": "updated", "site": site}


@app.delete("/api/customers/{customer_id}/sites/{site_id}")
def api_delete_customer_site_v713(customer_id: int, site_id: int, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_customer_sites_v713()
    with db() as conn:
        site_row = conn.execute("SELECT * FROM customer_sites WHERE id = ? AND customer_id = ?", (site_id, customer_id)).fetchone()
        if not site_row:
            raise HTTPException(status_code=404, detail="Site client introuvable")
        conn.execute("UPDATE assets SET customer_site_id = NULL, updated_at = ? WHERE customer_site_id = ?", (now_iso(), site_id))
        conn.execute("DELETE FROM customer_sites WHERE id = ? AND customer_id = ?", (site_id, customer_id))
    write_app_log("customer_site_deleted", "customer", customer_id, f"Site client supprimé : {dict(site_row).get('name')}", request=request)
    return {"status": "deleted", "id": site_id}


@app.patch("/api/assets/{asset_id}/customer-site")
def api_update_asset_customer_site_v713(asset_id: int, payload: AssetCustomerSitePayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_customer_sites_v713()
    with db() as conn:
        asset_row = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not asset_row:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        asset = dict(asset_row)
        if not asset.get("customer_id"):
            raise HTTPException(status_code=400, detail="Ce matériel n'est pas attribué à un client")
        site_id = payload.customer_site_id
        if site_id:
            site_row = conn.execute(
                "SELECT * FROM customer_sites WHERE id = ? AND customer_id = ?",
                (site_id, asset.get("customer_id")),
            ).fetchone()
            if not site_row:
                raise HTTPException(status_code=400, detail="Ce site n'appartient pas au client du matériel")
        now = now_iso()
        conn.execute("UPDATE assets SET customer_site_id = ?, updated_at = ? WHERE id = ?", (site_id, now, asset_id))
        details = f"Affectation site client : {site_id or 'non affecté'}"
        insert_asset_event(
            conn,
            asset_id,
            "customer_site_changed",
            details,
            now,
            request=request,
            source="affectation_site",
            field_name="customer_site_id",
            old_value=asset.get("customer_site_id"),
            new_value=site_id,
            customer_id=asset.get("customer_id"),
            customer_site_id=site_id,
        )
        updated = get_asset_full(conn, asset_id)
    write_app_log("asset_customer_site_updated", "asset", asset_id, details, request=request)
    return {"status": "updated", "asset": updated}


@app.get("/api/customers/{customer_id}/sites/{site_id}/installation-sheet")
@app.post("/api/customers/{customer_id}/sites/{site_id}/installation-sheet")
def api_generate_customer_site_installation_sheet_v713(customer_id: int, site_id: int, request: Request) -> dict[str, Any]:
    # La génération de fiche ne modifie pas le stock : une session authentifiée suffit.
    # Cela évite de bloquer les comptes sans droit d’écriture qui doivent seulement éditer/ouvrir une fiche PDF.
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    ensure_customer_sites_v713()
    GENERATED_DOCUMENTS_DIR.mkdir(parents=True, exist_ok=True)
    with db() as conn:
        customer = get_customer_by_id(customer_id, conn)
        if not customer:
            raise HTTPException(status_code=404, detail="Client introuvable")
        site_row = conn.execute("SELECT * FROM customer_sites WHERE id = ? AND customer_id = ?", (site_id, customer_id)).fetchone()
        if not site_row:
            raise HTTPException(status_code=404, detail="Site client introuvable")
        site = dict(site_row)
        # Requête directe par site : plus fiable que le filtre indirect par client/nom client.
        # Elle récupère uniquement le matériel réellement affecté au site demandé.
        asset_rows = conn.execute(
            """
            SELECT id FROM assets
            WHERE customer_site_id = ?
            ORDER BY CASE WHEN status='vendu' THEN 0 WHEN status='en_stock' THEN 1 ELSE 2 END, updated_at DESC, id DESC
            """,
            (site_id,),
        ).fetchall()
        assets = [get_asset_full(conn, int(row["id"])) for row in asset_rows]
    if not assets:
        raise HTTPException(status_code=409, detail="Site vide : aucun matériel n’est lié à ce site. La fiche n’a pas été générée.")
    customer_for_pdf = {**customer}
    site_name = str(site.get("name") or "Site").strip()
    if customer_for_pdf.get("company"):
        customer_for_pdf["company"] = f"{customer_for_pdf.get('company')} - {site_name}"
    else:
        customer_for_pdf["name"] = f"{customer_for_pdf.get('name') or 'Client'} - {site_name}"
    if site.get("address"):
        customer_for_pdf["address"] = site.get("address")
    caisse_asset = find_caisse_asset(assets)
    model = get_reference_by_id("Modeles", caisse_asset.get("model_id")) if caisse_asset else None
    schema = {
        "title": f"Schéma site - {site_name} - {len(assets)} matériel(s)",
        "signature": build_connection_signature(assets),
        "caisse_model": model_display_label(model) if model else "",
    }
    diagram_path = generate_connection_diagram_image(customer_for_pdf, assets, schema)
    sorted_assets = sorted(
        assets,
        key=lambda a: (
            0 if is_caisse_category(a.get("category")) else 1,
            str(a.get("category") or ""),
            str(a.get("model_name") or ""),
        ),
    )
    code = safe_filename_part(customer.get("customer_code"), "client")
    name = safe_filename_part(customer.get("company") or customer.get("name"), "client")
    site_part = safe_filename_part(site_name, "site")
    material_signature = build_installation_assets_signature(sorted_assets)
    pdf_file_name = f"Fiche_installation_{code}_{name}_{site_part}_{material_signature}.pdf"
    pdf_path = GENERATED_DOCUMENTS_DIR / pdf_file_name
    generate_installation_pdf(customer_for_pdf, sorted_assets, schema, diagram_path, pdf_path)
    write_app_log(
        "installation_site_sheet_pdf_generated",
        "customer_site",
        site_id,
        f"Fiche installation site générée : {pdf_file_name}",
        request=request,
    )
    return {
        "status": "ok",
        "customer": customer,
        "site": site,
        "assets_count": len(sorted_assets),
        "file_name": pdf_file_name,
        "download_url": f"/api/generated-documents/{urllib.parse.quote(pdf_file_name)}",
        "pdf_file_name": pdf_file_name,
        "pdf_download_url": f"/api/generated-documents/{urllib.parse.quote(pdf_file_name)}",
        "diagram_file": diagram_path.name,
        "diagram_url": f"/api/generated-documents/{urllib.parse.quote(diagram_path.name)}",
        "format": "PDF",
    }


# --- V8.0.6 : traçabilité métier simplifiée, abîmé et remplacement matériel ---
class AssetMarkDamagedPayload(BaseModel):
    reason: str | None = None


class AssetReplacementPayload(BaseModel):
    serial_number: str = Field(min_length=1)
    reason: str = Field(min_length=1)


class AssetSupplierSendPayload(BaseModel):
    reason: str = Field(min_length=1)
    sent_at: str | None = None


class AssetSupplierBackPayload(BaseModel):
    repaired: bool = True
    back_at: str | None = None
    damaged_reason: str | None = None


def ensure_asset_trace_columns_v7736() -> None:
    """Sécurise les colonnes V8.0.6 même sur une ancienne base déjà existante."""
    with db() as conn:
        asset_columns = {row["name"] for row in conn.execute("PRAGMA table_info(assets)").fetchall()}
        extra = {
            "return_supplier_sent_at": "TEXT",
            "return_supplier_back_at": "TEXT",
            "damaged_reason": "TEXT",
            "replacement_of_asset_id": "INTEGER",
            "replaced_by_asset_id": "INTEGER",
            "replacement_date": "TEXT",
            "replacement_reason": "TEXT",
        }
        for name, col_type in extra.items():
            if name not in asset_columns:
                conn.execute(f"ALTER TABLE assets ADD COLUMN {name} {col_type}")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_assets_replacement_of ON assets(replacement_of_asset_id)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_assets_replaced_by ON assets(replaced_by_asset_id)")


@app.post("/api/assets/{asset_id}/supplier-return/send")
def api_asset_supplier_return_send_v7736(asset_id: int, payload: AssetSupplierSendPayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_asset_trace_columns_v7736()
    reason = validate_return_reason_value(payload.reason, required=True)
    with db() as conn:
        asset = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not asset:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        now = payload.sent_at or now_iso()
        old_status = asset["status"]
        conn.execute(
            """
            UPDATE assets
            SET status = 'retour_fournisseur', customer_id = NULL, customer_site_id = NULL, client_name = ?, sale_date = NULL,
                return_reason = ?, return_supplier_sent_at = ?, return_supplier_back_at = NULL, updated_at = ?
            WHERE id = ?
            """,
            (build_return_supplier_client_name(None), reason, now, now, asset_id),
        )
        insert_asset_event(
            conn, asset_id, "retour_fournisseur", f"Envoi fournisseur : {now} | Motif : {return_reason_label(reason)}",
            now, request=request, source="retour_fournisseur", field_name="status", old_value=old_status, new_value="retour_fournisseur",
            customer_id=asset["customer_id"], customer_site_id=asset["customer_site_id"] if "customer_site_id" in asset.keys() else None,
        )
        updated = get_asset_full(conn, asset_id)
    sync_asset_to_excel(updated)
    write_app_log("asset_supplier_return_sent", "asset", asset_id, f"Retour fournisseur : {return_reason_label(reason)}", request=request)
    return {"status": "ok", "message": "Retour fournisseur enregistré.", "asset": updated}


@app.post("/api/assets/{asset_id}/supplier-return/back")
def api_asset_supplier_return_back_v7736(asset_id: int, payload: AssetSupplierBackPayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_asset_trace_columns_v7736()
    with db() as conn:
        asset = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not asset:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        now = payload.back_at or now_iso()
        old_status = asset["status"]
        new_status = "en_stock" if payload.repaired else "abime"
        damaged_reason = None if payload.repaired else (payload.damaged_reason or "Fournisseur incapable de réparer le matériel")
        conn.execute(
            """
            UPDATE assets
            SET status = ?, client_name = NULL, customer_id = NULL, customer_site_id = NULL, sale_date = NULL,
                return_supplier_back_at = ?, damaged_reason = ?, updated_at = ?
            WHERE id = ?
            """,
            (new_status, now, damaged_reason, now, asset_id),
        )
        details = f"Retour fournisseur : {now}"
        if damaged_reason:
            details += f" | Matériel abîmé : {damaged_reason}"
        insert_asset_event(
            conn, asset_id, "retour_fournisseur_termine", details, now, request=request,
            source="retour_fournisseur", field_name="status", old_value=old_status, new_value=new_status,
            customer_id=asset["customer_id"], customer_site_id=asset["customer_site_id"] if "customer_site_id" in asset.keys() else None,
        )
        updated = get_asset_full(conn, asset_id)
    sync_asset_to_excel(updated)
    write_app_log("asset_supplier_return_back", "asset", asset_id, details, request=request)
    return {"status": "ok", "message": "Retour fournisseur clôturé.", "asset": updated}


@app.post("/api/assets/{asset_id}/mark-damaged")
def api_mark_asset_damaged_v7736(asset_id: int, payload: AssetMarkDamagedPayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_asset_trace_columns_v7736()
    reason = str(payload.reason or "Matériel abîmé / irréparable").strip() or "Matériel abîmé / irréparable"
    with db() as conn:
        asset = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not asset:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        old_status = asset["status"]
        now = now_iso()
        back_at = asset["return_supplier_back_at"] if "return_supplier_back_at" in asset.keys() else None
        if old_status == "retour_fournisseur" and not back_at:
            back_at = now
        conn.execute(
            """
            UPDATE assets
            SET status = 'abime', customer_id = NULL, customer_site_id = NULL, client_name = NULL, sale_date = NULL,
                teamviewer_id = NULL, teamviewer_password = NULL, damaged_reason = ?, return_supplier_back_at = ?, updated_at = ?
            WHERE id = ?
            """,
            (reason, back_at, now, asset_id),
        )
        details = f"Matériel marqué abîmé / irréparable : {reason}"
        insert_asset_event(
            conn, asset_id, "materiel_abime", details, now, request=request,
            source="abime", field_name="status", old_value=old_status, new_value="abime",
            customer_id=asset["customer_id"], customer_site_id=asset["customer_site_id"] if "customer_site_id" in asset.keys() else None,
        )
        updated = get_asset_full(conn, asset_id)
    sync_asset_to_excel(updated)
    write_app_log("asset_marked_damaged", "asset", asset_id, details, request=request)
    return {"status": "ok", "message": "Matériel marqué abîmé.", "asset": updated}


@app.post("/api/assets/{asset_id}/replacement")
def api_replace_customer_asset_v7736(asset_id: int, payload: AssetReplacementPayload, request: Request) -> dict[str, Any]:
    require_asset_write(request)
    ensure_asset_trace_columns_v7736()
    sn_norm = normalize_sn(payload.serial_number)
    reason = str(payload.reason or "").strip()
    if not reason:
        raise HTTPException(status_code=400, detail="Raison du remplacement obligatoire.")
    with db() as conn:
        old_row = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not old_row:
            raise HTTPException(status_code=404, detail="Ancien matériel introuvable")
        old = dict(old_row)
        if not old.get("customer_id"):
            raise HTTPException(status_code=400, detail="Remplacement impossible : l’ancien matériel n’est pas attribué à un client.")
        new_asset_id = find_asset_id_by_scan_sn(conn, sn_norm)
        if not new_asset_id:
            raise HTTPException(status_code=404, detail="Nouveau matériel introuvable : il doit être enregistré avant le remplacement.")
        if int(new_asset_id) == int(asset_id):
            raise HTTPException(status_code=400, detail="Le nouveau matériel doit être différent de l’ancien.")
        new_row = conn.execute("SELECT * FROM assets WHERE id = ?", (new_asset_id,)).fetchone()
        if not new_row:
            raise HTTPException(status_code=404, detail="Nouveau matériel introuvable")
        new = dict(new_row)
        if new.get("status") != "en_stock" or new.get("customer_id"):
            raise HTTPException(status_code=400, detail="Le nouveau matériel doit être disponible en stock et non attribué.")
        customer = conn.execute("SELECT * FROM customers WHERE id = ?", (old.get("customer_id"),)).fetchone()
        if not customer:
            raise HTTPException(status_code=404, detail="Client de l’ancien matériel introuvable")
        customer_dict = dict(customer)
        display_name = customer_display_name(customer_dict)
        now = now_iso()
        customer_site_id = old.get("customer_site_id")
        replacement_status = "vendu"
        # Ancien matériel : sortie du parc actif client, marqué abîmé/remplacé.
        conn.execute(
            """
            UPDATE assets
            SET status = 'abime', customer_id = NULL, customer_site_id = NULL, client_name = NULL, sale_date = NULL,
                teamviewer_id = NULL, teamviewer_password = NULL, damaged_reason = ?, replaced_by_asset_id = ?,
                replacement_date = ?, replacement_reason = ?, updated_at = ?
            WHERE id = ?
            """,
            (reason, new_asset_id, now, reason, now, asset_id),
        )
        # Nouveau matériel : attribution au même client/site.
        conn.execute(
            """
            UPDATE assets
            SET status = ?, customer_id = ?, customer_site_id = ?, client_name = ?, sale_date = ?,
                return_reason = NULL, return_supplier_sent_at = NULL, return_supplier_back_at = NULL, damaged_reason = NULL,
                replacement_of_asset_id = ?, replacement_date = ?, replacement_reason = ?, updated_at = ?
            WHERE id = ?
            """,
            (replacement_status, old.get("customer_id"), customer_site_id, display_name, now, asset_id, now, reason, now, new_asset_id),
        )
        old_sn = old.get("serial_number_raw") or old.get("asset_code")
        new_sn = new.get("serial_number_raw") or new.get("asset_code")
        insert_asset_event(
            conn, asset_id, "remplacement_sortie", f"Remplacé par {new_sn} | Date : {now} | Raison : {reason}", now,
            request=request, source="remplacement", field_name="status", old_value=old.get("status"), new_value="abime",
            customer_id=old.get("customer_id"), customer_site_id=customer_site_id,
        )
        insert_asset_event(
            conn, new_asset_id, "remplacement_entree", f"Remplace {old_sn} | Client : {display_name} | Date : {now} | Raison : {reason}", now,
            request=request, source="remplacement", field_name="status", old_value=new.get("status"), new_value=replacement_status,
            customer_id=old.get("customer_id"), customer_site_id=customer_site_id,
        )
        old_asset = get_asset_full(conn, asset_id)
        new_asset = get_asset_full(conn, new_asset_id)
    sync_asset_to_excel(old_asset)
    sync_asset_to_excel(new_asset)
    details = f"Remplacement {old_asset.get('serial_number_raw')} -> {new_asset.get('serial_number_raw')} | {reason}"
    write_app_log("asset_replacement", "asset", asset_id, details, request=request)
    return {"status": "ok", "message": "Remplacement effectué avec traçabilité.", "old_asset": old_asset, "new_asset": new_asset}

try:
    ensure_asset_trace_columns_v7736()
except Exception as exc:
    safe_log(f"Migration V8.0.6 traçabilité/remplacement impossible : {exc}")


