# --- V8.0.6 : API fiable pour sous-catégories matériel ---
def _asset_status_key_v7740(value: Any) -> str:
    raw = str(value or "").strip().lower()
    normalized = unicodedata.normalize("NFD", raw)
    normalized = "".join(ch for ch in normalized if unicodedata.category(ch) != "Mn")
    normalized = normalized.replace("_", " ").replace("-", " ")
    normalized = " ".join(normalized.split())
    if normalized in {"en stock", "stock", "disponible", "available", "enstock"}:
        return "en_stock"
    if normalized in {"reserve", "reservation", "booked", "reserved"}:
        return "reserve"
    if normalized in {"vendu", "sold"}:
        return "vendu"
    if "vendu" in normalized or "sold" in normalized:
        return "vendu"
    if "reserve" in normalized or "reservation" in normalized or "reserved" in normalized:
        return "reserve"
    if "stock" in normalized or "disponible" in normalized or "available" in normalized:
        return "en_stock"
    return "autres"


@app.get("/api/assets-category-status")
def api_assets_category_status_v7740(category: str = Query(default="")) -> dict[str, Any]:
    """Retourne une catégorie avec ses matériels par statut.

    Cette API utilise la même normalisation de catégorie que le tableau de bord afin
    que les compteurs des cartes principales et les sous-catégories affichent les
    mêmes chiffres.

    V8.0.6 : category peut être vide. Certaines vues déclenchent un rafraîchissement
    après modification alors qu'aucune catégorie n'est active. Dans ce cas on renvoie
    une réponse vide au lieu d'une erreur 422 affichée à l'utilisateur.
    """
    category_input = urllib.parse.unquote(str(category or "")).strip()
    if not category_input:
        empty_buckets = {"en_stock": [], "reserve": [], "vendu": [], "autres": []}
        return {
            "category": "",
            "total": 0,
            "counts": {"en_stock": 0, "reserve": 0, "vendu": 0, "autres": 0},
            "stock_value_eur": 0.0,
            "total_value_eur": 0.0,
            "rows": [],
            "buckets": empty_buckets,
        }
    target = canonical_category_label(category_input)
    models = get_references_index("Modeles")
    suppliers = get_references_index("Fournisseurs")
    customers_cache: dict[int, dict[str, Any] | None] = {}

    def customer_for(asset_customer_id: Any) -> dict[str, Any] | None:
        try:
            cid = int(asset_customer_id or 0)
        except (TypeError, ValueError):
            cid = 0
        if not cid:
            return None
        if cid not in customers_cache:
            customers_cache[cid] = get_customer_by_id(cid)
        return customers_cache[cid]

    with db() as conn:
        rows = conn.execute(
            """
            SELECT *
            FROM assets
            ORDER BY updated_at DESC, id DESC
            """
        ).fetchall()

    out: list[dict[str, Any]] = []
    buckets: dict[str, list[dict[str, Any]]] = {"en_stock": [], "reserve": [], "vendu": [], "autres": []}
    value_stock = 0.0
    value_total = 0.0
    for row in rows:
        asset = dict(row)
        model = models.get(int(asset["model_id"])) if asset.get("model_id") else None
        supplier = suppliers.get(int(asset["supplier_id"])) if asset.get("supplier_id") else None
        category_raw = str(model.get("category") or "Non classé") if model else "Modèle supprimé"
        category_label = canonical_category_label(category_raw)
        if canonical_category_label(category_label) != target:
            continue
        status_key = _asset_status_key_v7740(asset.get("status"))
        try:
            price = float(asset.get("purchase_price_eur") or 0)
        except (TypeError, ValueError):
            price = 0.0
        value_total += price
        if status_key in {"en_stock", "reserve"}:
            value_stock += price
        customer = customer_for(asset.get("customer_id"))
        item = enrich_asset_image_fields({
            **asset,
            "brand": model.get("brand") if model else "Modèle supprimé",
            "model_name": model.get("model_name") if model else "",
            "category": category_label,
            "category_key": canonical_category_label(category_label),
            "supplier_name": supplier.get("name") if supplier else None,
            "customer_code": (customer or {}).get("customer_code"),
            "customer_display_name": customer_display_name(customer),
            "customer_company": (customer or {}).get("company"),
            "customer_email": (customer or {}).get("email"),
            "customer_phone": (customer or {}).get("phone"),
            "status_key": status_key,
            "status_label": excel_safe_status_label(asset.get("status")),
            "return_reason_label": return_reason_label(asset.get("return_reason")),
        })
        out.append(item)
        buckets.setdefault(status_key, []).append(item)

    counts = {key: len(buckets.get(key, [])) for key in ["en_stock", "reserve", "vendu", "autres"]}
    return {
        "category": target,
        "total": len(out),
        "counts": counts,
        "stock_value_eur": round(value_stock, 2),
        "total_value_eur": round(value_total, 2),
        "rows": out,
        "buckets": buckets,
    }

