# --- V8.0.6 : tri modèle, nouvelle base robuste, routes utilitaires ---
def _v7741_norm_text(value: Any) -> str:
    try:
        import unicodedata
        text = str(value or "")
        text = unicodedata.normalize("NFD", text)
        text = "".join(ch for ch in text if unicodedata.category(ch) != "Mn")
        return re.sub(r"\s+", " ", text).strip().casefold()
    except Exception:
        return str(value or "").strip().lower()


def sort_assets_category_model_v7741(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """Tri standard : catégorie -> marque -> modèle -> SN -> id."""
    def key(a: dict[str, Any]) -> tuple[Any, ...]:
        return (
            _v7741_norm_text(a.get("category") or "Non classé"),
            _v7741_norm_text(a.get("brand") or ""),
            _v7741_norm_text(a.get("model_name") or ""),
            _v7741_norm_text(a.get("serial_number_raw") or a.get("asset_code") or ""),
            int(a.get("id") or 0),
        )
    return sorted(list(rows or []), key=key)


def create_new_base_at_path(raw_path: str | None) -> dict[str, Any]:
    """V8.0.6 : création de nouvelle base plus robuste avec rollback si échec."""
    global AUTO_SYNC_SUSPENDED
    target = resolve_new_base_path(raw_path)
    validation = validate_new_base_folder(target)
    previous_data_folder = DATA_DIR
    previous_auto_sync = AUTO_SYNC_SUSPENDED
    reference_payload: dict[str, Any] | None = None
    try:
        reference_payload = capture_reference_preserve_payload(previous_data_folder)
    except Exception as exc:
        safe_log(f"V8.0.6 capture référentiel avant nouvelle base impossible : {exc}")
        reference_payload = None
    AUTO_SYNC_SUSPENDED = True
    archived_to: Path | None = None
    preserved: dict[str, Any] | None = None
    try:
        switch_active_data_dir(target)
        archived_to = reset_application_data_for_new_base(reference_payload)
        # Force les tables et dossiers attendus après le switch, même sur base totalement vide.
        ensure_data_directories()
        init_db()
        ensure_sqlite_reference_store()
        ensure_status_defaults()
        ensure_return_reason_defaults()
        ensure_superadmin_user()
        ensure_customer_sites_v713()
        if reference_payload:
            preserved = restore_reference_preserve_payload(reference_payload, DATA_DIR)
        else:
            preserved = {"files": 0, "dirs": 0, "reference_rows": 0, "model_prices": 0}
        clear_excel_read_cache()
        try:
            ensure_reference_workbook()
        except Exception as exc:
            safe_log(f"V8.0.6 création classeur référentiel nouvelle base : {exc}")
            recover_reference_workbook("nouvelle_base_v7741")
        append_update_history_event({
            "event": "create_new_base_v7741",
            "version": APP_VERSION,
            "target_folder": str(DATA_DIR),
            "previous_data_folder": str(previous_data_folder),
            "archived_existing_files_to": str(archived_to) if archived_to else None,
            "referentiel_conserve": preserved,
        })
    except Exception:
        try:
            switch_active_data_dir(previous_data_folder)
        except Exception as rollback_exc:
            safe_log(f"V8.0.6 rollback nouvelle base impossible : {rollback_exc}")
        raise
    finally:
        AUTO_SYNC_SUSPENDED = previous_auto_sync

    return {
        "created": True,
        "previous_data_folder": str(previous_data_folder),
        "active_data_folder": str(DATA_DIR),
        "archived_existing_files_to": str(archived_to) if archived_to else None,
        "existing_files_archived": validation.get("existing", []),
        "referentiel_conserve": preserved,
        "warnings": validation.get("warnings", []),
        "message": "Nouvelle base créée et démarrée dans le dossier clyoStock. Le référentiel, les modèles, règles, statuts et motifs ont été conservés quand ils étaient lisibles.",
    }


@app.get("/api/assets/by-status/{status_value}")
def api_assets_by_status_v7741(status_value: str, request: Request) -> dict[str, Any]:
    """Vue complète d'un statut, triée par catégorie puis modèle."""
    get_request_user(request)
    status_value = urllib.parse.unquote(str(status_value or "")).strip()
    if status_value not in get_status_options_map():
        raise HTTPException(status_code=404, detail="Statut inconnu")
    data = dashboard_status_detail(status_value)
    rows = sort_assets_category_model_v7741(data.get("rows") or [])
    return {**data, "rows": rows, "grouping": "category_model", "count": len(rows)}


@app.get("/api/update/check-online-v7741")
def api_check_online_update_v7741(request: Request) -> dict[str, Any]:
    """Diagnostic GitHub renforcé pour l'interface."""
    require_superadmin(request)
    manifest = fetch_update_manifest_v717()
    return {
        "status": "ok",
        "app_version": APP_VERSION,
        "manifest_url": UPDATE_MANIFEST_URL,
        "message": "Mise à jour disponible." if manifest.get("update_available") else "Aucune mise à jour disponible.",
        **manifest,
    }


