_PREV_LAUNCH_AUTONOMOUS_UPDATER_V7752 = launch_autonomous_updater


def _extract_version_from_text_v7752(content: str) -> str:
    m = re.search(r"APP_VERSION\s*=\s*['\"]([^'\"]+)['\"]", content or "")
    return m.group(1).strip() if m else ""


def inspect_update_zip_v7752(zip_path: Path) -> dict[str, Any]:
    zip_path = Path(zip_path).resolve()
    if not zip_path.exists() or not zip_path.is_file():
        raise HTTPException(status_code=400, detail=f"ZIP introuvable : {zip_path}")
    size = zip_path.stat().st_size if zip_path.exists() else 0
    if size < 1024:
        raise HTTPException(status_code=400, detail="ZIP invalide : fichier trop petit ou vide.")
    with zipfile.ZipFile(zip_path) as zf:
        bad = zf.testzip()
        if bad:
            raise HTTPException(status_code=400, detail=f"ZIP invalide ou corrompu : {bad}")
        names = [n.replace('\\', '/') for n in zf.namelist()]
        app_candidates = [n for n in names if n == 'app.py' or n.endswith('/app.py')]
        if not app_candidates:
            raise HTTPException(status_code=400, detail="ZIP invalide : aucun app.py trouvé dans la mise à jour.")
        preferred = next((n for n in app_candidates if n == 'app.py'), app_candidates[0])
        try:
            target_version = _extract_version_from_text_v7752(zf.read(preferred).decode('utf-8', errors='ignore'))
        except Exception:
            target_version = ""
    return {"zip_path": str(zip_path), "zip_size_bytes": size, "target_version": target_version, "current_version": APP_VERSION}


def launch_autonomous_updater(update_zip: Path, stamp: str, target_root: Path, create_desktop_shortcut: bool) -> dict[str, Any]:
    """V8.0.6 : lance un updater externe PowerShell si aucun updater Python/EXE fiable n'est possible."""
    try:
        inspect_update_zip_v7752(update_zip)
    except Exception as exc:
        return {"started": False, "reason": f"ZIP non installable : {exc}", "progress_log": str(target_root / 'update_autobuild.log')}
    # Sous Windows, PowerShell est disponible par défaut et permet d'installer sans Python.
    if os.name == "nt":
        try:
            target_root = target_root.resolve()
            runner_dir = target_root / "update_backups" / f"ps_runner_{stamp}"
            runner_dir.mkdir(parents=True, exist_ok=True)
            src_ps = APP_DIR / "CLYO_Stock_Update_PowerShell.ps1"
            if not src_ps.exists():
                src_ps = target_root / "CLYO_Stock_Update_PowerShell.ps1"
            if not src_ps.exists():
                raise RuntimeError("CLYO_Stock_Update_PowerShell.ps1 introuvable")
            runner_ps = runner_dir / "CLYO_Stock_Update_PowerShell.ps1"
            shutil.copy2(src_ps, runner_ps)
            progress_log = target_root / "update_autobuild.log"
            powershell = shutil.which("powershell.exe") or shutil.which("powershell") or "powershell.exe"
            cmd = [
                powershell,
                "-NoProfile",
                "-ExecutionPolicy", "Bypass",
                "-File", str(runner_ps),
                "-AppDir", str(target_root),
                "-ZipPath", str(update_zip),
                "-OldPid", str(os.getpid()),
                "-CurrentExe", str(Path(sys.executable).resolve()),
                "-LogPath", str(progress_log),
            ]
            creationflags = getattr(subprocess, "CREATE_NEW_CONSOLE", 0) | getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0)
            subprocess.Popen(cmd, cwd=str(runner_dir), stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, creationflags=creationflags, close_fds=True)
            return {"started": True, "mode": "powershell_external_updater_v7752", "progress_server_started": False, "script": str(runner_ps), "runner": str(runner_ps), "launcher": str(runner_ps), "progress_log": str(progress_log), "message": "Updater externe V8.0.6 lancé : fermeture de l’application, sauvegarde, extraction ZIP, copie contrôlée, relance."}
        except Exception as exc:
            try:
                with (target_root / "update_autobuild.log").open("a", encoding="utf-8", errors="ignore") as fh:
                    fh.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] PowerShell updater V7752 impossible : {type(exc).__name__}: {exc}\n")
            except Exception:
                pass
            return _PREV_LAUNCH_AUTONOMOUS_UPDATER_V7752(update_zip, stamp, target_root, create_desktop_shortcut)
    return _PREV_LAUNCH_AUTONOMOUS_UPDATER_V7752(update_zip, stamp, target_root, create_desktop_shortcut)


def fetch_update_manifest_v717() -> dict[str, Any]:
    manifest_url = UPDATE_MANIFEST_URL
    req = urllib.request.Request(manifest_url, headers={"User-Agent": f"{APP_NAME.replace(' ', '-')}/{APP_VERSION}", "Accept": "application/json,text/plain,*/*", "Cache-Control": "no-cache", "Pragma": "no-cache"})
    try:
        with urllib.request.urlopen(req, timeout=25) as resp:
            status = getattr(resp, "status", 200); content_type = resp.headers.get("Content-Type", ""); raw = resp.read(2 * 1024 * 1024)
    except urllib.error.HTTPError as exc:
        raise HTTPException(status_code=502, detail=f"GitHub refuse version.json : HTTP {exc.code}. URL : {manifest_url}") from exc
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Impossible de lire version.json GitHub. URL : {manifest_url}. Détail : {exc}") from exc
    if not raw:
        raise HTTPException(status_code=502, detail=f"version.json GitHub est vide. URL : {manifest_url}")
    try:
        decoded = raw.decode("utf-8-sig"); data = json.loads(decoded)
    except Exception as exc:
        sample = raw[:350].decode("utf-8", errors="replace").replace("\n", " ").replace("\r", " ")
        raise HTTPException(status_code=502, detail=f"version.json n'est pas un JSON valide. Début reçu : {sample}. Détail : {exc}") from exc
    if not isinstance(data, dict):
        raise HTTPException(status_code=502, detail="version.json doit contenir un objet JSON.")
    latest = str(data.get("latest_version") or data.get("version") or data.get("app_version") or data.get("tag_name") or "").strip().lstrip("vV")
    zip_url = str(data.get("zip_url") or data.get("download_url") or data.get("asset_url") or data.get("package_url") or data.get("url_zip") or "").strip()
    if not zip_url and isinstance(data.get("assets"), list):
        for asset in data.get("assets"):
            if isinstance(asset, dict):
                candidate = str(asset.get("browser_download_url") or asset.get("download_url") or asset.get("url") or "").strip()
                name = str(asset.get("name") or candidate).lower()
                if candidate and (candidate.lower().endswith(".zip") or ".zip" in name):
                    zip_url = candidate; break
    if not latest:
        raise HTTPException(status_code=502, detail="version.json invalide : champ version/latest_version/app_version manquant.")
    if zip_url and "github.com" in zip_url and "/blob/" in zip_url:
        zip_url = zip_url.replace("github.com/", "raw.githubusercontent.com/").replace("/blob/", "/")
    changelog = data.get("changelog") or data.get("changes") or data.get("release_notes") or []
    if isinstance(changelog, str): changelog = [line.strip(" -•\t") for line in changelog.splitlines() if line.strip()]
    elif isinstance(changelog, dict): changelog = [f"{k}: {v}" for k, v in changelog.items()]
    elif not isinstance(changelog, list): changelog = []
    normalized = {"latest_version": latest, "minimum_version": str(data.get("minimum_version") or "").strip(), "zip_url": zip_url, "sha256": str(data.get("sha256") or data.get("checksum_sha256") or "").strip().lower(), "mandatory": bool(data.get("mandatory", False)), "changelog": [str(item) for item in changelog], "source_url": manifest_url, "content_type": content_type, "http_status": status, "raw_keys": sorted([str(k) for k in data.keys()])[:40]}
    normalized["update_available"] = is_version_newer_v717(normalized["latest_version"], APP_VERSION)
    return normalized


def download_online_update_zip_v717(manifest: dict[str, Any], stamp: str) -> Path:
    zip_url = str(manifest.get("zip_url") or "").strip()
    if not zip_url:
        raise HTTPException(status_code=400, detail="zip_url manquant dans version.json : impossible d’installer depuis GitHub.")
    target_root = APP_DIR.resolve(); download_dir = target_root / "update_backups" / "downloads"; download_dir.mkdir(parents=True, exist_ok=True)
    file_name = safe_update_zip_name_v717(str(manifest.get("latest_version") or ""), zip_url)
    tmp_path = download_dir / f"download_{stamp}_{file_name}"
    req = urllib.request.Request(zip_url, headers={"User-Agent": f"{APP_NAME.replace(' ', '-')}/{APP_VERSION}", "Accept": "application/zip,application/octet-stream,*/*"})
    sha = hashlib.sha256(); read_bytes = 0; content_type = ""
    try:
        with urllib.request.urlopen(req, timeout=90) as resp, tmp_path.open("wb") as out:
            content_type = resp.headers.get("Content-Type", "")
            while True:
                chunk = resp.read(1024 * 1024)
                if not chunk: break
                read_bytes += len(chunk)
                if read_bytes > 500 * 1024 * 1024: raise HTTPException(status_code=400, detail="ZIP trop volumineux pour une mise à jour automatique.")
                sha.update(chunk); out.write(chunk)
    except HTTPException:
        tmp_path.unlink(missing_ok=True); raise
    except Exception as exc:
        tmp_path.unlink(missing_ok=True); raise HTTPException(status_code=502, detail=f"Téléchargement du ZIP impossible. URL : {zip_url}. Détail : {exc}") from exc
    if read_bytes < 1024:
        sample = tmp_path.read_text(encoding="utf-8", errors="replace")[:250] if tmp_path.exists() else ""
        tmp_path.unlink(missing_ok=True); raise HTTPException(status_code=502, detail=f"Téléchargement GitHub invalide : fichier reçu trop petit. Content-Type : {content_type}. Début : {sample}")
    expected_sha = str(manifest.get("sha256") or "").strip().lower(); actual_sha = sha.hexdigest().lower()
    if expected_sha and expected_sha != actual_sha:
        tmp_path.unlink(missing_ok=True); raise HTTPException(status_code=400, detail=f"Contrôle SHA256 échoué : attendu {expected_sha}, obtenu {actual_sha}")
    inspect_update_zip_v7752(tmp_path)
    return tmp_path


