def reference_payload_has_content_v7753(payload: dict[str, Any] | None) -> bool:
    if not payload:
        return False
    tables = payload.get("tables") or {}
    files = payload.get("files") or {}
    dirs = payload.get("dirs") or {}
    if any(files.values()):
        return True
    if any(entries for entries in dirs.values()):
        return True
    if any(tables.get(key) for key in ("reference_rows", "model_prices")):
        return True
    return False


def save_application_reference_store_v7753(payload: dict[str, Any] | None, reason: str = "auto") -> dict[str, Any]:
    """Sauvegarde les référentiels dans le dossier de l'application, hors base active."""
    if not reference_payload_has_content_v7753(payload):
        return {"status": "empty", "files": 0, "dirs": 0, "reference_rows": 0, "model_prices": 0}
    APP_REFERENCE_STORE_FILES_V7753.mkdir(parents=True, exist_ok=True)
    APP_REFERENCE_STORE_DIRS_V7753.mkdir(parents=True, exist_ok=True)
    stored_files = 0
    stored_dir_files = 0
    for name, data in (payload.get("files") or {}).items():
        try:
            dest = APP_REFERENCE_STORE_FILES_V7753 / str(name)
            dest.parent.mkdir(parents=True, exist_ok=True)
            if isinstance(data, bytes):
                dest.write_bytes(data)
            elif isinstance(data, str):
                dest.write_text(data, encoding="utf-8")
            else:
                continue
            stored_files += 1
        except Exception as exc:
            safe_log(f"Sauvegarde référentiel application fichier impossible {name}: {exc}")
    for dirname, entries in (payload.get("dirs") or {}).items():
        root = APP_REFERENCE_STORE_DIRS_V7753 / str(dirname)
        try:
            if root.exists():
                shutil.rmtree(root, ignore_errors=True)
            root.mkdir(parents=True, exist_ok=True)
        except Exception as exc:
            safe_log(f"Préparation dossier référentiel application impossible {dirname}: {exc}")
            continue
        for rel, data in (entries or {}).items():
            try:
                dest = root / str(rel)
                dest.parent.mkdir(parents=True, exist_ok=True)
                if isinstance(data, bytes):
                    dest.write_bytes(data)
                elif isinstance(data, str):
                    dest.write_text(data, encoding="utf-8")
                else:
                    continue
                stored_dir_files += 1
            except Exception as exc:
                safe_log(f"Sauvegarde référentiel application dossier impossible {dirname}/{rel}: {exc}")
    tables = payload.get("tables") or {}
    try:
        APP_REFERENCE_STORE_TABLES_V7753.write_text(json.dumps(tables, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        safe_log(f"Sauvegarde tables référentiel application impossible : {exc}")
    reference_rows = len(tables.get("reference_rows") or [])
    model_prices = len(tables.get("model_prices") or [])
    meta = {
        "status": "ok",
        "app_version": APP_VERSION,
        "reason": reason,
        "updated_at": now_iso(),
        "source_dir": str(payload.get("source_dir") or DATA_DIR),
        "active_data_dir_at_save": str(DATA_DIR),
        "files": stored_files,
        "dir_files": stored_dir_files,
        "reference_rows": reference_rows,
        "model_prices": model_prices,
    }
    try:
        APP_REFERENCE_STORE_META_V7753.write_text(json.dumps(meta, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        safe_log(f"Sauvegarde méta référentiel application impossible : {exc}")
    return meta


def load_application_reference_store_v7753() -> dict[str, Any] | None:
    if not APP_REFERENCE_STORE_DIR_V7753.exists():
        return None
    payload: dict[str, Any] = {
        "source_dir": str(APP_REFERENCE_STORE_DIR_V7753),
        "captured_at": now_iso(),
        "tables": {"reference_rows": [], "model_prices": []},
        "files": {},
        "dirs": {},
    }
    try:
        if APP_REFERENCE_STORE_TABLES_V7753.exists():
            tables = json.loads(APP_REFERENCE_STORE_TABLES_V7753.read_text(encoding="utf-8"))
            if isinstance(tables, dict):
                payload["tables"] = tables
    except Exception as exc:
        safe_log(f"Lecture tables référentiel application impossible : {exc}")
    try:
        if APP_REFERENCE_STORE_FILES_V7753.exists():
            for file_path in APP_REFERENCE_STORE_FILES_V7753.rglob("*"):
                if file_path.is_file():
                    rel = str(file_path.relative_to(APP_REFERENCE_STORE_FILES_V7753)).replace("\\", "/")
                    payload["files"][rel] = file_path.read_bytes()
    except Exception as exc:
        safe_log(f"Lecture fichiers référentiel application impossible : {exc}")
    try:
        if APP_REFERENCE_STORE_DIRS_V7753.exists():
            for root in APP_REFERENCE_STORE_DIRS_V7753.iterdir():
                if not root.is_dir():
                    continue
                entries: dict[str, bytes] = {}
                for file_path in root.rglob("*"):
                    if file_path.is_file():
                        rel = str(file_path.relative_to(root)).replace("\\", "/")
                        entries[rel] = file_path.read_bytes()
                payload["dirs"][root.name] = entries
    except Exception as exc:
        safe_log(f"Lecture dossiers référentiel application impossible : {exc}")
    return payload if reference_payload_has_content_v7753(payload) else None


_PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7753 = capture_reference_preserve_payload
_PREV_RESTORE_REFERENCE_PRESERVE_PAYLOAD_V7753 = restore_reference_preserve_payload


def capture_reference_preserve_payload(source_dir: Path | None = None) -> dict[str, Any]:
    payload = _PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7753(source_dir)
    try:
        save_application_reference_store_v7753(payload, reason="capture_before_base_change")
    except Exception as exc:
        safe_log(f"Sauvegarde référentiel application après capture impossible : {exc}")
    return payload


def restore_reference_preserve_payload(payload: dict[str, Any] | None, target_dir: Path | None = None) -> dict[str, Any]:
    # V8.0.6 : ne jamais restaurer automatiquement le référentiel applicatif
    # si aucun payload explicite n'est fourni. Cela évite d'écraser les
    # référentiels d'une base existante chargée par l'utilisateur.
    if not reference_payload_has_content_v7753(payload):
        return {"files": 0, "dirs": 0, "reference_rows": 0, "model_prices": 0, "skipped": "no_explicit_payload"}
    result = _PREV_RESTORE_REFERENCE_PRESERVE_PAYLOAD_V7753(payload, target_dir)
    try:
        save_application_reference_store_v7753(payload, reason="restore_explicit_new_base")
    except Exception as exc:
        safe_log(f"Mise à jour référentiel application après restauration impossible : {exc}")
    return result


@app.on_event("startup")
def startup_reference_store_v7753() -> None:
    """Au démarrage, sauvegarde le référentiel actif sans jamais l'écraser.

    V8.0.6 : une base existante chargée par l'utilisateur devient toujours
    la source de vérité. Le référentiel applicatif est mis à jour depuis cette
    base, et non restauré par-dessus.
    """
    ensure_app_logs_computer_column_v7753()
    try:
        active_payload = _PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7753(DATA_DIR)
        if reference_payload_has_content_v7753(active_payload):
            save_application_reference_store_v7753(active_payload, reason="startup_refresh_from_active_base_no_restore")
        else:
            safe_log("Référentiel actif vide au démarrage : aucune restauration automatique pour éviter un écrasement.")
    except Exception as exc:
        safe_log(f"Référentiel application V8.0.6 indisponible au démarrage : {exc}")



# --- V8.0.6 : support EXE distribuable onefile ---
# Si l'application est compilée en onefile, le référentiel applicatif peut être
# embarqué dans _MEIPASS. On le copie une seule fois à côté de l'EXE pour qu'il
# reste modifiable, sans jamais écraser une base existante.
APP_REFERENCE_STORE_RESOURCE_DIR_V7772 = APP_RESOURCE_DIR / "referentiel_application_store"


def ensure_bundled_reference_store_seed_v7772() -> None:
    try:
        if APP_REFERENCE_STORE_DIR_V7753.exists():
            return
        if not APP_REFERENCE_STORE_RESOURCE_DIR_V7772.exists():
            return
        shutil.copytree(APP_REFERENCE_STORE_RESOURCE_DIR_V7772, APP_REFERENCE_STORE_DIR_V7753, dirs_exist_ok=True)
        safe_log(f"Référentiel applicatif initial copié depuis ressources onefile : {APP_REFERENCE_STORE_RESOURCE_DIR_V7772}")
    except Exception as exc:
        safe_log(f"Initialisation référentiel onefile impossible : {exc}")


_PREV_LOAD_APPLICATION_REFERENCE_STORE_V7772 = load_application_reference_store_v7753


def load_application_reference_store_v7753() -> dict[str, Any] | None:
    ensure_bundled_reference_store_seed_v7772()
    return _PREV_LOAD_APPLICATION_REFERENCE_STORE_V7772()


_PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7772 = capture_reference_preserve_payload


def capture_reference_preserve_payload(source_dir: Path | None = None) -> dict[str, Any]:
    payload = _PREV_CAPTURE_REFERENCE_PRESERVE_PAYLOAD_V7772(source_dir)
    if reference_payload_has_content_v7753(payload):
        return payload
    fallback = load_application_reference_store_v7753()
    if reference_payload_has_content_v7753(fallback):
        safe_log("Référentiel vide : utilisation du référentiel applicatif embarqué en secours.")
        return fallback
    return payload


