# V8.0.6 FINAL - surcharge après anciens correctifs V8.0.6 pour GitHub ZIP ou EXE.
def fetch_update_manifest_v717() -> dict[str, Any]:
    manifest_url = UPDATE_MANIFEST_URL
    req = urllib.request.Request(
        manifest_url,
        headers={
            "User-Agent": f"{APP_NAME.replace(' ', '-')}/{APP_VERSION}",
            "Accept": "application/json,text/plain,*/*",
            "Cache-Control": "no-cache",
            "Pragma": "no-cache",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=25) as resp:
            status = getattr(resp, "status", 200)
            content_type = resp.headers.get("Content-Type", "")
            raw = resp.read(2 * 1024 * 1024)
    except urllib.error.HTTPError as exc:
        raise HTTPException(status_code=502, detail=f"GitHub refuse version.json : HTTP {exc.code}. URL : {manifest_url}") from exc
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Impossible de lire version.json GitHub. URL : {manifest_url}. Détail : {exc}") from exc
    if not raw:
        raise HTTPException(status_code=502, detail=f"version.json GitHub est vide. URL : {manifest_url}")
    try:
        decoded = raw.decode("utf-8-sig")
        data = json.loads(decoded)
    except Exception as exc:
        sample = raw[:350].decode("utf-8", errors="replace").replace("\n", " ").replace("\r", " ")
        raise HTTPException(status_code=502, detail=f"version.json n'est pas un JSON valide. Début reçu : {sample}. Détail : {exc}") from exc
    if not isinstance(data, dict):
        raise HTTPException(status_code=502, detail="version.json doit contenir un objet JSON.")

    def first_text(*keys: str) -> str:
        for key in keys:
            value = data.get(key)
            if isinstance(value, (int, float)):
                value = str(value)
            if isinstance(value, str) and value.strip():
                return value.strip()
        return ""

    latest = first_text("latest_version", "version", "app_version", "tag_name", "name").lstrip("vV")
    if latest.lower().startswith("version "):
        latest = latest.split(" ", 1)[1].strip()
    download_url = first_text("zip_url", "download_url", "installer_url", "exe_url", "asset_url", "package_url", "url_zip", "url")
    selected_asset_name = ""
    if not download_url and isinstance(data.get("assets"), list):
        assets = [asset for asset in data.get("assets") if isinstance(asset, dict)]
        preferred = None
        for asset in assets:
            candidate = str(asset.get("browser_download_url") or asset.get("download_url") or asset.get("url") or "").strip()
            name = str(asset.get("name") or Path(urllib.parse.urlparse(candidate).path).name or candidate).lower()
            if candidate and (name.endswith(".zip") or name.endswith(".exe")):
                preferred = asset
                break
        if not preferred and assets:
            preferred = assets[0]
        if preferred:
            download_url = str(preferred.get("browser_download_url") or preferred.get("download_url") or preferred.get("url") or "").strip()
            selected_asset_name = str(preferred.get("name") or "").strip()
    if download_url and "github.com" in download_url and "/blob/" in download_url:
        download_url = download_url.replace("github.com/", "raw.githubusercontent.com/").replace("/blob/", "/")
    if not latest:
        raise HTTPException(status_code=502, detail="version.json invalide : champ version/latest_version/app_version manquant.")
    if download_url and not download_url.lower().startswith(("https://", "http://")):
        raise HTTPException(status_code=502, detail=f"version.json invalide : URL de téléchargement non HTTP/HTTPS : {download_url}")

    parsed_name = Path(urllib.parse.urlparse(download_url).path).name if download_url else ""
    file_name = selected_asset_name or parsed_name
    lower_name = file_name.lower()
    explicit_type = first_text("asset_type", "type", "package_type").lower()
    if explicit_type in {"installer", "setup", "exe", "inno"} or lower_name.endswith(".exe") or "installer_url" in data or "exe_url" in data:
        asset_type = "installer_exe"
    else:
        raise HTTPException(
            status_code=502,
            detail="version.json invalide : la mise à jour GitHub doit pointer vers un installeur .exe via installer_url.",
        )

    changelog = data.get("changelog") or data.get("changes") or data.get("release_notes") or data.get("notes") or data.get("body") or []
    if isinstance(changelog, str):
        changelog = [line.strip(" -•\t") for line in changelog.splitlines() if line.strip()]
    elif isinstance(changelog, dict):
        changelog = [f"{k}: {v}" for k, v in changelog.items()]
    elif not isinstance(changelog, list):
        changelog = []

    normalized = {
        "latest_version": latest,
        "minimum_version": str(data.get("minimum_version") or "").strip(),
        "zip_url": "",
        "download_url": download_url,
        "installer_url": download_url,
        "asset_type": asset_type,
        "file_name": file_name,
        "sha256": str(data.get("sha256") or data.get("checksum_sha256") or "").strip().lower(),
        "mandatory": bool(data.get("mandatory", False)),
        "changelog": [str(item) for item in changelog],
        "source_url": manifest_url,
        "content_type": content_type,
        "http_status": status,
        "raw_keys": sorted([str(k) for k in data.keys()])[:40],
    }
    normalized["update_available"] = is_version_newer_v717(normalized["latest_version"], APP_VERSION)
    return normalized


def download_online_update_zip_v717(manifest: dict[str, Any], stamp: str) -> Path:
    download_url = str(manifest.get("installer_url") or manifest.get("download_url") or "").strip()
    if not download_url:
        raise HTTPException(status_code=400, detail="URL de téléchargement manquante dans version.json : impossible d’installer depuis GitHub.")
    target_root = APP_DIR.resolve()
    download_dir = target_root / "update_backups" / "downloads"
    download_dir.mkdir(parents=True, exist_ok=True)
    file_name = safe_update_zip_name_v717(str(manifest.get("latest_version") or ""), download_url)
    tmp_path = download_dir / f"download_{stamp}_{file_name}"
    accept = "application/octet-stream,*/*" if file_name.lower().endswith(".exe") else "application/zip,application/octet-stream,*/*"
    req = urllib.request.Request(download_url, headers={"User-Agent": f"{APP_NAME.replace(' ', '-')}/{APP_VERSION}", "Accept": accept})
    sha = hashlib.sha256()
    read_bytes = 0
    content_type = ""
    try:
        with urllib.request.urlopen(req, timeout=90) as resp, tmp_path.open("wb") as out:
            content_type = resp.headers.get("Content-Type", "")
            while True:
                chunk = resp.read(1024 * 1024)
                if not chunk:
                    break
                read_bytes += len(chunk)
                if read_bytes > 750 * 1024 * 1024:
                    raise HTTPException(status_code=400, detail="Fichier trop volumineux pour une mise à jour automatique.")
                sha.update(chunk)
                out.write(chunk)
    except HTTPException:
        tmp_path.unlink(missing_ok=True)
        raise
    except Exception as exc:
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=502, detail=f"Téléchargement GitHub impossible. URL : {download_url}. Détail : {exc}") from exc
    if read_bytes < 1024:
        sample = tmp_path.read_text(encoding="utf-8", errors="replace")[:250] if tmp_path.exists() else ""
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=502, detail=f"Téléchargement GitHub invalide : fichier reçu trop petit. Content-Type : {content_type}. Début : {sample}")
    expected_sha = str(manifest.get("sha256") or "").strip().lower()
    actual_sha = sha.hexdigest().lower()
    if expected_sha and expected_sha != actual_sha:
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=400, detail=f"Contrôle SHA256 échoué : attendu {expected_sha}, obtenu {actual_sha}")
    if tmp_path.suffix.lower() == ".zip":
        inspect_update_zip_v7752(tmp_path)
    elif tmp_path.suffix.lower() != ".exe":
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=400, detail="Le fichier GitHub doit être un .zip ou un .exe d'installation.")
    return tmp_path


