# --- V8.0.6 : correctif final mise à jour GitHub EXE sans fenêtre CMD ---
def download_online_update_zip_v717(manifest: dict[str, Any], stamp: str) -> Path:
    """Télécharge l'installeur EXE GitHub dans un dossier inscriptible hors Program Files.

    Correctif V8.0.6 : les anciennes surcharges utilisaient encore
    APP_DIR/update_backups/downloads. Cette version force le dossier de travail
    via get_update_workspace_dir_v7776(), qui privilégie ProgramData,
    LocalAppData puis Temp.
    """
    download_url = str(manifest.get("installer_url") or manifest.get("download_url") or "").strip()
    if not download_url:
        raise HTTPException(status_code=400, detail="installer_url manquant dans version.json : la mise à jour GitHub attend un installeur .exe.")
    if not download_url.lower().startswith(("https://", "http://")):
        raise HTTPException(status_code=400, detail=f"URL installer_url invalide : {download_url}")

    download_root = get_update_workspace_dir_v7776()
    download_dir = download_root / "downloads"
    try:
        download_dir.mkdir(parents=True, exist_ok=True)
        probe = download_dir / ".write_test_v779"
        probe.write_text("ok", encoding="utf-8")
        probe.unlink(missing_ok=True)
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Dossier de téléchargement non inscriptible : {download_dir}. Détail : {exc}") from exc

    file_name = safe_update_zip_name_v717(str(manifest.get("latest_version") or ""), download_url)
    if not file_name.lower().endswith(".exe"):
        file_name += ".exe"
    tmp_path = download_dir / f"download_{stamp}_{file_name}"

    req = urllib.request.Request(
        download_url,
        headers={
            "User-Agent": f"{APP_NAME.replace(' ', '-')}/{APP_VERSION}",
            "Accept": "application/octet-stream,*/*",
            "Cache-Control": "no-cache",
        },
    )
    sha = hashlib.sha256()
    read_bytes = 0
    content_type = ""
    try:
        with urllib.request.urlopen(req, timeout=120) as resp, tmp_path.open("wb") as out:
            content_type = resp.headers.get("Content-Type", "")
            while True:
                chunk = resp.read(1024 * 1024)
                if not chunk:
                    break
                read_bytes += len(chunk)
                if read_bytes > 750 * 1024 * 1024:
                    raise HTTPException(status_code=400, detail="Fichier de mise à jour trop volumineux pour le téléchargement automatique.")
                sha.update(chunk)
                out.write(chunk)
    except HTTPException:
        tmp_path.unlink(missing_ok=True)
        raise
    except urllib.error.HTTPError as exc:
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=502, detail=f"Téléchargement GitHub impossible. URL : {download_url}. HTTP {exc.code} : {exc.reason}") from exc
    except Exception as exc:
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=502, detail=f"Téléchargement GitHub impossible. URL : {download_url}. Détail : {exc}") from exc

    if read_bytes < 1024:
        sample = ""
        try:
            sample = tmp_path.read_text(encoding="utf-8", errors="replace")[:250]
        except Exception:
            pass
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=502, detail=f"Téléchargement GitHub invalide : fichier reçu trop petit. Content-Type : {content_type}. Début : {sample}")

    expected_sha = str(manifest.get("sha256") or "").strip().lower()
    actual_sha = sha.hexdigest().lower()
    if expected_sha and expected_sha != actual_sha:
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=400, detail=f"Contrôle SHA256 échoué : attendu {expected_sha}, obtenu {actual_sha}")

    if tmp_path.suffix.lower() != ".exe":
        tmp_path.unlink(missing_ok=True)
        raise HTTPException(status_code=400, detail="Le fichier GitHub doit être un installeur .exe. Les ZIP ne sont plus acceptés pour la mise à jour GitHub.")
    return tmp_path


def launch_github_installer_v7774(installer_path: Path, manifest: dict[str, Any], stamp: str) -> dict[str, Any]:
    """Lance l'installeur GitHub sans CMD visible.

    Correctif V8.0.6 : suppression complète du lanceur .cmd et de
    `cmd.exe /c start`. L'application démarre un petit lanceur VBS invisible
    avec wscript.exe, attend 2,5 secondes que l'application se ferme, puis lance
    directement l'EXE Inno Setup en mode silencieux.
    """
    if os.name != "nt":
        raise HTTPException(status_code=400, detail="L'installation automatique par .exe est disponible uniquement sous Windows.")
    installer_path = Path(installer_path).resolve()
    if not installer_path.exists() or installer_path.suffix.lower() != ".exe":
        raise HTTPException(status_code=400, detail=f"Installeur introuvable ou invalide : {installer_path}")

    installer_args_list = ["/SP-", "/SILENT", "/SUPPRESSMSGBOXES", "/NORESTART", "/CLOSEAPPLICATIONS", "/FORCECLOSEAPPLICATIONS"]
    installer_args = " ".join(installer_args_list)
    launcher = installer_path.parent / f"launch_installer_{stamp}.vbs"
    # VBS : aucune fenêtre CMD. WindowStyle=1 laisse apparaître uniquement l'UAC si nécessaire.
    vbs = (
        'Option Explicit\r\n'
        'Dim shell, exePath, args\r\n'
        'Set shell = CreateObject("WScript.Shell")\r\n'
        'WScript.Sleep 2500\r\n'
        f'exePath = "{str(installer_path).replace(chr(34), "")} "\r\n'
        f'args = "{installer_args}"\r\n'
        'shell.Run Chr(34) & Trim(exePath) & Chr(34) & " " & args, 1, False\r\n'
    )
    try:
        launcher.write_text(vbs, encoding="utf-8")
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Impossible de créer le lanceur silencieux de l'installeur : {exc}") from exc

    creationflags = 0
    try:
        creationflags = getattr(subprocess, "CREATE_NO_WINDOW", 0) | getattr(subprocess, "DETACHED_PROCESS", 0)
    except Exception:
        creationflags = 0

    try:
        proc = subprocess.Popen(
            ["wscript.exe", "//B", "//Nologo", str(launcher)],
            cwd=str(installer_path.parent),
            stdin=subprocess.DEVNULL,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            close_fds=False,
            creationflags=creationflags,
        )
    except Exception:
        # Secours sans CMD : lancement direct de l'EXE, toujours sans console.
        try:
            proc = subprocess.Popen(
                [str(installer_path), *installer_args_list],
                cwd=str(installer_path.parent),
                stdin=subprocess.DEVNULL,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                close_fds=False,
                creationflags=creationflags,
            )
            launcher = Path("")
        except Exception as exc:
            raise HTTPException(status_code=500, detail=f"Impossible de lancer l'installeur GitHub sans fenêtre CMD : {exc}") from exc

    return {
        "started": True,
        "pid": proc.pid,
        "installer_path": str(installer_path),
        "launcher_path": str(launcher) if str(launcher) else "",
        "installer_args": installer_args,
        "target_version": manifest.get("latest_version"),
        "no_cmd_window": True,
        "download_workspace": str(installer_path.parent.parent),
    }


