# --- V8.0.6 : première installation = choix de base obligatoire, mise à jour = base conservée ---
_PREV_SETUP_CHOICE_REQUIRED_V7783 = setup_choice_required

def setup_choice_required() -> bool:
    """Affiche le choix de base uniquement sur une vraie première installation.

    Les routines de démarrage peuvent créer une base vide technique avant
    l'affichage de la page. On ne considère donc plus la simple présence de
    stock_assets.db/referentiel_stock.xlsx comme une sélection utilisateur.
    Une mise à jour conserve la base uniquement si un choix ou un fichier
    nexvandal_active_data.json existe déjà.
    """
    if globals().get("DATA_DIR_FALLBACK_ACTIVE"):
        # Une base NAS configurée mais inaccessible ne doit plus faire planter
        # le logiciel. On redonne accès à l'écran de choix pour reconnecter ou
        # sélectionner une autre base sans écraser l'ancien chemin.
        return True
    data = load_setup_choice()
    if data.get("choice") in {"use_existing", "create_new", "use_sql"}:
        return False
    try:
        if ACTIVE_DATA_CONFIG_PATH.exists():
            cfg = json.loads(ACTIVE_DATA_CONFIG_PATH.read_text(encoding="utf-8"))
            raw = cfg.get("data_dir") if isinstance(cfg, dict) else None
            if raw:
                active = _safe_data_path_v808(raw)
                markers = [
                    active / "stock_assets.db",
                    active / "referentiel_stock.xlsx",
                    active / "activity_log.jsonl",
                    active / "ui_settings.json",
                    active / "update_history.jsonl",
                ]
                if active.exists() and any(p.exists() for p in markers):
                    return False
    except Exception as exc:
        safe_log(f"Contrôle base active V8.0.6 impossible : {exc}")
    if os.environ.get("CLYO_STOCK_DATA_ROOT") or os.environ.get("CLYO_STOCK_APPDATA_DIR"):
        return False
    # Sans choix utilisateur persistant, c'est une première installation.
    return True

