_PREV_COLLECT_RELEASE_NOTES_V7783 = collect_release_notes

def collect_release_notes() -> list[dict[str, Any]]:
    # Notes de version à jour même après build EXE.
    items: list[dict[str, Any]] = []
    try:
        items.extend(_PREV_COLLECT_RELEASE_NOTES_V7783() or [])
    except Exception as exc:
        safe_log(f"Lecture notes version précédente impossible : {exc}")
    try:
        for root_dir in [APP_RESOURCE_DIR, APP_DIR]:
            try:
                if not root_dir or not Path(root_dir).exists():
                    continue
                for path in Path(root_dir).glob("README_v*.md"):
                    item = extract_release_notes_from_readme(path)
                    if item and not any(str(x.get("version")) == str(item.get("version")) for x in items):
                        items.append(item)
            except Exception:
                continue
    except Exception:
        pass
    if not any(str(item.get("version")) == APP_VERSION for item in items):
        items.insert(0, {
            "version": APP_VERSION,
            "title": f"Version {APP_VERSION}",
            "notes": RELEASE_NOTES_V7783,
            "file": "notes intégrées",
            "modified_at": now_iso(),
        })
    items.sort(key=lambda item: version_sort_key(item.get("version", "")), reverse=True)
    return items

try:
    from fastapi.exceptions import RequestValidationError

    @app.exception_handler(RequestValidationError)
    async def clyo_validation_exception_handler_v7783(request: Request, exc: RequestValidationError):
        try:
            errors = exc.errors()
        except Exception:
            errors = []
        try:
            append_update_history_event({
                "event": "api_validation_error",
                "version": APP_VERSION,
                "path": str(getattr(request, "url", "")),
                "method": str(getattr(request, "method", "")),
                "errors": errors,
            })
        except Exception:
            pass
        details = []
        for item in errors:
            loc = item.get("loc") if isinstance(item, dict) else None
            msg = item.get("msg") if isinstance(item, dict) else None
            if isinstance(loc, (list, tuple)):
                loc = ".".join(str(x) for x in loc)
            if loc or msg:
                details.append({"loc": loc or "", "msg": msg or "Paramètre invalide"})
        return JSONResponse(
            status_code=422,
            content={
                "detail": details or "Paramètre API invalide.",
                "message": "Un paramètre envoyé à l'API est invalide. La demande a été refusée proprement.",
                "error_type": "RequestValidationError",
                "path": str(getattr(request, "url", "")),
                "version": APP_VERSION,
            },
        )
except Exception as exc:
    safe_log(f"Gestionnaire validation API V8.0.6 non installé : {exc}")

