# --- V8.1.0 : profils simplifiés, mot de passe temporaire, langue dans Profil et rafraîchissement temps réel ---
APP_VERSION = "8.2.9"
try:
    app.version = APP_VERSION
except Exception:
    pass

DEFAULT_FIRST_LOGIN_PASSWORD_V807 = "clyo1234!"


def _ensure_user_password_plain_column_v807() -> None:
    """Ajoute et alimente la colonne de mot de passe visible pour le superadmin.

    Les anciens PIN numériques à 4 chiffres peuvent être retrouvés par essai local,
    car les anciennes versions forçaient ce format. Les nouveaux mots de passe
    sont enregistrés dans password_plain afin que le superadmin puisse les voir.
    """
    try:
        with db() as conn:
            cols = {row["name"] for row in conn.execute("PRAGMA table_info(app_users)").fetchall()}
            if "password_plain" not in cols:
                conn.execute("ALTER TABLE app_users ADD COLUMN password_plain TEXT")
            if "birth_date" not in cols:
                conn.execute("ALTER TABLE app_users ADD COLUMN birth_date TEXT")
            if "must_change_password" not in cols:
                conn.execute("ALTER TABLE app_users ADD COLUMN must_change_password INTEGER NOT NULL DEFAULT 0")
            rows = conn.execute("SELECT id, username, password_salt, password_hash, must_change_password, password_plain FROM app_users").fetchall()
            for row in rows:
                current_plain = str(row["password_plain"] or "").strip()
                if current_plain:
                    continue
                recovered = ""
                username = str(row["username"] or "")
                if username.lower() == str(SUPERADMIN_USERNAME).lower():
                    recovered = SUPERADMIN_PASSWORD
                elif int(row["must_change_password"] or 0) == 1:
                    recovered = DEFAULT_FIRST_LOGIN_PASSWORD_V807
                else:
                    salt = str(row["password_salt"] or "")
                    expected = str(row["password_hash"] or "")
                    if salt and expected:
                        for i in range(10000):
                            candidate = f"{i:04d}"
                            try:
                                if verify_password(candidate, salt, expected):
                                    recovered = candidate
                                    break
                            except Exception:
                                break
                if recovered:
                    conn.execute("UPDATE app_users SET password_plain = ? WHERE id = ?", (recovered, int(row["id"])))
    except Exception as exc:
        safe_log(f"Migration password_plain V8.1.0 impossible : {exc}")


@app.on_event("startup")
def _startup_password_plain_v807() -> None:
    _ensure_user_password_plain_column_v807()


def _password_v807(value: str | None, label: str = "mot de passe") -> str:
    clean = str(value or "").strip()
    if len(clean) < 4:
        raise HTTPException(status_code=400, detail=f"Le {label} doit contenir au minimum 4 caractères.")
    return clean


def validate_pin_password(value: str | None, label: str = "mot de passe") -> str:  # type: ignore[override]
    return _password_v807(value, label)


def _remove_api_route_v807(path: str, methods: set[str]) -> None:
    try:
        kept = []
        for route in list(app.router.routes):
            route_path = getattr(route, "path", None)
            route_methods = set(getattr(route, "methods", set()) or set())
            if route_path == path and methods.issubset(route_methods):
                continue
            kept.append(route)
        app.router.routes = kept
    except Exception as exc:
        safe_log(f"Suppression route {path} V8.1.0 impossible : {exc}")


_remove_api_route_v807("/api/users", {"GET"})
_remove_api_route_v807("/api/users", {"POST"})
_remove_api_route_v807("/api/users/{user_id}", {"PATCH"})
_remove_api_route_v807("/api/auth/change-password", {"POST"})
_remove_api_route_v807("/api/auth/forgot-password", {"POST"})


class UserCreateV807(BaseModel):
    username: str = Field(min_length=3, max_length=80)
    password: str | None = Field(default=None, min_length=4)
    role: str | None = Field(default="administrateur", min_length=1, max_length=40)
    birth_date: str | None = None
    is_admin: bool = True


class UserUpdateV807(BaseModel):
    username: str | None = Field(default=None, min_length=3, max_length=80)
    password: str | None = Field(default=None, min_length=4)
    role: str | None = Field(default=None, min_length=1, max_length=40)
    birth_date: str | None = None
    is_admin: bool | None = None


class ChangePasswordPayloadV807(BaseModel):
    new_password: str = Field(min_length=4)
    birth_date: str | None = Field(default=None, min_length=4)


class ForgotPasswordPayloadV807(BaseModel):
    username: str = Field(min_length=1)
    birth_date: str = Field(min_length=4)


def _user_row_public_v807(row: Any, expose_password: bool = False) -> dict[str, Any]:
    data = dict(row)
    if expose_password:
        data["visible_password"] = str(data.get("password_plain") or "")
    data.pop("password_salt", None)
    data.pop("password_hash", None)
    if not expose_password:
        data.pop("password_plain", None)
    return data


@app.get("/api/users")
def list_users_v807(request: Request) -> list[dict[str, Any]]:
    require_superadmin(request)
    _ensure_user_password_plain_column_v807()
    with db() as conn:
        rows = conn.execute(
            """
            SELECT id, username, role, is_admin, birth_date, profile_photo_data_url,
                   must_change_password, created_at, password_plain
            FROM app_users
            ORDER BY id DESC
            """
        ).fetchall()
    return [_user_row_public_v807(row, expose_password=True) for row in rows]


@app.post("/api/users")
def create_user_v807(payload: UserCreateV807, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    _ensure_user_password_plain_column_v807()
    username = payload.username.strip()
    if not username:
        raise HTTPException(status_code=400, detail="Nom du profil vide")
    role, is_admin = normalize_role(payload.role or "administrateur", True if payload.is_admin is None else payload.is_admin)
    first_password = DEFAULT_FIRST_LOGIN_PASSWORD_V807
    salt, digest = hash_password(first_password)
    with db() as conn:
        try:
            cur = conn.execute(
                """
                INSERT INTO app_users(username, password_salt, password_hash, password_plain, role, is_admin, birth_date, must_change_password, created_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?)
                """,
                (username, salt, digest, first_password, role, is_admin, None, now_iso()),
            )
        except sqlite3.IntegrityError:
            raise HTTPException(status_code=409, detail="Ce profil existe déjà")
        row = conn.execute(
            """
            SELECT id, username, role, is_admin, birth_date, profile_photo_data_url,
                   must_change_password, created_at, password_plain
            FROM app_users WHERE id = ?
            """,
            (cur.lastrowid,),
        ).fetchone()
    result = _user_row_public_v807(row, expose_password=True)
    write_app_log("user_created", "user", result.get("id"), f"Profil créé : {result.get('username')} ({result.get('role')}) — mot de passe temporaire", request=request)
    return result


def _count_superadmins_v807(conn: sqlite3.Connection) -> int:
    return int(conn.execute("SELECT COUNT(*) AS c FROM app_users WHERE role = 'superadmin'").fetchone()["c"] or 0)


@app.patch("/api/users/{user_id}")
def update_user_v807(user_id: int, payload: UserUpdateV807, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    _ensure_user_password_plain_column_v807()
    with db() as conn:
        existing = conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Profil introuvable")
        username = payload.username.strip() if payload.username is not None else existing["username"]
        if not username:
            raise HTTPException(status_code=400, detail="Nom du profil vide")
        duplicate = conn.execute("SELECT id FROM app_users WHERE LOWER(username) = LOWER(?) AND id <> ?", (username, user_id)).fetchone()
        if duplicate:
            raise HTTPException(status_code=409, detail="Ce profil existe déjà")
        role_input = payload.role if payload.role is not None else existing["role"]
        role, is_admin = normalize_role(role_input, bool(payload.is_admin) if payload.is_admin is not None else bool(existing["is_admin"]))
        if existing["role"] == "superadmin" and role != "superadmin" and _count_superadmins_v807(conn) <= 1:
            raise HTTPException(status_code=400, detail="Impossible de retirer le dernier compte superadmin")
        birth_date = payload.birth_date if payload.birth_date is not None else existing["birth_date"]
        if payload.password:
            password = _password_v807(payload.password)
            salt, digest = hash_password(password)
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, password_salt = ?, password_hash = ?, password_plain = ?,
                    role = ?, is_admin = ?, birth_date = ?, must_change_password = 0
                WHERE id = ?
                """,
                (username, salt, digest, password, role, is_admin, birth_date, user_id),
            )
        else:
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, role = ?, is_admin = ?, birth_date = ?
                WHERE id = ?
                """,
                (username, role, is_admin, birth_date, user_id),
            )
        row = conn.execute(
            """
            SELECT id, username, role, is_admin, birth_date, profile_photo_data_url,
                   must_change_password, created_at, password_plain
            FROM app_users WHERE id = ?
            """,
            (user_id,),
        ).fetchone()
    result = _user_row_public_v807(row, expose_password=True)
    write_app_log("user_updated", "user", user_id, f"Profil modifié : {result.get('username')} ({result.get('role')})", request=request)
    return result


@app.post("/api/auth/change-password")
def change_password_v807(payload: ChangePasswordPayloadV807, request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    password = _password_v807(payload.new_password)
    birth_date = str(payload.birth_date or "").strip()
    with db() as conn:
        row = conn.execute("SELECT birth_date FROM app_users WHERE id = ?", (int(user["id"]),)).fetchone()
        existing_birth = str(row["birth_date"] or "").strip() if row else ""
        if not existing_birth and not birth_date:
            raise HTTPException(status_code=400, detail="Date de naissance obligatoire pour récupérer le mot de passe oublié.")
        final_birth = birth_date or existing_birth
        salt, digest = hash_password(password)
        conn.execute(
            """
            UPDATE app_users
            SET password_salt = ?, password_hash = ?, password_plain = ?, birth_date = ?, must_change_password = 0
            WHERE id = ?
            """,
            (salt, digest, password, final_birth, int(user["id"])),
        )
    write_app_log("password_changed", "user", user.get("id"), "Mot de passe changé avec date de naissance", request=request)
    return {"status": "password_changed", "birth_date_saved": bool(final_birth)}


@app.post("/api/auth/forgot-password")
def forgot_password_v807(payload: ForgotPasswordPayloadV807, request: Request) -> dict[str, Any]:
    username = payload.username.strip()
    birth_date = payload.birth_date.strip()
    _ensure_user_password_plain_column_v807()
    with db() as conn:
        row = conn.execute("SELECT * FROM app_users WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
        if not row or str(row["birth_date"] or "") != birth_date:
            write_app_log("forgot_password_failed", "user", username, "Identifiant ou date de naissance incorrect", request=request, username=username)
            raise HTTPException(status_code=404, detail="Identifiant ou date de naissance incorrect")
        temp_password = DEFAULT_FIRST_LOGIN_PASSWORD_V807
        salt, digest = hash_password(temp_password)
        conn.execute(
            "UPDATE app_users SET password_salt = ?, password_hash = ?, password_plain = ?, must_change_password = 1 WHERE id = ?",
            (salt, digest, temp_password, row["id"]),
        )
    write_app_log("forgot_password_temp_generated", "user", row["id"], "Mot de passe temporaire réinitialisé", request=request, username=row["username"], role=row["role"])
    return {"temporary_password": temp_password, "visible_seconds": 30, "warning": "Mot de passe temporaire : il devra être changé à la prochaine connexion."}


@app.get("/api/realtime/state-v807")
def realtime_state_v807(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    with db() as conn:
        assets = conn.execute("SELECT COUNT(*) AS c, COALESCE(MAX(updated_at), '') AS m FROM assets").fetchone()
        customers = conn.execute("SELECT COUNT(*) AS c, COALESCE(MAX(updated_at), '') AS m FROM customers").fetchone()
        logs = conn.execute("SELECT COUNT(*) AS c, COALESCE(MAX(created_at), '') AS m FROM app_logs").fetchone()
        users = conn.execute("SELECT COUNT(*) AS c, COALESCE(MAX(created_at), '') AS m FROM app_users").fetchone()
    signature = f"a:{assets['c']}:{assets['m']}|c:{customers['c']}:{customers['m']}|l:{logs['c']}:{logs['m']}|u:{users['c']}:{users['m']}"
    return {
        "status": "ok",
        "signature": signature,
        "assets_signature": f"{assets['c']}|{assets['m']}",
        "customers_signature": f"{customers['c']}|{customers['m']}",
        "logs_signature": f"{logs['c']}|{logs['m']}",
        "users_signature": f"{users['c']}|{users['m']}",
        "checked_at": datetime.now().isoformat(timespec="seconds"),
    }


