# --- V8.1.4 : conservation stricte de la base active pendant les mises à jour ---
def preserve_active_base_before_update_v814(reason: str = "update", manifest: dict[str, Any] | None = None) -> dict[str, Any]:
    """Sauvegarde le chemin de base juste avant de lancer l'installeur.

    La mise à jour ne doit jamais transformer une installation existante en
    nouvelle installation. Cette sauvegarde permet à la version suivante de
    rouvrir l'ancienne base de travail, qu'elle soit locale, NAS ou SQL.
    """
    payload: dict[str, Any] = {}
    try:
        if ACTIVE_DATA_CONFIG_PATH.exists():
            raw = json.loads(ACTIVE_DATA_CONFIG_PATH.read_text(encoding="utf-8", errors="ignore") or "{}")
            if isinstance(raw, dict):
                payload.update(raw)
    except Exception:
        pass
    payload.update({
        "data_dir": str(DATA_DIR),
        "database_mode": "sql" if bool(load_sql_config_v810(False).get("enabled")) else str(payload.get("database_mode") or "local_or_nas"),
        "setup_choice": (load_setup_choice().get("choice") if isinstance(load_setup_choice(), dict) else "") or payload.get("setup_choice") or "preserve_existing_base",
        "app_version_before_update": APP_VERSION,
        "target_version": str((manifest or {}).get("latest_version") or ""),
        "reason": reason,
        "preserved_at": datetime.now().isoformat(timespec="seconds"),
    })
    try:
        ACTIVE_DATA_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
        ACTIVE_DATA_CONFIG_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass
    try:
        ACTIVE_DATA_PRESERVE_PATH_V814.parent.mkdir(parents=True, exist_ok=True)
        ACTIVE_DATA_PRESERVE_PATH_V814.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass
    try:
        append_update_history_event({
            "event": "active_base_preserved_before_update_v814",
            "version": APP_VERSION,
            "target_version": payload.get("target_version"),
            "data_dir": payload.get("data_dir"),
            "database_mode": payload.get("database_mode"),
            "message": "Base active sauvegardée avant mise à jour pour relance sur la même base.",
        })
    except Exception:
        pass
    return payload

try:
    APP_VERSION = "8.2.9"
    app.version = APP_VERSION
except Exception:
    pass


# --- V8.1.9 : base introuvable -> retour choix / SQL MariaDB robuste / responsive global ---
def _base_marker_exists_v815(base_dir: Path) -> bool:
    """Vérifie qu'un dossier de données ressemble vraiment à une base CLYO utilisable."""
    try:
        if not base_dir or not _path_exists_quiet_v808(base_dir):
            return False
        markers = [
            base_dir / "stock_assets.db",
            base_dir / "referentiel_stock.xlsx",
            base_dir / "activity_log.jsonl",
            base_dir / "ui_settings.json",
            base_dir / "update_history.jsonl",
        ]
        for marker in markers:
            try:
                if marker.exists():
                    return True
            except Exception:
                continue
    except Exception:
        return False
    return False


def _configured_sql_available_v815() -> tuple[bool, str]:
    """Teste rapidement la configuration SQL sans faire planter le démarrage."""
    try:
        cfg = load_sql_config_v810(include_password=True)
        if not isinstance(cfg, dict) or not cfg.get("enabled"):
            return False, "Mode SQL non activé."
        conn = sql_connect_v810(cfg, with_database=True)
        try:
            with conn.cursor() as cur:
                cur.execute("SELECT 1 AS ok")
                cur.fetchone()
            conn.commit()
        finally:
            conn.close()
        return True, "Base SQL disponible."
    except Exception as exc:
        return False, f"Base SQL inaccessible : {exc}"


def _active_base_available_v815() -> tuple[bool, str]:
    """Contrôle centralisé utilisé après mise à jour.

    Si l'ancienne base locale/NAS/SQL n'est plus disponible, l'application doit
    revenir sur la page de sélection au lieu de pointer vers une base vide ou de
    déclencher une erreur API.
    """
    if globals().get("DATA_DIR_FALLBACK_ACTIVE"):
        return False, globals().get("DATA_DIR_STARTUP_ERROR") or "Base configurée inaccessible."

    try:
        for cfg_path in _active_data_config_candidates_v814():
            cfg = _read_active_config_file_v814(cfg_path)
            if not cfg:
                continue
            if str(cfg.get("database_mode") or "").lower() in {"sql", "mariadb", "mysql"}:
                return _configured_sql_available_v815()
            raw = cfg.get("data_dir")
            if raw:
                active = _safe_data_path_v808(raw)
                if _base_marker_exists_v815(active):
                    return True, f"Base active trouvée : {active}"
                return False, f"Base précédemment utilisée introuvable : {active}"
    except Exception as exc:
        return False, f"Contrôle de l'ancienne base impossible : {exc}"

    try:
        if _base_marker_exists_v815(DATA_DIR):
            return True, f"Base active trouvée : {DATA_DIR}"
    except Exception:
        pass

    try:
        cfg = load_sql_config_v810(include_password=True)
        if isinstance(cfg, dict) and cfg.get("enabled"):
            return _configured_sql_available_v815()
    except Exception:
        pass

    return False, "Aucune base de travail existante trouvée."


def setup_choice_required() -> bool:
    """V8.1.9 : première installation ou ancienne base introuvable = page de sélection.

    Mise à jour : on conserve la base uniquement si elle existe encore.
    Si le chemin local/NAS n'existe plus ou si SQL ne répond pas, on revient
    immédiatement sur le choix de base.
    """
    available, reason = _active_base_available_v815()
    if available:
        return False
    try:
        globals()["DATA_DIR_STARTUP_ERROR"] = reason
        globals()["DATA_DIR_FALLBACK_ACTIVE"] = True
    except Exception:
        pass
    return True


def _mysql_quote_identifier_v815(name: str) -> str:
    return "`" + str(name or "").replace("`", "``") + "`"


def mysql_type_from_sqlite_v810(declared: str, pk: bool = False) -> str:
    """V8.1.9 : mapping MariaDB sans AUTO_INCREMENT automatique multiple."""
    t = str(declared or "TEXT").upper()
    if "INT" in t:
        return "INT"
    if any(x in t for x in ["REAL", "FLOA", "DOUB", "NUM", "DEC"]):
        return "DOUBLE"
    if "BLOB" in t:
        return "LONGBLOB"
    return "LONGTEXT"


def create_mysql_table_like_sqlite_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str, *, reset_existing: bool = False) -> int:
    """V8.1.9 : création de table compatible MariaDB.

    - une seule colonne AUTO_INCREMENT maximum ;
    - AUTO_INCREMENT seulement sur une clé primaire entière unique ;
    - clés primaires composites gérées avec PRIMARY KEY(...);
    - en migration de test, une table mal créée précédemment est recréée proprement.
    """
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return 0

    pk_cols = [col for col in info if int(col["pk"] or 0) > 0]
    single_pk = len(pk_cols) == 1
    single_pk_name = str(pk_cols[0]["name"]) if single_pk else ""
    single_pk_type = str(pk_cols[0]["type"] or "").upper() if single_pk else ""
    single_pk_integer = single_pk and "INT" in single_pk_type

    column_defs: list[str] = []
    table_constraints: list[str] = []
    for col in info:
        name = str(col["name"])
        declared = str(col["type"] or "")
        is_pk = int(col["pk"] or 0) > 0
        col_type = mysql_type_from_sqlite_v810(declared, False)
        if single_pk_integer and name == single_pk_name:
            column_defs.append(f"{_mysql_quote_identifier_v815(name)} INT NOT NULL AUTO_INCREMENT")
        else:
            not_null = " NOT NULL" if bool(col["notnull"]) or is_pk else ""
            column_defs.append(f"{_mysql_quote_identifier_v815(name)} {col_type}{not_null}")

    if pk_cols:
        ordered_pk = sorted(pk_cols, key=lambda c: int(c["pk"] or 0))
        pk_sql = ", ".join(_mysql_quote_identifier_v815(str(c["name"])) for c in ordered_pk)
        table_constraints.append(f"PRIMARY KEY ({pk_sql})")

    sql_parts = column_defs + table_constraints
    table_sql = _mysql_quote_identifier_v815(table_name)
    create_sql = f"CREATE TABLE IF NOT EXISTS {table_sql} (" + ", ".join(sql_parts) + ") ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci"
    with mysql_conn.cursor() as cur:
        if reset_existing:
            cur.execute(f"DROP TABLE IF EXISTS {table_sql}")
        cur.execute(create_sql)
    return len(info)


def migrate_sqlite_table_to_mysql_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str) -> dict[str, Any]:
    """V8.1.9 : migration de test nettoyée et compatible MariaDB."""
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return {"table": table_name, "columns": 0, "rows": 0, "skipped": True}
    create_mysql_table_like_sqlite_v810(mysql_conn, sqlite_conn, table_name, reset_existing=True)
    col_names = [str(c["name"]) for c in info]
    rows = sqlite_conn.execute(f"SELECT * FROM {table_name}").fetchall()
    with mysql_conn.cursor() as cur:
        if rows:
            placeholders = ", ".join(["%s"] * len(col_names))
            cols_sql = ", ".join(_mysql_quote_identifier_v815(c) for c in col_names)
            insert_sql = f"INSERT INTO {_mysql_quote_identifier_v815(table_name)} ({cols_sql}) VALUES ({placeholders})"
            batch = [tuple(row[c] for c in col_names) for row in rows]
            cur.executemany(insert_sql, batch)
    return {"table": table_name, "columns": len(col_names), "rows": len(rows), "skipped": False}


