def _sqlite_login_profiles_status_v816(base_dir: Path | None = None) -> tuple[bool, str]:
    """Contrôle qu'une base locale/NAS peut réellement ouvrir la connexion.

    Une base est considérée utilisable seulement si le fichier SQLite existe,
    est lisible, contient la table app_users et au moins un profil. Cela évite
    le cas vu après mise à jour : écran Connexion affiché avec la liste des
    identifiants vide.
    """
    try:
        root = _safe_data_path_v808(base_dir or DATA_DIR)
        db_path = root / "stock_assets.db"
    except Exception as exc:
        return False, f"Chemin de base invalide : {exc}"

    try:
        if not _path_exists_quiet_v808(root):
            return False, f"Dossier de base introuvable : {root}"
        if not db_path.exists() or not db_path.is_file():
            return False, f"Base SQLite introuvable : {db_path}"
    except Exception as exc:
        return False, f"Base inaccessible : {exc}"

    try:
        uri = "file:" + urllib.parse.quote(str(db_path), safe="/:\\") + "?mode=ro"
        with sqlite3.connect(uri, uri=True, timeout=5) as conn:
            conn.row_factory = sqlite3.Row
            try:
                row = conn.execute("PRAGMA quick_check").fetchone()
                quick = str(row[0] if row else "").strip().lower()
                if quick and quick != "ok":
                    return False, f"Base SQLite invalide : quick_check = {quick}"
            except Exception:
                # Certaines très anciennes bases peuvent refuser quick_check ; on continue
                # mais la présence des tables reste obligatoire.
                pass
            tables = {str(r[0]) for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()}
            if "app_users" not in tables:
                return False, "Base sans table de profils utilisateur."
            try:
                users = conn.execute("SELECT COUNT(*) AS c FROM app_users WHERE TRIM(COALESCE(username,'')) <> ''").fetchone()
                count = int(users["c"] if users and "c" in users.keys() else 0)
            except Exception as exc:
                return False, f"Profils utilisateur illisibles : {exc}"
            if count <= 0:
                return False, "Aucun profil utilisateur dans cette base."
            return True, f"Base utilisable : {db_path} ({count} profil(s))"
    except Exception as exc:
        return False, f"Base SQLite non lisible : {exc}"


def _sql_login_profiles_status_v816(config: dict[str, Any] | None = None) -> tuple[bool, str]:
    """Contrôle léger des profils côté SQL si la migration SQL a déjà créé app_users."""
    try:
        cfg = config or load_sql_config_v810(include_password=True)
        if not isinstance(cfg, dict) or not cfg.get("enabled"):
            return False, "Mode SQL non activé."
        conn = sql_connect_v810(cfg, with_database=True)
        try:
            with conn.cursor() as cur:
                cur.execute("SHOW TABLES LIKE 'app_users'")
                exists = cur.fetchone()
                if not exists:
                    return False, "Base SQL sans table app_users."
                cur.execute("SELECT COUNT(*) AS c FROM app_users WHERE TRIM(COALESCE(username,'')) <> ''")
                row = cur.fetchone()
                if isinstance(row, dict):
                    count = int(row.get("c") or 0)
                else:
                    count = int((row[0] if row else 0) or 0)
                if count <= 0:
                    return False, "Aucun profil utilisateur dans la base SQL."
                return True, f"Base SQL utilisable ({count} profil(s))."
        finally:
            conn.close()
    except Exception as exc:
        return False, f"Base SQL inaccessible ou incomplète : {exc}"


def _active_base_available_v816() -> tuple[bool, str]:
    """Décide si l'application peut ouvrir la connexion après mise à jour.

    La sélection automatique n'est autorisée que si la base active est réellement
    exploitable. Sinon, l'utilisateur revient à la page de sélection de base.
    """
    if globals().get("DATA_DIR_FALLBACK_ACTIVE"):
        return False, globals().get("DATA_DIR_STARTUP_ERROR") or "Base configurée inaccessible."

    config_seen = False
    first_error = ""

    try:
        for cfg_path in _active_data_config_candidates_v814():
            cfg = _read_active_config_file_v814(cfg_path)
            if not cfg:
                continue
            config_seen = True
            mode = str(cfg.get("database_mode") or "").lower()
            if mode in {"sql", "mariadb", "mysql"}:
                sql_ok, sql_msg = _configured_sql_available_v815()
                # Tant que toutes les requêtes ne sont pas basculées SQL, les profils
                # SQLite restent vérifiés pour éviter une connexion vide.
                local_ok, local_msg = _sqlite_login_profiles_status_v816(DATA_DIR)
                if sql_ok and local_ok:
                    return True, f"Mode SQL disponible. {local_msg}"
                if not first_error:
                    first_error = f"SQL : {sql_msg} / Profils locaux : {local_msg}"
                continue

            raw = cfg.get("data_dir")
            if raw:
                active = _safe_data_path_v808(raw)
                if not _path_exists_quiet_v808(active):
                    if not first_error:
                        first_error = f"Base précédemment utilisée introuvable : {active}"
                    continue
                ok, msg = _sqlite_login_profiles_status_v816(active)
                if ok:
                    try:
                        _mirror_active_config_to_primary_v814(cfg)
                    except Exception:
                        pass
                    return True, msg
                if not first_error:
                    first_error = msg
    except Exception as exc:
        if not first_error:
            first_error = f"Contrôle de l'ancienne base impossible : {exc}"

    if config_seen:
        return False, first_error or "Ancienne base configurée invalide."

    # Compatibilité : si aucun fichier de configuration global n'existe mais que
    # la base courante a explicitement été choisie/créée dans cette installation.
    try:
        choice = load_setup_choice().get("choice") if isinstance(load_setup_choice(), dict) else ""
    except Exception:
        choice = ""
    if choice in {"use_existing", "create_new", "use_sql"}:
        if choice == "use_sql":
            sql_ok, sql_msg = _configured_sql_available_v815()
            local_ok, local_msg = _sqlite_login_profiles_status_v816(DATA_DIR)
            if sql_ok and local_ok:
                return True, f"Mode SQL disponible. {local_msg}"
            return False, f"Configuration SQL incomplète : {sql_msg} / {local_msg}"
        return _sqlite_login_profiles_status_v816(DATA_DIR)

    # Aucune configuration explicite : c'est une première installation ou une
    # configuration perdue. On ne valide pas une base créée automatiquement au
    # démarrage, afin de forcer le choix de base.
    return False, first_error or "Aucune base active explicitement configurée."


def setup_choice_required() -> bool:
    """V8.1.9 : page de sélection si l'ancienne base n'est pas utilisable.

    Une base doit exister ET contenir des profils utilisateur. Sinon, on évite
    l'écran Connexion vide et on redirige l'utilisateur vers la sélection.
    """
    available, reason = _active_base_available_v816()
    try:
        globals()["DATA_DIR_STARTUP_ERROR"] = "" if available else reason
        globals()["DATA_DIR_FALLBACK_ACTIVE"] = not available
    except Exception:
        pass
    return not available


