def mysql_type_from_sqlite_v810(declared: str, pk: bool = False) -> str:
    """Mapping MariaDB robuste.

    - Colonnes indexées / PK : jamais LONGTEXT/LONGBLOB, sinon MariaDB refuse la clé.
    - Colonne INTEGER PRIMARY KEY unique : gérée par create_mysql_table_like_sqlite_v810 en AUTO_INCREMENT.
    - TEXT normal : LONGTEXT conservé hors index.
    """
    t = str(declared or "TEXT").upper()
    if pk:
        if "INT" in t:
            return "INT"
        if any(x in t for x in ["REAL", "FLOA", "DOUB", "NUM", "DEC"]):
            return "DOUBLE"
        return "VARCHAR(191)"
    if "INT" in t:
        return "INT"
    if any(x in t for x in ["REAL", "FLOA", "DOUB", "NUM", "DEC"]):
        return "DOUBLE"
    if "BLOB" in t:
        return "LONGBLOB"
    return "LONGTEXT"


def _mysql_quote_identifier_v817(name: str) -> str:
    return "`" + str(name or "").replace("`", "``") + "`"


def _sqlite_table_info_v817(sqlite_conn: sqlite3.Connection, table_name: str) -> list[Any]:
    try:
        return list(sqlite_conn.execute(f"PRAGMA table_info({_mysql_quote_identifier_v817(table_name)})").fetchall())
    except Exception:
        return list(sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall())


def create_mysql_table_like_sqlite_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str, *, reset_existing: bool = False) -> int:
    """Création de table compatible MariaDB.

    Corrections V8.1.9 :
    - les PRIMARY KEY composites sont déclarées en contrainte de table ;
    - les colonnes TEXT/BLOB utilisées dans une clé deviennent VARCHAR(191) ;
    - AUTO_INCREMENT uniquement pour une clé primaire entière unique ;
    - si reset_existing=True, la table est supprimée avant recréation pour nettoyer
      les schémas générés par les versions précédentes.
    """
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return 0

    pk_cols = [col for col in info if int(col["pk"] or 0) > 0]
    ordered_pk = sorted(pk_cols, key=lambda c: int(c["pk"] or 0))
    single_pk = len(ordered_pk) == 1
    single_pk_name = str(ordered_pk[0]["name"]) if single_pk else ""
    single_pk_type = str(ordered_pk[0]["type"] or "").upper() if single_pk else ""
    single_pk_integer = single_pk and "INT" in single_pk_type

    column_defs: list[str] = []
    for col in info:
        name = str(col["name"])
        declared = str(col["type"] or "")
        is_pk = int(col["pk"] or 0) > 0
        not_null = bool(col["notnull"]) or is_pk

        if single_pk_integer and name == single_pk_name:
            col_def = f"{_mysql_quote_identifier_v817(name)} INT NOT NULL AUTO_INCREMENT"
        else:
            col_type = mysql_type_from_sqlite_v810(declared, pk=is_pk)
            col_def = f"{_mysql_quote_identifier_v817(name)} {col_type}"
            if not_null:
                col_def += " NOT NULL"
        column_defs.append(col_def)

    constraints: list[str] = []
    if ordered_pk:
        pk_sql = ", ".join(_mysql_quote_identifier_v817(str(c["name"])) for c in ordered_pk)
        constraints.append(f"PRIMARY KEY ({pk_sql})")

    table_sql = _mysql_quote_identifier_v817(table_name)
    create_sql = (
        f"CREATE TABLE IF NOT EXISTS {table_sql} ("
        + ", ".join(column_defs + constraints)
        + ") ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci"
    )

    with mysql_conn.cursor() as cur:
        if reset_existing:
            try:
                cur.execute("SET FOREIGN_KEY_CHECKS=0")
            except Exception:
                pass
            cur.execute(f"DROP TABLE IF EXISTS {table_sql}")
            try:
                cur.execute("SET FOREIGN_KEY_CHECKS=1")
            except Exception:
                pass
        cur.execute(create_sql)
    return len(info)


def migrate_sqlite_table_to_mysql_v810(mysql_conn: Any, sqlite_conn: sqlite3.Connection, table_name: str) -> dict[str, Any]:
    """Migration MariaDB non bloquante sur anciens schémas mal créés."""
    info = sqlite_conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    if not info:
        return {"table": table_name, "columns": 0, "rows": 0, "skipped": True}

    create_mysql_table_like_sqlite_v810(mysql_conn, sqlite_conn, table_name, reset_existing=True)
    col_names = [str(c["name"]) for c in info]
    rows = sqlite_conn.execute(f"SELECT * FROM {table_name}").fetchall()
    with mysql_conn.cursor() as cur:
        if rows:
            placeholders = ", ".join(["%s"] * len(col_names))
            cols_sql = ", ".join(_mysql_quote_identifier_v817(c) for c in col_names)
            insert_sql = f"INSERT INTO {_mysql_quote_identifier_v817(table_name)} ({cols_sql}) VALUES ({placeholders})"
            batch = [tuple(row[c] for c in col_names) for row in rows]
            cur.executemany(insert_sql, batch)
    return {"table": table_name, "columns": len(col_names), "rows": len(rows), "skipped": False}


_SQL_ERROR_HELP_V817 = {
    1170: "Colonne TEXT/BLOB utilisée dans une clé SQL. Le correctif V8.1.9 convertit les colonnes indexées en VARCHAR(191). Relance la migration sur une base de test propre.",
    1075: "Définition AUTO_INCREMENT invalide. Le correctif V8.1.9 limite AUTO_INCREMENT à une clé primaire entière unique.",
}


def _sql_error_detail_v817(exc: Exception) -> str:
    code = None
    try:
        if getattr(exc, 'args', None):
            code = int(exc.args[0])
    except Exception:
        code = None
    if code in _SQL_ERROR_HELP_V817:
        return f"{exc} — {_SQL_ERROR_HELP_V817[code]}"
    return str(exc)


_original_migrate_current_database_to_sql_v817 = migrate_current_database_to_sql_v810

def migrate_current_database_to_sql_v810() -> dict[str, Any]:
    try:
        return _original_migrate_current_database_to_sql_v817()
    except HTTPException:
        raise
    except Exception as exc:
        safe_log(f"Migration SQL MariaDB V8.1.9 impossible : {exc}")
        raise HTTPException(status_code=500, detail=f"Migration SQL impossible : {_sql_error_detail_v817(exc)}") from exc


# --- V8.1.9 : désinstallation propre = nouvelle sélection de base à la réinstallation ---
# Règle métier :
# - mise à jour par-dessus une version existante : conserver la base active locale / NAS / SQL ;
# - désinstallation puis réinstallation : redemander le choix de base, sans supprimer les données métier.
try:
    APP_VERSION = "8.2.9"
    app.version = APP_VERSION
except Exception:
    pass

FRESH_INSTALL_REQUIRED_FLAG_V818 = APP_WRITABLE_ROOT_DIR / "fresh_install_required.flag"


def _runtime_choice_files_v818() -> list[Path]:
    files: list[Path] = []
    for p in [
        ACTIVE_DATA_CONFIG_PATH,
        ACTIVE_DATA_PRESERVE_PATH_V814,
        SQL_CONFIG_PATH_V810,
        FRESH_INSTALL_REQUIRED_FLAG_V818,
        APP_WRITABLE_ROOT_DIR / "NexVandal" / "setup_choice.json",
        DEFAULT_DATA_DIR / "setup_choice.json",
    ]:
        try:
            if p not in files:
                files.append(p)
        except Exception:
            pass
    if os.name == "nt":
        for env_name in ("ProgramData", "LOCALAPPDATA", "APPDATA"):
            raw = os.environ.get(env_name)
            if not raw:
                continue
            base = Path(raw) / "CLYO Stock Atelier"
            for rel in [
                "nexvandal_active_data.json",
                "nexvandal_active_data_preserved_before_update.json",
                "sql_database_config.json",
                "fresh_install_required.flag",
                "NexVandal/setup_choice.json",
            ]:
                p = base / rel
                try:
                    if p not in files:
                        files.append(p)
                except Exception:
                    pass
    return files


def _fresh_install_marker_exists_v818() -> bool:
    for p in _runtime_choice_files_v818():
        try:
            if p.name == "fresh_install_required.flag" and p.exists():
                return True
        except Exception:
            continue
    return False


def _has_active_base_config_v818() -> bool:
    for p in _active_data_config_candidates_v814():
        try:
            if p.exists() and p.is_file():
                data = _read_active_config_file_v814(p)
                if isinstance(data, dict) and (data.get("data_dir") or data.get("database_mode")):
                    return True
        except Exception:
            continue
    try:
        if SQL_CONFIG_PATH_V810.exists() and SQL_CONFIG_PATH_V810.is_file():
            data = json.loads(SQL_CONFIG_PATH_V810.read_text(encoding="utf-8", errors="ignore") or "{}")
            if isinstance(data, dict) and data.get("enabled"):
                return True
    except Exception:
        pass
    return False


def _clear_fresh_install_marker_v818() -> None:
    for p in _runtime_choice_files_v818():
        try:
            if p.name == "fresh_install_required.flag" and p.exists():
                p.unlink(missing_ok=True)
        except Exception:
            pass


def reset_base_choice_only_v818(reason: str = "manual") -> dict[str, Any]:
    """Supprime uniquement le choix de base mémorisé, jamais les données métier.

    Utilisé après désinstallation/réinstallation ou en dépannage. Les fichiers
    SQLite, Excel, images, documents, sauvegardes et historiques ne sont pas
    supprimés. Au prochain lancement, l'écran de sélection de base s'affichera.
    """
    deleted: list[str] = []
    errors: list[str] = []
    for p in _runtime_choice_files_v818():
        try:
            if p.exists() and p.is_file():
                # Ne supprimer que les fichiers de configuration de choix, pas les bases.
                if p.name in {
                    "nexvandal_active_data.json",
                    "nexvandal_active_data_preserved_before_update.json",
                    "sql_database_config.json",
                    "setup_choice.json",
                    "fresh_install_required.flag",
                }:
                    p.unlink(missing_ok=True)
                    deleted.append(str(p))
        except Exception as exc:
            errors.append(f"{p}: {exc}")
    try:
        safe_log(f"Choix de base réinitialisé ({reason}). Fichiers supprimés : {len(deleted)}")
    except Exception:
        pass
    return {"status": "ok", "deleted": deleted, "errors": errors, "reason": reason}


_PREV_MARK_SETUP_CHOICE_V818 = mark_setup_choice

def mark_setup_choice(choice: str) -> None:
    _PREV_MARK_SETUP_CHOICE_V818(choice)
    _clear_fresh_install_marker_v818()


_PREV_SETUP_CHOICE_REQUIRED_V818 = setup_choice_required

def setup_choice_required() -> bool:
    """V8.1.9 : une réinstallation après désinstallation redemande la base.

    L'installateur crée un marqueur fresh_install_required.flag pendant la
    désinstallation et supprime les fichiers de choix de base. Si ce marqueur
    existe, l'application affiche l'écran de sélection, même si d'anciennes
    données sont encore présentes dans ProgramData. Une mise à jour normale ne
    crée pas ce marqueur et conserve donc l'ancienne base.
    """
    if _fresh_install_marker_exists_v818():
        try:
            globals()["DATA_DIR_STARTUP_ERROR"] = "Nouvelle installation détectée : choisis ou crée une base de travail."
            globals()["DATA_DIR_FALLBACK_ACTIVE"] = True
        except Exception:
            pass
        return True

    # Si aucun fichier global ne mémorise explicitement la base, on considère
    # que c'est une installation neuve, même si d'anciens fichiers de données
    # existent encore. Cela évite une réinstallation qui repointe en silence
    # vers une ancienne base.
    try:
        choice_data = load_setup_choice()
    except Exception:
        choice_data = {}
    if not _has_active_base_config_v818() and not (isinstance(choice_data, dict) and choice_data.get("choice") in {"use_existing", "create_new", "use_sql"}):
        try:
            globals()["DATA_DIR_STARTUP_ERROR"] = "Aucune base active explicitement configurée."
            globals()["DATA_DIR_FALLBACK_ACTIVE"] = True
        except Exception:
            pass
        return True

    return _PREV_SETUP_CHOICE_REQUIRED_V818()


@app.post("/api/setup/reset-base-choice")
def api_reset_base_choice_v818(request: Request) -> dict[str, Any]:
    """Dépannage : réinitialise le choix de base sans supprimer la base."""
    require_superadmin(request)
    return reset_base_choice_only_v818("api")

# --- V8.1.9 : importer une ancienne base locale/NAS vers MariaDB sans ressaisie ---
try:
    APP_VERSION = "8.2.9"
    app.version = APP_VERSION
except Exception:
    pass

SQL_IMPORT_UNPACK_DIR_V819 = APP_WRITABLE_ROOT_DIR / "sql_import_sources"


def _resolve_sql_import_source_v819(raw_path: str | None) -> Path:
    """Résout un dossier d'ancienne base à importer vers SQL."""
    if not raw_path or not str(raw_path).strip():
        raise HTTPException(status_code=400, detail="Chemin de l'ancienne base obligatoire.")
    raw = str(raw_path).strip().strip('"')
    p = Path(raw).expanduser()
    if not p.exists():
        raise HTTPException(status_code=400, detail=f"Chemin introuvable : {p}")

    if p.is_file() and p.suffix.lower() == ".zip":
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        target = SQL_IMPORT_UNPACK_DIR_V819 / f"{p.stem}_{stamp}"
        target.mkdir(parents=True, exist_ok=True)
        try:
            with zipfile.ZipFile(p, "r") as zf:
                zf.extractall(target)
        except Exception as exc:
            raise HTTPException(status_code=400, detail=f"Impossible d'extraire le ZIP d'ancienne base : {exc}") from exc
        p = target
    elif p.is_file():
        p = p.parent

    candidates: list[Path] = []
    try:
        candidates.append(p)
        candidates.append(p / "NexVandal")
        candidates.append(p / "BaseClyo2025")
        candidates.extend([child for child in p.iterdir() if child.is_dir()])
    except Exception:
        pass

    seen: set[str] = set()
    ordered: list[Path] = []
    for c in candidates:
        try:
            key = str(c.resolve())
        except Exception:
            key = str(c)
        if key not in seen:
            seen.add(key)
            ordered.append(c)

    for c in ordered:
        try:
            if c.exists() and c.is_dir() and ((c / "stock_assets.db").exists() or (c / "referentiel_stock.xlsx").exists()):
                return c.resolve()
        except Exception:
            continue

    raise HTTPException(
        status_code=400,
        detail=(
            "Ancienne base non reconnue. Sélectionne le dossier qui contient "
            "stock_assets.db et/ou referentiel_stock.xlsx, ou le ZIP BaseClyo extrait."
        ),
    )


def _browse_old_base_for_sql_v819() -> dict[str, Any]:
    try:
        import tkinter as tk
        from tkinter import filedialog
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Sélection de dossier indisponible : {exc}")
    try:
        root = tk.Tk()
        root.withdraw()
        root.attributes("-topmost", True)
        selected = filedialog.askdirectory(
            title="Sélectionner l'ancienne base à importer vers SQL",
            initialdir=str(Path.home()),
            mustexist=True,
        )
        root.destroy()
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"Impossible d'ouvrir la sélection de dossier : {exc}")
    if not selected:
        return {"selected": False, "path": None, "valid": False, "message": "Sélection annulée."}
    source = _resolve_sql_import_source_v819(selected)
    found = []
    for name in ["stock_assets.db", "referentiel_stock.xlsx", "activity_log.jsonl", "ui_settings.json", "connection_schemas.json", "material_connection_profiles.json"]:
        if (source / name).exists():
            found.append(name)
    return {"selected": True, "path": str(source), "valid": True, "found": found, "message": "Ancienne base détectée pour import SQL."}


def _ensure_mysql_import_tables_v819(mysql_conn: Any) -> None:
    ensure_mysql_meta_tables_v810(mysql_conn)
    with mysql_conn.cursor() as cur:
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS clyo_config_files (
                file_name VARCHAR(191) NOT NULL PRIMARY KEY,
                content_json LONGTEXT,
                source_path LONGTEXT,
                imported_at VARCHAR(32)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS clyo_excel_rows (
                sheet_name VARCHAR(191) NOT NULL,
                row_id INT NOT NULL,
                data_json LONGTEXT,
                imported_at VARCHAR(32),
                PRIMARY KEY(sheet_name, row_id)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
            """
        )
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS clyo_import_files (
                id INT NOT NULL AUTO_INCREMENT PRIMARY KEY,
                relative_path VARCHAR(512) NOT NULL,
                size_bytes BIGINT DEFAULT 0,
                source_path LONGTEXT,
                imported_at VARCHAR(32),
                KEY idx_relative_path (relative_path(191))
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
            """
        )


def _import_json_configs_to_mysql_v819(mysql_conn: Any, source_dir: Path) -> list[dict[str, Any]]:
    names = [
        "ui_settings.json",
        "connection_schemas.json",
        "material_connection_profiles.json",
        "drawing_layout_settings.json",
        "deleted_status_values.json",
        "setup_choice.json",
    ]
    imported: list[dict[str, Any]] = []
    with mysql_conn.cursor() as cur:
        for name in names:
            p = source_dir / name
            if not p.exists() or not p.is_file():
                continue
            try:
                raw = p.read_text(encoding="utf-8", errors="ignore")
                cur.execute(
                    "REPLACE INTO clyo_config_files(file_name, content_json, source_path, imported_at) VALUES(%s, %s, %s, %s)",
                    (name, raw, str(p), now_iso()),
                )
                imported.append({"file": name, "bytes": p.stat().st_size})
            except Exception as exc:
                imported.append({"file": name, "error": str(exc)})
    return imported


def _import_excel_workbook_to_mysql_v819(mysql_conn: Any, source_dir: Path) -> dict[str, Any]:
    xlsx = source_dir / "referentiel_stock.xlsx"
    if not xlsx.exists() or not xlsx.is_file():
        return {"status": "skipped", "reason": "referentiel_stock.xlsx absent", "rows": 0, "sheets": []}
    rows_inserted = 0
    sheets: list[str] = []
    try:
        wb = load_workbook(xlsx, read_only=True, data_only=True)
    except Exception as exc:
        return {"status": "error", "reason": str(exc), "rows": 0, "sheets": []}
    try:
        with mysql_conn.cursor() as cur:
            cur.execute("DELETE FROM clyo_excel_rows")
            for ws in wb.worksheets:
                sheet_name = str(ws.title or "").strip()[:191]
                if not sheet_name:
                    continue
                sheets.append(sheet_name)
                values_iter = ws.iter_rows(values_only=True)
                try:
                    headers_row = next(values_iter)
                except StopIteration:
                    continue
                headers = [str(h).strip() if h not in (None, "") else f"col_{i+1}" for i, h in enumerate(headers_row)]
                row_id = 1
                batch = []
                for row in values_iter:
                    row_id += 1
                    data = {headers[i] if i < len(headers) else f"col_{i+1}": row[i] for i in range(len(row))}
                    if not any(v not in (None, "") for v in data.values()):
                        continue
                    clean = {}
                    for k, v in data.items():
                        if isinstance(v, (datetime, date)):
                            clean[k] = v.isoformat()
                        else:
                            clean[k] = v
                    batch.append((sheet_name, row_id, json.dumps(clean, ensure_ascii=False, default=str), now_iso()))
                    if len(batch) >= 500:
                        cur.executemany("REPLACE INTO clyo_excel_rows(sheet_name, row_id, data_json, imported_at) VALUES(%s,%s,%s,%s)", batch)
                        rows_inserted += len(batch)
                        batch = []
                if batch:
                    cur.executemany("REPLACE INTO clyo_excel_rows(sheet_name, row_id, data_json, imported_at) VALUES(%s,%s,%s,%s)", batch)
                    rows_inserted += len(batch)
    finally:
        try:
            wb.close()
        except Exception:
            pass
    return {"status": "ok", "rows": rows_inserted, "sheets": sheets, "file": str(xlsx)}


def _index_support_files_v819(mysql_conn: Any, source_dir: Path) -> dict[str, Any]:
    folders = [
        "documents_clients",
        "material_connection_images",
        "connection_schema_images",
        "connection_equipment_images",
        "qr_codes",
        "product_images",
    ]
    indexed = 0
    with mysql_conn.cursor() as cur:
        cur.execute("DELETE FROM clyo_import_files")
        for folder in folders:
            base = source_dir / folder
            if not base.exists() or not base.is_dir():
                continue
            for p in base.rglob("*"):
                if not p.is_file():
                    continue
                try:
                    rel = str(p.relative_to(source_dir)).replace("\\", "/")
                except Exception:
                    rel = p.name
                cur.execute(
                    "INSERT INTO clyo_import_files(relative_path, size_bytes, source_path, imported_at) VALUES(%s,%s,%s,%s)",
                    (rel[:512], int(p.stat().st_size), str(p), now_iso()),
                )
                indexed += 1
    return {"indexed_files": indexed, "folders": folders}


def import_old_base_to_sql_v819(old_base_path: str | None, sql_payload: dict[str, Any] | None = None) -> dict[str, Any]:
    source_dir = _resolve_sql_import_source_v819(old_base_path)
    source_db = source_dir / "stock_assets.db"
    source_excel = source_dir / "referentiel_stock.xlsx"
    if not source_db.exists() and not source_excel.exists():
        raise HTTPException(status_code=400, detail="Aucun stock_assets.db ni referentiel_stock.xlsx trouvé dans l'ancienne base.")

    if isinstance(sql_payload, dict) and any(k in sql_payload for k in ["host", "port", "database", "user", "password"]):
        cfg = normalize_sql_payload_v810(sql_payload)
        test_sql_connection_v810({**cfg, "enabled": True})
    else:
        cfg = load_sql_config_v810(include_password=True)
        if not cfg.get("last_test_ok"):
            test_sql_connection_v810(cfg)

    mysql_conn = sql_connect_v810(cfg, with_database=True)
    migrated_tables: list[dict[str, Any]] = []
    json_configs: list[dict[str, Any]] = []
    excel_result: dict[str, Any] = {}
    support_files: dict[str, Any] = {}
    try:
        _ensure_mysql_import_tables_v819(mysql_conn)
        if source_db.exists():
            with sqlite3.connect(source_db, timeout=20) as sqlite_conn:
                sqlite_conn.row_factory = sqlite3.Row
                table_rows = sqlite_conn.execute("SELECT name FROM sqlite_master WHERE type='table' ORDER BY name").fetchall()
                table_names = [str(r["name"]) for r in table_rows if not str(r["name"]).startswith("sqlite_")]
                for table_name in table_names:
                    migrated_tables.append(migrate_sqlite_table_to_mysql_v810(mysql_conn, sqlite_conn, table_name))
        json_configs = _import_json_configs_to_mysql_v819(mysql_conn, source_dir)
        excel_result = _import_excel_workbook_to_mysql_v819(mysql_conn, source_dir)
        support_files = _index_support_files_v819(mysql_conn, source_dir)
        with mysql_conn.cursor() as cur:
            cur.execute(
                "REPLACE INTO clyo_sql_meta(meta_key, meta_value, updated_at) VALUES(%s, %s, %s)",
                (
                    "old_base_import",
                    json.dumps(
                        {
                            "app_version": APP_VERSION,
                            "source_dir": str(source_dir),
                            "source_db": str(source_db) if source_db.exists() else None,
                            "source_excel": str(source_excel) if source_excel.exists() else None,
                            "tables": migrated_tables,
                            "json_configs": json_configs,
                            "excel": excel_result,
                            "support_files": support_files,
                        },
                        ensure_ascii=False,
                        default=str,
                    ),
                    now_iso(),
                ),
            )
        mysql_conn.commit()
    except HTTPException:
        try:
            mysql_conn.rollback()
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            mysql_conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Import ancienne base vers SQL impossible : {_sql_error_detail_v817(exc) if '_sql_error_detail_v817' in globals() else exc}") from exc
    finally:
        try:
            mysql_conn.close()
        except Exception:
            pass

    cfg_public = save_sql_config_v810({**cfg, "last_migration_at": now_iso()}, enabled=True, test_ok=True)
    try:
        mark_sql_database_mode_v810()
        mark_setup_choice("use_sql")
        append_update_history_event({
            "event": "sql_import_old_base",
            "version": APP_VERSION,
            "source_folder": str(source_dir),
            "database": cfg_public.get("database"),
            "tables": migrated_tables,
            "excel": excel_result,
            "support_files": support_files,
        })
    except Exception:
        pass

    total_rows = sum(int(t.get("rows") or 0) for t in migrated_tables if isinstance(t, dict))
    return {
        "status": "ok",
        "message": "Ancienne base importée dans MariaDB. La base locale/NAS source n'a pas été supprimée.",
        "source_folder": str(source_dir),
        "database": cfg_public.get("database"),
        "host": cfg_public.get("host"),
        "port": cfg_public.get("port"),
        "tables": migrated_tables,
        "total_sqlite_rows": total_rows,
        "json_configs": json_configs,
        "excel": excel_result,
        "support_files": support_files,
        "database_mode": "sql",
    }


