class _SqlCompatRowV820(dict):
    """Ligne compatible sqlite.Row : accès par nom et par index."""
    def __init__(self, data: dict[str, Any] | None = None, order: list[str] | None = None):
        super().__init__(data or {})
        self._order = list(order or list(self.keys()))

    def __getitem__(self, key: Any) -> Any:
        if isinstance(key, int):
            try:
                return dict.__getitem__(self, self._order[key])
            except Exception:
                raise IndexError(key)
        return dict.__getitem__(self, key)


class _SqlCompatCursorV820:
    def __init__(self, rows: list[dict[str, Any]] | None = None, rowcount: int = 0, lastrowid: int | None = None):
        self._rows = []
        for row in rows or []:
            if isinstance(row, _SqlCompatRowV820):
                self._rows.append(row)
            elif isinstance(row, dict):
                self._rows.append(_SqlCompatRowV820(row, list(row.keys())))
            else:
                self._rows.append(row)
        self.rowcount = rowcount if rowcount is not None else len(self._rows)
        self.lastrowid = lastrowid or 0

    def fetchone(self):
        return self._rows[0] if self._rows else None

    def fetchall(self):
        return list(self._rows)


class _SqlPyCursorWrapperV820:
    def __init__(self, owner: "_SqlCompatConnectionV820", cursor: Any):
        self.owner = owner
        self.cursor = cursor
        self.rowcount = 0
        self.lastrowid = 0

    def __enter__(self):
        return self

    def __exit__(self, exc_type, exc, tb):
        try:
            self.cursor.close()
        except Exception:
            pass
        return False

    def execute(self, sql: str, params: Any = None):
        result = self.owner.execute(sql, params)
        self.rowcount = getattr(result, "rowcount", 0)
        self.lastrowid = getattr(result, "lastrowid", 0)
        self._result = result
        return self

    def executemany(self, sql: str, seq: list[Any]):
        sql2 = self.owner._translate_sql(sql)
        if not sql2:
            return self
        sql2 = self.owner._translate_create_table_sql(sql2)
        try:
            self.cursor.executemany(sql2, seq)
        except Exception as exc:
            raise HTTPException(status_code=500, detail=f"Erreur SQL MariaDB : {exc}") from exc
        self.rowcount = getattr(self.cursor, "rowcount", 0)
        self.lastrowid = getattr(self.cursor, "lastrowid", 0) or 0
        return self

    def fetchone(self):
        if hasattr(self, "_result"):
            return self._result.fetchone()
        row = self.cursor.fetchone()
        return self.owner._row(row)

    def fetchall(self):
        if hasattr(self, "_result"):
            return self._result.fetchall()
        rows = self.cursor.fetchall() or []
        return [self.owner._row(r) for r in rows]


class _SqlCompatConnectionV820:
    """Adaptateur minimal pour faire fonctionner les API existantes sur MariaDB.

    Le code historique parle à SQLite avec conn.execute(..., ?).
    Cet adaptateur convertit les requêtes courantes vers MariaDB afin que le mode SQL devienne actif
    pour les lectures et les écritures, sans supprimer le mode local/NAS.
    """
    def __init__(self, cfg: dict[str, Any] | None = None):
        self.cfg = cfg or load_sql_config_v810(include_password=True)
        self._conn = sql_connect_v810(self.cfg, with_database=True)
        self.row_factory = None

    def close(self):
        try:
            self._conn.close()
        except Exception:
            pass

    def commit(self):
        self._conn.commit()

    def rollback(self):
        self._conn.rollback()

    def cursor(self):
        return _SqlPyCursorWrapperV820(self, self._conn.cursor())

    def _row(self, row: Any):
        if row is None:
            return None
        if isinstance(row, _SqlCompatRowV820):
            return row
        if isinstance(row, dict):
            return _SqlCompatRowV820(row, list(row.keys()))
        return row

    def _query_rows(self, sql: str, params: Any = None) -> _SqlCompatCursorV820:
        with self._conn.cursor() as cur:
            cur.execute(sql, params or ())
            rows = cur.fetchall() or []
        return _SqlCompatCursorV820([self._row(r) for r in rows], rowcount=len(rows))

    def _database_name(self) -> str:
        return str(self.cfg.get("database") or "")

    def _column_type(self, table: str, column: str) -> str:
        with self._conn.cursor() as cur:
            cur.execute(
                "SELECT DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=%s AND TABLE_NAME=%s AND COLUMN_NAME=%s",
                (self._database_name(), table, column),
            )
            row = cur.fetchone() or {}
        return str(row.get("DATA_TYPE") or "").lower()

    def _index_exists(self, table: str, index_name: str) -> bool:
        with self._conn.cursor() as cur:
            cur.execute(
                "SELECT COUNT(*) AS c FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA=%s AND TABLE_NAME=%s AND INDEX_NAME=%s",
                (self._database_name(), table, index_name),
            )
            row = cur.fetchone() or {}
        try:
            return int(row.get("c") or 0) > 0
        except Exception:
            return False

    def _handle_sqlite_master(self, sql: str, params: Any = None):
        low = " ".join(sql.lower().split())
        name_filter = None
        if "and name=" in low:
            if params:
                name_filter = list(params)[0]
            else:
                m = re.search(r"name\s*=\s*'([^']+)'", sql, flags=re.I)
                if m:
                    name_filter = m.group(1)
        q = "SELECT TABLE_NAME AS name FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_SCHEMA=%s"
        args: list[Any] = [self._database_name()]
        if name_filter:
            q += " AND TABLE_NAME=%s"
            args.append(str(name_filter))
        q += " ORDER BY TABLE_NAME"
        return self._query_rows(q, tuple(args))

    def _handle_pragma_table_info(self, sql: str):
        m = re.search(r"PRAGMA\s+table_info\s*\(\s*`?\"?([A-Za-z0-9_]+)`?\"?\s*\)", sql, flags=re.I)
        if not m:
            return _SqlCompatCursorV820([])
        table = m.group(1)
        with self._conn.cursor() as cur:
            cur.execute(
                """
                SELECT COLUMN_NAME, COLUMN_TYPE, IS_NULLABLE, COLUMN_DEFAULT, COLUMN_KEY, EXTRA, ORDINAL_POSITION
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA=%s AND TABLE_NAME=%s
                ORDER BY ORDINAL_POSITION
                """,
                (self._database_name(), table),
            )
            rows = cur.fetchall() or []
        out = []
        for idx, r in enumerate(rows):
            out.append({
                "cid": idx,
                "name": r.get("COLUMN_NAME"),
                "type": r.get("COLUMN_TYPE"),
                "notnull": 0 if str(r.get("IS_NULLABLE") or "YES").upper() == "YES" else 1,
                "dflt_value": r.get("COLUMN_DEFAULT"),
                "pk": 1 if str(r.get("COLUMN_KEY") or "").upper() == "PRI" else 0,
            })
        return _SqlCompatCursorV820(out, rowcount=len(out))

    def _translate_sql(self, sql: str | None) -> str | None:
        if sql is None:
            return None
        s = str(sql).strip()
        if not s:
            return None
        low = " ".join(s.lower().split())
        if low.startswith("pragma busy_timeout") or low.startswith("pragma foreign_keys") or low.startswith("pragma journal_mode") or low.startswith("pragma synchronous") or low.startswith("pragma wal_checkpoint"):
            return None
        s = re.sub(r"INSERT\s+OR\s+REPLACE\s+INTO", "REPLACE INTO", s, flags=re.I)
        s = re.sub(r"INSERT\s+OR\s+IGNORE\s+INTO", "INSERT IGNORE INTO", s, flags=re.I)
        s = re.sub(r"\s+COLLATE\s+NOCASE", "", s, flags=re.I)
        s = s.replace("?", "%s")
        s = re.sub(r"\bAUTOINCREMENT\b", "AUTO_INCREMENT", s, flags=re.I)
        # Types SQLite fréquents vers MariaDB.
        s = re.sub(r"\bINTEGER\s+PRIMARY\s+KEY\s+AUTO_INCREMENT\b", "INT NOT NULL AUTO_INCREMENT PRIMARY KEY", s, flags=re.I)
        s = re.sub(r"\bINTEGER\s+PRIMARY\s+KEY\b", "INT NOT NULL AUTO_INCREMENT PRIMARY KEY", s, flags=re.I)
        return s

    def _translate_create_table_sql(self, sql: str) -> str:
        s = sql
        if not re.match(r"\s*CREATE\s+TABLE", s, flags=re.I | re.S):
            return s
        # Colonnes qui sont indexées/uniques : MariaDB ne peut pas indexer LONGTEXT sans longueur.
        for col in [
            "asset_code", "serial_number_norm", "customer_code", "username", "token_hash",
            "sheet_name", "status", "updated_at", "created_at", "meta_key", "relative_path",
            "customer_id", "model_id", "supplier_id", "customer_site_id", "replacement_of_asset_id", "replaced_by_asset_id",
        ]:
            s = re.sub(rf"(`?{col}`?)\s+TEXT\b", rf"\1 VARCHAR(191)", s, flags=re.I)
        s = re.sub(r"\bTEXT\s+NOT\s+NULL\s+UNIQUE\b", "VARCHAR(191) NOT NULL UNIQUE", s, flags=re.I)
        s = re.sub(r"\bTEXT\s+UNIQUE\b", "VARCHAR(191) UNIQUE", s, flags=re.I)
        s = re.sub(r"\bREAL\b", "DOUBLE", s, flags=re.I)
        s = re.sub(r"\bINTEGER\b", "INT", s, flags=re.I)
        # SQLite accepte plusieurs formes plus souples que MariaDB.
        s = re.sub(r"INT\s+NOT\s+NULL\s+AUTO_INCREMENT\s+PRIMARY\s+KEY", "INT NOT NULL AUTO_INCREMENT PRIMARY KEY", s, flags=re.I)
        if "ENGINE=" not in s.upper():
            s = s.rstrip().rstrip(";") + " ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci"
        return s

    def _execute_create_index(self, sql: str):
        m = re.match(r"\s*CREATE\s+(UNIQUE\s+)?INDEX\s+(?:IF\s+NOT\s+EXISTS\s+)?`?([A-Za-z0-9_]+)`?\s+ON\s+`?([A-Za-z0-9_]+)`?\s*\((.+)\)\s*;?\s*$", sql, flags=re.I | re.S)
        if not m:
            return None
        unique = bool(m.group(1))
        index_name = m.group(2)
        table = m.group(3)
        cols_raw = m.group(4)
        if self._index_exists(table, index_name):
            return _SqlCompatCursorV820([], rowcount=0)
        exprs = []
        for part in cols_raw.split(','):
            clean = part.strip().strip('`').strip('"')
            clean = re.sub(r"\s+.*$", "", clean)
            if not clean:
                continue
            dtype = self._column_type(table, clean)
            if dtype in {"text", "tinytext", "mediumtext", "longtext", "blob", "tinyblob", "mediumblob", "longblob"}:
                exprs.append(f"`{clean}`(191)")
            else:
                exprs.append(f"`{clean}`")
        if not exprs:
            return _SqlCompatCursorV820([], rowcount=0)
        create = f"CREATE {'UNIQUE ' if unique else ''}INDEX `{index_name}` ON `{table}` (" + ", ".join(exprs) + ")"
        with self._conn.cursor() as cur:
            try:
                cur.execute(create)
            except Exception as exc:
                if getattr(exc, 'args', [None])[0] in (1061,):
                    return _SqlCompatCursorV820([], rowcount=0)
                raise
        return _SqlCompatCursorV820([], rowcount=0)

    def execute(self, sql: str, params: Any = None):
        s_raw = str(sql or "")
        low = " ".join(s_raw.lower().split())
        if low.startswith("pragma table_info"):
            return self._handle_pragma_table_info(s_raw)
        if "sqlite_master" in low:
            return self._handle_sqlite_master(s_raw, params)
        if low.startswith("pragma quick_check"):
            return _SqlCompatCursorV820([{"quick_check": "ok"}], rowcount=1)
        translated = self._translate_sql(s_raw)
        if not translated:
            return _SqlCompatCursorV820([], rowcount=0)
        idx_result = self._execute_create_index(translated)
        if idx_result is not None:
            return idx_result
        translated = self._translate_create_table_sql(translated)
        with self._conn.cursor() as cur:
            try:
                cur.execute(translated, params or ())
            except Exception as exc:
                code = getattr(exc, 'args', [None])[0]
                # Duplicate column / duplicate index pendant les migrations idempotentes.
                if code in (1060, 1061, 1050):
                    return _SqlCompatCursorV820([], rowcount=0)
                raise HTTPException(status_code=500, detail=f"Erreur SQL MariaDB : {exc}") from exc
            rows = []
            try:
                if cur.description:
                    rows = cur.fetchall() or []
            except Exception:
                rows = []
            return _SqlCompatCursorV820([self._row(r) for r in rows], rowcount=getattr(cur, "rowcount", 0), lastrowid=getattr(cur, "lastrowid", 0) or 0)

    def executescript(self, script: str):
        statements: list[str] = []
        buf: list[str] = []
        in_single = False
        in_double = False
        prev = ''
        for ch in str(script or ''):
            if ch == "'" and not in_double and prev != "\\":
                in_single = not in_single
            elif ch == '"' and not in_single and prev != "\\":
                in_double = not in_double
            if ch == ';' and not in_single and not in_double:
                st = ''.join(buf).strip()
                if st:
                    statements.append(st)
                buf = []
            else:
                buf.append(ch)
            prev = ch
        tail = ''.join(buf).strip()
        if tail:
            statements.append(tail)
        last = _SqlCompatCursorV820([])
        for st in statements:
            last = self.execute(st)
        return last


@contextmanager
def db() -> Any:
    """V8.2.3 : utilise MariaDB quand le mode SQL est activé, sinon conserve SQLite/local/NAS."""
    cfg = {}
    try:
        cfg = load_sql_config_v810(include_password=True)
    except Exception:
        cfg = {}
    if bool(cfg.get("enabled")):
        conn = _SqlCompatConnectionV820(cfg)
        try:
            yield conn
            conn.commit()
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
            raise
        finally:
            conn.close()
    else:
        with _SQLITE_DB_CONTEXT_V820() as conn:
            yield conn


def init_db() -> None:
    """V8.2.3 : initialise la base active, SQLite ou MariaDB selon le mode configuré."""
    _ORIGINAL_INIT_DB_V820()
    try:
        # Si le mode SQL est actif, les tables complémentaires doivent aussi exister côté MariaDB.
        if bool(load_sql_config_v810(False).get("enabled")):
            ensure_customer_sites_v713()
            ensure_sqlite_reference_store()
            ensure_superadmin_user()
    except Exception as exc:
        safe_log(f"Initialisation SQL active incomplète : {exc}")


@app.get("/api/sql/runtime-status")
def api_sql_runtime_status_v820(request: Request) -> dict[str, Any]:
    cfg = load_sql_config_v810(include_password=False)
    active = bool(cfg.get("enabled"))
    counts: dict[str, Any] = {}
    if active:
        try:
            with db() as conn:
                for table in ["app_users", "assets", "customers", "reference_rows", "app_logs"]:
                    try:
                        row = conn.execute(f"SELECT COUNT(*) AS c FROM `{table}`").fetchone()
                        counts[table] = int(row["c"] or 0) if row else 0
                    except Exception as exc:
                        counts[table] = f"erreur: {exc}"
        except Exception as exc:
            return {"status": "error", "database_mode": "sql", "message": str(exc), "config": cfg, "counts": counts}
    return {"status": "ok", "database_mode": "sql" if active else "local_or_nas", "config": cfg, "counts": counts, "app_version": APP_VERSION}


