@app.post("/api/sql/use-existing")
async def api_sql_use_existing_v821(request: Request) -> dict[str, Any]:
    """Configure le poste sur une base MariaDB existante sans importer ni écraser les données.

    Ce point d'entrée est prévu pour les postes supplémentaires : ils renseignent le
    serveur SQL central, valident la connexion, puis lisent directement les données déjà
    présentes dans MariaDB.
    """
    try:
        payload = await request.json()
        if not isinstance(payload, dict):
            payload = {}
    except Exception:
        payload = {}
    cfg = normalize_sql_payload_v810(payload)
    test_result = test_sql_connection_v810({**cfg, "enabled": True})
    save_sql_config_v810(cfg, test_ok=True, enabled=True)
    mark_sql_database_mode_v810()
    mark_setup_choice("use_sql")
    counts: dict[str, Any] = {}
    try:
        conn = _SqlCompatConnectionV820(cfg)
        try:
            for table in ["app_users", "assets", "customers", "reference_rows", "app_logs"]:
                try:
                    row = conn.execute(f"SELECT COUNT(*) AS c FROM `{table}`").fetchone()
                    counts[table] = int(row["c"] or 0) if row else 0
                except Exception as exc:
                    counts[table] = f"erreur: {exc}"
            conn.commit()
        finally:
            conn.close()
    except Exception as exc:
        counts["error"] = str(exc)
    return {
        "status": "ok",
        "message": "Base SQL centrale enregistrée. Ce poste utilise les données déjà présentes dans MariaDB.",
        "database_mode": "sql",
        "sql": test_result,
        "counts": counts,
        "warnings": ["Aucune migration/import n'a été lancé depuis ce poste."],
    }

