PASSWORD_HASH_SCHEME_V822 = "pbkdf2_sha256"
PASSWORD_HASH_ITERATIONS_V822 = 310000
PASSWORD_HASH_SALT_BYTES_V822 = 16
PASSWORD_HASH_DKLEN_V822 = 32
SECURITY_TEMP_PASSWORD_V822 = globals().get("DEFAULT_FIRST_LOGIN_PASSWORD_V807", "clyo1234!")


def _b64_password_v822(raw: bytes) -> str:
    return base64.urlsafe_b64encode(raw).decode("ascii").rstrip("=")


def _unb64_password_v822(value: str) -> bytes:
    value = str(value or "").strip()
    pad = "=" * (-len(value) % 4)
    return base64.urlsafe_b64decode((value + pad).encode("ascii"))


def _pbkdf2_hash_v822(password: str, salt_raw: bytes, iterations: int = PASSWORD_HASH_ITERATIONS_V822) -> str:
    digest = hashlib.pbkdf2_hmac("sha256", str(password or "").encode("utf-8"), salt_raw, int(iterations), dklen=PASSWORD_HASH_DKLEN_V822)
    return _b64_password_v822(digest)


def hash_password(password: str, salt: str | None = None) -> tuple[str, str]:  # type: ignore[override]
    if salt and str(salt).startswith(PASSWORD_HASH_SCHEME_V822 + "$"):
        try:
            _, iterations_raw, salt_b64 = str(salt).split("$", 2)
            iterations = int(iterations_raw or PASSWORD_HASH_ITERATIONS_V822)
            salt_raw = _unb64_password_v822(salt_b64)
            return str(salt), _pbkdf2_hash_v822(password, salt_raw, iterations)
        except Exception:
            pass
    salt_raw = secrets.token_bytes(PASSWORD_HASH_SALT_BYTES_V822)
    salt_value = f"{PASSWORD_HASH_SCHEME_V822}${PASSWORD_HASH_ITERATIONS_V822}${_b64_password_v822(salt_raw)}"
    return salt_value, _pbkdf2_hash_v822(password, salt_raw, PASSWORD_HASH_ITERATIONS_V822)


def _verify_pbkdf2_password_v822(password: str, salt: str, expected_hash: str) -> bool:
    try:
        if not str(salt or "").startswith(PASSWORD_HASH_SCHEME_V822 + "$"):
            return False
        _, iterations_raw, salt_b64 = str(salt).split("$", 2)
        digest = _pbkdf2_hash_v822(password, _unb64_password_v822(salt_b64), int(iterations_raw))
        return secrets.compare_digest(digest, str(expected_hash or ""))
    except Exception:
        return False


def _verify_legacy_sha256_password_v822(password: str, salt: str, expected_hash: str) -> bool:
    try:
        digest = hashlib.sha256((str(salt or "") + str(password or "")).encode("utf-8")).hexdigest()
        return secrets.compare_digest(digest, str(expected_hash or ""))
    except Exception:
        return False


def verify_password(password: str, salt: str, expected_hash: str) -> bool:  # type: ignore[override]
    salt = str(salt or "")
    expected_hash = str(expected_hash or "")
    if salt.startswith(PASSWORD_HASH_SCHEME_V822 + "$"):
        return _verify_pbkdf2_password_v822(password, salt, expected_hash)
    return _verify_legacy_sha256_password_v822(password, salt, expected_hash)


def _password_hash_needs_upgrade_v822(row: Any) -> bool:
    try:
        salt = str(row["password_salt"] or "")
    except Exception:
        return True
    return not salt.startswith(PASSWORD_HASH_SCHEME_V822 + "$")


def _valid_password_v822(value: str | None, label: str = "mot de passe") -> str:
    clean = str(value or "").strip()
    if len(clean) < 4:
        raise HTTPException(status_code=400, detail=f"Le {label} doit contenir au minimum 4 caractères.")
    return clean


def validate_pin_password(value: str | None, label: str = "mot de passe") -> str:  # type: ignore[override]
    return _valid_password_v822(value, label)


def _row_to_plain_dict_v822(row: Any) -> dict[str, Any]:
    if row is None:
        return {}
    try:
        return dict(row)
    except Exception:
        return {k: getattr(row, k) for k in dir(row) if not k.startswith("_")}


def _table_columns_v822(conn: Any, table_name: str) -> set[str]:
    try:
        rows = conn.execute(f"PRAGMA table_info({table_name})").fetchall()
        out: set[str] = set()
        for row in rows or []:
            try:
                out.add(str(row["name"]))
            except Exception:
                try:
                    out.add(str(row[1]))
                except Exception:
                    pass
        return out
    except Exception:
        return set()


def _ensure_password_security_columns_v822(conn: Any) -> set[str]:
    cols = _table_columns_v822(conn, "app_users")
    try:
        if "birth_date" not in cols:
            conn.execute("ALTER TABLE app_users ADD COLUMN birth_date TEXT")
            cols.add("birth_date")
    except Exception:
        pass
    try:
        if "must_change_password" not in cols:
            conn.execute("ALTER TABLE app_users ADD COLUMN must_change_password INTEGER NOT NULL DEFAULT 0")
            cols.add("must_change_password")
    except Exception:
        pass
    return _table_columns_v822(conn, "app_users")


def _set_user_password_v822(conn: Any, user_id: int, password: str, *, must_change: bool) -> None:
    password = _valid_password_v822(password)
    salt, digest = hash_password(password)
    cols = _ensure_password_security_columns_v822(conn)
    if "password_plain" in cols:
        conn.execute("UPDATE app_users SET password_salt = ?, password_hash = ?, password_plain = NULL, must_change_password = ? WHERE id = ?", (salt, digest, 1 if must_change else 0, int(user_id)))
    else:
        conn.execute("UPDATE app_users SET password_salt = ?, password_hash = ?, must_change_password = ? WHERE id = ?", (salt, digest, 1 if must_change else 0, int(user_id)))


def _sanitize_user_output_v822(row: Any) -> dict[str, Any]:
    data = _row_to_plain_dict_v822(row)
    for key in ["password_salt", "password_hash", "password_plain", "visible_password"]:
        data.pop(key, None)
    data["password_storage"] = "hash sécurisé"
    data["password_visible"] = False
    data["password_note"] = "Mot de passe non affichable. Utilise Réinitialiser si besoin."
    return data


def _migrate_passwords_to_hashes_v822() -> dict[str, Any]:
    migrated_from_plain = 0
    cleared_plain = 0
    legacy_left = 0
    try:
        with db() as conn:
            cols = _ensure_password_security_columns_v822(conn)
            select_cols = "id, username, password_salt, password_hash, must_change_password"
            if "password_plain" in cols:
                select_cols += ", password_plain"
            rows = conn.execute(f"SELECT {select_cols} FROM app_users").fetchall()
            for row in rows or []:
                data = _row_to_plain_dict_v822(row)
                user_id = int(data.get("id") or 0)
                if not user_id:
                    continue
                plain = str(data.get("password_plain") or "").strip()
                if plain:
                    _set_user_password_v822(conn, user_id, plain, must_change=bool(data.get("must_change_password") or 0))
                    migrated_from_plain += 1
                    continue
                if _password_hash_needs_upgrade_v822(data):
                    legacy_left += 1
                if "password_plain" in cols:
                    try:
                        conn.execute("UPDATE app_users SET password_plain = NULL WHERE id = ?", (user_id,))
                        cleared_plain += 1
                    except Exception:
                        pass
    except Exception as exc:
        safe_log(f"Migration sécurité mots de passe V8.2.3 impossible : {exc}")
    return {"migrated_from_plain": migrated_from_plain, "cleared_plain": cleared_plain, "legacy_left_until_next_login": legacy_left}


@app.on_event("startup")
def _startup_password_security_v822() -> None:
    _migrate_passwords_to_hashes_v822()


