@app.post("/api/auth/login")
def login_v822(payload: LoginPayload, response: Response, request: Request) -> dict[str, Any]:
    username = payload.username.strip()
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        row = conn.execute("SELECT * FROM app_users WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
        if not row or not verify_password(payload.password, row["password_salt"], row["password_hash"]):
            write_app_log("login_failed", "user", username, "Échec de connexion", request=request, username=username)
            raise HTTPException(status_code=401, detail="Identifiant ou mot de passe incorrect")
        if _password_hash_needs_upgrade_v822(row):
            _set_user_password_v822(conn, int(row["id"]), payload.password, must_change=bool(row["must_change_password"]))
    token = create_session(int(row["id"]))
    write_app_log("login_success", "user", row["id"], "Connexion réussie", request=request, username=row["username"], role=row["role"])
    try:
        log_site_connection_once_v7753(request, username=row["username"], role=row["role"])
    except Exception:
        pass
    response.set_cookie(SESSION_COOKIE_NAME, token, max_age=SESSION_TIMEOUT_MINUTES * 60, httponly=True, samesite="lax")
    role = row["role"]
    return {"authenticated": True, "username": row["username"], "role": role, "is_admin": bool(row["is_admin"]), "can_write_assets": role in {"administrateur", "superadmin"}, "is_superadmin": role == "superadmin", "must_change_password": bool(row["must_change_password"]), "timeout_minutes": SESSION_TIMEOUT_MINUTES, "password_storage": "hash sécurisé"}


@app.get("/api/users")
def list_users_v822(request: Request) -> list[dict[str, Any]]:
    require_superadmin(request)
    _migrate_passwords_to_hashes_v822()
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        rows = conn.execute('''SELECT id, username, role, is_admin, birth_date, profile_photo_data_url, must_change_password, created_at FROM app_users ORDER BY id DESC''').fetchall()
    return [_sanitize_user_output_v822(row) for row in rows]


@app.post("/api/users")
def create_user_v822(payload: UserCreateV822, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    username = payload.username.strip()
    if not username:
        raise HTTPException(status_code=400, detail="Nom du profil vide")
    role, is_admin = normalize_role(payload.role or "administrateur", True if payload.is_admin is None else bool(payload.is_admin))
    first_password = SECURITY_TEMP_PASSWORD_V822
    salt, digest = hash_password(first_password)
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        try:
            cur = conn.execute('''INSERT INTO app_users(username, password_salt, password_hash, role, is_admin, birth_date, must_change_password, created_at) VALUES (?, ?, ?, ?, ?, ?, 1, ?)''', (username, salt, digest, role, is_admin, None, now_iso()))
        except Exception as exc:
            if "Duplicate" in str(exc) or "UNIQUE" in str(exc) or "existe" in str(exc):
                raise HTTPException(status_code=409, detail="Ce profil existe déjà")
            raise
        row = conn.execute("SELECT id, username, role, is_admin, birth_date, profile_photo_data_url, must_change_password, created_at FROM app_users WHERE id = ?", (cur.lastrowid,)).fetchone()
    result = _sanitize_user_output_v822(row)
    result["temporary_password"] = first_password
    result["password_visible_seconds"] = 60
    write_app_log("user_created", "user", result.get("id"), f"Profil créé : {result.get('username')} ({result.get('role')}) — mot de passe temporaire", request=request)
    return result


def _count_superadmins_v822(conn: Any) -> int:
    row = conn.execute("SELECT COUNT(*) AS c FROM app_users WHERE role = 'superadmin'").fetchone()
    try:
        return int(row["c"] or 0)
    except Exception:
        return 0


@app.patch("/api/users/{user_id}")
def update_user_v822(user_id: int, payload: UserUpdateV822, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        existing = conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Profil introuvable")
        username = payload.username.strip() if payload.username is not None else existing["username"]
        if not username:
            raise HTTPException(status_code=400, detail="Nom du profil vide")
        duplicate = conn.execute("SELECT id FROM app_users WHERE LOWER(username) = LOWER(?) AND id <> ?", (username, user_id)).fetchone()
        if duplicate:
            raise HTTPException(status_code=409, detail="Ce profil existe déjà")
        role_input = payload.role if payload.role is not None else existing["role"]
        role, is_admin = normalize_role(role_input, bool(payload.is_admin) if payload.is_admin is not None else bool(existing["is_admin"]))
        if existing["role"] == "superadmin" and role != "superadmin" and _count_superadmins_v822(conn) <= 1:
            raise HTTPException(status_code=400, detail="Impossible de retirer le dernier compte superadmin")
        birth_date = payload.birth_date if payload.birth_date is not None else existing["birth_date"]
        conn.execute("UPDATE app_users SET username = ?, role = ?, is_admin = ?, birth_date = ? WHERE id = ?", (username, role, is_admin, birth_date, user_id))
        if payload.password:
            _set_user_password_v822(conn, user_id, payload.password, must_change=True)
        row = conn.execute("SELECT id, username, role, is_admin, birth_date, profile_photo_data_url, must_change_password, created_at FROM app_users WHERE id = ?", (user_id,)).fetchone()
    result = _sanitize_user_output_v822(row)
    write_app_log("user_updated", "user", user_id, f"Profil modifié : {result.get('username')} ({result.get('role')})", request=request)
    return result


@app.post("/api/users/{user_id}/reset-password")
def reset_user_password_v822(user_id: int, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    temp_password = SECURITY_TEMP_PASSWORD_V822
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        row = conn.execute("SELECT id, username FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="Profil introuvable")
        _set_user_password_v822(conn, user_id, temp_password, must_change=True)
    write_app_log("user_password_reset", "user", user_id, "Mot de passe temporaire réinitialisé par le superadmin", request=request)
    return {"status": "reset", "temporary_password": temp_password, "visible_seconds": 60, "message": "Mot de passe temporaire généré. L'utilisateur devra le changer à la prochaine connexion."}


@app.post("/api/auth/change-password")
def change_password_v822(payload: ChangePasswordPayloadV822, request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    if not user:
        raise HTTPException(status_code=401, detail="Connexion requise")
    password = _valid_password_v822(payload.new_password)
    birth_date = str(payload.birth_date or "").strip()
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        row = conn.execute("SELECT birth_date FROM app_users WHERE id = ?", (int(user["id"]),)).fetchone()
        existing_birth = str(row["birth_date"] or "").strip() if row else ""
        if not existing_birth and not birth_date:
            raise HTTPException(status_code=400, detail="Date de naissance obligatoire pour récupérer le mot de passe oublié.")
        final_birth = birth_date or existing_birth
        _set_user_password_v822(conn, int(user["id"]), password, must_change=False)
        conn.execute("UPDATE app_users SET birth_date = ? WHERE id = ?", (final_birth, int(user["id"])))
    write_app_log("password_changed", "user", user.get("id"), "Mot de passe changé et stocké en hash sécurisé", request=request)
    return {"status": "password_changed", "birth_date_saved": bool(final_birth), "password_storage": "hash sécurisé"}


@app.post("/api/auth/forgot-password")
def forgot_password_v822(payload: ForgotPasswordPayloadV822, request: Request) -> dict[str, Any]:
    username = payload.username.strip()
    birth_date = payload.birth_date.strip()
    with db() as conn:
        _ensure_password_security_columns_v822(conn)
        row = conn.execute("SELECT * FROM app_users WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
        if not row or str(row["birth_date"] or "") != birth_date:
            write_app_log("forgot_password_failed", "user", username, "Identifiant ou date de naissance incorrect", request=request, username=username)
            raise HTTPException(status_code=404, detail="Identifiant ou date de naissance incorrect")
        temp_password = SECURITY_TEMP_PASSWORD_V822
        _set_user_password_v822(conn, int(row["id"]), temp_password, must_change=True)
    write_app_log("forgot_password_temp_generated", "user", row["id"], "Mot de passe temporaire réinitialisé", request=request, username=row["username"], role=row["role"])
    return {"temporary_password": temp_password, "visible_seconds": 60, "warning": "Mot de passe temporaire : il devra être changé à la prochaine connexion."}


@app.get("/api/security/password-status")
def password_security_status_v822(request: Request) -> dict[str, Any]:
    require_superadmin(request)
    result = _migrate_passwords_to_hashes_v822()
    counts = {"total": 0, "secure": 0, "legacy": 0, "plaintext_column_present": False, "plaintext_not_empty": 0}
    with db() as conn:
        cols = _table_columns_v822(conn, "app_users")
        counts["plaintext_column_present"] = "password_plain" in cols
        select_cols = "id, password_salt"
        if "password_plain" in cols:
            select_cols += ", password_plain"
        rows = conn.execute(f"SELECT {select_cols} FROM app_users").fetchall()
        for row in rows or []:
            data = _row_to_plain_dict_v822(row)
            counts["total"] += 1
            if str(data.get("password_salt") or "").startswith(PASSWORD_HASH_SCHEME_V822 + "$"):
                counts["secure"] += 1
            else:
                counts["legacy"] += 1
            if str(data.get("password_plain") or "").strip():
                counts["plaintext_not_empty"] += 1
    return {"status": "ok", "algorithm": PASSWORD_HASH_SCHEME_V822, "iterations": PASSWORD_HASH_ITERATIONS_V822, "migration": result, "counts": counts}


try:
    _ORIGINAL_SQL_CONNECT_V822 = sql_connect_v810  # type: ignore[name-defined]
    def sql_connect_v810(config: dict[str, Any] | None = None, *, with_database: bool = True):  # type: ignore[override]
        conn = _ORIGINAL_SQL_CONNECT_V822(config, with_database=with_database)
        try:
            with conn.cursor() as cur:
                cur.execute("SET SESSION innodb_lock_wait_timeout = 15")
                cur.execute("SET SESSION TRANSACTION ISOLATION LEVEL READ COMMITTED")
        except Exception:
            pass
        return conn
except Exception as exc:
    safe_log(f"Patch connexion SQL V8.2.3 non appliqué : {exc}")

try:
    _ORIGINAL_SQL_COMPAT_EXECUTE_V822 = _SqlCompatConnectionV820.execute  # type: ignore[name-defined]
    def _sql_compat_execute_retry_v822(self, sql: str, params: Any = None):
        last_exc: Exception | None = None
        for attempt in range(3):
            try:
                return _ORIGINAL_SQL_COMPAT_EXECUTE_V822(self, sql, params)
            except HTTPException as exc:
                text = str(getattr(exc, "detail", exc))
                if any(marker in text.lower() for marker in ["deadlock", "lock wait", "1205", "1213"]):
                    last_exc = exc
                    time.sleep(0.15 * (attempt + 1))
                    continue
                raise
            except Exception as exc:
                text = str(exc).lower()
                if any(marker in text for marker in ["deadlock", "lock wait", "1205", "1213"]):
                    last_exc = exc
                    time.sleep(0.15 * (attempt + 1))
                    continue
                raise
        raise HTTPException(status_code=409, detail=f"Conflit d'écriture SQL : une autre modification est en cours. Recharge la page puis réessaie. Détail : {last_exc}")
    _SqlCompatConnectionV820.execute = _sql_compat_execute_retry_v822  # type: ignore[name-defined]
except Exception as exc:
    safe_log(f"Patch exécution SQL V8.2.3 non appliqué : {exc}")


