def _sql_host_display_warning_v823(host: str) -> str:
    host = str(host or "").strip()
    if host.lower() in {"127.0.0.1", "localhost", "::1"}:
        return "Attention : 127.0.0.1 / localhost désigne ce poste. Sur un autre poste, indique l'adresse IP du PC/NAS MariaDB, par exemple 192.168.0.161."
    return ""


def _normalise_sql_host_v823(host: Any) -> str:
    """Conserve strictement l'hôte saisi par l'utilisateur."""
    value = str(host or "").strip()
    if value.startswith("http://") or value.startswith("https://"):
        try:
            from urllib.parse import urlparse
            parsed = urlparse(value)
            value = parsed.hostname or value
        except Exception:
            value = value.replace("http://", "").replace("https://", "").split("/")[0]
    return value.strip()


def load_sql_config_v810(include_password: bool = False) -> dict[str, Any]:
    """V8.2.3 : charge la configuration MariaDB sans imposer 127.0.0.1."""
    try:
        if SQL_CONFIG_PATH_V810.exists():
            data = json.loads(SQL_CONFIG_PATH_V810.read_text(encoding="utf-8", errors="ignore") or "{}")
            if not isinstance(data, dict):
                data = {}
        else:
            data = {}
    except Exception:
        data = {}
    try:
        port = int(data.get("port") or 3307)
    except Exception:
        port = 3307
    cfg = {
        "engine": str(data.get("engine") or "mariadb"),
        "host": _normalise_sql_host_v823(data.get("host") or ""),
        "port": port,
        "database": str(data.get("database") or "clyo_stock_atelier_test").strip(),
        "user": str(data.get("user") or "clyo_stock").strip(),
        "enabled": bool(data.get("enabled", False)),
        "mode": str(data.get("mode") or "sql"),
        "saved_at": data.get("saved_at"),
        "last_test_at": data.get("last_test_at"),
        "last_test_ok": bool(data.get("last_test_ok", False)),
        "last_migration_at": data.get("last_migration_at"),
        "warning": _sql_host_display_warning_v823(str(data.get("host") or "")),
    }
    if include_password:
        cfg["password"] = str(data.get("password") or "")
    return cfg


def save_sql_config_v810(payload: dict[str, Any], *, test_ok: bool | None = None, enabled: bool | None = None) -> dict[str, Any]:
    """V8.2.3 : sauvegarde l'hôte MariaDB exact saisi dans le formulaire."""
    previous = load_sql_config_v810(include_password=True)
    cfg = dict(previous)
    if not isinstance(payload, dict):
        payload = {}
    if "engine" in payload:
        cfg["engine"] = str(payload.get("engine") or "mariadb").strip() or "mariadb"
    if "host" in payload:
        cfg["host"] = _normalise_sql_host_v823(payload.get("host"))
    if "database" in payload:
        cfg["database"] = str(payload.get("database") or "").strip()
    if "user" in payload:
        cfg["user"] = str(payload.get("user") or "").strip()
    if "password" in payload:
        cfg["password"] = str(payload.get("password") or "")
    if "mode" in payload:
        cfg["mode"] = str(payload.get("mode") or "sql").strip() or "sql"
    else:
        cfg["mode"] = "sql"
    if "last_migration_at" in payload and payload.get("last_migration_at") is not None:
        cfg["last_migration_at"] = str(payload.get("last_migration_at") or "")
    if "port" in payload:
        try:
            cfg["port"] = int(payload.get("port") or 3307)
        except Exception:
            cfg["port"] = 3307
    if enabled is not None:
        cfg["enabled"] = bool(enabled)
    if test_ok is not None:
        cfg["last_test_ok"] = bool(test_ok)
        cfg["last_test_at"] = now_iso()
    cfg["saved_at"] = now_iso()
    SQL_CONFIG_PATH_V810.parent.mkdir(parents=True, exist_ok=True)
    SQL_CONFIG_PATH_V810.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    public = dict(cfg)
    public.pop("password", None)
    public["config_path"] = str(SQL_CONFIG_PATH_V810)
    public["warning"] = _sql_host_display_warning_v823(str(public.get("host") or ""))
    return public


def normalize_sql_payload_v810(payload: dict[str, Any] | None) -> dict[str, Any]:
    payload = payload if isinstance(payload, dict) else {}
    try:
        port = int(payload.get("port") or 3307)
    except Exception:
        port = 3307
    return {
        "engine": "mariadb",
        "host": _normalise_sql_host_v823(payload.get("host")),
        "port": port,
        "database": str(payload.get("database") or "clyo_stock_atelier_test").strip(),
        "user": str(payload.get("user") or "clyo_stock").strip(),
        "password": str(payload.get("password") or ""),
        "mode": "sql",
    }


def sql_connect_v810(config: dict[str, Any] | None = None, *, with_database: bool = True):
    cfg = {**load_sql_config_v810(include_password=True), **(config or {})}
    host = _normalise_sql_host_v823(cfg.get("host"))
    database = str(cfg.get("database") or "").strip()
    user = str(cfg.get("user") or "").strip()
    password = str(cfg.get("password") or "")
    try:
        port = int(cfg.get("port") or 3307)
    except Exception:
        port = 3307
    if not host:
        raise HTTPException(status_code=400, detail="Adresse du serveur MariaDB obligatoire. Sur un poste client, utilise l'IP du PC/NAS MariaDB, pas 127.0.0.1.")
    if not user:
        raise HTTPException(status_code=400, detail="Utilisateur MariaDB obligatoire.")
    if with_database and not database:
        raise HTTPException(status_code=400, detail="Nom de base MariaDB obligatoire.")
    pymysql = _import_pymysql_v810()
    kwargs = {
        "host": host,
        "port": port,
        "user": user,
        "password": password,
        "charset": "utf8mb4",
        "cursorclass": pymysql.cursors.DictCursor,
        "connect_timeout": 8,
        "read_timeout": 20,
        "write_timeout": 20,
        "autocommit": False,
    }
    if with_database:
        kwargs["database"] = database
    try:
        return pymysql.connect(**kwargs)
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Connexion MariaDB impossible vers {host}:{port} / base {database or '(sans base)'} : {exc}") from exc


def _sql_users_count_v823(config: dict[str, Any] | None = None) -> tuple[bool, str, int]:
    try:
        cfg = config or load_sql_config_v810(include_password=True)
        if not cfg.get("enabled"):
            return False, "Configuration MariaDB non validée sur ce poste.", 0
        conn = sql_connect_v810(cfg, with_database=True)
        try:
            with conn.cursor() as cur:
                cur.execute("SHOW TABLES LIKE 'app_users'")
                if not cur.fetchone():
                    return False, "La base MariaDB ne contient pas encore la table app_users.", 0
                cur.execute("SELECT COUNT(*) AS c FROM app_users WHERE TRIM(COALESCE(username,'')) <> ''")
                row = cur.fetchone() or {}
                count = int(row.get("c") or 0)
                if count <= 0:
                    return False, "La base MariaDB est accessible mais ne contient aucun profil utilisateur.", 0
                return True, f"Base MariaDB centrale utilisable ({count} profil(s)).", count
        finally:
            conn.close()
    except Exception as exc:
        return False, f"MariaDB inaccessible ou invalide : {exc}", 0


def setup_choice_required() -> bool:
    """V8.2.3 : SQL uniquement au démarrage."""
    ok, reason, _count = _sql_users_count_v823()
    try:
        globals()["DATA_DIR_STARTUP_ERROR"] = "" if ok else reason
        globals()["DATA_DIR_FALLBACK_ACTIVE"] = not ok
    except Exception:
        pass
    return not ok


