SQL_DEFAULT_PORT_V824 = 5936
SQL_DEFAULT_DATABASE_V824 = "clyo_stock_atelier"
SQL_DEFAULT_USER_V824 = "clyo_stock"


def _sql_host_display_warning_v824(host: str) -> str:
    host = str(host or "").strip()
    if host.lower() in {"127.0.0.1", "localhost", "::1"}:
        return "Attention : 127.0.0.1 / localhost désigne ce poste. Sur un poste client, indique l'adresse IP du PC/NAS MariaDB."
    return ""


def _normalise_sql_host_v824(host: Any) -> str:
    value = str(host or "").strip()
    if value.startswith("http://") or value.startswith("https://"):
        try:
            from urllib.parse import urlparse
            parsed = urlparse(value)
            value = parsed.hostname or value
        except Exception:
            value = value.replace("http://", "").replace("https://", "").split("/")[0]
    return value.strip()


def _sql_fixed_defaults_v824() -> dict[str, Any]:
    return {
        "engine": "mariadb",
        "port": SQL_DEFAULT_PORT_V824,
        "database": SQL_DEFAULT_DATABASE_V824,
        "user": SQL_DEFAULT_USER_V824,
        "mode": "sql",
    }


def load_sql_config_v810(include_password: bool = False) -> dict[str, Any]:  # type: ignore[override]
    # V8.2.9 : l'utilisateur ne saisit que l'IP MariaDB + le mot de passe.
    try:
        if SQL_CONFIG_PATH_V810.exists():
            data = json.loads(SQL_CONFIG_PATH_V810.read_text(encoding="utf-8", errors="ignore") or "{}")
            if not isinstance(data, dict):
                data = {}
        else:
            data = {}
    except Exception:
        data = {}
    host = _normalise_sql_host_v824(data.get("host") or "")
    cfg = {
        **_sql_fixed_defaults_v824(),
        "host": host,
        "enabled": bool(data.get("enabled", False)),
        "saved_at": data.get("saved_at"),
        "last_test_at": data.get("last_test_at"),
        "last_test_ok": bool(data.get("last_test_ok", False)),
        "last_migration_at": data.get("last_migration_at"),
        "warning": _sql_host_display_warning_v824(host),
        "display_mode": "simple_ip_password",
    }
    if include_password:
        cfg["password"] = str(data.get("password") or "")
    return cfg


def save_sql_config_v810(payload: dict[str, Any], *, test_ok: bool | None = None, enabled: bool | None = None) -> dict[str, Any]:  # type: ignore[override]
    # V8.2.9 : sauvegarde seulement l'hôte et le mot de passe, avec paramètres SQL fixes.
    previous = load_sql_config_v810(include_password=True)
    if not isinstance(payload, dict):
        payload = {}
    host = _normalise_sql_host_v824(payload.get("host") if "host" in payload else previous.get("host"))
    password = str(payload.get("password") if "password" in payload else previous.get("password") or "")
    cfg = {
        **_sql_fixed_defaults_v824(),
        "host": host,
        "password": password,
        "enabled": bool(previous.get("enabled", False)) if enabled is None else bool(enabled),
        "saved_at": now_iso(),
        "last_test_at": previous.get("last_test_at"),
        "last_test_ok": bool(previous.get("last_test_ok", False)),
        "last_migration_at": previous.get("last_migration_at"),
        "display_mode": "simple_ip_password",
    }
    if test_ok is not None:
        cfg["last_test_ok"] = bool(test_ok)
        cfg["last_test_at"] = now_iso()
    if "last_migration_at" in payload and payload.get("last_migration_at") is not None:
        cfg["last_migration_at"] = str(payload.get("last_migration_at") or "")
    SQL_CONFIG_PATH_V810.parent.mkdir(parents=True, exist_ok=True)
    SQL_CONFIG_PATH_V810.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    public = dict(cfg)
    public.pop("password", None)
    public["config_path"] = str(SQL_CONFIG_PATH_V810)
    public["warning"] = _sql_host_display_warning_v824(str(public.get("host") or ""))
    return public


def normalize_sql_payload_v810(payload: dict[str, Any] | None) -> dict[str, Any]:  # type: ignore[override]
    payload = payload if isinstance(payload, dict) else {}
    return {
        **_sql_fixed_defaults_v824(),
        "host": _normalise_sql_host_v824(payload.get("host")),
        "password": str(payload.get("password") or ""),
    }


def sql_connect_v810(config: dict[str, Any] | None = None, *, with_database: bool = True):  # type: ignore[override]
    cfg = {**load_sql_config_v810(include_password=True), **(config or {})}
    host = _normalise_sql_host_v824(cfg.get("host"))
    database = SQL_DEFAULT_DATABASE_V824
    user = SQL_DEFAULT_USER_V824
    password = str(cfg.get("password") or "")
    port = SQL_DEFAULT_PORT_V824
    if not host:
        raise HTTPException(status_code=400, detail="Adresse IP du serveur MariaDB obligatoire.")
    if not password:
        raise HTTPException(status_code=400, detail="Mot de passe MariaDB obligatoire.")
    pymysql = _import_pymysql_v810()
    kwargs = {
        "host": host,
        "port": port,
        "user": user,
        "password": password,
        "charset": "utf8mb4",
        "cursorclass": pymysql.cursors.DictCursor,
        "connect_timeout": 8,
        "read_timeout": 20,
        "write_timeout": 20,
        "autocommit": False,
    }
    if with_database:
        kwargs["database"] = database
    try:
        return pymysql.connect(**kwargs)
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"Connexion MariaDB impossible vers {host}:{port} / base {database} / utilisateur {user} : {exc}") from exc


