def _sql_config_present_v825() -> tuple[bool, str]:
    """Contrôle non bloquant : présence d'une configuration SQL locale.

    Ne teste pas le réseau ici : la page / doit répondre vite, même si le NAS
    MariaDB est lent ou inaccessible. Le test réseau est fait seulement via les
    routes SQL ou pendant la connexion utilisateur.
    """
    try:
        cfg = load_sql_config_v810(include_password=True)
        if not isinstance(cfg, dict) or not cfg.get("enabled"):
            return False, "Configuration MariaDB absente."
        if not str(cfg.get("host") or "").strip():
            return False, "Adresse IP MariaDB absente."
        if not str(cfg.get("password") or ""):
            return False, "Mot de passe MariaDB absent."
        return True, "Configuration MariaDB présente."
    except Exception as exc:
        return False, f"Configuration MariaDB illisible : {exc}"


def setup_choice_required() -> bool:  # type: ignore[override]
    """V8.2.9 : SQL uniquement.

    La page de connexion MariaDB s'affiche seulement si la configuration SQL
    locale est absente/incomplète. La disponibilité du NAS n'est plus testée sur
    la route d'accueil pour éviter les attentes de 20/30 secondes et les erreurs
    127.0.0.1 au démarrage.
    """
    ok, reason = _sql_config_present_v825()
    try:
        globals()["DATA_DIR_STARTUP_ERROR"] = "" if ok else reason
        globals()["DATA_DIR_FALLBACK_ACTIVE"] = not ok
    except Exception:
        pass
    return not ok


def _sql_connect_kwargs_v825(cfg: dict[str, Any], *, with_database: bool = True, fast: bool = False) -> dict[str, Any]:
    pymysql = _import_pymysql_v810()
    host = _normalise_sql_host_v824(cfg.get("host")) if "_normalise_sql_host_v824" in globals() else str(cfg.get("host") or "").strip()
    database = SQL_DEFAULT_DATABASE_V824 if "SQL_DEFAULT_DATABASE_V824" in globals() else str(cfg.get("database") or "clyo_stock_atelier")
    user = SQL_DEFAULT_USER_V824 if "SQL_DEFAULT_USER_V824" in globals() else str(cfg.get("user") or "clyo_stock")
    password = str(cfg.get("password") or "")
    port = SQL_DEFAULT_PORT_V824 if "SQL_DEFAULT_PORT_V824" in globals() else int(cfg.get("port") or 5936)
    connect_timeout = 3 if fast else 5
    read_timeout = 6 if fast else 12
    write_timeout = 6 if fast else 12
    kwargs = {
        "host": host,
        "port": int(port),
        "user": user,
        "password": password,
        "charset": "utf8mb4",
        "cursorclass": pymysql.cursors.DictCursor,
        "connect_timeout": connect_timeout,
        "read_timeout": read_timeout,
        "write_timeout": write_timeout,
        "autocommit": False,
    }
    if with_database:
        kwargs["database"] = database
    return kwargs


def sql_connect_v810(config: dict[str, Any] | None = None, *, with_database: bool = True):  # type: ignore[override]
    """V8.2.9 : connexion MariaDB avec timeouts plus courts et message clair.

    Objectif : ne plus laisser l'application attendre 30 secondes au démarrage
    si le NAS ne répond pas ou si une requête reste bloquée.
    """
    cfg = {**load_sql_config_v810(include_password=True), **(config or {})}
    host = _normalise_sql_host_v824(cfg.get("host")) if "_normalise_sql_host_v824" in globals() else str(cfg.get("host") or "").strip()
    password = str(cfg.get("password") or "")
    if not host:
        raise HTTPException(status_code=400, detail="Adresse IP du serveur MariaDB obligatoire.")
    if not password:
        raise HTTPException(status_code=400, detail="Mot de passe MariaDB obligatoire.")
    pymysql = _import_pymysql_v810()
    kwargs = _sql_connect_kwargs_v825(cfg, with_database=with_database, fast=bool(cfg.get("fast")))
    try:
        return pymysql.connect(**kwargs)
    except Exception as exc:
        port = kwargs.get("port")
        db_name = kwargs.get("database") if with_database else "sans base"
        raise HTTPException(status_code=502, detail=f"MariaDB inaccessible sur {host}:{port} / {db_name}. Vérifie l'IP, le port 5936, le pare-feu et le mot de passe. Détail : {exc}") from exc


def _sql_fast_users_v825() -> dict[str, Any]:
    cfg = load_sql_config_v810(include_password=True)
    if not cfg.get("enabled"):
        return {"users": [], "sql_configured": False, "message": "Configuration MariaDB absente."}
    conn = None
    try:
        cfg = {**cfg, "fast": True}
        conn = sql_connect_v810(cfg, with_database=True)
        with conn.cursor() as cur:
            cur.execute("SELECT username, role FROM app_users WHERE TRIM(COALESCE(username,'')) <> '' ORDER BY username LIMIT 200")
            rows = cur.fetchall() or []
        conn.commit()
        return {"users": [{"username": r.get("username"), "role": r.get("role") or "lecteur"} for r in rows if r.get("username")], "sql_configured": True, "source": "mariadb"}
    except Exception as exc:
        try:
            if conn:
                conn.rollback()
        except Exception:
            pass
        return {"users": [], "sql_configured": True, "source": "mariadb", "error": str(exc), "message": "MariaDB inaccessible ou trop lent. Vérifie l'adresse IP du serveur et le port 5936."}
    finally:
        try:
            if conn:
                conn.close()
        except Exception:
            pass


