def repair_sql_schema_v826() -> None:
    """Réparations SQL légères et idempotentes pour les bases MariaDB existantes."""
    if not _sql_mode_enabled_v826():
        return
    try:
        with db() as conn:
            try:
                conn.execute("ALTER TABLE customers ADD COLUMN sync_active TINYINT(1) NOT NULL DEFAULT 1")
            except Exception:
                pass
            try:
                conn.execute("ALTER TABLE customers MODIFY COLUMN sync_active TINYINT(1) NOT NULL DEFAULT 1")
            except Exception:
                pass
            try:
                conn.execute("UPDATE customers SET sync_active = 1 WHERE sync_active IS NULL")
            except Exception:
                pass
    except Exception as exc:
        try:
            safe_log(f"Réparation SQL V8.2.9 incomplète : {exc}")
        except Exception:
            pass


