@app.get("/api/assets/{asset_id}/history")
def api_asset_history_v826(asset_id: int, request: Request, limit: int = Query(default=100, ge=1, le=500)) -> dict[str, Any]:
    get_request_user(request)
    init_db()
    with db() as conn:
        asset_row = conn.execute("SELECT * FROM assets WHERE id = ?", (asset_id,)).fetchone()
        if not asset_row:
            raise HTTPException(status_code=404, detail="Matériel introuvable")
        raw_events = [dict(row) for row in conn.execute(
            """
            SELECT * FROM asset_events
            WHERE asset_id = ?
            ORDER BY created_at ASC, id ASC
            LIMIT ?
            """,
            (asset_id, limit),
        ).fetchall()]
        try:
            asset = get_asset_full(conn, asset_id)
        except Exception:
            asset = dict(asset_row)

    def label_for_event(ev: dict[str, Any]) -> str:
        et = str(ev.get("event_type") or "").strip()
        mapping = {
            "created": "Création",
            "updated": "Modification",
            "deleted": "Suppression",
            "assigned": "Attribution client",
            "sold": "Vente",
            "returned": "Retour",
            "status_changed": "Changement de statut",
            "material_connection_profile_saved": "Dessin matériel enregistré",
        }
        return mapping.get(et, et.replace("_", " ").strip().capitalize() or "Action")

    events: list[dict[str, Any]] = []
    for ev in raw_events:
        events.append({
            **ev,
            "label": ev.get("label") or label_for_event(ev),
            "details": ev.get("details") or "",
            "created_at": ev.get("created_at") or "",
            "username": ev.get("username") or ev.get("user") or "",
            "source": ev.get("source") or "",
            "field_name": ev.get("field_name") or "",
            "old_value": ev.get("old_value"),
            "new_value": ev.get("new_value"),
        })
    return {"status": "ok", "asset": asset, "events": events, "count": len(events)}


def ensure_user_ui_settings_table_v826() -> None:
    with db() as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS user_ui_settings (
                user_id INT NOT NULL PRIMARY KEY,
                username VARCHAR(191),
                settings_json TEXT,
                updated_at TEXT
            )
            """
        )


def _load_user_ui_settings_v826(user: dict[str, Any] | None) -> dict[str, Any]:
    if not user:
        return load_ui_settings()
    try:
        ensure_user_ui_settings_table_v826()
        with db() as conn:
            row = conn.execute("SELECT settings_json FROM user_ui_settings WHERE user_id = ?", (int(user.get("id") or 0),)).fetchone()
        if row and row["settings_json"]:
            data = json.loads(row["settings_json"])
            if isinstance(data, dict):
                return _sanitize_ui_settings_dict(data)
    except Exception as exc:
        try:
            safe_log(f"Lecture apparence utilisateur V8.2.9 impossible : {exc}")
        except Exception:
            pass
    return load_ui_settings()


def _save_user_ui_settings_v826(user: dict[str, Any], settings: dict[str, Any]) -> dict[str, Any]:
    saved = _sanitize_ui_settings_dict(settings)
    saved["user_id"] = int(user.get("id") or 0)
    saved["username"] = str(user.get("username") or "")
    saved["personal_scope"] = True
    ensure_user_ui_settings_table_v826()
    with db() as conn:
        existing = conn.execute("SELECT user_id FROM user_ui_settings WHERE user_id = ?", (int(user.get("id") or 0),)).fetchone()
        payload = json.dumps(saved, ensure_ascii=False)
        if existing:
            conn.execute(
                "UPDATE user_ui_settings SET username = ?, settings_json = ?, updated_at = ? WHERE user_id = ?",
                (str(user.get("username") or ""), payload, now_iso(), int(user.get("id") or 0)),
            )
        else:
            conn.execute(
                "INSERT INTO user_ui_settings(user_id, username, settings_json, updated_at) VALUES (?, ?, ?, ?)",
                (int(user.get("id") or 0), str(user.get("username") or ""), payload, now_iso()),
            )
    return saved


