_SQL_ONLY_MESSAGE_V831 = "Mode SQL obligatoire : aucune lecture/écriture applicative locale n'est autorisée. Configure une base MariaDB centrale."


def sql_runtime_enabled_v831() -> bool:
    try:
        return bool(load_sql_config_v810(False).get("enabled"))
    except Exception:
        return False


def require_sql_runtime_v831() -> None:
    if not sql_runtime_enabled_v831():
        raise HTTPException(status_code=503, detail=_SQL_ONLY_MESSAGE_V831)


def ensure_user_ui_settings_table_v831() -> None:
    """Table centrale MariaDB : une apparence/disposition par utilisateur."""
    require_sql_runtime_v831()
    with db() as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS user_ui_settings (
                user_id INTEGER NOT NULL PRIMARY KEY,
                username VARCHAR(255),
                settings_json LONGTEXT NOT NULL,
                created_at TEXT,
                updated_at TEXT
            )
            """
        )
        try:
            conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_user_ui_settings_user_id ON user_ui_settings(user_id)")
        except Exception:
            pass


def load_user_ui_settings_v831(user: dict[str, Any] | None) -> dict[str, Any]:
    require_sql_runtime_v831()
    if not user or not user.get("id"):
        raise HTTPException(status_code=401, detail="Connexion requise")
    ensure_user_ui_settings_table_v831()
    with db() as conn:
        row = conn.execute("SELECT settings_json FROM user_ui_settings WHERE user_id = ?", (int(user["id"]),)).fetchone()
    if not row:
        return _sanitize_ui_settings_dict(DEFAULT_UI_SETTINGS.copy())
    try:
        raw = row["settings_json"] if isinstance(row, dict) or hasattr(row, "keys") else row[0]
        data = json.loads(raw or "{}")
        if not isinstance(data, dict):
            data = {}
    except Exception:
        data = {}
    return _sanitize_ui_settings_dict(data)


def save_user_ui_settings_v831(user: dict[str, Any] | None, settings: dict[str, Any]) -> dict[str, Any]:
    require_sql_runtime_v831()
    if not user or not user.get("id"):
        raise HTTPException(status_code=401, detail="Connexion requise")
    ensure_user_ui_settings_table_v831()
    merged = _sanitize_ui_settings_dict({**DEFAULT_UI_SETTINGS, **(settings or {})})
    try:
        merged["card_radius"] = max(0, min(40, int(merged.get("card_radius") or 16)))
    except Exception:
        merged["card_radius"] = DEFAULT_UI_SETTINGS["card_radius"]
    try:
        merged["bubble_radius"] = max(0, min(999, int(merged.get("bubble_radius") or 999)))
    except Exception:
        merged["bubble_radius"] = DEFAULT_UI_SETTINGS["bubble_radius"]
    try:
        merged["sidebar_radius"] = max(0, min(40, int(merged.get("sidebar_radius") or 22)))
    except Exception:
        merged["sidebar_radius"] = DEFAULT_UI_SETTINGS["sidebar_radius"]
    if not isinstance(merged.get("layout_positions"), dict):
        merged["layout_positions"] = {}
    merged["logo_data_url"] = ""
    merged["force_config_visibility"] = False
    payload = json.dumps(merged, ensure_ascii=False)
    now = now_iso()
    with db() as conn:
        existing = conn.execute("SELECT user_id FROM user_ui_settings WHERE user_id = ?", (int(user["id"]),)).fetchone()
        if existing:
            conn.execute(
                "UPDATE user_ui_settings SET username = ?, settings_json = ?, updated_at = ? WHERE user_id = ?",
                (str(user.get("username") or ""), payload, now, int(user["id"])),
            )
        else:
            conn.execute(
                "INSERT INTO user_ui_settings(user_id, username, settings_json, created_at, updated_at) VALUES (?, ?, ?, ?, ?)",
                (int(user["id"]), str(user.get("username") or ""), payload, now, now),
            )
    return merged


# Neutralise l'ancien fichier ui_settings.json : il ne doit plus être la source de vérité.
def load_ui_settings() -> dict[str, Any]:  # type: ignore[no-redef]
    return _sanitize_ui_settings_dict(DEFAULT_UI_SETTINGS.copy())


def save_ui_settings(settings: dict[str, Any]) -> dict[str, Any]:  # type: ignore[no-redef]
    raise HTTPException(status_code=503, detail="Sauvegarde locale désactivée : les préférences doivent être enregistrées par utilisateur dans MariaDB.")


async def api_get_ui_settings_v831(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    return load_user_ui_settings_v831(user)


async def api_patch_ui_settings_v831(payload: UiSettingsUpdate, request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    current = load_user_ui_settings_v831(user)
    updates = payload.dict(exclude_unset=True)
    for key, value in updates.items():
        if value is not None:
            current[key] = value
    saved = save_user_ui_settings_v831(user, current)
    write_app_log("ui_settings_updated", "settings", "ui", f"Configuration visuelle modifiée pour {user.get('username') if user else ''}", request=request)
    return saved


async def api_reset_ui_settings_v831(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    saved = save_user_ui_settings_v831(user, DEFAULT_UI_SETTINGS.copy())
    write_app_log("ui_settings_reset", "settings", "ui", f"Configuration visuelle réinitialisée pour {user.get('username') if user else ''}", request=request)
    return saved


def replace_route_endpoint_v831(path: str, methods: set[str], endpoint: Any) -> None:
    for route in getattr(app.router, "routes", []):
        if getattr(route, "path", None) == path and set(getattr(route, "methods", set()) or set()) == methods:
            route.endpoint = endpoint
            route.dependant = None
            try:
                from fastapi.routing import request_response
                route.app = request_response(endpoint)
            except Exception:
                pass
            try:
                route.name = getattr(endpoint, "__name__", route.name)
            except Exception:
                pass
            return

try:
    replace_route_endpoint_v831("/api/ui-settings", {"GET"}, api_get_ui_settings_v831)
    replace_route_endpoint_v831("/api/ui-settings", {"PATCH"}, api_patch_ui_settings_v831)
    replace_route_endpoint_v831("/api/ui-settings/reset", {"POST"}, api_reset_ui_settings_v831)
except Exception as exc:
    safe_log(f"Remplacement endpoints UI SQL impossible : {exc}")

