# Mode strict : la base applicative locale/SQLite n'est plus autorisée.
_SQLITE_DB_CONTEXT_LEGACY_V831 = globals().get("_SQLITE_DB_CONTEXT_V820")

@contextmanager
def db() -> Any:  # type: ignore[no-redef]
    """V8.3.1 : MariaDB obligatoire pour les données applicatives."""
    cfg: dict[str, Any] = {}
    try:
        cfg = load_sql_config_v810(include_password=True)
    except Exception:
        cfg = {}
    if not bool(cfg.get("enabled")):
        raise HTTPException(status_code=503, detail=_SQL_ONLY_MESSAGE_V831)
    conn = _SqlCompatConnectionV820(cfg)
    try:
        yield conn
        conn.commit()
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass
        raise
    finally:
        conn.close()

