# Apparence utilisateur : clé profil MariaDB robuste (username), sans stockage local.
def ensure_user_ui_settings_table_v833() -> None:
    require_sql_runtime_v831()
    with db() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS user_ui_settings (
                username VARCHAR(255) NOT NULL PRIMARY KEY,
                settings_json LONGTEXT NOT NULL,
                created_at TEXT,
                updated_at TEXT
            )
        """)
        for sql in [
            "ALTER TABLE user_ui_settings ADD COLUMN username VARCHAR(255)",
            "ALTER TABLE user_ui_settings ADD COLUMN settings_json LONGTEXT",
            "ALTER TABLE user_ui_settings ADD COLUMN created_at TEXT",
            "ALTER TABLE user_ui_settings ADD COLUMN updated_at TEXT",
            "CREATE UNIQUE INDEX IF NOT EXISTS idx_user_ui_settings_username_v833 ON user_ui_settings(username)",
        ]:
            try:
                conn.execute(sql)
            except Exception:
                pass


def _ui_username_key_v833(user: dict[str, Any] | None) -> str:
    username = str((user or {}).get("username") or "").strip().lower()
    if not username:
        raise HTTPException(status_code=401, detail="Connexion requise")
    return username


def load_user_ui_settings_v833(user: dict[str, Any] | None) -> dict[str, Any]:
    require_sql_runtime_v831()
    username = _ui_username_key_v833(user)
    ensure_user_ui_settings_table_v833()
    with db() as conn:
        row = conn.execute("SELECT settings_json FROM user_ui_settings WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
    if not row:
        return _sanitize_ui_settings_dict(DEFAULT_UI_SETTINGS.copy())
    try:
        raw = row["settings_json"] if hasattr(row, "keys") else row[0]
        data = json.loads(raw or "{}")
        if not isinstance(data, dict):
            data = {}
    except Exception:
        data = {}
    return _sanitize_ui_settings_dict({**DEFAULT_UI_SETTINGS, **data})


def save_user_ui_settings_v833(user: dict[str, Any] | None, settings: dict[str, Any]) -> dict[str, Any]:
    require_sql_runtime_v831()
    username = _ui_username_key_v833(user)
    ensure_user_ui_settings_table_v833()
    merged = _sanitize_ui_settings_dict({**DEFAULT_UI_SETTINGS, **(settings or {})})
    for key, default, min_v, max_v in (("card_radius", 16, 0, 40), ("bubble_radius", 999, 0, 999), ("sidebar_radius", 22, 0, 40), ("category_card_radius", 16, 0, 40)):
        try:
            merged[key] = max(min_v, min(max_v, int(merged.get(key) if merged.get(key) is not None else default)))
        except Exception:
            merged[key] = default
    if not isinstance(merged.get("layout_positions"), dict):
        merged["layout_positions"] = {}
    merged["logo_data_url"] = ""
    merged["force_config_visibility"] = False
    payload = json.dumps(merged, ensure_ascii=False)
    now = now_iso()
    with db() as conn:
        existing = conn.execute("SELECT username FROM user_ui_settings WHERE LOWER(username) = LOWER(?)", (username,)).fetchone()
        if existing:
            conn.execute("UPDATE user_ui_settings SET settings_json = ?, updated_at = ? WHERE LOWER(username) = LOWER(?)", (payload, now, username))
        else:
            conn.execute("INSERT INTO user_ui_settings(username, settings_json, created_at, updated_at) VALUES (?, ?, ?, ?)", (username, payload, now, now))
    return merged


async def api_get_ui_settings_v833(request: Request) -> dict[str, Any]:
    return load_user_ui_settings_v833(get_request_user(request))


async def api_patch_ui_settings_v833(payload: UiSettingsUpdate, request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    current = load_user_ui_settings_v833(user)
    updates = payload.dict(exclude_unset=True)
    for key, value in updates.items():
        if value is not None:
            current[key] = value
    saved = save_user_ui_settings_v833(user, current)
    write_app_log("ui_settings_updated_v833", "settings", str((user or {}).get("username") or ""), f"Configuration visuelle modifiée pour {(user or {}).get('username') or ''}", request=request)
    return saved


async def api_reset_ui_settings_v833(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    saved = save_user_ui_settings_v833(user, DEFAULT_UI_SETTINGS.copy())
    write_app_log("ui_settings_reset_v833", "settings", str((user or {}).get("username") or ""), f"Configuration visuelle réinitialisée pour {(user or {}).get('username') or ''}", request=request)
    return saved

MODULE_PERMISSIONS_V833 = {
    "dashboard-panel": "Tableau de bord",
    "assets-panel": "Stock / Matériels",
    "clients-panel": "Clients / Vente",
    "refs-panel": "Référentiel",
    "visual-panel": "Apparence",
    "logs-panel": "Logs",
    "updates-panel": "Mises à jour",
    "users-panel": "Gestion des identifiants",
}
DEFAULT_USER_PERMISSIONS_V833 = {key: True for key in MODULE_PERMISSIONS_V833}

class UserPermissionsPayloadV833(BaseModel):
    permissions: dict[str, bool] = Field(default_factory=dict)


def ensure_user_permissions_table_v833() -> None:
    require_sql_runtime_v831()
    with db() as conn:
        conn.execute("""
            CREATE TABLE IF NOT EXISTS user_module_permissions (
                username VARCHAR(255) NOT NULL PRIMARY KEY,
                permissions_json LONGTEXT NOT NULL,
                created_at TEXT,
                updated_at TEXT
            )
        """)


def _permissions_username_key_v833(username: str | None) -> str:
    key = str(username or "").strip().lower()
    if not key:
        raise HTTPException(status_code=400, detail="Profil invalide")
    return key


def normalize_permissions_v833(raw: dict[str, Any] | None, *, superadmin: bool = False) -> dict[str, bool]:
    if superadmin:
        return {key: True for key in MODULE_PERMISSIONS_V833}
    out = DEFAULT_USER_PERMISSIONS_V833.copy()
    if isinstance(raw, dict):
        for key in MODULE_PERMISSIONS_V833:
            if key in raw:
                out[key] = bool(raw.get(key))
    out["users-panel"] = False
    return out


def get_user_permissions_by_username_v833(username: str | None, *, superadmin: bool = False) -> dict[str, bool]:
    if superadmin:
        return normalize_permissions_v833({}, superadmin=True)
    key = _permissions_username_key_v833(username)
    try:
        ensure_user_permissions_table_v833()
        with db() as conn:
            row = conn.execute("SELECT permissions_json FROM user_module_permissions WHERE LOWER(username) = LOWER(?)", (key,)).fetchone()
        if row:
            raw = row["permissions_json"] if hasattr(row, "keys") else row[0]
            data = json.loads(raw or "{}")
            return normalize_permissions_v833(data, superadmin=False)
    except Exception as exc:
        try:
            safe_log(f"Lecture droits utilisateur V8.3.3 impossible : {exc}")
        except Exception:
            pass
    return normalize_permissions_v833({}, superadmin=False)


def save_user_permissions_by_username_v833(username: str, permissions: dict[str, Any]) -> dict[str, bool]:
    key = _permissions_username_key_v833(username)
    normalized = normalize_permissions_v833(permissions, superadmin=False)
    payload = json.dumps(normalized, ensure_ascii=False)
    now = now_iso()
    ensure_user_permissions_table_v833()
    with db() as conn:
        existing = conn.execute("SELECT username FROM user_module_permissions WHERE LOWER(username) = LOWER(?)", (key,)).fetchone()
        if existing:
            conn.execute("UPDATE user_module_permissions SET permissions_json = ?, updated_at = ? WHERE LOWER(username) = LOWER(?)", (payload, now, key))
        else:
            conn.execute("INSERT INTO user_module_permissions(username, permissions_json, created_at, updated_at) VALUES (?, ?, ?, ?)", (key, payload, now, now))
    return normalized


@app.get("/api/user-permissions/modules")
def api_user_permission_modules_v833(request: Request) -> dict[str, Any]:
    require_superadmin(request)
    return {"modules": MODULE_PERMISSIONS_V833}


@app.get("/api/user-permissions/{username}")
def api_get_user_permissions_v833(username: str, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    user_lookup = str(username or "").strip()
    superadmin = user_lookup.lower() == str(SUPERADMIN_USERNAME).lower()
    return {"username": user_lookup, "permissions": get_user_permissions_by_username_v833(user_lookup, superadmin=superadmin), "modules": MODULE_PERMISSIONS_V833}


@app.patch("/api/user-permissions/{username}")
def api_patch_user_permissions_v833(username: str, payload: UserPermissionsPayloadV833, request: Request) -> dict[str, Any]:
    require_superadmin(request)
    if str(username or "").strip().lower() == str(SUPERADMIN_USERNAME).lower():
        raise HTTPException(status_code=400, detail="Le superadmin conserve toujours tous les accès.")
    saved = save_user_permissions_by_username_v833(username, payload.permissions)
    write_app_log("user_permissions_updated_v833", "user", username, f"Droits du profil {username} modifiés", request=request)
    return {"username": username, "permissions": saved, "modules": MODULE_PERMISSIONS_V833}

async def api_auth_me_v833(request: Request) -> dict[str, Any]:
    user = get_request_user(request, touch=False)
    if not user:
        return {"authenticated": False}
    is_super = user_is_superadmin(user)
    permissions = get_user_permissions_by_username_v833(user.get("username"), superadmin=is_super)
    return {**user, "authenticated": True, "can_write_assets": user_can_write_assets(user), "is_superadmin": is_super, "module_permissions": permissions, "timeout_minutes": SESSION_TIMEOUT_MINUTES, "app_name": APP_NAME, "app_version": APP_VERSION}

