try:
    DEFAULT_USER_PERMISSIONS_V833["visual-panel"] = True
except Exception:
    pass

try:
    _normalize_permissions_original_v837 = normalize_permissions_v833
except Exception:
    _normalize_permissions_original_v837 = None


def normalize_permissions_v833(raw: dict[str, Any] | None, *, superadmin: bool = False) -> dict[str, bool]:  # type: ignore[no-redef]
    try:
        if _normalize_permissions_original_v837:
            out = dict(_normalize_permissions_original_v837(raw, superadmin=superadmin))
        else:
            out = {key: True for key in MODULE_PERMISSIONS_V833}
            if isinstance(raw, dict):
                for key in MODULE_PERMISSIONS_V833:
                    if key in raw:
                        out[key] = bool(raw.get(key))
    except Exception:
        out = {key: True for key in MODULE_PERMISSIONS_V833}
    out["visual-panel"] = True
    if not superadmin:
        out["users-panel"] = False
    return out


# Les réglages Apparence acceptent toutes les clés utiles envoyées par le front,
# notamment category_card_text_color, sans être bloqués par le modèle Pydantic historique.
async def api_get_ui_settings_v837(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    return load_user_ui_settings_v833(user)


async def api_patch_ui_settings_v837(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    current = load_user_ui_settings_v833(user)
    try:
        updates = await request.json()
    except Exception:
        updates = {}
    if not isinstance(updates, dict):
        updates = {}
    for key, value in updates.items():
        if value is not None:
            current[str(key)] = value
    current["logo_data_url"] = ""
    current["force_config_visibility"] = False
    saved = save_user_ui_settings_v833(user, current)
    write_app_log(
        "ui_settings_updated_v837",
        "settings",
        str((user or {}).get("username") or ""),
        f"Configuration visuelle modifiée pour {(user or {}).get('username') or ''}",
        request=request,
    )
    return saved


async def api_reset_ui_settings_v837(request: Request) -> dict[str, Any]:
    user = get_request_user(request)
    saved = save_user_ui_settings_v833(user, DEFAULT_UI_SETTINGS.copy())
    write_app_log(
        "ui_settings_reset_v837",
        "settings",
        str((user or {}).get("username") or ""),
        f"Configuration visuelle réinitialisée pour {(user or {}).get('username') or ''}",
        request=request,
    )
    return saved


try:
    app.router.routes = [
        r for r in app.router.routes
        if not (
            getattr(r, "path", None) in {"/api/ui-settings", "/api/ui-settings/reset"}
            and (set(getattr(r, "methods", set()) or set()) & {"GET", "PATCH", "POST"})
        )
    ]
    app.add_api_route("/api/ui-settings", api_get_ui_settings_v837, methods=["GET"])
    app.add_api_route("/api/ui-settings", api_patch_ui_settings_v837, methods=["PATCH"])
    app.add_api_route("/api/ui-settings/reset", api_reset_ui_settings_v837, methods=["POST"])
except Exception as exc:
    try:
        safe_log(f"Réenregistrement routes UI V8.3.7 impossible : {exc}")
    except Exception:
        pass

