def normalize_permissions_v833(raw: dict[str, Any] | None, *, superadmin: bool = False) -> dict[str, bool]:  # type: ignore[no-redef]
    try:
        if _normalize_permissions_before_v8310:
            out = dict(_normalize_permissions_before_v8310(raw, superadmin=superadmin))
        else:
            out = {key: True for key in MODULE_PERMISSIONS_V833}
            if isinstance(raw, dict):
                for key in MODULE_PERMISSIONS_V833:
                    if key in raw:
                        out[key] = bool(raw.get(key))
    except Exception:
        out = {key: True for key in MODULE_PERMISSIONS_V833}
    out["visual-panel"] = True
    return out

async def api_auth_me_v8310(request: Request) -> dict[str, Any]:
    user = get_request_user(request, touch=False)
    if not user:
        return {"authenticated": False}
    is_super = user_is_superadmin(user)
    permissions = get_user_permissions_by_username_v833(user.get("username"), superadmin=is_super)
    permissions["visual-panel"] = True
    return {
        **user,
        "authenticated": True,
        "can_write_assets": user_can_write_assets(user),
        "is_superadmin": is_super,
        "module_permissions": permissions,
        "timeout_minutes": SESSION_TIMEOUT_MINUTES,
        "app_name": APP_NAME,
        "app_version": APP_VERSION,
    }

async def api_update_user_v8310(request: Request, user_id: int) -> dict[str, Any]:
    # Route réenregistrée proprement pour éviter l'erreur missing request.
    current_user = require_superadmin(request)
    try:
        payload = await request.json()
        if not isinstance(payload, dict):
            payload = {}
    except Exception:
        payload = {}
    with db() as conn:
        existing = conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone()
        if not existing:
            raise HTTPException(status_code=404, detail="Identifiant introuvable")
        username = str(payload.get("username") if payload.get("username") is not None else existing["username"]).strip()
        if len(username) < 3:
            raise HTTPException(status_code=400, detail="Identifiant vide ou trop court")
        duplicate = conn.execute(
            "SELECT id FROM app_users WHERE LOWER(username) = LOWER(?) AND id <> ?",
            (username, user_id),
        ).fetchone()
        if duplicate:
            raise HTTPException(status_code=409, detail="Cet identifiant existe déjà")
        role_input = payload.get("role") if payload.get("role") is not None else existing["role"]
        is_admin_input = bool(payload.get("is_admin")) if payload.get("is_admin") is not None else bool(existing["is_admin"])
        role, is_admin = normalize_role(role_input, is_admin_input)
        if existing["role"] == "superadmin" and role != "superadmin" and count_superadmins(conn) <= 1:
            raise HTTPException(status_code=400, detail="Impossible de retirer le dernier compte superadmin")
        birth_date = payload.get("birth_date") if payload.get("birth_date") is not None else existing["birth_date"]
        must_change = bool(payload.get("must_change_password")) if payload.get("must_change_password") is not None else bool(existing["must_change_password"])
        password = str(payload.get("password") or "").strip()
        if password:
            code = validate_pin_password(password, "code")
            salt, digest = hash_password(code)
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, password_salt = ?, password_hash = ?, role = ?, is_admin = ?, birth_date = ?, must_change_password = ?
                WHERE id = ?
                """,
                (username, salt, digest, role, is_admin, birth_date, int(must_change), user_id),
            )
        else:
            conn.execute(
                """
                UPDATE app_users
                SET username = ?, role = ?, is_admin = ?, birth_date = ?, must_change_password = ?
                WHERE id = ?
                """,
                (username, role, is_admin, birth_date, int(must_change), user_id),
            )
        row = conn.execute(
            "SELECT id, username, role, is_admin, birth_date, must_change_password, created_at FROM app_users WHERE id = ?",
            (user_id,),
        ).fetchone()
        result = dict(row)
    write_app_log("user_updated_v8310", "user", user_id, f"Identifiant modifié : {result.get('username')} ({result.get('role')})", request=request)
    return result

